import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { AppraisalResult } from "../types";

const SYSTEM_INSTRUCTION = `You are the Vault-Tec Lead Architect and Master Appraiser. 
Your goal is to identify and value items for wasteland survivors and collectors. 
Be thorough, historical, and professional. 
Always look for maker marks and condition issues.
Provide output strictly in the requested JSON format.
If you use web search to find comparable sales, include the source URLs.`;

export const analyzeItem = async (imageBuffer: string): Promise<AppraisalResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Analyze this image of an item. Identify its name, era, manufacturer/origin, condition, and estimated market value. 
  Perform a search for current market trends and comparable sales.
  Provide detailed materials analysis and historical context.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        { inlineData: { data: imageBuffer.split(',')[1], mimeType: 'image/jpeg' } },
        { text: prompt }
      ]
    },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          itemName: { type: Type.STRING },
          category: { type: Type.STRING },
          era: { type: Type.STRING },
          origin: { type: Type.STRING },
          condition: { type: Type.STRING },
          valuation: {
            type: Type.OBJECT,
            properties: {
              low: { type: Type.NUMBER },
              mid: { type: Type.NUMBER },
              high: { type: Type.NUMBER },
              currency: { type: Type.STRING }
            }
          },
          authenticationMarks: { type: Type.ARRAY, items: { type: Type.STRING } },
          historicalContext: { type: Type.STRING },
          materials: { type: Type.STRING },
          careInstructions: { type: Type.STRING },
          comparableSales: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                platform: { type: Type.STRING },
                price: { type: Type.STRING },
                date: { type: Type.STRING },
                link: { type: Type.STRING }
              }
            }
          },
          confidence: { type: Type.NUMBER }
        },
        required: ["itemName", "valuation", "historicalContext"]
      }
    }
  });

  if (!response.text) throw new Error("No data received from intelligence core.");
  return JSON.parse(response.text) as AppraisalResult;
};

