import React, { useRef, useState, useCallback } from 'react';
import { Camera, RefreshCw, Save, Search, AlertTriangle } from 'lucide-react';
import { RetroButton } from './RetroButton';
import { analyzeItem } from '../services/geminiService';
import { AppraisalResult } from '../types';

interface ScanTerminalProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

export const ScanTerminal: React.FC<ScanTerminalProps> = ({ onSave }) => {
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AppraisalResult | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);

  const startCamera = async () => {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      setStream(s);
      if (videoRef.current) videoRef.current.srcObject = s;
    } catch (err) {
      console.error("CAMERA SIGNAL LOST", err);
    }
  };

  const capture = useCallback(() => {
    if (!videoRef.current) return;
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    const ctx = canvas.getContext('2d');
    ctx?.drawImage(videoRef.current, 0, 0);
    const data = canvas.toDataURL('image/jpeg');
    setCapturedImage(data);

    // Stop stream to save processing
    stream?.getTracks().forEach(t => t.stop());
    setStream(null);
  }, [stream]);

  const handleAnalyze = async () => {
    if (!capturedImage) return;
    setIsAnalyzing(true);
    try {
      const res = await analyzeItem(capturedImage);
      setResult(res);
    } catch (err) {
      alert("SIGNAL INTERFERENCE: ANALYSIS FAILED");
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="flex flex-col gap-6 max-w-4xl mx-auto p-4 animate-pulse">
      <div className="border-retro p-2 bg-black relative">
        <div className="absolute top-2 left-2 flex items-center gap-2 z-10 bg-black/50 p-1">
          <div className="w-2 h-2 bg-red-600 rounded-full animate-ping"></div>
          <span className="text-xs">LIVE FEED // SENSOR ACTIVE</span>
        </div>

        {!capturedImage ? (
          <div className="aspect-video bg-zinc-900 overflow-hidden relative border-2 border-[#14F514]/30">
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              className="w-full h-full object-cover grayscale brightness-125 contrast-125"
            />
            {!stream && (
              <div className="absolute inset-0 flex items-center justify-center">
                <RetroButton onClick={startCamera}>INITIALIZE CAMERA</RetroButton>
              </div>
            )}
          </div>
        ) : (
          <div className="aspect-video bg-zinc-900 border-2 border-[#14F514]/30">
            <img src={capturedImage} className="w-full h-full object-cover grayscale" />
          </div>
        )}
      </div>

      <div className="flex gap-4 justify-center">
        {!capturedImage ? (
          <RetroButton onClick={capture} active className="flex items-center gap-2">
            <Camera size={18} /> SCAN ENTITY
          </RetroButton>
        ) : (
          <>
            <RetroButton onClick={() => { setCapturedImage(null); setResult(null); startCamera(); }} className="flex items-center gap-2">
              <RefreshCw size={18} /> RETRY
            </RetroButton>
            <RetroButton onClick={handleAnalyze} active={!isAnalyzing} className="flex items-center gap-2">
              {isAnalyzing ? "ANALYZING..." : <><Search size={18} /> IDENTIFY</>}
            </RetroButton>
          </>
        )}
      </div>

      {result && (
        <div className="border-retro p-6 bg-black/80 space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="flex justify-between items-start border-b border-[#14F514]/50 pb-2">
            <div>
              <h2 className="text-4xl glow font-bold">{result.itemName}</h2>
              <p className="opacity-70">{result.era} // {result.origin}</p>
            </div>
            <div className="text-right">
              <p className="text-xs">ESTIMATED CAPS VALUE</p>
              <p className="text-3xl text-yellow-400 glow">${result.valuation.low} - ${result.valuation.high}</p>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <section className="space-y-2">
              <h3 className="border-b border-[#14F514]/30 text-lg flex items-center gap-2">
                <AlertTriangle size={16} /> CONDITION ANALYSIS
              </h3>
              <p className="text-sm">{result.condition}</p>

              <h3 className="border-b border-[#14F514]/30 text-lg mt-4">PROVENANCE & MARKS</h3>
              <ul className="list-disc list-inside text-sm">
                {result.authenticationMarks.map((m, i) => <li key={i}>{m}</li>)}
              </ul>
            </section>

            <section className="space-y-2">
              <h3 className="border-b border-[#14F514]/30 text-lg">HISTORICAL RECORD</h3>
              <p className="text-sm leading-relaxed">{result.historicalContext}</p>

              <h3 className="border-b border-[#14F514]/30 text-lg mt-4">MARKET COMPARABLES</h3>
              <div className="space-y-1">
                {result.comparableSales.map((sale, i) => (
                  <div key={i} className="flex justify-between text-xs p-1 border border-[#14F514]/20">
                    <span>{sale.platform} ({sale.date})</span>
                    <span className="font-bold">{sale.price}</span>
                  </div>
                ))}
              </div>
            </section>
          </div>

          <RetroButton 
            onClick={() => onSave(result, capturedImage!)} 
            className="w-full mt-4 flex items-center justify-center gap-2 py-4 text-xl"
            active
          >
            <Save size={24} /> SECURE TO VAULT
          </RetroButton>
        </div>
      )}
    </div>
  );
};

