const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>('SCAN');
  const [vault, setVault] = useState<CollectionItem[]>([]);
  const [bootSequence, setBootSequence] = useState(true);

  useEffect(() => {
    const saved = localStorage.getItem('vault_tec_inventory');
    if (saved) setVault(JSON.parse(saved));

    setTimeout(() => setBootSequence(false), 2000);
  }, []);

  const saveToVault = (result: AppraisalResult, imageData: string) => {
    const newItem: CollectionItem = {
      ...result,
      id: crypto.randomUUID(),
      dateScanned: new Date().toISOString(),
      imageUrl: imageData
    };
    const updated = [newItem, ...vault];
    setVault(updated);
    localStorage.setItem('vault_tec_inventory', JSON.stringify(updated));
    setActiveTab('VAULT');
  };

  const deleteItem = (id: string) => {
    const updated = vault.filter(i => i.id !== id);
    setVault(updated);
    localStorage.setItem('vault_tec_inventory', JSON.stringify(updated));
  };

  if (bootSequence) {
    return (
      <div className="h-screen w-full bg-black flex flex-col items-center justify-center p-8">
        <div className="w-full max-w-lg space-y-4">
          <div className="text-4xl glow text-center mb-8">SUBTEXT // VAULT-TEC OS</div>
          <div className="h-1 bg-[#14F514]/20 overflow-hidden">
            <div className="h-full bg-[#14F514] animate-[loading_2s_ease-in-out]"></div>
          </div>
          <div className="text-xs space-y-1 font-mono opacity-80">
            <p>INITIALIZING CPU CORE...</p>
            <p>LOADING KNOWLEDGE GRAPH...</p>
            <p>CALIBRATING SENSOR ARRAY...</p>
            <p>ESTABLISHING GEMINI UPLINK...</p>
          </div>
        </div>
        <style>{`
          @keyframes loading {
            0% { width: 0%; }
            100% { width: 100%; }
          }
        `}</style>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black flex flex-col p-2 md:p-6 lg:p-8">
      {/* Pip-Boy Header Navigation */}
      <nav className="flex flex-wrap gap-2 mb-8 justify-center border-b-4 border-[#14F514] pb-4 sticky top-0 bg-black z-50">
        <RetroButton 
          active={activeTab === 'SCAN'} 
          onClick={() => setActiveTab('SCAN')}
          className="flex items-center gap-2"
        >
          <Radio size={18} /> SCANNER
        </RetroButton>
        <RetroButton 
          active={activeTab === 'VAULT'} 
          onClick={() => setActiveTab('VAULT')}
          className="flex items-center gap-2"
        >
          <Database size={18} /> THE VAULT
        </RetroButton>
        <RetroButton 
          active={activeTab === 'DATA'} 
          onClick={() => setActiveTab('DATA')}
          className="flex items-center gap-2"
        >
          <Activity size={18} /> DATA ANALYSIS
        </RetroButton>
        <RetroButton 
          active={activeTab === 'MAP'} 
          onClick={() => setActiveTab('MAP')}
          className="flex items-center gap-2"
        >
          <ShieldAlert size={18} /> MARKET MAP
        </RetroButton>
      </nav>

      {/* Main Terminal Screen */}
      <main className="flex-1 overflow-auto">
        {activeTab === 'SCAN' && <ScanTerminal onSave={saveToVault} />}
        {activeTab === 'VAULT' && <VaultTerminal items={vault} onDelete={deleteItem} />}
        {activeTab === 'DATA' && <DataTerminal />}
        {activeTab === 'MAP' && (
          <div className="max-w-4xl mx-auto p-12 border-2 border-dashed border-[#14F514]/40 text-center opacity-70">
            <h2 className="text-4xl mb-4">GEOLOCATION OFFLINE</h2>
            <p>SATELLITE LINK REQUIRES OVERRIDE CODES. MARKET RADIUS LIMITED TO LOCAL SECTOR.</p>
            <RetroButton className="mt-8">RE-ESTABLISH LINK</RetroButton>
          </div>
        )}
      </main>

      {/* System Status Footer */}
      <footer className="mt-8 pt-4 border-t border-[#14F514]/30 text-xs flex flex-wrap justify-between opacity-60">
        <div>OS: VT-PIPB_MK4 // USER: WANDERER_01</div>
        <div className="flex gap-4">
          <span>MEM: 128.4 PB</span>
          <span>SENSORS: OPTIMAL</span>
          <span>ENCRYPTION: VAULT-PROT-19</span>
        </div>
