import { GoogleGenAI, Type } from "@google/genai";
import { AppraisalResult } from "../types";

const SYSTEM_INSTRUCTION = `You are a universal item identifier and valuation expert with two distinct modes:

MODE A: THE CURATOR (for Antiques/Collectibles)
- Used for: Items >20 years old, art, rare finds.
- Tone: Scholarly, historical, nuanced.
- Focus: Provenance, craftsmanship, maker's marks, cultural context.

MODE B: THE PRODUCT SPECIALIST (for Modern/Everyday Items)
- Used for: Contemporary electronics, appliances, modern furniture, tools, mass-produced goods.
- Tone: Practical, direct, technical.
- Focus: Brand, model number, specifications, utility, resale value.
- RESTRICTION: Do NOT use words like "patina," "provenance," or "historical context" for modern items. Do not invent history for a 2015 telephone.

YOUR TASK:
1. Classify the image immediately (Antique, Vintage, Modern, New, or Specialty).
2. Adopt the correct MODE based on classification.
3. Provide accurate identification and valuation.
`;

export const analyzeItem = async (imageBuffer: string): Promise<AppraisalResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Analyze this image.

  STEP 1: CLASSIFY
  Is this item Antique (100+ yrs), Vintage (20-99 yrs), Modern (Used/Secondhand), New (Current Production), or Specialty?

  STEP 2: IDENTIFY
  - If Modern/New: Identify Brand, Model Number, Year, and Specs.
  - If Antique/Vintage: Identify Maker, Era, Style, and Provenance markers.

  STEP 3: ASSESS CONDITION
  - Rate 1-10. Note specific wear.

  STEP 4: VALUATION
  - Estimate Fair Market Value based on its specific market (e.g., Used Electronics market vs. Antique Auction market).

  STEP 5: CONTEXT
  - If Modern: Provide technical specs and intended use.
  - If Antique: Provide historical context and cultural significance.

  STEP 6: SELLING STRATEGY
  - Draft a listing title and description.
  - Choose the right venue (e.g., eBay/Mercari for modern goods; 1stDibs/Auction for antiques).

  Return strictly JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        { inlineData: { data: imageBuffer.split(',')[1], mimeType: 'image/jpeg' } },
        { text: prompt }
      ]
    },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          itemName: { type: Type.STRING },
          category: { type: Type.STRING },
          classification: { type: Type.STRING, enum: ["Antique", "Vintage", "Modern", "New", "Specialty"] },
          era: { type: Type.STRING },
          origin: { type: Type.STRING },
          condition: { type: Type.STRING },
          conditionScore: { type: Type.NUMBER },
          valuation: {
            type: Type.OBJECT,
            properties: {
              low: { type: Type.NUMBER },
              mid: { type: Type.NUMBER },
              high: { type: Type.NUMBER },
              currency: { type: Type.STRING }
            }
          },
          // Maps to "Key Identifiers" (Modern) or "Authentication Marks" (Antique)
          authenticationMarks: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "For modern items, list Model Numbers, Serial Locations, or Specs. For antiques, list Hallmarks or Signatures." 
          },
          // Maps to "Specs/Details" (Modern) or "Historical Context" (Antique)
          historicalContext: { 
            type: Type.STRING,
            description: "If modern, provide product specs and utility. If antique, provide history."
          },
          materials: { type: Type.STRING },
          careInstructions: { type: Type.STRING },
          comparableSales: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                price: { type: Type.STRING },
                date: { type: Type.STRING },
                link: { type: Type.STRING },
                source: { type: Type.STRING }
              }
            }
          },
          sellingProfile: {
            type: Type.OBJECT,
            properties: {
              listingTitle: { type: Type.STRING },
              listingDescription: { type: Type.STRING },
              keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
              recommendedVenue: { type: Type.STRING },
              pricingStrategy: { type: Type.STRING }
            }
          },
          confidence: { type: Type.NUMBER }
        },
        required: ["itemName", "valuation", "historicalContext", "sellingProfile", "classification"]
      }
    }
  });

  if (!response.text) throw new Error("Analysis failed to return data.");
  return JSON.parse(response.text) as AppraisalResult;
};

import React, { useState, useEffect } from 'react';
import { AppTab, CollectionItem, AppraisalResult } from './types';
import { Scanner } from './components/ScanTerminal';
import { CollectionManager } from './components/VaultTerminal';
import { MarketTrends } from './components/DataTerminal';
import { ScanLine, Box, BarChart3 } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>('SCAN');
  const [collection, setCollection] = useState<CollectionItem[]>([]);

  useEffect(() => {
    const saved = localStorage.getItem('curator_collection');
    if (saved) setCollection(JSON.parse(saved));
  }, []);

  const saveToCollection = (result: AppraisalResult, imageData: string) => {
    const newItem: CollectionItem = {
      ...result,
      id: crypto.randomUUID(),
      dateScanned: new Date().toISOString(),
      imageUrl: imageData
    };
    const updated = [newItem, ...collection];
    setCollection(updated);
    localStorage.setItem('curator_collection', JSON.stringify(updated));
    setActiveTab('COLLECTION');
  };

  const deleteItem = (id: string) => {
    const updated = collection.filter(i => i.id !== id);
    setCollection(updated);
    localStorage.setItem('curator_collection', JSON.stringify(updated));
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'SCAN': return <Scanner onSave={saveToCollection} />;
      case 'COLLECTION': return <CollectionManager items={collection} onDelete={deleteItem} />;
      case 'MARKET': return <MarketTrends />;
      default: return <Scanner onSave={saveToCollection} />;
    }
  };

  return (
    // Dark mode container
    <div className="flex flex-col h-[100dvh] w-full bg-zinc-950 text-zinc-100 selection:bg-blue-500/30">

      {/* Main Content Area */}
      <main className="flex-1 relative overflow-hidden flex flex-col">
        {renderContent()}
