import React, { useRef, useState, useCallback } from 'react';
import { RefreshCw, Sparkles, Image as ImageIcon, Camera } from 'lucide-react';
import { Button } from './Button';
import { analyzeItem } from '../services/geminiService';
import { AppraisalResult } from '../types';
import { ItemResult } from './ItemResult';

interface ScannerProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AppraisalResult | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const startCamera = async () => {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' },
        audio: false 
      });
      setStream(s);
      if (videoRef.current) videoRef.current.srcObject = s;
    } catch (err) {
      console.error("Camera access denied", err);
    }
  };

  const capture = useCallback(() => {
    if (!videoRef.current) return;
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    const ctx = canvas.getContext('2d');
    ctx?.drawImage(videoRef.current, 0, 0);
    const data = canvas.toDataURL('image/jpeg', 0.8);
    setCapturedImage(data);

    stream?.getTracks().forEach(t => t.stop());
    setStream(null);
  }, [stream]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setCapturedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAnalyze = async () => {
    if (!capturedImage) return;
    setIsAnalyzing(true);
    try {
      const res = await analyzeItem(capturedImage);
      setResult(res);
    } catch (err) {
      alert("Unable to identify item. Please try a clearer angle.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const reset = () => {
    setCapturedImage(null);
    setResult(null);
    startCamera();
  };

  // If we have a result, show the Result View
  if (result && capturedImage) {
    return (
      <ItemResult 
        result={result} 
        imageData={capturedImage} 
        onBack={reset} 
        onSave={(res) => onSave(res, capturedImage)} 
      />
    );
  }

  // Camera View
  return (
    <div className="flex-1 flex flex-col bg-zinc-950 relative">
      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        accept="image/*"
        onChange={handleFileUpload}
      />

      {/* Header Overlay */}
      <div className="absolute top-0 left-0 right-0 z-20 pt-[env(safe-area-inset-top)] p-4 flex justify-between items-start bg-gradient-to-b from-black/90 to-transparent pointer-events-none">
        <div className="pointer-events-auto">
           <h2 className="text-xl font-bold font-serif tracking-tight text-white drop-shadow-md">Identify</h2>
        </div>
        {capturedImage && (
          <button onClick={reset} className="text-xs font-bold uppercase tracking-widest text-zinc-300 hover:text-white bg-zinc-900/50 backdrop-blur border border-white/10 px-4 py-2 rounded-full pointer-events-auto">Reset</button>
        )}
      </div>

      {/* Viewfinder Area */}
      <div className="flex-1 relative overflow-hidden bg-zinc-900">
        {!capturedImage ? (
          <>
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              className="absolute inset-0 w-full h-full object-cover opacity-80"
            />
            {!stream && (
              <div className="absolute inset-0 flex flex-col items-center justify-center gap-4 p-6">
                <Camera size={48} className="text-zinc-700" />
                <Button onClick={startCamera} variant="secondary">Initialize Visual Sensor</Button>
                <button onClick={() => fileInputRef.current?.click()} className="text-zinc-500 text-sm font-medium hover:text-white transition-colors">
                  or upload from gallery
                </button>
              </div>
            )}
            {stream && (
              <div className="absolute inset-0 pointer-events-none">
                {/* Multi-Angle Guide Overlay */}
                <div className="absolute inset-0 flex items-center justify-center">
                  <div className="w-[75%] aspect-[3/4] border border-white/20 rounded-2xl relative shadow-[0_0_100px_rgba(0,0,0,0.5)_inset]">
                    {/* Corners */}
                    <div className="absolute top-0 left-0 w-8 h-8 border-t-2 border-l-2 border-blue-500 rounded-tl-xl"></div>
                    <div className="absolute top-0 right-0 w-8 h-8 border-t-2 border-r-2 border-blue-500 rounded-tr-xl"></div>
                    <div className="absolute bottom-0 left-0 w-8 h-8 border-b-2 border-l-2 border-blue-500 rounded-bl-xl"></div>
                    <div className="absolute bottom-0 right-0 w-8 h-8 border-b-2 border-r-2 border-blue-500 rounded-br-xl"></div>

                    {/* Crosshair */}
                    <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-4 h-4">
                      <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[1px] h-full bg-white/30"></div>
                      <div className="absolute top-1/2 left-0 -translate-y-1/2 w-full h-[1px] bg-white/30"></div>
                    </div>
                  </div>
                </div>

                {/* Visual Guides */}
                <div className="absolute bottom-28 left-0 right-0 flex justify-center gap-8 text-[10px] font-bold uppercase tracking-widest text-white/50">
                  <div className="text-white drop-shadow-md">Front View</div>
                  <div>Markings</div>
                  <div>Damage</div>
                </div>
              </div>
            )}
          </>
        ) : (
          <img src={capturedImage} className="w-full h-full object-cover" />
        )}
      </div>

      {/* Controls Container */}
      <div className="bg-zinc-950 border-t border-zinc-800 -mt-6 z-20 relative pt-6 pb-4 rounded-t-3xl">
        <div className="px-6">
          <div className="flex flex-col gap-4">
            {!capturedImage ? (
              <div className="flex justify-between items-center px-4">
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="p-4 rounded-full bg-zinc-900 text-zinc-400 hover:text-white border border-zinc-800 hover:border-zinc-700 transition-all"
                >
                  <ImageIcon size={22} />
                </button>

                <button 
                  onClick={capture} 
                  className="w-20 h-20 rounded-full border border-zinc-700 p-1 flex items-center justify-center relative group"
                >
                  <div className="absolute inset-0 bg-white/5 rounded-full blur-xl group-hover:bg-white/10 transition-colors"></div>
                  <div className="w-full h-full bg-white rounded-full group-active:scale-90 transition-transform shadow-[0_0_20px_rgba(255,255,255,0.3)]"></div>
                </button>

                <button 
                  onClick={reset}
                  className="p-4 rounded-full bg-zinc-900 text-zinc-400 hover:text-white border border-zinc-800 hover:border-zinc-700 transition-all"
                >
                  <RefreshCw size={22} />
                </button>
              </div>
            ) : (
              <div className="space-y-3 pt-2">
                <Button 
                  onClick={handleAnalyze} 
                  isLoading={isAnalyzing} 
                  className="w-full text-lg shadow-[0_0_30px_rgba(37,99,235,0.15)] py-4 bg-white text-black hover:bg-zinc-200 border-none"
                >
                  {isAnalyzing ? "Processing Visual Data..." : "Identify & Appraise"}
                </Button>
                <Button onClick={reset} variant="ghost" className="w-full text-zinc-500 hover:bg-zinc-900">
                  Retake Evidence
                </Button>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
