const SYSTEM_INSTRUCTION = `You are a universal item identifier and valuation expert with two distinct modes:

MODE A: THE CURATOR (for Antiques/Collectibles)
- Used for: Items >20 years old, art, rare finds.
- Tone: Scholarly, historical, nuanced.
- Focus: Provenance, craftsmanship, maker's marks, cultural context.

MODE B: THE PRODUCT SPECIALIST (for Modern/Everyday Items)
- Used for: Contemporary electronics, appliances, modern furniture, tools, mass-produced goods.
- Tone: Practical, direct, technical.
- Focus: Brand, model number, specifications, utility, resale value.
- RESTRICTION: Do NOT use words like "patina," "provenance," or "historical context" for modern items. Do not invent history for a 2015 telephone.

YOUR TASK:
1. Classify the image immediately (Antique, Vintage, Modern, New, or Specialty).
2. Adopt the correct MODE based on classification.
3. Provide accurate identification and valuation.
`;

export const analyzeItem = async (imageBuffers: string[]): Promise<AppraisalResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Analyze these images. They may show different angles or details of the same item.

  STEP 1: CLASSIFY
  Is this item Antique (100+ yrs), Vintage (20-99 yrs), Modern (Used/Secondhand), New (Current Production), or Specialty?

  STEP 2: IDENTIFY
  - If Modern/New: Identify Brand, Model Number, Year, and Specs.
  - If Antique/Vintage: Identify Maker, Era, Style, and Provenance markers.

  STEP 3: ASSESS CONDITION
  - Rate 1-10. Note specific wear visible across all images.

  STEP 4: VALUATION
  - Estimate Fair Market Value based on its specific market.

  STEP 5: CONTEXT
  - If Modern: Provide technical specs and intended use.
  - If Antique: Provide historical context and cultural significance.

  STEP 6: SELLING STRATEGY
  - Draft a listing title and description.
  - Choose the right venue.

  Return strictly JSON.`;

  // Create an image part for every captured image
  const imageParts = imageBuffers.map(buffer => ({
    inlineData: { data: buffer.split(',')[1], mimeType: 'image/jpeg' }
  }));

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        ...imageParts,
        { text: prompt }
      ]
    },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          itemName: { type: Type.STRING },
          category: { type: Type.STRING },
          classification: { type: Type.STRING, enum: ["Antique", "Vintage", "Modern", "New", "Specialty"] },
          era: { type: Type.STRING },
          origin: { type: Type.STRING },
          condition: { type: Type.STRING },
          conditionScore: { type: Type.NUMBER },
          valuation: {
            type: Type.OBJECT,
            properties: {
              low: { type: Type.NUMBER },
              mid: { type: Type.NUMBER },
              high: { type: Type.NUMBER },
              currency: { type: Type.STRING }
            }
          },
          authenticationMarks: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "For modern items, list Model Numbers/Specs. For antiques, list Hallmarks/Signatures." 
          },
          historicalContext: { 
            type: Type.STRING,
            description: "If modern, provide product specs. If antique, provide history."
          },
          materials: { type: Type.STRING },
          careInstructions: { type: Type.STRING },
          comparableSales: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                price: { type: Type.STRING },
                date: { type: Type.STRING },
                link: { type: Type.STRING },
                source: { type: Type.STRING }
              }
            }
          },
          sellingProfile: {
            type: Type.OBJECT,
            properties: {
              listingTitle: { type: Type.STRING },
              listingDescription: { type: Type.STRING },
              keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
              recommendedVenue: { type: Type.STRING },
              pricingStrategy: { type: Type.STRING }
            }
          },
          confidence: { type: Type.NUMBER }
        },
        required: ["itemName", "valuation", "historicalContext", "sellingProfile", "classification"]
      }
    }
  });

  if (!response.text) throw new Error("Analysis failed to return data.");
  return JSON.parse(response.text) as AppraisalResult;
};

import React, { useRef, useState, useCallback, useEffect } from 'react';
import { RefreshCw, Sparkles, Image as ImageIcon, Camera, Plus, Trash2, X } from 'lucide-react';
import { Button } from './Button';
import { analyzeItem } from '../services/geminiService';
import { AppraisalResult } from '../types';
import { ItemResult } from './ItemResult';

interface ScannerProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AppraisalResult | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const startCamera = async () => {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' },
        audio: false 
      });
      setStream(s);
      setIsCameraActive(true);
      if (videoRef.current) videoRef.current.srcObject = s;
    } catch (err) {
      console.error("Camera access denied", err);
    }
  };

  const stopCamera = () => {
    stream?.getTracks().forEach(t => t.stop());
    setStream(null);
    setIsCameraActive(false);
  };

  const capture = useCallback(() => {
    if (!videoRef.current) return;
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    const ctx = canvas.getContext('2d');
    ctx?.drawImage(videoRef.current, 0, 0);
    const data = canvas.toDataURL('image/jpeg', 0.8);

    setCapturedImages(prev => [...prev, data]);
    stopCamera();
  }, [stream]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files && files.length > 0) {
      Array.from(files).forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          setCapturedImages(prev => [...prev, reader.result as string]);
        };
        reader.readAsDataURL(file);
      });
      stopCamera();
    }
  };

  const handleAnalyze = async () => {
    if (capturedImages.length === 0) return;
    setIsAnalyzing(true);
    try {
      const res = await analyzeItem(capturedImages);
      setResult(res);
    } catch (err) {
      alert("Unable to identify item. Please try again.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const reset = () => {
    setCapturedImages([]);
    setResult(null);
    startCamera();
  };

  const removeImage = (index: number) => {
    setCapturedImages(prev => prev.filter((_, i) => i !== index));
  };

  // Re-attach stream when camera becomes active
  useEffect(() => {
    if (isCameraActive && videoRef.current && stream) {
      videoRef.current.srcObject = stream;
    }
  }, [isCameraActive, stream]);

  // Initial load
  useEffect(() => {
    startCamera();
    return () => {
      stopCamera();
    };
  }, []);

  // SHOW RESULT
  if (result && capturedImages.length > 0) {
    return (
      <ItemResult 
        result={result} 
        imageData={capturedImages[0]} // Use first image as hero
        onBack={() => setResult(null)} 
        onSave={(res) => onSave(res, capturedImages[0])} 
      />
    );
  }

  // PREVIEW / REVIEW MODE
  // If we have images and camera is NOT active, show the "Review" screen
  if (capturedImages.length > 0 && !isCameraActive) {
    return (
      <div className="flex-1 flex flex-col bg-zinc-950 relative">
        {/* Header */}
        <div className="absolute top-0 left-0 right-0 z-20 pt-[env(safe-area-inset-top)] p-4 flex justify-between items-center pointer-events-none">
           <h2 className="text-xl font-bold font-serif tracking-tight text-white drop-shadow-md pointer-events-auto">Evidence Review</h2>
           <button onClick={reset} className="p-2 bg-black/50 backdrop-blur rounded-full text-zinc-400 hover:text-white pointer-events-auto">
             <Trash2 size={20} />
           </button>
        </div>

        {/* Main Preview (Last Image) */}
        <div className="flex-1 relative bg-zinc-900 flex items-center justify-center p-8">
          <div className="relative w-full max-w-md aspect-[3/4] rounded-2xl overflow-hidden shadow-2xl border border-zinc-800">
             <img src={capturedImages[capturedImages.length - 1]} className="w-full h-full object-cover" />
             <div className="absolute bottom-4 right-4 bg-black/60 backdrop-blur px-3 py-1 rounded-lg border border-white/10 text-xs font-bold text-white uppercase tracking-widest">
               Image {capturedImages.length}
             </div>
          </div>
