           <button onClick={reset} className="p-2 bg-black/50 backdrop-blur rounded-full text-zinc-400 hover:text-white pointer-events-auto">
             <Trash2 size={20} />
           </button>
        </div>

        {/* Main Preview (Last Image) */}
        <div className="flex-1 relative bg-zinc-900 flex items-center justify-center p-8">
          <div className="relative w-full max-w-md aspect-[3/4] rounded-2xl overflow-hidden shadow-2xl border border-zinc-800">
             <img src={capturedImages[capturedImages.length - 1]} className="w-full h-full object-cover" />
             <div className="absolute bottom-4 right-4 bg-black/60 backdrop-blur px-3 py-1 rounded-lg border border-white/10 text-xs font-bold text-white uppercase tracking-widest">
               Image {capturedImages.length}
             </div>
          </div>
        </div>

        {/* Thumbnail Strip & Controls */}
        <div className="bg-zinc-950 border-t border-zinc-800 p-6 rounded-t-3xl shadow-[0_-10px_40px_rgba(0,0,0,0.5)] z-20">

           {/* Thumbnails */}
           <div className="flex gap-3 overflow-x-auto pb-6 -mx-2 px-2 no-scrollbar">
              {capturedImages.map((img, idx) => (
                <div key={idx} className="relative w-16 h-16 shrink-0 rounded-lg overflow-hidden border border-zinc-700 group">
                  <img src={img} className="w-full h-full object-cover" />
                  <button 
                    onClick={() => removeImage(idx)}
                    className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                  >
                    <X size={16} className="text-white"/>
                  </button>
                </div>
              ))}
              {/* Add Button in Strip */}
              <button 
                onClick={startCamera}
                className="w-16 h-16 shrink-0 rounded-lg border-2 border-dashed border-zinc-700 flex flex-col items-center justify-center gap-1 text-zinc-500 hover:text-white hover:border-zinc-500 transition-colors"
              >
                <Plus size={20} />
              </button>
           </div>

           {/* Actions */}
           <div className="flex flex-col gap-3">
             <Button 
               onClick={handleAnalyze} 
               isLoading={isAnalyzing} 
               className="w-full py-4 text-lg bg-white text-black hover:bg-zinc-200 border-none shadow-[0_0_30px_rgba(37,99,235,0.15)]"
             >
               {isAnalyzing ? "Analyzing Evidence..." : `Evaluate Evidence (${capturedImages.length})`}
             </Button>

             <div className="flex gap-3">
