          onChange={handleFileUpload}
        />
      </div>
    );
  }

  // CAMERA MODE
  return (
    <div className="flex-1 flex flex-col bg-zinc-950 relative">
      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        accept="image/*"
        multiple
        onChange={handleFileUpload}
      />

      {/* Viewfinder Header */}
      <div className="absolute top-0 left-0 right-0 z-20 pt-[env(safe-area-inset-top)] p-4 flex justify-between items-start bg-gradient-to-b from-black/80 to-transparent pointer-events-none">
        <div className="pointer-events-auto">
           <h2 className="text-xl font-bold font-serif tracking-tight text-white drop-shadow-md">Capture</h2>
        </div>
        {capturedImages.length > 0 && (
          <button onClick={() => stopCamera()} className="px-4 py-2 bg-black/50 backdrop-blur rounded-full border border-white/10 text-xs font-bold uppercase text-white pointer-events-auto">
            Cancel
          </button>
        )}
      </div>

      {/* Viewfinder */}
      <div className="flex-1 relative overflow-hidden bg-zinc-900">
        <video 
          ref={videoRef} 
          autoPlay 
          playsInline 
          className="absolute inset-0 w-full h-full object-cover"
        />

        {/* Guides */}
        <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
            <div className="w-[80%] aspect-[3/4] border border-white/30 rounded-2xl relative shadow-[0_0_100px_rgba(0,0,0,0.5)_inset]">
                <div className="absolute top-0 left-0 w-6 h-6 border-t-2 border-l-2 border-white rounded-tl-lg"></div>
                <div className="absolute top-0 right-0 w-6 h-6 border-t-2 border-r-2 border-white rounded-tr-lg"></div>
                <div className="absolute bottom-0 left-0 w-6 h-6 border-b-2 border-l-2 border-white rounded-bl-lg"></div>
                <div className="absolute bottom-0 right-0 w-6 h-6 border-b-2 border-r-2 border-white rounded-br-lg"></div>
