import { ItemResult } from './ItemResult';

interface ScannerProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

type ScanMode = 'LIVE' | 'MANUAL';

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  const [mode, setMode] = useState<ScanMode>('MANUAL');
  const [stream, setStream] = useState<MediaStream | null>(null);

  // MANUAL STATE
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [manualResult, setManualResult] = useState<AppraisalResult | null>(null);

  // LIVE STATE
  const [liveData, setLiveData] = useState<LiveAnalysisUpdate | null>(null);
  const [isLivePaused, setIsLivePaused] = useState(false);
  const [lastScanTime, setLastScanTime] = useState<number>(0);
  const [isPulsing, setIsPulsing] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // --- CAMERA LOGIC ---
  const startCamera = async () => {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } },
        audio: false 
      });
      setStream(s);
      if (videoRef.current) videoRef.current.srcObject = s;
    } catch (err) {
      console.error("Camera access denied", err);
    }
  };

  const stopCamera = () => {
    stream?.getTracks().forEach(t => t.stop());
    setStream(null);
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  useEffect(() => {
    if (stream && videoRef.current) videoRef.current.srcObject = stream;
  }, [stream, mode]); // Re-attach on mode switch

  // --- MANUAL MODE HANDLERS ---
  const captureManual = useCallback(() => {
    if (!videoRef.current) return;
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    const ctx = canvas.getContext('2d');
    ctx?.drawImage(videoRef.current, 0, 0);
    const data = canvas.toDataURL('image/jpeg', 0.85);
    setCapturedImages(prev => [...prev, data]);
  }, []);

  const handleManualAnalyze = async () => {
    if (capturedImages.length === 0) return;
    setIsAnalyzing(true);
    try {
      const res = await analyzeItem(capturedImages);
      setManualResult(res);
    } catch (err) {
      alert("Analysis failed. Try again.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  // --- LIVE MODE HEARTBEAT ---
  useEffect(() => {
    if (mode !== 'LIVE' || isLivePaused || !stream) return;

    const intervalId = setInterval(async () => {
      const now = Date.now();
      // Rate limit to every 3.5 seconds to allow reading and save costs
      if (now - lastScanTime < 3500) return;

      if (videoRef.current) {
        setIsPulsing(true);
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth / 2; // Downscale for speed
        canvas.height = videoRef.current.videoHeight / 2;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const frameData = canvas.toDataURL('image/jpeg', 0.6);

        // Analyze Frame
        try {
          const context = liveData ? `Previous guess: ${liveData.shortTitle}. ${liveData.detailedNote}` : "";
          const result = await analyzeLiveFrame(frameData, context);

          // Only update if confident or if we were searching
          if (result.status !== 'SEARCHING' || liveData?.status === 'SEARCHING') {
             setLiveData(result);
          }

          setLastScanTime(Date.now());
        } catch (e) {
          console.error("Live pulse failed", e);
        } finally {
          setIsPulsing(false);
        }
      }
    }, 1000); // Check every second, execute every 3.5s

    return () => clearInterval(intervalId);
  }, [mode, isLivePaused, stream, lastScanTime, liveData]);

  // --- RENDER HELPERS ---

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    // Existing logic...
    const files = e.target.files;
    if (files && files.length > 0) {
      Array.from(files).forEach((file) => {
        const reader = new FileReader();
        reader.onloadend = () => setCapturedImages(prev => [...prev, reader.result as string]);
        reader.readAsDataURL(file as Blob);
      });
      setMode('MANUAL');
    }
  };

  const saveLiveItem = () => {
    if (!liveData) return;
    // Construct a partial AppraisalResult from LiveData for saving
    // In a real app, we might trigger a full scan here to get perfect data
    const partialResult: AppraisalResult = {
        itemName: liveData.shortTitle,
        category: 'Live Scan Capture',
        classification: liveData.classification,
        era: liveData.quickFacts[0] || 'Unknown',
        origin: 'Unknown',
        condition: 'Assessed Live',
        conditionScore: 5,
        valuation: { low: 0, mid: 0, high: 0, currency: 'USD' }, // Placeholder
        authenticationMarks: [],
        historicalContext: liveData.detailedNote || '',
        materials: liveData.quickFacts[1] || 'Unknown',
        careInstructions: 'Handle with care.',
        comparableSales: [],
        sellingProfile: { listingTitle: liveData.shortTitle, listingDescription: liveData.detailedNote || '', keywords: [], recommendedVenue: 'Online', pricingStrategy: 'Auction' },
        confidence: liveData.confidence
    };

    // Capture current frame for the save
    if (videoRef.current) {
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth;
        canvas.height = videoRef.current.videoHeight;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(videoRef.current, 0, 0);
        const data = canvas.toDataURL('image/jpeg', 0.85);
        onSave(partialResult, data);
    }
  };

  // IF MANUAL RESULT EXISTS
  if (manualResult && capturedImages.length > 0) {
    return (
      <ItemResult 
        result={manualResult} 
        imageData={capturedImages[0]} 
        onBack={() => setManualResult(null)} 
        onSave={(res) => onSave(res, capturedImages[0])} 
      />
    );
  }

  // --- MAIN RENDER ---
  return (
    <div className="flex-1 flex flex-col bg-zinc-950 relative h-full overflow-hidden">

      {/* HEADER CONTROLS */}
      <div className="absolute top-0 left-0 right-0 z-30 pt-[env(safe-area-inset-top)] p-4 flex justify-between items-start bg-gradient-to-b from-black/90 to-transparent pointer-events-none">
