import { getMarketAnalysis } from '../services/geminiService';

interface MarketTrendsProps {
  items: CollectionItem[];
}

// Generate simulated curve based on trend direction for visual feedback
const generateTrendData = (trend: 'UP' | 'DOWN' | 'STABLE') => {
  const data = [];
  let value = 4000;
  for (let i = 0; i < 6; i++) {
    const month = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'][i];
    let change = 0;
    if (trend === 'UP') change = Math.random() * 500 + 100;
    if (trend === 'DOWN') change = -(Math.random() * 500 + 100);
    if (trend === 'STABLE') change = Math.random() * 200 - 100;

    value += change;
    data.push({ name: month, value: Math.round(value) });
  }
  return data;
};

export const MarketTrends: React.FC<MarketTrendsProps> = ({ items }) => {
  const [analysis, setAnalysis] = useState<MarketAnalysis | null>(null);
  const [loading, setLoading] = useState(false);
  const [chartData, setChartData] = useState<any[]>(generateTrendData('STABLE'));

  // Logic: Analyze the most recently added item to give "Intel on current item"
  const latestItem = items.length > 0 ? items[0] : null;

  useEffect(() => {
    const fetchIntel = async () => {
      if (!latestItem) return;

      setLoading(true);
      try {
        // Use the item name + category + classification for a precise search query
        const query = `${latestItem.classification} ${latestItem.era} ${latestItem.itemName} ${latestItem.category}`;
        const result = await getMarketAnalysis(query);
        setAnalysis(result);
        setChartData(generateTrendData(result.trend));
      } catch (error) {
        console.error("Failed to fetch market intel", error);
      } finally {
        setLoading(false);
      }
    };

    fetchIntel();
  }, [latestItem?.id]); // Re-run if the latest item changes (e.g. user scans something new)

  // Calculate Portfolio Composition
  const categories = items.reduce((acc, item) => {
    acc[item.category] = (acc[item.category] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const sortedCategories = Object.entries(categories)
    .sort((a, b) => (b[1] as number) - (a[1] as number))
    .slice(0, 4);

  if (!latestItem) {
    return (
      <div className="h-full flex flex-col items-center justify-center bg-zinc-950 p-8 text-center">
        <div className="w-20 h-20 bg-zinc-900 rounded-full mb-6 flex items-center justify-center border border-zinc-800">
          <PieChart size={32} className="opacity-50 text-zinc-500" />
