        <h2 className="text-xl font-serif text-white mb-2">Market Intelligence Offline</h2>
        <p className="text-zinc-500 max-w-xs">Scan or add items to your vault to unlock real-time valuation tracking and market insights.</p>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col bg-zinc-950 overflow-auto">
      <div className="bg-zinc-950 p-6 border-b border-zinc-800 pt-[calc(20px+env(safe-area-inset-top))]">
        <h1 className="text-2xl font-serif font-bold text-white mb-1">Market Intel</h1>
        <p className="text-xs text-zinc-500 uppercase tracking-widest font-bold">
          Analysis for: <span className="text-blue-400">{latestItem.itemName}</span>
        </p>
      </div>

      <div className="p-4 space-y-6 pb-24">
        {/* Main Chart Section */}
        <div className="bg-zinc-900 p-6 rounded-2xl border border-zinc-800 relative overflow-hidden">
          {loading ? (
            <div className="absolute inset-0 z-10 bg-zinc-900/80 backdrop-blur-sm flex items-center justify-center">
              <div className="flex flex-col items-center gap-3">
                <Loader2 size={24} className="animate-spin text-blue-500" />
                <span className="text-xs text-blue-400 font-bold uppercase tracking-widest">Analyzing Market...</span>
              </div>
            </div>
          ) : null}

          <div className="flex justify-between items-center mb-6">
            <h3 className="font-bold text-zinc-200 text-sm uppercase tracking-wide">Market Trajectory</h3>
            {analysis && (
              <span className={`text-sm font-bold flex items-center gap-1 px-2 py-1 rounded border ${analysis.trend === 'UP' ? 'bg-emerald-950/30 border-emerald-900 text-emerald-400' : analysis.trend === 'DOWN' ? 'bg-red-950/30 border-red-900 text-red-400' : 'bg-zinc-800 border-zinc-700 text-zinc-400'}`}>
                {analysis.trend === 'UP' ? <TrendingUp size={14} /> : analysis.trend === 'DOWN' ? <ArrowDownRight size={14} /> : <ArrowUpRight size={14} />} 
                {analysis.changePercent}
              </span>
            )}
          </div>
          <div className="h-64 -ml-4">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={chartData}>
                <defs>
                  <linearGradient id="colorValue" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor={analysis?.trend === 'DOWN' ? '#ef4444' : '#3b82f6'} stopOpacity={0.3}/>
                    <stop offset="95%" stopColor={analysis?.trend === 'DOWN' ? '#ef4444' : '#3b82f6'} stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#27272a" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#52525b', fontSize: 10, fontWeight: 700}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#52525b', fontSize: 10, fontWeight: 700}} />
                <Tooltip 
