import React, { useRef, useState, useCallback, useEffect } from 'react';
import { RefreshCw, Image as ImageIcon, Camera, Plus, Trash2, X, Zap, Pause, Play, ScanLine, Loader2, ChevronUp, ChevronDown, Save, Share2, History, Clock } from 'lucide-react';
import { Button } from './Button';
import { analyzeItem, analyzeLiveFrame } from '../services/geminiService';
import { AppraisalResult, LiveAnalysisUpdate } from '../types';
import { ItemResult } from './ItemResult';

interface ScannerProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

type ScanMode = 'LIVE' | 'MANUAL';

interface SessionHistoryItem {
  id: string;
  timestamp: Date;
  thumbnail: string;
  data: LiveAnalysisUpdate;
}

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  const [mode, setMode] = useState<ScanMode>('MANUAL');
  const [stream, setStream] = useState<MediaStream | null>(null);

  // MANUAL STATE
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [manualResult, setManualResult] = useState<AppraisalResult | null>(null);

  // LIVE STATE
  const [liveData, setLiveData] = useState<LiveAnalysisUpdate | null>(null);
  const [isLivePaused, setIsLivePaused] = useState(false);
  const [lastScanTime, setLastScanTime] = useState<number>(0);
  const [isPulsing, setIsPulsing] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);

  // HISTORY STATE
  const [sessionHistory, setSessionHistory] = useState<SessionHistoryItem[]>([]);
  const [activeHistoryId, setActiveHistoryId] = useState<string | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // --- CAMERA LOGIC ---
  const startCamera = async () => {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } },
        audio: false 
      });
      setStream(s);
      if (videoRef.current) videoRef.current.srcObject = s;
    } catch (err) {
      console.error("Camera access denied", err);
    }
  };

  const stopCamera = () => {
    stream?.getTracks().forEach(t => t.stop());
    setStream(null);
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  useEffect(() => {
    if (stream && videoRef.current) videoRef.current.srcObject = stream;
  }, [stream, mode]); // Re-attach on mode switch

  // --- MANUAL MODE HANDLERS ---
  const captureManual = useCallback(() => {
    if (!videoRef.current) return;
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    const ctx = canvas.getContext('2d');
    ctx?.drawImage(videoRef.current, 0, 0);
    const data = canvas.toDataURL('image/jpeg', 0.85);
    setCapturedImages(prev => [...prev, data]);
  }, []);

  const handleManualAnalyze = async () => {
    if (capturedImages.length === 0) return;
    setIsAnalyzing(true);
    try {
      const res = await analyzeItem(capturedImages);
      setManualResult(res);
    } catch (err) {
      alert("Analysis failed. Try again.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  // --- LIVE MODE HEARTBEAT ---
  useEffect(() => {
    if (mode !== 'LIVE' || isLivePaused || !stream) return;

    const intervalId = setInterval(async () => {
      const now = Date.now();
      // Rate limit to every 3.5 seconds to allow reading and save costs
      if (now - lastScanTime < 3500) return;

      if (videoRef.current) {
        setIsPulsing(true);
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth / 2; // Downscale for speed
        canvas.height = videoRef.current.videoHeight / 2;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const frameData = canvas.toDataURL('image/jpeg', 0.6);

        // Analyze Frame
        try {
          const context = liveData ? `Previous guess: ${liveData.shortTitle}. ${liveData.detailedNote}` : "";
          const result = await analyzeLiveFrame(frameData, context);

          // Only update if confident or if we were searching
          if (result.status !== 'SEARCHING' || liveData?.status === 'SEARCHING') {
             setLiveData(result);

             // HISTORY LOGIC: If LOCKED and different from last history item, add it
             if (result.status === 'LOCKED') {
               setSessionHistory(prev => {
                 // Check if we already have this item as the most recent one to avoid duplicates
                 if (prev.length > 0 && prev[0].data.shortTitle === result.shortTitle) {
                   return prev;
                 }

                 // Add new item
                 return [{
                   id: crypto.randomUUID(),
                   timestamp: new Date(),
                   thumbnail: frameData, // Store the frame that triggered the lock
                   data: result
                 }, ...prev];
               });
             }
          }

          setLastScanTime(Date.now());
        } catch (e) {
          console.error("Live pulse failed", e);
        } finally {
          setIsPulsing(false);
        }
      }
    }, 1000); // Check every second, execute every 3.5s

    return () => clearInterval(intervalId);
  }, [mode, isLivePaused, stream, lastScanTime, liveData]);

  // --- RENDER HELPERS ---

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files && files.length > 0) {
      Array.from(files).forEach((file) => {
        const reader = new FileReader();
        reader.onloadend = () => setCapturedImages(prev => [...prev, reader.result as string]);
        reader.readAsDataURL(file as Blob);
      });
      setMode('MANUAL');
    }
  };

  const saveLiveItem = () => {
    if (!liveData) return;

    // Find thumbnail: either from active history item or capture current frame
    let imageData = '';

    if (activeHistoryId) {
      const historyItem = sessionHistory.find(h => h.id === activeHistoryId);
      if (historyItem) imageData = historyItem.thumbnail;
    }

    // Fallback to current capture if no history selected or history missing image
    if (!imageData && videoRef.current) {
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth;
        canvas.height = videoRef.current.videoHeight;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(videoRef.current, 0, 0);
        imageData = canvas.toDataURL('image/jpeg', 0.85);
    }

    const partialResult: AppraisalResult = {
        itemName: liveData.shortTitle,
        category: 'Live Scan Capture',
        classification: liveData.classification,
        era: liveData.quickFacts[0] || 'Unknown',
        origin: 'Unknown',
        condition: 'Assessed Live',
        conditionScore: 5,
        valuation: { low: 0, mid: 0, high: 0, currency: 'USD' }, // Placeholder
        authenticationMarks: [],
        historicalContext: liveData.detailedNote || '',
        materials: liveData.quickFacts[1] || 'Unknown',
        careInstructions: 'Handle with care.',
        comparableSales: [],
        sellingProfile: { listingTitle: liveData.shortTitle, listingDescription: liveData.detailedNote || '', keywords: [], recommendedVenue: 'Online', pricingStrategy: 'Auction' },
        confidence: liveData.confidence
    };

    onSave(partialResult, imageData);
  };

  const restoreHistoryItem = (item: SessionHistoryItem) => {
    setIsLivePaused(true);
    setLiveData(item.data);
    setActiveHistoryId(item.id);
  };

  const resumeLiveScanning = () => {
    setIsLivePaused(false);
    setActiveHistoryId(null);
    setLiveData(null); // Optional: clear data to force new scan, or keep last
  };

  // IF MANUAL RESULT EXISTS
  if (manualResult && capturedImages.length > 0) {
    return (
      <ItemResult 
        result={manualResult} 
        imageData={capturedImages[0]} 
        onBack={() => setManualResult(null)} 
        onSave={(res) => onSave(res, capturedImages[0])} 
      />
    );
  }

  // --- MAIN RENDER ---
  return (
    <div className="flex-1 flex flex-col bg-zinc-950 relative h-full overflow-hidden">

      {/* HEADER CONTROLS */}
      <div className="absolute top-0 left-0 right-0 z-30 pt-[env(safe-area-inset-top)] p-4 flex justify-between items-start bg-gradient-to-b from-black/90 to-transparent pointer-events-none">
        <div className="pointer-events-auto flex gap-2">
           <button 
             onClick={() => setMode('LIVE')}
             className={`px-4 py-2 rounded-full text-xs font-bold uppercase tracking-widest border transition-all ${mode === 'LIVE' ? 'bg-red-600/20 border-red-500 text-red-500 shadow-[0_0_15px_rgba(239,68,68,0.4)]' : 'bg-black/40 border-zinc-700 text-zinc-500'}`}
           >
             <Zap size={12} className="inline mr-1 mb-0.5" fill={mode === 'LIVE' ? "currentColor" : "none"}/> Live
           </button>
           <button 
             onClick={() => setMode('MANUAL')}
             className={`px-4 py-2 rounded-full text-xs font-bold uppercase tracking-widest border transition-all ${mode === 'MANUAL' ? 'bg-blue-600/20 border-blue-500 text-blue-500 shadow-[0_0_15px_rgba(59,130,246,0.4)]' : 'bg-black/40 border-zinc-700 text-zinc-500'}`}
           >
             Manual
           </button>
        </div>

        {mode === 'MANUAL' && capturedImages.length > 0 && (
          <button onClick={() => setCapturedImages([])} className="pointer-events-auto p-2 bg-black/50 backdrop-blur rounded-full text-zinc-400 hover:text-white border border-white/10">
            <Trash2 size={16} />
          </button>
        )}
      </div>

      {/* CAMERA VIEWFINDER */}
      <div className="flex-1 relative bg-black">
        <video 
          ref={videoRef} 
          autoPlay 
          playsInline 
          className="absolute inset-0 w-full h-full object-cover"
        />

        {/* VIEWING HISTORY ITEM OVERLAY (When paused and viewing history) */}
        {activeHistoryId && mode === 'LIVE' && (
          <div className="absolute inset-0 z-10 bg-black">
             {/* Show the thumbnail as the full background when reviewing history */}
             <img 
               src={sessionHistory.find(h => h.id === activeHistoryId)?.thumbnail} 
               className="w-full h-full object-cover opacity-80"
             />
             <div className="absolute inset-0 bg-black/20 backdrop-blur-[2px]"></div>
             <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 flex flex-col items-center">
                <div className="px-4 py-2 bg-black/60 backdrop-blur rounded-full border border-white/10 text-white text-xs font-bold uppercase tracking-widest mb-4">
                  Reviewing History
                </div>
             </div>
          </div>
        )}

        {/* LIVE MODE OVERLAYS */}
        {mode === 'LIVE' && (
          <>
            {/* AR Grid */}
            <div className="absolute inset-0 pointer-events-none opacity-20" 
                 style={{ backgroundImage: 'linear-gradient(#fff 1px, transparent 1px), linear-gradient(90deg, #fff 1px, transparent 1px)', backgroundSize: '40px 40px' }}>
            </div>

            {/* Scanning Line */}
            {!isLivePaused && (
              <div className="absolute left-0 right-0 h-1 bg-red-500/50 shadow-[0_0_20px_rgba(239,68,68,0.8)] animate-[scan_3s_ease-in-out_infinite] top-0 z-10"></div>
            )}

            {/* Central Reticle */}
            <div className={`absolute inset-0 flex flex-col items-center justify-center pointer-events-none transition-all duration-500 ${isPulsing ? 'scale-105 opacity-100' : 'scale-100 opacity-50'}`}>
              <div className="w-64 h-64 border border-white/30 rounded-lg relative">
                 <div className="absolute top-0 left-0 w-4 h-4 border-t-2 border-l-2 border-red-500"></div>
                 <div className="absolute top-0 right-0 w-4 h-4 border-t-2 border-r-2 border-red-500"></div>
                 <div className="absolute bottom-0 left-0 w-4 h-4 border-b-2 border-l-2 border-red-500"></div>
                 <div className="absolute bottom-0 right-0 w-4 h-4 border-b-2 border-r-2 border-red-500"></div>

                 {/* Pulse Indicator */}
                 {isPulsing && (
                   <div className="absolute inset-0 border-2 border-red-500/50 rounded-lg animate-ping"></div>
                 )}
              </div>

              {/* Guidance Prompt for Low Confidence */}
              {liveData?.status === 'IDENTIFYING' && (liveData.confidence || 0) < 0.7 && !activeHistoryId && (
                 <div className="mt-6 bg-black/40 backdrop-blur-md px-4 py-1.5 rounded-full border border-white/10 shadow-lg animate-pulse">
                   <p className="text-[10px] text-zinc-300 font-bold uppercase tracking-widest flex items-center gap-2">
                     <ScanLine size={12} className="text-red-400"/> Keep scanning for detail...
                   </p>
                 </div>
              )}
            </div>

            {/* LIVE DATA PANEL (COLLAPSIBLE BOTTOM SHEET) */}
            <div 
              className={`absolute left-4 right-4 z-30 transition-all duration-500 ease-[cubic-bezier(0.32,0.72,0,1)] flex flex-col ${
                isExpanded 
                  ? 'top-[100px] bottom-4' // Expanded state
                  : 'bottom-[80px] h-auto' // Collapsed state (floating above nav)
              }`}
            >
               {liveData ? (
                 <div className={`glass-panel w-full h-full rounded-2xl overflow-hidden flex flex-col shadow-2xl border-l-4 transition-colors duration-500 ${liveData.status === 'LOCKED' ? 'border-l-emerald-500 bg-black/90' : 'border-l-red-500 bg-black/80'}`}>

                    {/* Header / Drag Handle */}
                    <div className="p-5 pb-2 shrink-0 relative cursor-pointer active:bg-white/5" onClick={() => setIsExpanded(!isExpanded)}>
                       {/* Handle */}
                       <div className="absolute top-2 left-1/2 -translate-x-1/2 w-8 h-1 bg-zinc-600 rounded-full"></div>

                       <div className="flex justify-between items-start mt-3">
                          <div className="flex-1 pr-4">
                             <div className="flex items-center gap-2 mb-1.5">
                                 {/* Status & Confidence */}
                                 {isPulsing ? <Loader2 size={10} className="animate-spin text-zinc-400"/> : <div className={`w-1.5 h-1.5 rounded-full ${liveData.status === 'LOCKED' ? 'bg-emerald-500' : 'bg-red-500 animate-pulse'}`}></div>}
                                 <span className={`text-[10px] font-bold uppercase tracking-widest ${liveData.status === 'LOCKED' ? 'text-emerald-400' : 'text-red-400'}`}>
                                   {liveData.status === 'SEARCHING' ? 'Scanning...' : liveData.status}
                                 </span>
                                 {liveData.confidence > 0 && (
                                    <span className="text-[10px] text-zinc-500 font-medium border-l border-zinc-700 pl-2">
                                        {Math.round(liveData.confidence * 100)}% Confidence
                                    </span>
                                 )}
                             </div>
                             <h2 className="text-2xl font-serif text-white leading-none tracking-tight mb-1">
                                 {liveData.shortTitle || "Identifying..."}
                             </h2>
                          </div>
                          <button className="text-zinc-500 hover:text-white transition-colors">
                              {isExpanded ? <ChevronDown size={20} /> : <ChevronUp size={20} />}
                          </button>
                       </div>

                       {/* Progress Bar */}
                       <div className="mt-3 h-0.5 w-full bg-zinc-800 rounded-full overflow-hidden">
                           <div 
                               className={`h-full transition-all duration-700 ${liveData.status === 'LOCKED' ? 'bg-emerald-500' : 'bg-red-500'}`}
                               style={{ width: `${(liveData.confidence || 0.1) * 100}%` }}
                           ></div>
                       </div>
                    </div>

                    {/* Scrollable Content */}
                    <div className={`flex-1 overflow-y-auto p-5 pt-2 transition-all duration-500 ${isExpanded ? 'opacity-100' : 'opacity-90'}`}>
                        {/* Quick Tags (Always visible) */}
                        <div className="flex flex-wrap gap-2 mb-3">
                           <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase border ${liveData.classification === 'Antique' ? 'border-amber-700 text-amber-500 bg-amber-950/30' : 'border-zinc-700 text-zinc-400 bg-zinc-900'}`}>
                             {liveData.classification}
                           </span>
                           {liveData.valuationEstimate && (
                             <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase border border-emerald-900 text-emerald-400 bg-emerald-950/30">
                               {liveData.valuationEstimate}
                             </span>
                           )}
                        </div>

                        {/* Description */}
                        <p className={`text-sm text-zinc-300 leading-relaxed font-light transition-all duration-300 ${isExpanded ? '' : 'line-clamp-2'}`}>
                          {liveData.detailedNote || "Keep the object in frame to gather more details..."}
                        </p>

                        {/* Expanded Only Content */}
                        <div className={`space-y-6 mt-6 transition-all duration-500 ${isExpanded ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4 hidden'}`}>
                             {liveData.quickFacts.length > 0 && (
                               <div>
                                  <h4 className="text-[10px] uppercase font-bold text-zinc-500 tracking-widest mb-3">Quick Analysis</h4>
                                  <div className="grid grid-cols-2 gap-3">
                                     {liveData.quickFacts.map((fact, i) => (
                                        <div key={i} className="bg-white/5 border border-white/10 rounded-lg p-3 text-xs text-zinc-300">
                                            {fact}
                                        </div>
                                     ))}
                                  </div>
                               </div>
                             )}

                             {/* Actions */}
                             <div className="grid grid-cols-2 gap-3 pt-4 border-t border-white/10">
                                <Button variant="secondary" onClick={() => isLivePaused ? resumeLiveScanning() : setIsLivePaused(true)}>
                                   {isLivePaused ? 'Resume Scan' : 'Pause Stream'}
                                </Button>
                                <Button variant="primary" onClick={saveLiveItem} disabled={liveData.status === 'SEARCHING'}>
                                   <Save size={16} className="mr-2" /> Save Asset
                                </Button>
                             </div>

                             {/* Session History Section */}
                             {sessionHistory.length > 0 && (
                               <div className="pt-4 border-t border-white/10">
                                 <div className="flex items-center gap-2 mb-3">
                                   <History size={12} className="text-zinc-500" />
                                   <h4 className="text-[10px] uppercase font-bold text-zinc-500 tracking-widest">Session History</h4>
                                 </div>
                                 <div className="flex gap-3 overflow-x-auto pb-2 no-scrollbar">
                                   {sessionHistory.map((item) => (
                                     <button 
                                       key={item.id}
                                       onClick={() => restoreHistoryItem(item)}
                                       className={`relative shrink-0 w-20 h-20 rounded-lg overflow-hidden border transition-all ${activeHistoryId === item.id ? 'border-white ring-2 ring-white/20' : 'border-zinc-700 hover:border-zinc-500'}`}
                                     >
                                       <img src={item.thumbnail} className="w-full h-full object-cover" />
                                       <div className="absolute inset-x-0 bottom-0 bg-black/60 backdrop-blur p-1 text-center">
                                         <p className="text-[8px] text-white truncate font-medium">{item.data.shortTitle}</p>
                                       </div>
                                       {activeHistoryId === item.id && (
                                         <div className="absolute inset-0 bg-white/10 flex items-center justify-center">
                                           <div className="w-2 h-2 bg-white rounded-full shadow-lg"></div>
                                         </div>
                                       )}
                                     </button>
                                   ))}
                                 </div>
                               </div>
                             )}
                        </div>
                    </div>
                 </div>
               ) : (
                 <div className="glass-panel rounded-2xl p-4 text-center mx-auto w-full max-w-sm">
                   <p className="text-zinc-500 text-sm font-medium tracking-wide animate-pulse">Initializing Neural Net...</p>
                 </div>
               )}
            </div>
          </>
        )}

        {/* MANUAL MODE UI OVERLAY */}
        {mode === 'MANUAL' && (
           <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
             <div className="w-[80%] aspect-[3/4] border-2 border-dashed border-white/30 rounded-2xl"></div>
           </div>
        )}
      </div>

      {/* CONTROLS FOOTER */}
      <div className={`bg-zinc-950 border-t border-zinc-800 -mt-6 z-20 relative pt-8 pb-8 rounded-t-3xl shadow-[0_-10px_40px_rgba(0,0,0,0.8)] transition-transform duration-300 ${isExpanded ? 'translate-y-full' : 'translate-y-0'}`}>
        {mode === 'LIVE' ? (
          <div className="px-8 text-center">
             <p className="text-xs text-zinc-500 uppercase tracking-widest mb-2 font-bold">Auto-Scan Active</p>
             <div className="h-1 w-32 bg-zinc-800 mx-auto rounded-full overflow-hidden">
               <div className={`h-full bg-red-500 transition-all duration-300 ${isPulsing ? 'w-full' : 'w-0'}`}></div>
             </div>
          </div>
        ) : (
          <div className="flex justify-between items-center px-8">
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" multiple onChange={handleFileUpload} />

            <button onClick={() => fileInputRef.current?.click()} className="p-4 rounded-full bg-zinc-900 text-zinc-400 hover:text-white border border-zinc-800">
              <ImageIcon size={24} />
            </button>

            <button onClick={captureManual} className="w-20 h-20 rounded-full border-4 border-zinc-700 p-1 flex items-center justify-center relative group active:scale-95 transition-transform">
              <div className="w-full h-full bg-white rounded-full shadow-[0_0_20px_rgba(255,255,255,0.5)]"></div>
            </button>

            <div className="relative">
              {capturedImages.length > 0 ? (
                 <button onClick={handleManualAnalyze} className="w-14 h-14 rounded-xl overflow-hidden border-2 border-blue-500 relative flex items-center justify-center bg-blue-500/20">
                   <span className="font-bold text-blue-400">{capturedImages.length}</span>
                   {isAnalyzing && <div className="absolute inset-0 bg-black/50 flex items-center justify-center"><Loader2 className="animate-spin text-white" size={20}/></div>}
                 </button>
              ) : (
                <div className="w-14 h-14 opacity-0"></div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useRef, useState, useCallback, useEffect } from 'react';
import { RefreshCw, Image as ImageIcon, Camera, Plus, Trash2, X, Zap, Pause, Play, ScanLine, Loader2, ChevronUp, ChevronDown, Save, Share2, History, Clock } from 'lucide-react';
import { Button } from './Button';
import { analyzeItem, analyzeLiveFrame } from '../services/geminiService';
import { AppraisalResult, LiveAnalysisUpdate } from '../types';
import { ItemResult } from './ItemResult';

interface ScannerProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

type ScanMode = 'LIVE' | 'MANUAL';

interface SessionHistoryItem {
  id: string;
  timestamp: Date;
  thumbnail: string;
  data: LiveAnalysisUpdate;
}

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  const [mode, setMode] = useState<ScanMode>('MANUAL');
  const [stream, setStream] = useState<MediaStream | null>(null);

  // MANUAL STATE
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [manualResult, setManualResult] = useState<AppraisalResult | null>(null);

  // LIVE STATE
  const [liveData, setLiveData] = useState<LiveAnalysisUpdate | null>(null);
  const [isLivePaused, setIsLivePaused] = useState(false);
  const [lastScanTime, setLastScanTime] = useState<number>(0);
  const [isPulsing, setIsPulsing] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);

  // HISTORY STATE
  const [sessionHistory, setSessionHistory] = useState<SessionHistoryItem[]>([]);
  const [activeHistoryId, setActiveHistoryId] = useState<string | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // --- CAMERA LOGIC ---
  const startCamera = async () => {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } },
        audio: false 
      });
      setStream(s);
      if (videoRef.current) videoRef.current.srcObject = s;
    } catch (err) {
      console.error("Camera access denied", err);
    }
  };

  const stopCamera = () => {
    stream?.getTracks().forEach(t => t.stop());
    setStream(null);
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  useEffect(() => {
    if (stream && videoRef.current) videoRef.current.srcObject = stream;
  }, [stream, mode]); // Re-attach on mode switch

  // --- MANUAL MODE HANDLERS ---
  const captureManual = useCallback(() => {
    if (!videoRef.current) return;
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    const ctx = canvas.getContext('2d');
    ctx?.drawImage(videoRef.current, 0, 0);
    const data = canvas.toDataURL('image/jpeg', 0.85);
    setCapturedImages(prev => [...prev, data]);
  }, []);

  const handleManualAnalyze = async () => {
    if (capturedImages.length === 0) return;
    setIsAnalyzing(true);
    try {
      const res = await analyzeItem(capturedImages);
      setManualResult(res);
    } catch (err) {
      alert("Analysis failed. Try again.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  // --- LIVE MODE HEARTBEAT ---
  useEffect(() => {
    if (mode !== 'LIVE' || isLivePaused || !stream) return;

    const intervalId = setInterval(async () => {
      const now = Date.now();
      // Rate limit to every 3.5 seconds to allow reading and save costs
      if (now - lastScanTime < 3500) return;

      if (videoRef.current) {
        setIsPulsing(true);
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth / 2; // Downscale for speed
        canvas.height = videoRef.current.videoHeight / 2;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const frameData = canvas.toDataURL('image/jpeg', 0.6);

        // Analyze Frame
        try {
          const context = liveData ? `Previous guess: ${liveData.shortTitle}. ${liveData.detailedNote}` : "";
          const result = await analyzeLiveFrame(frameData, context);

          // Only update if confident or if we were searching
          if (result.status !== 'SEARCHING' || liveData?.status === 'SEARCHING') {
             setLiveData(result);

             // HISTORY LOGIC: If LOCKED and different from last history item, add it
             if (result.status === 'LOCKED') {
               setSessionHistory(prev => {
                 // Check if we already have this item as the most recent one to avoid duplicates
                 if (prev.length > 0 && prev[0].data.shortTitle === result.shortTitle) {
                   return prev;
                 }

                 // Add new item
                 return [{
                   id: crypto.randomUUID(),
                   timestamp: new Date(),
                   thumbnail: frameData, // Store the frame that triggered the lock
                   data: result
                 }, ...prev];
               });
             }
          }

          setLastScanTime(Date.now());
        } catch (e) {
          console.error("Live pulse failed", e);
        } finally {
          setIsPulsing(false);
        }
      }
    }, 1000); // Check every second, execute every 3.5s

    return () => clearInterval(intervalId);
  }, [mode, isLivePaused, stream, lastScanTime, liveData]);

  // --- RENDER HELPERS ---

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files && files.length > 0) {
      Array.from(files).forEach((file) => {
        const reader = new FileReader();
        reader.onloadend = () => setCapturedImages(prev => [...prev, reader.result as string]);
        reader.readAsDataURL(file as Blob);
      });
      setMode('MANUAL');
    }
  };

  const saveLiveItem = () => {
    if (!liveData) return;

    // Find thumbnail: either from active history item or capture current frame
    let imageData = '';

    if (activeHistoryId) {
      const historyItem = sessionHistory.find(h => h.id === activeHistoryId);
      if (historyItem) imageData = historyItem.thumbnail;
    }

    // Fallback to current capture if no history selected or history missing image
    if (!imageData && videoRef.current) {
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth;
        canvas.height = videoRef.current.videoHeight;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(videoRef.current, 0, 0);
        imageData = canvas.toDataURL('image/jpeg', 0.85);
    }

    const partialResult: AppraisalResult = {
        itemName: liveData.shortTitle,
        category: 'Live Scan Capture',
        classification: liveData.classification,
        era: liveData.quickFacts[0] || 'Unknown',
        origin: 'Unknown',
        condition: 'Assessed Live',
        conditionScore: 5,
        valuation: { low: 0, mid: 0, high: 0, currency: 'USD' }, // Placeholder
        authenticationMarks: [],
        historicalContext: liveData.detailedNote || '',
        materials: liveData.quickFacts[1] || 'Unknown',
        careInstructions: 'Handle with care.',
        comparableSales: [],
        sellingProfile: { listingTitle: liveData.shortTitle, listingDescription: liveData.detailedNote || '', keywords: [], recommendedVenue: 'Online', pricingStrategy: 'Auction' },
        confidence: liveData.confidence
    };

    onSave(partialResult, imageData);
  };

  const restoreHistoryItem = (item: SessionHistoryItem) => {
    setIsLivePaused(true);
    setLiveData(item.data);
    setActiveHistoryId(item.id);
  };

  const resumeLiveScanning = () => {
    setIsLivePaused(false);
    setActiveHistoryId(null);
    setLiveData(null); // Optional: clear data to force new scan, or keep last
  };

  // IF MANUAL RESULT EXISTS
  if (manualResult && capturedImages.length > 0) {
    return (
      <ItemResult 
        result={manualResult} 
        imageData={capturedImages[0]} 
        onBack={() => setManualResult(null)} 
        onSave={(res) => onSave(res, capturedImages[0])} 
      />
    );
  }

  // --- MAIN RENDER ---
  return (
    <div className="flex-1 flex flex-col bg-zinc-950 relative h-full overflow-hidden">

      {/* HEADER CONTROLS */}
      <div className="absolute top-0 left-0 right-0 z-30 pt-[env(safe-area-inset-top)] p-4 flex justify-between items-start bg-gradient-to-b from-black/90 to-transparent pointer-events-none">
        <div className="pointer-events-auto flex gap-2">
           <button 
             onClick={() => setMode('LIVE')}
             className={`px-4 py-2 rounded-full text-xs font-bold uppercase tracking-widest border transition-all ${mode === 'LIVE' ? 'bg-red-600/20 border-red-500 text-red-500 shadow-[0_0_15px_rgba(239,68,68,0.4)]' : 'bg-black/40 border-zinc-700 text-zinc-500'}`}
           >
             <Zap size={12} className="inline mr-1 mb-0.5" fill={mode === 'LIVE' ? "currentColor" : "none"}/> Live
           </button>
           <button 
             onClick={() => setMode('MANUAL')}
             className={`px-4 py-2 rounded-full text-xs font-bold uppercase tracking-widest border transition-all ${mode === 'MANUAL' ? 'bg-blue-600/20 border-blue-500 text-blue-500 shadow-[0_0_15px_rgba(59,130,246,0.4)]' : 'bg-black/40 border-zinc-700 text-zinc-500'}`}
           >
             Manual
           </button>
        </div>

        {mode === 'MANUAL' && capturedImages.length > 0 && (
          <button onClick={() => setCapturedImages([])} className="pointer-events-auto p-2 bg-black/50 backdrop-blur rounded-full text-zinc-400 hover:text-white border border-white/10">
            <Trash2 size={16} />
          </button>
        )}
      </div>

      {/* CAMERA VIEWFINDER */}
      <div className="flex-1 relative bg-black">
        <video 
          ref={videoRef} 
          autoPlay 
          playsInline 
          className="absolute inset-0 w-full h-full object-cover"
        />

        {/* VIEWING HISTORY ITEM OVERLAY (When paused and viewing history) */}
        {activeHistoryId && mode === 'LIVE' && (
          <div className="absolute inset-0 z-10 bg-black animate-in fade-in duration-500">
             {/* Show the thumbnail as the full background when reviewing history */}
             <img 
               src={sessionHistory.find(h => h.id === activeHistoryId)?.thumbnail} 
               className="w-full h-full object-cover opacity-80"
             />
             <div className="absolute inset-0 bg-black/20 backdrop-blur-[2px]"></div>
             <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 flex flex-col items-center">
                <div className="px-4 py-2 bg-black/60 backdrop-blur rounded-full border border-white/10 text-white text-xs font-bold uppercase tracking-widest mb-4 animate-in zoom-in duration-300">
                  Reviewing History
                </div>
             </div>
          </div>
        )}

        {/* LIVE MODE OVERLAYS */}
        {mode === 'LIVE' && (
          <>
            {/* AR Grid */}
            <div className="absolute inset-0 pointer-events-none opacity-20" 
                 style={{ backgroundImage: 'linear-gradient(#fff 1px, transparent 1px), linear-gradient(90deg, #fff 1px, transparent 1px)', backgroundSize: '40px 40px' }}>
            </div>

            {/* Scanning Line */}
            {!isLivePaused && (
              <div className="absolute left-0 right-0 h-1 bg-red-500/50 shadow-[0_0_20px_rgba(239,68,68,0.8)] animate-[scan_3s_ease-in-out_infinite] top-0 z-10"></div>
            )}

            {/* Central Reticle */}
            <div className={`absolute inset-0 flex flex-col items-center justify-center pointer-events-none transition-all duration-700 ease-[cubic-bezier(0.19,1,0.22,1)] ${isPulsing ? 'scale-105 opacity-100' : 'scale-100 opacity-50'}`}>
              <div className="w-64 h-64 border border-white/30 rounded-lg relative">
                 <div className="absolute top-0 left-0 w-4 h-4 border-t-2 border-l-2 border-red-500"></div>
                 <div className="absolute top-0 right-0 w-4 h-4 border-t-2 border-r-2 border-red-500"></div>
                 <div className="absolute bottom-0 left-0 w-4 h-4 border-b-2 border-l-2 border-red-500"></div>
                 <div className="absolute bottom-0 right-0 w-4 h-4 border-b-2 border-r-2 border-red-500"></div>

                 {/* Pulse Indicator */}
                 {isPulsing && (
                   <div className="absolute inset-0 border-2 border-red-500/50 rounded-lg animate-ping"></div>
                 )}
              </div>

              {/* Guidance Prompt for Low Confidence */}
              {liveData?.status === 'IDENTIFYING' && (liveData.confidence || 0) < 0.7 && !activeHistoryId && (
                 <div className="mt-6 bg-black/40 backdrop-blur-md px-4 py-1.5 rounded-full border border-white/10 shadow-lg animate-pulse">
                   <p className="text-[10px] text-zinc-300 font-bold uppercase tracking-widest flex items-center gap-2">
                     <ScanLine size={12} className="text-red-400"/> Keep scanning for detail...
                   </p>
                 </div>
              )}
            </div>

            {/* LIVE DATA PANEL (COLLAPSIBLE BOTTOM SHEET) */}
            <div 
              className={`absolute left-4 right-4 z-30 flex flex-col transition-all duration-700 ease-[cubic-bezier(0.19,1,0.22,1)] ${
                isExpanded 
                  ? 'top-[100px] bottom-4' // Expanded state
                  : 'top-[calc(100%-240px)] bottom-[80px]' // Collapsed state (Explicit top allows smooth interpolation)
              }`}
            >
               {liveData ? (
                 <div className={`glass-panel w-full h-full rounded-2xl overflow-hidden flex flex-col shadow-2xl border-l-4 transition-colors duration-700 ease-[cubic-bezier(0.19,1,0.22,1)] ${liveData.status === 'LOCKED' ? 'border-l-emerald-500 bg-black/90' : 'border-l-red-500 bg-black/80'}`}>

                    {/* Header / Drag Handle */}
                    <div className="p-5 pb-2 shrink-0 relative cursor-pointer active:bg-white/5" onClick={() => setIsExpanded(!isExpanded)}>
                       {/* Handle */}
                       <div className="absolute top-2 left-1/2 -translate-x-1/2 w-8 h-1 bg-zinc-600 rounded-full"></div>

                       <div className="flex justify-between items-start mt-3">
                          <div className="flex-1 pr-4">
                             <div className="flex items-center gap-2 mb-1.5">
                                 {/* Status & Confidence */}
                                 {isPulsing ? <Loader2 size={10} className="animate-spin text-zinc-400"/> : <div className={`w-1.5 h-1.5 rounded-full ${liveData.status === 'LOCKED' ? 'bg-emerald-500' : 'bg-red-500 animate-pulse'}`}></div>}
                                 <span className={`text-[10px] font-bold uppercase tracking-widest ${liveData.status === 'LOCKED' ? 'text-emerald-400' : 'text-red-400'}`}>
                                   {liveData.status === 'SEARCHING' ? 'Scanning...' : liveData.status}
                                 </span>
                                 {liveData.confidence > 0 && (
                                    <span className="text-[10px] text-zinc-500 font-medium border-l border-zinc-700 pl-2">
                                        {Math.round(liveData.confidence * 100)}% Confidence
                                    </span>
                                 )}
                             </div>
                             <h2 className="text-2xl font-serif text-white leading-none tracking-tight mb-1">
                                 {liveData.shortTitle || "Identifying..."}
                             </h2>
                          </div>
                          <button className="text-zinc-500 hover:text-white transition-colors">
                              {isExpanded ? <ChevronDown size={20} /> : <ChevronUp size={20} />}
                          </button>
                       </div>

                       {/* Progress Bar */}
                       <div className="mt-3 h-0.5 w-full bg-zinc-800 rounded-full overflow-hidden">
                           <div 
                               className={`h-full transition-all duration-700 ease-[cubic-bezier(0.19,1,0.22,1)] ${liveData.status === 'LOCKED' ? 'bg-emerald-500' : 'bg-red-500'}`}
                               style={{ width: `${(liveData.confidence || 0.1) * 100}%` }}
                           ></div>
                       </div>
                    </div>

                    {/* Scrollable Content */}
                    <div className={`flex-1 overflow-y-auto p-5 pt-2 transition-all duration-700 ease-[cubic-bezier(0.19,1,0.22,1)] ${isExpanded ? 'opacity-100' : 'opacity-90'}`}>
                        {/* Quick Tags (Always visible) */}
                        <div className="flex flex-wrap gap-2 mb-3">
                           <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase border ${liveData.classification === 'Antique' ? 'border-amber-700 text-amber-500 bg-amber-950/30' : 'border-zinc-700 text-zinc-400 bg-zinc-900'}`}>
                             {liveData.classification}
                           </span>
                           {liveData.valuationEstimate && (
                             <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase border border-emerald-900 text-emerald-400 bg-emerald-950/30">
                               {liveData.valuationEstimate}
                             </span>
                           )}
                        </div>

                        {/* Description */}
                        <p className={`text-sm text-zinc-300 leading-relaxed font-light transition-all duration-500 ${isExpanded ? '' : 'line-clamp-2'}`}>
                          {liveData.detailedNote || "Keep the object in frame to gather more details..."}
                        </p>

                        {/* Expanded Only Content */}
                        <div className={`space-y-6 mt-6 transition-all duration-700 ease-[cubic-bezier(0.19,1,0.22,1)] ${isExpanded ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4 pointer-events-none'}`}>
                             {liveData.quickFacts.length > 0 && (
                               <div>
                                  <h4 className="text-[10px] uppercase font-bold text-zinc-500 tracking-widest mb-3">Quick Analysis</h4>
                                  <div className="grid grid-cols-2 gap-3">
                                     {liveData.quickFacts.map((fact, i) => (
                                        <div key={i} className="bg-white/5 border border-white/10 rounded-lg p-3 text-xs text-zinc-300">
                                            {fact}
                                        </div>
                                     ))}
                                  </div>
                               </div>
                             )}

                             {/* Actions */}
                             <div className="grid grid-cols-2 gap-3 pt-4 border-t border-white/10">
                                <Button variant="secondary" onClick={() => isLivePaused ? resumeLiveScanning() : setIsLivePaused(true)}>
                                   {isLivePaused ? 'Resume Scan' : 'Pause Stream'}
                                </Button>
                                <Button variant="primary" onClick={saveLiveItem} disabled={liveData.status === 'SEARCHING'}>
                                   <Save size={16} className="mr-2" /> Save Asset
                                </Button>
                             </div>

                             {/* Session History Section */}
                             {sessionHistory.length > 0 && (
                               <div className="pt-4 border-t border-white/10">
                                 <div className="flex items-center gap-2 mb-3">
                                   <History size={12} className="text-zinc-500" />
                                   <h4 className="text-[10px] uppercase font-bold text-zinc-500 tracking-widest">Session History</h4>
                                 </div>
                                 <div className="flex gap-3 overflow-x-auto pb-2 no-scrollbar">
                                   {sessionHistory.map((item) => (
                                     <button 
                                       key={item.id}
                                       onClick={() => restoreHistoryItem(item)}
                                       className={`relative shrink-0 w-20 h-20 rounded-lg overflow-hidden border transition-all duration-300 ${activeHistoryId === item.id ? 'border-white ring-2 ring-white/20 scale-105' : 'border-zinc-700 hover:border-zinc-500'}`}
                                     >
                                       <img src={item.thumbnail} className="w-full h-full object-cover" />
                                       <div className="absolute inset-x-0 bottom-0 bg-black/60 backdrop-blur p-1 text-center">
                                         <p className="text-[8px] text-white truncate font-medium">{item.data.shortTitle}</p>
                                       </div>
                                       {activeHistoryId === item.id && (
                                         <div className="absolute inset-0 bg-white/10 flex items-center justify-center">
                                           <div className="w-2 h-2 bg-white rounded-full shadow-lg"></div>
                                         </div>
                                       )}
                                     </button>
                                   ))}
                                 </div>
                               </div>
                             )}
                        </div>
                    </div>
                 </div>
               ) : (
                 <div className="glass-panel rounded-2xl p-4 text-center mx-auto w-full max-w-sm">
                   <p className="text-zinc-500 text-sm font-medium tracking-wide animate-pulse">Initializing Neural Net...</p>
                 </div>
               )}
            </div>
          </>
        )}

        {/* MANUAL MODE UI OVERLAY */}
        {mode === 'MANUAL' && (
           <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
             <div className="w-[80%] aspect-[3/4] border-2 border-dashed border-white/30 rounded-2xl"></div>
           </div>
        )}
      </div>

      {/* CONTROLS FOOTER */}
      <div className={`bg-zinc-950 border-t border-zinc-800 -mt-6 z-20 relative pt-8 pb-8 rounded-t-3xl shadow-[0_-10px_40px_rgba(0,0,0,0.8)] transition-transform duration-700 ease-[cubic-bezier(0.19,1,0.22,1)] ${isExpanded ? 'translate-y-full' : 'translate-y-0'}`}>
        {mode === 'LIVE' ? (
          <div className="px-8 text-center">
             <p className="text-xs text-zinc-500 uppercase tracking-widest mb-2 font-bold">Auto-Scan Active</p>
             <div className="h-1 w-32 bg-zinc-800 mx-auto rounded-full overflow-hidden">
               <div className={`h-full bg-red-500 transition-all duration-300 ${isPulsing ? 'w-full' : 'w-0'}`}></div>
             </div>
          </div>
        ) : (
          <div className="flex justify-between items-center px-8">
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" multiple onChange={handleFileUpload} />

            <button onClick={() => fileInputRef.current?.click()} className="p-4 rounded-full bg-zinc-900 text-zinc-400 hover:text-white border border-zinc-800">
              <ImageIcon size={24} />
            </button>

            <button onClick={captureManual} className="w-20 h-20 rounded-full border-4 border-zinc-700 p-1 flex items-center justify-center relative group active:scale-95 transition-transform">
              <div className="w-full h-full bg-white rounded-full shadow-[0_0_20px_rgba(255,255,255,0.5)]"></div>
            </button>

            <div className="relative">
              {capturedImages.length > 0 ? (
                 <button onClick={handleManualAnalyze} className="w-14 h-14 rounded-xl overflow-hidden border-2 border-blue-500 relative flex items-center justify-center bg-blue-500/20">
                   <span className="font-bold text-blue-400">{capturedImages.length}</span>
                   {isAnalyzing && <div className="absolute inset-0 bg-black/50 flex items-center justify-center"><Loader2 className="animate-spin text-white" size={20}/></div>}
                 </button>
              ) : (
                <div className="w-14 h-14 opacity-0"></div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useRef, useState, useCallback, useEffect } from 'react';
import { RefreshCw, Image as ImageIcon, Camera, Plus, Trash2, X, Zap, Pause, Play, ScanLine, Loader2, ChevronUp, ChevronDown, Save, Share2, History, Clock } from 'lucide-react';
import { Button } from './Button';
import { analyzeItem, analyzeLiveFrame } from '../services/geminiService';
import { AppraisalResult, LiveAnalysisUpdate } from '../types';
import { ItemResult } from './ItemResult';

interface ScannerProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

type ScanMode = 'LIVE' | 'MANUAL';

interface SessionHistoryItem {
  id: string;
  timestamp: Date;
  thumbnail: string;
  data: LiveAnalysisUpdate;
}

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  const [mode, setMode] = useState<ScanMode>('MANUAL');
  const [stream, setStream] = useState<MediaStream | null>(null);

  // MANUAL STATE
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [manualResult, setManualResult] = useState<AppraisalResult | null>(null);

  // LIVE STATE
  const [liveData, setLiveData] = useState<LiveAnalysisUpdate | null>(null);
  const [isLivePaused, setIsLivePaused] = useState(false);
  const [lastScanTime, setLastScanTime] = useState<number>(0);
  const [isPulsing, setIsPulsing] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);

  // HISTORY STATE
  const [sessionHistory, setSessionHistory] = useState<SessionHistoryItem[]>([]);
  const [activeHistoryId, setActiveHistoryId] = useState<string | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // --- CAMERA LOGIC ---
  const startCamera = async () => {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } },
        audio: false 
      });
      setStream(s);
      if (videoRef.current) videoRef.current.srcObject = s;
    } catch (err) {
      console.error("Camera access denied", err);
    }
  };

  const stopCamera = () => {
    stream?.getTracks().forEach(t => t.stop());
    setStream(null);
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  useEffect(() => {
    if (stream && videoRef.current) videoRef.current.srcObject = stream;
  }, [stream, mode]); // Re-attach on mode switch

  // --- MANUAL MODE HANDLERS ---
  const captureManual = useCallback(() => {
    if (!videoRef.current) return;
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    const ctx = canvas.getContext('2d');
    ctx?.drawImage(videoRef.current, 0, 0);
    const data = canvas.toDataURL('image/jpeg', 0.85);
    setCapturedImages(prev => [...prev, data]);
  }, []);

  const handleManualAnalyze = async () => {
    if (capturedImages.length === 0) return;
    setIsAnalyzing(true);
    try {
      const res = await analyzeItem(capturedImages);
      setManualResult(res);
    } catch (err) {
      alert("Analysis failed. Try again.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  // --- LIVE MODE HEARTBEAT ---
  useEffect(() => {
    if (mode !== 'LIVE' || isLivePaused || !stream) return;

    const intervalId = setInterval(async () => {
      const now = Date.now();
      // Rate limit to every 3.5 seconds to allow reading and save costs
      if (now - lastScanTime < 3500) return;

      if (videoRef.current) {
        setIsPulsing(true);
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth / 2; // Downscale for speed
        canvas.height = videoRef.current.videoHeight / 2;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const frameData = canvas.toDataURL('image/jpeg', 0.6);

        // Analyze Frame
        try {
          const context = liveData ? `Previous guess: ${liveData.shortTitle}. ${liveData.detailedNote}` : "";
          const result = await analyzeLiveFrame(frameData, context);

          // Only update if confident or if we were searching
          if (result.status !== 'SEARCHING' || liveData?.status === 'SEARCHING') {
             setLiveData(result);

             // HISTORY LOGIC: If LOCKED and different from last history item, add it
             if (result.status === 'LOCKED') {
               setSessionHistory(prev => {
                 // Check if we already have this item as the most recent one to avoid duplicates
                 if (prev.length > 0 && prev[0].data.shortTitle === result.shortTitle) {
                   return prev;
                 }

                 // Add new item
                 return [{
                   id: crypto.randomUUID(),
                   timestamp: new Date(),
                   thumbnail: frameData, // Store the frame that triggered the lock
                   data: result
                 }, ...prev];
               });
             }
          }

          setLastScanTime(Date.now());
        } catch (e) {
          console.error("Live pulse failed", e);
        } finally {
          setIsPulsing(false);
        }
      }
    }, 1000); // Check every second, execute every 3.5s

    return () => clearInterval(intervalId);
  }, [mode, isLivePaused, stream, lastScanTime, liveData]);

  // --- RENDER HELPERS ---

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files && files.length > 0) {
      Array.from(files).forEach((file) => {
        const reader = new FileReader();
        reader.onloadend = () => setCapturedImages(prev => [...prev, reader.result as string]);
        reader.readAsDataURL(file as Blob);
      });
      setMode('MANUAL');
    }
  };

  const saveLiveItem = () => {
    if (!liveData) return;

    // Find thumbnail: either from active history item or capture current frame
    let imageData = '';

    if (activeHistoryId) {
      const historyItem = sessionHistory.find(h => h.id === activeHistoryId);
      if (historyItem) imageData = historyItem.thumbnail;
    }

    // Fallback to current capture if no history selected or history missing image
    if (!imageData && videoRef.current) {
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth;
        canvas.height = videoRef.current.videoHeight;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(videoRef.current, 0, 0);
        imageData = canvas.toDataURL('image/jpeg', 0.85);
    }

    const partialResult: AppraisalResult = {
        itemName: liveData.shortTitle,
        category: 'Live Scan Capture',
        classification: liveData.classification,
        era: liveData.quickFacts[0] || 'Unknown',
        origin: 'Unknown',
        condition: 'Assessed Live',
        conditionScore: 5,
        valuation: { low: 0, mid: 0, high: 0, currency: 'USD' }, // Placeholder
        authenticationMarks: [],
        historicalContext: liveData.detailedNote || '',
        materials: liveData.quickFacts[1] || 'Unknown',
        careInstructions: 'Handle with care.',
        comparableSales: [],
        sellingProfile: { listingTitle: liveData.shortTitle, listingDescription: liveData.detailedNote || '', keywords: [], recommendedVenue: 'Online', pricingStrategy: 'Auction' },
        confidence: liveData.confidence
    };

    onSave(partialResult, imageData);
  };

  const restoreHistoryItem = (item: SessionHistoryItem) => {
    setIsLivePaused(true);
    setLiveData(item.data);
    setActiveHistoryId(item.id);
  };

  const resumeLiveScanning = () => {
    setIsLivePaused(false);
    setActiveHistoryId(null);
    setLiveData(null); // Optional: clear data to force new scan, or keep last
  };

  // IF MANUAL RESULT EXISTS
  if (manualResult && capturedImages.length > 0) {
    return (
      <ItemResult 
        result={manualResult} 
        imageData={capturedImages[0]} 
        onBack={() => setManualResult(null)} 
        onSave={(res) => onSave(res, capturedImages[0])} 
      />
    );
  }

  // --- MAIN RENDER ---
  return (
    <div className="flex-1 flex flex-col bg-zinc-950 relative h-full overflow-hidden">

      {/* HEADER CONTROLS */}
      <div className="absolute top-0 left-0 right-0 z-30 pt-[env(safe-area-inset-top)] p-4 flex justify-between items-start bg-gradient-to-b from-black/90 to-transparent pointer-events-none">
        <div className="pointer-events-auto flex gap-2">
           <button 
             onClick={() => setMode('LIVE')}
             className={`px-4 py-2 rounded-full text-xs font-bold uppercase tracking-widest border transition-all ${mode === 'LIVE' ? 'bg-red-600/20 border-red-500 text-red-500 shadow-[0_0_15px_rgba(239,68,68,0.4)]' : 'bg-black/40 border-zinc-700 text-zinc-500'}`}
           >
             <Zap size={12} className="inline mr-1 mb-0.5" fill={mode === 'LIVE' ? "currentColor" : "none"}/> Live
           </button>
           <button 
             onClick={() => setMode('MANUAL')}
             className={`px-4 py-2 rounded-full text-xs font-bold uppercase tracking-widest border transition-all ${mode === 'MANUAL' ? 'bg-blue-600/20 border-blue-500 text-blue-500 shadow-[0_0_15px_rgba(59,130,246,0.4)]' : 'bg-black/40 border-zinc-700 text-zinc-500'}`}
           >
             Manual
           </button>
        </div>

        {mode === 'MANUAL' && capturedImages.length > 0 && (
          <button onClick={() => setCapturedImages([])} className="pointer-events-auto p-2 bg-black/50 backdrop-blur rounded-full text-zinc-400 hover:text-white border border-white/10">
            <Trash2 size={16} />
          </button>
        )}
      </div>

      {/* CAMERA VIEWFINDER */}
      <div className="flex-1 relative bg-black">
        <video 
          ref={videoRef} 
          autoPlay 
          playsInline 
          className="absolute inset-0 w-full h-full object-cover"
        />

        {/* VIEWING HISTORY ITEM OVERLAY (When paused and viewing history) */}
        {activeHistoryId && mode === 'LIVE' && (
          <div className="absolute inset-0 z-10 bg-black animate-in fade-in duration-500">
             {/* Show the thumbnail as the full background when reviewing history */}
             <img 
               src={sessionHistory.find(h => h.id === activeHistoryId)?.thumbnail} 
               className="w-full h-full object-cover opacity-80"
             />
             <div className="absolute inset-0 bg-black/20 backdrop-blur-[2px]"></div>
             <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 flex flex-col items-center">
                <div className="px-4 py-2 bg-black/60 backdrop-blur rounded-full border border-white/10 text-white text-xs font-bold uppercase tracking-widest mb-4 animate-in zoom-in duration-300">
