                             {liveData.classification}
                           </span>
                           {liveData.valuationEstimate && (
                             <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase border border-emerald-900 text-emerald-400 bg-emerald-950/30">
                               {liveData.valuationEstimate}
                             </span>
                           )}
                        </div>

                        {/* Description */}
                        <p className={`text-sm text-zinc-300 leading-relaxed font-light transition-all duration-500 ${isExpanded ? '' : 'line-clamp-2'}`}>
                          {liveData.detailedNote || "Keep the object in frame to gather more details..."}
                        </p>

                        {/* Expanded Only Content */}
                        <div className={`space-y-6 mt-6 transition-all duration-700 ease-[cubic-bezier(0.19,1,0.22,1)] ${isExpanded ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4 pointer-events-none'}`}>
                             {liveData.quickFacts.length > 0 && (
                               <div>
                                  <h4 className="text-[10px] uppercase font-bold text-zinc-500 tracking-widest mb-3">Quick Analysis</h4>
                                  <div className="grid grid-cols-2 gap-3">
                                     {liveData.quickFacts.map((fact, i) => (
                                        <div key={i} className="bg-white/5 border border-white/10 rounded-lg p-3 text-xs text-zinc-300">
                                            {fact}
                                        </div>
                                     ))}
                                  </div>
                               </div>
                             )}

                             {/* Actions */}
                             <div className="grid grid-cols-2 gap-3 pt-4 border-t border-white/10">
                                <Button 
                                   variant={activeHistoryId ? "primary" : "secondary"} 
                                   onClick={() => isLivePaused ? resumeLiveScanning() : setIsLivePaused(true)}
                                   className={activeHistoryId ? "!bg-red-600 !text-white !border-red-500 hover:!bg-red-500 shadow-[0_0_15px_rgba(220,38,38,0.5)] transition-all duration-300" : ""}
                                >
                                   {isLivePaused ? (
                                      activeHistoryId ? <><Zap size={16} className="mr-2 fill-white" /> Return Live</> : <><Play size={16} className="mr-2" /> Resume</>
                                   ) : (
                                      <><Pause size={16} className="mr-2" /> Pause</>
                                   )}
                                </Button>
                                <Button variant="primary" onClick={saveLiveItem} disabled={liveData.status === 'SEARCHING'}>
                                   <Save size={16} className="mr-2" /> Save Asset
                                </Button>
                             </div>

                             {/* Session History Section */}
                             {sessionHistory.length > 0 && (
                               <div className="pt-4 border-t border-white/10">
                                 <div className="flex items-center gap-2 mb-3">
                                   <History size={12} className="text-zinc-500" />
                                   <h4 className="text-[10px] uppercase font-bold text-zinc-500 tracking-widest">Session History</h4>
                                 </div>
                                 <div className="flex gap-3 overflow-x-auto pb-4 px-1 -mx-1 no-scrollbar">
                                   {sessionHistory.map((item) => (
                                     <button 
                                       key={item.id}
                                       onClick={() => restoreHistoryItem(item)}
                                       className={`relative shrink-0 w-20 h-20 rounded-xl overflow-hidden border transition-all duration-500 ease-out group ${
                                         activeHistoryId === item.id 
                                           ? 'border-white ring-2 ring-white/20 scale-110 shadow-[0_0_20px_rgba(255,255,255,0.3)] z-10 opacity-100' 
                                           : 'border-zinc-800 hover:border-zinc-600 opacity-50 hover:opacity-100 grayscale hover:grayscale-0 scale-95 hover:scale-100'
                                       }`}
                                     >
                                       <img src={item.thumbnail} className="w-full h-full object-cover" />
                                       <div className={`absolute inset-x-0 bottom-0 bg-gradient-to-t from-black via-black/80 to-transparent p-1.5 pt-4 text-center transition-opacity duration-300 ${activeHistoryId === item.id ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>
                                         <p className="text-[9px] text-white truncate font-bold leading-none">{item.data.shortTitle}</p>
                                         <p className="text-[7px] text-zinc-400 mt-0.5">{new Date(item.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
                                       </div>

                                       {/* Active Indicator Overlay */}
                                       {activeHistoryId === item.id && (
                                         <div className="absolute top-1 right-1 w-2 h-2 bg-blue-500 rounded-full shadow-[0_0_8px_rgba(59,130,246,0.8)] ring-1 ring-white"></div>
                                       )}
                                     </button>
                                   ))}
                                 </div>
                               </div>
                             )}
                        </div>
                    </div>
                 </div>
               ) : (
                 <div className="glass-panel rounded-2xl p-4 text-center mx-auto w-full max-w-sm">
                   <p className="text-zinc-500 text-sm font-medium tracking-wide animate-pulse">Initializing Neural Net...</p>
                 </div>
               )}
            </div>
          </>
        )}

        {/* MANUAL MODE UI OVERLAY */}
        {mode === 'MANUAL' && (
           <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
             <div className="w-[80%] aspect-[3/4] border-2 border-dashed border-white/30 rounded-2xl"></div>
           </div>
        )}
      </div>

      {/* CONTROLS FOOTER */}
      <div className={`bg-zinc-950 border-t border-zinc-800 -mt-6 z-20 relative pt-8 pb-8 rounded-t-3xl shadow-[0_-10px_40px_rgba(0,0,0,0.8)] transition-transform duration-700 ease-[cubic-bezier(0.19,1,0.22,1)] ${isExpanded ? 'translate-y-full' : 'translate-y-0'}`}>
        {mode === 'LIVE' ? (
          <div className="px-8 text-center">
             <p className="text-xs text-zinc-500 uppercase tracking-widest mb-2 font-bold">Auto-Scan Active</p>
             <div className="h-1 w-32 bg-zinc-800 mx-auto rounded-full overflow-hidden">
               <div className={`h-full bg-red-500 transition-all duration-300 ${isPulsing ? 'w-full' : 'w-0'}`}></div>
             </div>
          </div>
        ) : (
          <div className="flex justify-between items-center px-8">
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" multiple onChange={handleFileUpload} />

            <button onClick={() => fileInputRef.current?.click()} className="p-4 rounded-full bg-zinc-900 text-zinc-400 hover:text-white border border-zinc-800">
              <ImageIcon size={24} />
            </button>

            <button onClick={captureManual} className="w-20 h-20 rounded-full border-4 border-zinc-700 p-1 flex items-center justify-center relative group active:scale-95 transition-transform">
              <div className="w-full h-full bg-white rounded-full shadow-[0_0_20px_rgba(255,255,255,0.5)]"></div>
            </button>

            <div className="relative">
              {capturedImages.length > 0 ? (
                 <button onClick={handleManualAnalyze} className="w-14 h-14 rounded-xl overflow-hidden border-2 border-blue-500 relative flex items-center justify-center bg-blue-500/20">
                   <span className="font-bold text-blue-400">{capturedImages.length}</span>
                   {isAnalyzing && <div className="absolute inset-0 bg-black/50 flex items-center justify-center"><Loader2 className="animate-spin text-white" size={20}/></div>}
                 </button>
              ) : (
                <div className="w-14 h-14 opacity-0"></div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { AppraisalResult } from '../types';
import { ArrowLeft, Share2, Heart, BadgeCheck, AlertCircle, Info, Tag, BookOpen, Copy, Cpu, History, Lock, TrendingUp } from 'lucide-react';
import { Button } from './Button';

interface ItemResultProps {
  result: AppraisalResult;
  imageData: string;
  onBack: () => void;
  onSave: (result: AppraisalResult) => void;
}

export const ItemResult: React.FC<ItemResultProps> = ({ result, imageData, onBack, onSave }) => {
  const [activeTab, setActiveTab] = useState<'details' | 'context' | 'selling'>('details');

  // Determine UI Mode based on classification
  const isAntique = ['Antique', 'Vintage'].includes(result.classification);

  // Dynamic Labels
  const labels = {
    contextTab: isAntique ? "History" : "Specs",
    contextTitle: isAntique ? "Historical Context" : "Product Specifications",
    identifiersTitle: isAntique ? "Authentication Marks" : "Key Features",
    identifiersIcon: isAntique ? BadgeCheck : Cpu,
    materialsTitle: isAntique ? "Materials & Craftsmanship" : "Build & Components",
    careTitle: isAntique ? "Preservation" : "Maintenance",
  };

  const handleShare = async () => {
    const shareText = `Curator Appraisal: ${result.itemName}\nEst. Value: $${result.valuation.low.toLocaleString()} - $${result.valuation.high.toLocaleString()}\n\n${result.classification} • ${result.era}\n${result.historicalContext.substring(0, 150)}...`;

    try {
      if (navigator.share) {
        // Try to construct a file from the image data to share the visual
        let shareData: ShareData = {
          title: `Curator: ${result.itemName}`,
          text: shareText,
        };

        try {
          // Convert base64 to blob/file
          if (imageData.startsWith('data:')) {
            const res = await fetch(imageData);
            const blob = await res.blob();
            const file = new File([blob], "curator-scan.jpg", { type: "image/jpeg" });

            // Check if system allows sharing files
            const fileShareData = { ...shareData, files: [file] };
            if (navigator.canShare && navigator.canShare(fileShareData)) {
              shareData = fileShareData;
            }
          }
        } catch (e) {
          console.warn("Could not prepare image for sharing, falling back to text.", e);
        }

        await navigator.share(shareData);
      } else {
        // Fallback for desktop/unsupported browsers
        await navigator.clipboard.writeText(shareText);
        alert("Appraisal details copied to clipboard.");
      }
    } catch (error) {
      console.error("Error sharing:", error);
    }
  };

  return (
    <div className="flex-1 flex flex-col bg-zinc-950 overflow-hidden relative font-sans text-zinc-100">
      {/* Floating Header Actions */}
      <div className="absolute top-0 left-0 right-0 p-4 pt-[calc(12px+env(safe-area-inset-top))] flex justify-between items-center z-30 pointer-events-none">
        <button onClick={onBack} className="p-2.5 bg-black/40 backdrop-blur-md hover:bg-black/60 border border-white/10 rounded-full text-white pointer-events-auto transition-colors">
          <ArrowLeft size={20} />
        </button>
        <div className="flex gap-3 pointer-events-auto">
          <button className="p-2.5 bg-black/40 backdrop-blur-md hover:bg-black/60 border border-white/10 rounded-full text-white transition-colors">
            <Heart size={20} />
          </button>
          <button onClick={handleShare} className="p-2.5 bg-black/40 backdrop-blur-md hover:bg-black/60 border border-white/10 rounded-full text-white transition-colors">
            <Share2 size={20} />
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto overflow-x-hidden no-scrollbar pb-6">
        {/* Top Layer: Hero Image */}
        <div className="relative h-[45vh] min-h-[350px] bg-zinc-900">
          <img src={imageData} className="w-full h-full object-cover opacity-80" />
          <div className="absolute inset-0 bg-gradient-to-t from-zinc-950 via-zinc-950/60 to-transparent"></div>

          <div className="absolute bottom-0 left-0 right-0 p-6 pt-12">
            <div className="flex items-center gap-2 mb-3">
              <span className={`px-3 py-1 rounded-md text-[10px] font-bold tracking-widest uppercase border backdrop-blur-md shadow-lg ${
                isAntique 
                  ? 'bg-amber-950/60 border-amber-700/50 text-amber-200' 
                  : 'bg-blue-950/60 border-blue-700/50 text-blue-200'
              }`}>
                {result.classification}
              </span>
              <span className="bg-white/10 backdrop-blur-md px-3 py-1 rounded-md text-[10px] font-bold tracking-widest uppercase border border-white/10 text-zinc-300">
                {result.category}
              </span>
            </div>
            <h1 className="text-3xl font-serif font-medium leading-tight mb-2 text-white drop-shadow-lg">{result.itemName}</h1>
            <p className="text-zinc-400 text-sm font-medium tracking-wide">{result.origin} • {result.era}</p>
          </div>
        </div>

        {/* Valuation Band */}
        <div className="bg-zinc-900 border-y border-zinc-800 p-6 relative z-10 backdrop-blur-sm bg-opacity-80">
          <div className="flex justify-between items-start mb-2">
             <p className="text-[10px] text-zinc-500 font-bold tracking-widest uppercase">Est. Market Value</p>
             <span className="text-[10px] text-emerald-400 font-bold uppercase tracking-wide flex items-center gap-1">
                <TrendingUp size={12} /> Active Market
             </span>
          </div>
          <div className="flex items-baseline gap-2 mb-4">
            <span className="text-4xl font-serif text-white tracking-tight">
              ${result.valuation.low.toLocaleString()} - ${result.valuation.high.toLocaleString()}
            </span>
            <span className="text-sm text-zinc-500 font-medium">{result.valuation.currency}</span>
          </div>

          {/* Confidence/Range Visual */}
          <div className="h-1.5 w-full bg-zinc-800 rounded-full overflow-hidden flex relative">
             <div className="h-full bg-zinc-700 w-[20%]"></div>
             <div className="h-full bg-gradient-to-r from-emerald-600 to-emerald-400 w-[60%] shadow-[0_0_10px_rgba(52,211,153,0.4)]"></div>
             <div className="h-full bg-zinc-700 w-[20%]"></div>
          </div>
          <div className="flex justify-between mt-2 text-[9px] text-zinc-600 uppercase font-bold tracking-widest">
            <span>Low Est.</span>
            <span>Median</span>
            <span>High Est.</span>
          </div>
        </div>

        {/* Tab Navigation */}
        <div className="flex border-b border-zinc-800 bg-zinc-950/95 sticky top-0 z-20 backdrop-blur-md">
          {[
            { id: 'details', label: 'Intel', icon: Info },
            { id: 'context', label: labels.contextTab, icon: isAntique ? History : BookOpen },
            { id: 'selling', label: 'Trade', icon: Tag },
          ].map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex-1 py-4 text-xs font-bold uppercase tracking-wider flex items-center justify-center gap-2 border-b-2 transition-all ${
                activeTab === tab.id 
                  ? 'border-white text-white bg-white/5' 
                  : 'border-transparent text-zinc-600 hover:text-zinc-400'
              }`}
            >
              <tab.icon size={14} />
              {tab.label}
            </button>
          ))}
        </div>

        {/* Content Layers */}
        <div className="p-6 space-y-6 min-h-[400px]">

          {/* TAB: DETAILS */}
          {activeTab === 'details' && (
            <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
              {/* Condition Report */}
              <div className="bg-zinc-900 p-5 rounded-2xl border border-zinc-800">
                <div className="flex justify-between items-start mb-4">
                  <h3 className="font-bold text-sm uppercase tracking-wide text-zinc-300 flex items-center gap-2">
                    <AlertCircle size={16} className={isAntique ? "text-amber-500" : "text-blue-500"} /> 
                    Condition Report
                  </h3>
                  <div className={`text-sm font-bold px-2 py-1 rounded bg-black border ${result.conditionScore >= 7 ? 'text-emerald-400 border-emerald-900' : 'text-amber-400 border-amber-900'}`}>
                    {result.conditionScore}/10
                  </div>
                </div>
                <p className="text-zinc-400 text-sm leading-relaxed">{result.condition}</p>
              </div>

              {/* Identifiers */}
              {result.authenticationMarks.length > 0 && (
                <div className="bg-zinc-900 p-5 rounded-2xl border border-zinc-800">
