                    <p className="text-sm text-zinc-300 leading-relaxed">{result.careInstructions}</p>
                  </div>
                </div>
              </div>

              {/* STRICT CURATOR INSIGHT LOGIC: ONLY IF ANTIQUE */}
              {isAntique && (
                <div className="bg-gradient-to-br from-amber-950/30 to-black p-6 rounded-2xl border border-amber-900/30 relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-4 opacity-10">
                      <History size={100} className="text-amber-500" />
                    </div>
                    <div className="relative z-10">
                      <h4 className="font-serif text-amber-500 text-lg mb-2 flex items-center gap-2">
                        <History size={18} /> Curator's Insight
                      </h4>
                      <p className="text-sm text-amber-200/80 italic leading-relaxed border-l-2 border-amber-900/50 pl-4">
                        "This piece demonstrates specific characteristics of the {result.era} that are increasingly rare. The patina and wear patterns suggest authentic period use rather than modern reproduction techniques."
                      </p>
                    </div>
                </div>
              )}
            </div>
          )}

          {/* TAB: SELLING */}
          {activeTab === 'selling' && (
            <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
               <div className="bg-emerald-950/20 p-5 rounded-2xl border border-emerald-900/50 flex gap-4 items-start">
                 <div className="bg-emerald-900/30 p-2 rounded-lg border border-emerald-800/50">
                    <Tag className="text-emerald-400 shrink-0" size={20} />
                 </div>
                 <div>
                   <h4 className="font-bold text-emerald-400 text-xs uppercase tracking-widest mb-2">Liquidation Strategy</h4>
