               <div className="bg-zinc-900 p-5 rounded-2xl border border-zinc-800 space-y-5">
                  <div className="flex justify-between items-center border-b border-zinc-800 pb-3">
                    <h3 className="font-bold text-sm text-white uppercase tracking-wide">Listing Draft</h3>
                    <button className="text-xs text-zinc-500 hover:text-white flex items-center gap-1 transition-colors"><Copy size={12}/> Copy</button>
                  </div>

                  <div>
                    <label className="text-[9px] font-bold text-zinc-600 uppercase tracking-widest">Title</label>
                    <div className="p-3 bg-black rounded-lg border border-zinc-800 text-sm font-medium mt-2 select-all text-white">
                      {result.sellingProfile.listingTitle}
