                  <div>
                    <label className="text-[9px] font-bold text-zinc-600 uppercase tracking-widest">Description</label>
                    <div className="p-3 bg-black rounded-lg border border-zinc-800 text-sm mt-2 whitespace-pre-wrap select-all text-zinc-300 leading-relaxed font-light">
                      {result.sellingProfile.listingDescription}
