                  <div>
                     <label className="text-[9px] font-bold text-zinc-600 uppercase tracking-widest">Tags</label>
                     <div className="flex flex-wrap gap-2 mt-3">
                        {result.sellingProfile.keywords.map(k => (
                          <span key={k} className="text-[10px] font-medium bg-zinc-800 text-zinc-300 px-2 py-1 rounded border border-zinc-700 hover:border-zinc-500 transition-colors">#{k}</span>
