                 <div className="flex items-center gap-2">
                   <div className={`w-2 h-2 rounded-full ${analysis.demandLevel === 'High' ? 'bg-emerald-500' : analysis.demandLevel === 'Medium' ? 'bg-amber-500' : 'bg-zinc-500'}`}></div>
                   <span className="text-xs text-zinc-400 font-medium">Demand: <span className="text-white">{analysis.demandLevel}</span></span>
                 </div>
                 <span className="text-[10px] text-zinc-600">{analysis.lastUpdated ? `Updated: ${analysis.lastUpdated}` : 'Just Now'}</span>
              </div>
            </div>

            {/* Verified Sources */}
            {analysis.sources && analysis.sources.length > 0 && (
              <div className="bg-zinc-900 p-5 rounded-2xl border border-zinc-800">
                <h3 className="font-bold text-zinc-400 text-xs uppercase tracking-widest mb-3 flex items-center gap-2">
                  <Info size={12} /> Verified Sources
                </h3>
                <div className="space-y-2">
                  {analysis.sources.map((source, idx) => (
                    <a 
                      key={idx} 
                      href={source.url} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="flex items-center justify-between p-3 bg-black/40 rounded-lg border border-white/5 hover:bg-white/5 hover:border-white/10 transition-colors group"
                    >
                      <span className="text-xs text-zinc-300 truncate max-w-[80%] group-hover:text-blue-300 transition-colors">{source.title}</span>
                      <ExternalLink size={12} className="text-zinc-600 group-hover:text-blue-400 transition-colors" />
                    </a>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {/* Portfolio Stats Section */}
        <div className="grid grid-cols-2 gap-4">
           {sortedCategories.map(([cat, count], i) => (
             <div key={i} className="bg-zinc-900 p-4 rounded-xl border border-zinc-800 hover:border-zinc-700 transition-colors">
               <span className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">In Vault</span>
               <div className="flex items-end justify-between mt-2">
                 <span className="text-sm font-bold text-white truncate pr-2">{cat}</span>
                 <span className="text-lg font-serif text-zinc-400">x{count}</span>
               </div>
             </div>
           ))}
        </div>
      </div>
    </div>
  );
};

