import { GoogleGenAI, Type } from "@google/genai";
import { AppraisalResult, LiveAnalysisUpdate, MarketAnalysis, LensMode } from "../types";

const SYSTEM_INSTRUCTION = `You are a universal item identifier and valuation expert with two distinct modes:

MODE A: THE CURATOR (for Antiques/Collectibles)
- Used for: Items >20 years old, art, rare finds.
- Tone: Scholarly, historical, nuanced.
- Focus: Provenance, craftsmanship, maker's marks, cultural context.

MODE B: THE PRODUCT SPECIALIST (for Modern/Everyday Items)
- Used for: Contemporary electronics, appliances, modern furniture, tools, mass-produced goods.
- Tone: Practical, direct, technical.
- Focus: Brand, model number, specifications, utility, resale value.
- RESTRICTION: Do NOT use words like "patina," "provenance," or "historical context" for modern items. Do not invent history for a 2015 telephone.

YOUR TASK:
1. Classify the image immediately (Antique, Vintage, Modern, New, or Specialty).
2. Adopt the correct MODE based on classification.
3. Provide accurate identification and valuation.
`;

// FULL APPRAISAL (Manual Mode)
export const analyzeItem = async (imageBuffers: string[]): Promise<AppraisalResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Analyze these images. They may show different angles or details of the same item.

  STEP 1: CLASSIFY
  Is this item Antique (100+ yrs), Vintage (20-99 yrs), Modern (Used/Secondhand), New (Current Production), or Specialty?

  STEP 2: IDENTIFY
  - If Modern/New: Identify Brand, Model Number, Year, and Specs.
  - If Antique/Vintage: Identify Maker, Era, Style, and Provenance markers.

  STEP 3: ASSESS CONDITION
  - Rate 1-10. Note specific wear visible across all images.

  STEP 4: VALUATION
  - Estimate Fair Market Value based on its specific market.

  STEP 5: CONTEXT
  - If Modern: Provide technical specs and intended use.
  - If Antique: Provide historical context and cultural significance.

  STEP 6: SELLING STRATEGY
  - Draft a listing title and description.
  - Choose the right venue.

  Return strictly JSON.`;

  const imageParts = imageBuffers.map(buffer => ({
    inlineData: { data: buffer.split(',')[1], mimeType: 'image/jpeg' }
  }));

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        ...imageParts,
        { text: prompt }
      ]
    },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          itemName: { type: Type.STRING },
          category: { type: Type.STRING },
          classification: { type: Type.STRING, enum: ["Antique", "Vintage", "Modern", "New", "Specialty"] },
          era: { type: Type.STRING },
          origin: { type: Type.STRING },
          condition: { type: Type.STRING },
          conditionScore: { type: Type.NUMBER },
          valuation: {
            type: Type.OBJECT,
            properties: {
              low: { type: Type.NUMBER },
              mid: { type: Type.NUMBER },
              high: { type: Type.NUMBER },
              currency: { type: Type.STRING }
            }
          },
          authenticationMarks: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "For modern items, list Model Numbers/Specs. For antiques, list Hallmarks/Signatures." 
          },
          historicalContext: { 
            type: Type.STRING,
            description: "If modern, provide product specs. If antique, provide history."
          },
          materials: { type: Type.STRING },
          careInstructions: { type: Type.STRING },
          comparableSales: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                price: { type: Type.STRING },
                date: { type: Type.STRING },
                link: { type: Type.STRING },
                source: { type: Type.STRING }
              }
            }
          },
          sellingProfile: {
            type: Type.OBJECT,
            properties: {
              listingTitle: { type: Type.STRING },
              listingDescription: { type: Type.STRING },
              keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
              recommendedVenue: { type: Type.STRING },
              pricingStrategy: { type: Type.STRING }
            }
          },
          confidence: { type: Type.NUMBER }
        },
        required: ["itemName", "valuation", "historicalContext", "sellingProfile", "classification"]
      }
    }
  });

  if (!response.text) throw new Error("Analysis failed to return data.");
  return JSON.parse(response.text) as AppraisalResult;
};

// LIVE PROGRESSIVE ANALYSIS (MULTI-LENS)
export const analyzeLiveFrame = async (imageBuffer: string, lensMode: LensMode, previousContext?: string): Promise<LiveAnalysisUpdate> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  let lensPrompt = "";
  if (lensMode === 'IDENTITY') {
    lensPrompt = "FOCUS: Rapid identification. Name, Era, and Origin. Ignore price.";
  } else if (lensMode === 'MARKET') {
    lensPrompt = "FOCUS: Value and Demand. Is it valuable? Is it rare? Estimate price range aggressively.";
  } else if (lensMode === 'FORENSICS') {
    lensPrompt = "FOCUS: Condition and Authenticity. Look for cracks, wear, patina, or signs of fake/reproduction. Be critical.";
  }

  const prompt = `You are a real-time visual scanner with a specialized LENS.
  ACTIVE LENS: ${lensMode}. ${lensPrompt}

  PREVIOUS CONTEXT: ${previousContext || "None."}

  TASK:
  1. Identify the MAIN object.
  2. Provide specific details based on the ACTIVE LENS.
  3. Classify: Antique, Vintage, Modern, New, or Specialty.

  OUTPUT RULES:
  - If nothing is clear, return status "SEARCHING".
  - If object is detected, return status "IDENTIFYING".
  - If analysis is high confidence, return status "LOCKED".

  Provide a JSON response.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview', 
    contents: {
      parts: [
        { inlineData: { data: imageBuffer.split(',')[1], mimeType: 'image/jpeg' } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          status: { type: Type.STRING, enum: ["SEARCHING", "IDENTIFYING", "LOCKED"] },
          shortTitle: { type: Type.STRING },
          classification: { type: Type.STRING, enum: ["Antique", "Vintage", "Modern", "New", "Specialty"] },
          quickFacts: { type: Type.ARRAY, items: { type: Type.STRING }, description: "3 bullet points specific to the active lens" },
          valuationEstimate: { type: Type.STRING, description: "Rough range e.g. '$50-100' or 'Unknown'" },
          detailedNote: { type: Type.STRING, description: "One insightful sentence based on the active lens." },
          confidence: { type: Type.NUMBER }
        }
      }
    }
  });

  if (!response.text) return { status: 'SEARCHING', shortTitle: '', classification: 'Modern', quickFacts: [], confidence: 0, lensMode };
  return { ...JSON.parse(response.text), lensMode };
};

// CHAT WITH CURATOR
export const askCurator = async (itemContext: AppraisalResult, question: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const systemContext = `You are an expert curator discussing a specific item: "${itemContext.itemName}" (${itemContext.era}, ${itemContext.classification}).
  Item Context: ${JSON.stringify(itemContext)}

  User Question: "${question}"

  Provide a helpful, expert answer (max 3 sentences). Be practical.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [{ text: systemContext }] }
  });

  return response.text || "I couldn't generate an answer at this moment.";
};

// REAL-TIME MARKET INTELLIGENCE
export const getMarketAnalysis = async (query: string): Promise<MarketAnalysis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Perform a real-time market analysis for: "${query}".

  Using Google Search, find the latest auction results, sales data, and collector interest for this specific item type.

  Provide:
  1. Market Trend (UP, DOWN, or STABLE)
  2. Estimated percentage change in value over the last year (e.g. "+15%" or "-2%")
  3. A concise, professional executive summary.
  4. One key actionable insight.
  5. Current Demand Level (High, Medium, Low).

  Return strictly JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [{ text: prompt }] },
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          itemName: { type: Type.STRING },
          trend: { type: Type.STRING, enum: ["UP", "DOWN", "STABLE"] },
          changePercent: { type: Type.STRING },
          summary: { type: Type.STRING },
          keyInsight: { type: Type.STRING },
          demandLevel: { type: Type.STRING, enum: ["High", "Medium", "Low"] },
          lastUpdated: { type: Type.STRING }
        },
        required: ["trend", "changePercent", "summary", "keyInsight", "demandLevel"]
      }
    }
  });

  if (!response.text) throw new Error("Market analysis failed.");

  const cleanText = response.text.replace(/```json|```/g, '').trim();
  const data = JSON.parse(cleanText) as MarketAnalysis;

  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  const sources = chunks
    .flatMap((chunk: any) => chunk.web?.uri ? [{ title: chunk.web.title || "Source", url: chunk.web.uri }] : [])
    .filter((v, i, a) => a.findIndex(t => (t.url === v.url)) === i)
    .slice(0, 5);

  return { ...data, sources };
};

import React, { useRef, useState, useCallback, useEffect } from 'react';
import { RefreshCw, Image as ImageIcon, Camera, Plus, Trash2, X, Zap, Pause, Play, ScanLine, Loader2, ChevronUp, ChevronDown, Save, Share2, History, Clock, Fingerprint, DollarSign, Search } from 'lucide-react';
import { Button } from './Button';
import { analyzeItem, analyzeLiveFrame } from '../services/geminiService';
import { AppraisalResult, LiveAnalysisUpdate, LensMode } from '../types';
import { ItemResult } from './ItemResult';

interface ScannerProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

type ScanMode = 'LIVE' | 'MANUAL';

interface SessionHistoryItem {
  id: string;
  timestamp: Date;
  thumbnail: string;
  data: LiveAnalysisUpdate;
}

const LENSES: { id: LensMode; label: string; icon: any; color: string; desc: string }[] = [
  { id: 'IDENTITY', label: 'Identity', icon: Search, color: 'text-blue-500', desc: 'Classification & Era' },
  { id: 'MARKET', label: 'Market', icon: DollarSign, color: 'text-emerald-500', desc: 'Value & Demand' },
  { id: 'FORENSICS', label: 'Forensics', icon: Fingerprint, color: 'text-amber-500', desc: 'Condition & Auth' },
];

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  const [mode, setMode] = useState<ScanMode>('LIVE'); // Default to LIVE for the "Super Lens" feel
  const [activeLens, setActiveLens] = useState<LensMode>('IDENTITY');
  const [stream, setStream] = useState<MediaStream | null>(null);

  // MANUAL STATE
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [manualResult, setManualResult] = useState<AppraisalResult | null>(null);

  // LIVE STATE
  const [liveData, setLiveData] = useState<LiveAnalysisUpdate | null>(null);
  const [isLivePaused, setIsLivePaused] = useState(false);
  const [lastScanTime, setLastScanTime] = useState<number>(0);
  const [isPulsing, setIsPulsing] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);

  // HISTORY STATE
  const [sessionHistory, setSessionHistory] = useState<SessionHistoryItem[]>([]);
  const [activeHistoryId, setActiveHistoryId] = useState<string | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- CAMERA LOGIC ---
  const startCamera = async () => {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } },
        audio: false 
      });
      setStream(s);
      if (videoRef.current) videoRef.current.srcObject = s;
    } catch (err) {
      console.error("Camera access denied", err);
    }
  };

  const stopCamera = () => {
    stream?.getTracks().forEach(t => t.stop());
    setStream(null);
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  useEffect(() => {
    if (stream && videoRef.current) videoRef.current.srcObject = stream;
  }, [stream, mode]); 

  // --- MANUAL MODE HANDLERS ---
  const captureManual = useCallback(() => {
    if (!videoRef.current) return;
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    const ctx = canvas.getContext('2d');
    ctx?.drawImage(videoRef.current, 0, 0);
    const data = canvas.toDataURL('image/jpeg', 0.85);
    setCapturedImages(prev => [...prev, data]);
    setMode('MANUAL'); // Switch to manual UI after capture
  }, []);

  const handleManualAnalyze = async () => {
    if (capturedImages.length === 0) return;
    setIsAnalyzing(true);
    try {
      const res = await analyzeItem(capturedImages);
      setManualResult(res);
    } catch (err) {
      alert("Analysis failed. Try again.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  // --- LIVE MODE HEARTBEAT ---
  useEffect(() => {
    if (mode !== 'LIVE' || isLivePaused || !stream) return;

    const intervalId = setInterval(async () => {
      const now = Date.now();
      // Rate limit to allow reading and save costs
      if (now - lastScanTime < 3500) return;

      if (videoRef.current) {
        setIsPulsing(true);
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth / 2; // Downscale
        canvas.height = videoRef.current.videoHeight / 2;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const frameData = canvas.toDataURL('image/jpeg', 0.6);

        // Analyze Frame with Active Lens
        try {
          const context = liveData ? `Previous guess: ${liveData.shortTitle}.` : "";
          const result = await analyzeLiveFrame(frameData, activeLens, context);

          if (result.status !== 'SEARCHING' || liveData?.status === 'SEARCHING') {
             setLiveData(result);

             if (result.status === 'LOCKED') {
               setSessionHistory(prev => {
                 if (prev.length > 0 && prev[0].data.shortTitle === result.shortTitle) {
                   return prev;
                 }
                 return [{
                   id: crypto.randomUUID(),
                   timestamp: new Date(),
                   thumbnail: frameData,
                   data: result
                 }, ...prev];
               });
             }
          }
          setLastScanTime(Date.now());
        } catch (e) {
          console.error("Live pulse failed", e);
        } finally {
          setIsPulsing(false);
        }
      }
    }, 1000); 

    return () => clearInterval(intervalId);
  }, [mode, isLivePaused, stream, lastScanTime, liveData, activeLens]); // Added activeLens to dependencies

  // --- RENDER HELPERS ---
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files && files.length > 0) {
      Array.from(files).forEach((file) => {
        const reader = new FileReader();
        reader.onloadend = () => setCapturedImages(prev => [...prev, reader.result as string]);
        reader.readAsDataURL(file as Blob);
      });
      setMode('MANUAL');
    }
  };

  const saveLiveItem = () => {
    if (!liveData) return;

    let imageData = '';
    if (activeHistoryId) {
      const historyItem = sessionHistory.find(h => h.id === activeHistoryId);
      if (historyItem) imageData = historyItem.thumbnail;
    }

    if (!imageData && videoRef.current) {
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth;
        canvas.height = videoRef.current.videoHeight;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(videoRef.current, 0, 0);
        imageData = canvas.toDataURL('image/jpeg', 0.85);
    }

    const partialResult: AppraisalResult = {
        itemName: liveData.shortTitle,
        category: 'Live Scan Capture',
        classification: liveData.classification,
        era: liveData.quickFacts[0] || 'Unknown',
        origin: 'Unknown',
        condition: 'Assessed Live',
        conditionScore: 5,
        valuation: { low: 0, mid: 0, high: 0, currency: 'USD' },
        authenticationMarks: [],
        historicalContext: liveData.detailedNote || '',
        materials: liveData.quickFacts[1] || 'Unknown',
        careInstructions: 'Handle with care.',
        comparableSales: [],
        sellingProfile: { listingTitle: liveData.shortTitle, listingDescription: liveData.detailedNote || '', keywords: [], recommendedVenue: 'Online', pricingStrategy: 'Auction' },
        confidence: liveData.confidence
    };

    onSave(partialResult, imageData);
  };

  const restoreHistoryItem = (item: SessionHistoryItem) => {
    setIsLivePaused(true);
    setLiveData(item.data);
    setActiveHistoryId(item.id);
  };

  const resumeLiveScanning = () => {
    setIsLivePaused(false);
    setActiveHistoryId(null);
    setLiveData(null); 
  };

  if (manualResult && capturedImages.length > 0) {
    return (
      <ItemResult 
        result={manualResult} 
        imageData={capturedImages[0]} 
        onBack={() => setManualResult(null)} 
        onSave={(res) => onSave(res, capturedImages[0])} 
      />
    );
  }

  const currentLens = LENSES.find(l => l.id === activeLens)!;

  return (
    <div className="flex-1 flex flex-col bg-zinc-950 relative h-full overflow-hidden font-sans">

      {/* TOP HEADER: HUD Status */}
      <div className="absolute top-0 left-0 right-0 z-30 pt-[env(safe-area-inset-top)] p-4 flex justify-between items-start bg-gradient-to-b from-black/80 to-transparent pointer-events-none">
        <div className="flex flex-col">
            <h1 className="text-xl font-serif text-white tracking-wide drop-shadow-md pointer-events-auto">Curator<span className="text-blue-500">Lens</span></h1>
            <div className="flex items-center gap-2 mt-1">
                <div className={`w-2 h-2 rounded-full ${isPulsing ? 'bg-red-500 animate-ping' : 'bg-zinc-600'}`}></div>
                <span className="text-[10px] uppercase font-bold text-zinc-400 tracking-widest">{mode} FEED</span>
            </div>
        </div>

        {mode === 'MANUAL' && capturedImages.length > 0 && (
          <button onClick={() => setCapturedImages([])} className="pointer-events-auto p-2 bg-black/50 backdrop-blur rounded-full text-zinc-400 hover:text-white border border-white/10">
            <Trash2 size={16} />
          </button>
        )}
      </div>

      {/* CAMERA VIEWFINDER */}
      <div className="flex-1 relative bg-black">
        <video 
          ref={videoRef} 
          autoPlay 
          playsInline 
          className="absolute inset-0 w-full h-full object-cover opacity-90"
        />

        {/* LENS MODE UI OVERLAYS */}
        {mode === 'LIVE' && (
          <>
            {/* HUD Overlay Graphics */}
            <div className="absolute inset-0 pointer-events-none opacity-30">
               {/* Corners */}
               <div className={`absolute top-8 left-8 w-16 h-16 border-t-2 border-l-2 ${currentLens.color.replace('text-', 'border-')} rounded-tl-2xl`}></div>
               <div className={`absolute top-8 right-8 w-16 h-16 border-t-2 border-r-2 ${currentLens.color.replace('text-', 'border-')} rounded-tr-2xl`}></div>
               <div className={`absolute bottom-32 left-8 w-16 h-16 border-b-2 border-l-2 ${currentLens.color.replace('text-', 'border-')} rounded-bl-2xl`}></div>
               <div className={`absolute bottom-32 right-8 w-16 h-16 border-b-2 border-r-2 ${currentLens.color.replace('text-', 'border-')} rounded-br-2xl`}></div>

               {/* Center Crosshair */}
               <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-8 h-8 flex items-center justify-center">
                  <div className={`w-1 h-3 ${currentLens.color.replace('text-', 'bg-')}`}></div>
                  <div className={`h-1 w-3 absolute ${currentLens.color.replace('text-', 'bg-')}`}></div>
               </div>
            </div>

            {/* SCANNING RETICLE - PULSING RING */}
            {!isLivePaused && (
                <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                    {/* Ring */}
                    <div className={`w-72 h-72 rounded-full border border-white/10 transition-all duration-500 ease-out
                        ${liveData?.status === 'LOCKED' ? `scale-110 opacity-0 border-2 ${currentLens.color.replace('text-', 'border-')}` : 'scale-100 opacity-100'}
                        ${isPulsing && liveData?.status !== 'LOCKED' ? 'border-white/40 shadow-[0_0_30px_rgba(255,255,255,0.1)]' : ''}
                    `}></div>

                    {/* Active Radar Sweep */}
                    <div className="absolute w-72 h-72 rounded-full overflow-hidden opacity-20">
                         <div className={`w-full h-1/2 bg-gradient-to-t from-white/50 to-transparent animate-spin origin-bottom`}></div>
                    </div>
                </div>
            )}

            {/* LIVE DATA PANEL */}
            <div 
              className={`absolute left-4 right-4 z-30 flex flex-col transition-all duration-500 ease-out ${
                isExpanded 
                  ? 'top-[100px] bottom-36' 
                  : 'top-[calc(100%-300px)] bottom-[100px]' 
              }`}
            >
               {liveData ? (
                 <div className={`glass-panel w-full h-full rounded-2xl overflow-hidden flex flex-col shadow-2xl border-l-4 transition-colors duration-500 ${liveData.status === 'LOCKED' ? `border-l-emerald-500 bg-black/90` : `border-l-zinc-500 bg-black/80`}`}>

                    {/* Header */}
                    <div className="p-5 pb-2 shrink-0 relative cursor-pointer active:bg-white/5" onClick={() => setIsExpanded(!isExpanded)}>
                       {/* Drag Handle */}
                       <div className="absolute top-2 left-1/2 -translate-x-1/2 w-8 h-1 bg-zinc-700 rounded-full"></div>

                       <div className="flex justify-between items-start mt-2">
                          <div className="flex-1">
                             <div className="flex items-center gap-2 mb-1">
                                 {/* Status Pill */}
                                 <span className={`px-2 py-0.5 rounded-full text-[9px] font-bold uppercase tracking-widest border ${liveData.status === 'LOCKED' ? 'border-emerald-900 bg-emerald-950/50 text-emerald-400' : 'border-zinc-700 bg-zinc-900 text-zinc-400'}`}>
                                   {liveData.status === 'SEARCHING' ? 'Scanning...' : liveData.status}
                                 </span>
                                 <span className="text-[9px] font-bold uppercase tracking-widest text-zinc-500">{activeLens} Lens</span>
                             </div>
                             <h2 className="text-2xl font-serif text-white leading-tight mt-1 mb-1">
                                 {liveData.shortTitle || "Analyzing Visuals..."}
                             </h2>
                          </div>
                          <button className="text-zinc-500 hover:text-white transition-colors">
                              {isExpanded ? <ChevronDown size={20} /> : <ChevronUp size={20} />}
                          </button>
                       </div>
                    </div>

                    {/* Content */}
                    <div className={`flex-1 overflow-y-auto p-5 pt-0 transition-opacity duration-300 ${isExpanded ? 'opacity-100' : 'opacity-95'}`}>
                        {/* Lens Specific Quick Facts */}
                        <div className="mt-2 space-y-2">
                             {liveData.quickFacts.map((fact, i) => (
                                <div key={i} className="flex items-center gap-2 text-xs text-zinc-300">
                                    <div className={`w-1 h-1 rounded-full ${currentLens.color.replace('text-', 'bg-')}`}></div>
                                    {fact}
                                </div>
                             ))}
                        </div>

                        <p className={`mt-4 text-sm text-zinc-400 leading-relaxed font-light border-l-2 ${currentLens.color.replace('text-', 'border-')} pl-3 italic`}>
                          "{liveData.detailedNote || "Hold steady for deeper analysis..."}"
                        </p>

                        {/* Actions (Expanded Only) */}
                        <div className={`grid grid-cols-2 gap-3 mt-6 pt-4 border-t border-white/10 transition-all duration-500 ${isExpanded ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4 pointer-events-none'}`}>
                            <Button 
                               variant={activeHistoryId ? "primary" : "secondary"} 
                               onClick={() => isLivePaused ? resumeLiveScanning() : setIsLivePaused(true)}
                            >
                               {isLivePaused ? "Resume" : "Pause"}
                            </Button>
                            <Button variant="primary" onClick={saveLiveItem} disabled={liveData.status === 'SEARCHING'}>
                               <Save size={16} className="mr-2" /> Save
                            </Button>
                        </div>
                    </div>
                 </div>
               ) : (
                 <div className="glass-panel rounded-2xl p-4 text-center mx-auto w-full max-w-sm flex items-center justify-center gap-3">
                    <Loader2 className={`animate-spin ${currentLens.color}`} size={16} />
                    <p className="text-zinc-400 text-xs font-bold uppercase tracking-widest">Calibrating {activeLens} Lens...</p>
                 </div>
               )}
            </div>
          </>
        )}
      </div>

      {/* LENS SELECTOR (BOTTOM DOCK) */}
      <div className="bg-zinc-950/90 border-t border-zinc-800 backdrop-blur-xl z-40 pb-[calc(20px+env(safe-area-inset-bottom))]">
          {/* Toggle Live/Manual Small */}
          <div className="flex justify-center -mt-3 mb-2">
             <button 
                onClick={() => setMode(mode === 'LIVE' ? 'MANUAL' : 'LIVE')}
                className="bg-zinc-900 border border-zinc-800 text-[10px] font-bold uppercase tracking-widest text-zinc-500 px-3 py-1 rounded-full hover:text-white transition-colors"
             >
                {mode === 'LIVE' ? 'Switch to Manual' : 'Switch to Live Lens'}
             </button>
          </div>

          {mode === 'LIVE' ? (
              <div className="flex justify-around items-center px-2">
                  {LENSES.map((lens) => (
                      <button
                        key={lens.id}
                        onClick={() => setActiveLens(lens.id)}
                        className={`flex flex-col items-center gap-1.5 p-3 rounded-2xl transition-all duration-300 w-24 ${activeLens === lens.id ? 'bg-white/10 scale-105' : 'opacity-50 hover:opacity-100'}`}
                      >
                          <lens.icon size={24} className={activeLens === lens.id ? lens.color : 'text-zinc-400'} />
                          <span className={`text-[9px] font-bold uppercase tracking-widest ${activeLens === lens.id ? 'text-white' : 'text-zinc-500'}`}>{lens.label}</span>
                      </button>
                  ))}
              </div>
          ) : (
              // Manual Mode Controls
              <div className="flex justify-between items-center px-8 py-4">
                <input type="file" ref={fileInputRef} className="hidden" accept="image/*" multiple onChange={handleFileUpload} />
                <button onClick={() => fileInputRef.current?.click()} className="p-4 rounded-full bg-zinc-900 text-zinc-400 hover:text-white border border-zinc-800">
                  <ImageIcon size={24} />
                </button>
                <button onClick={captureManual} className="w-20 h-20 rounded-full border-4 border-zinc-700 p-1 flex items-center justify-center relative group active:scale-95 transition-transform">
                  <div className="w-full h-full bg-white rounded-full shadow-[0_0_20px_rgba(255,255,255,0.5)]"></div>
                </button>
                <div className="w-14 h-14">
                    {capturedImages.length > 0 && (
                        <button onClick={handleManualAnalyze} className="w-full h-full rounded-xl overflow-hidden border-2 border-blue-500 relative flex items-center justify-center bg-blue-500/20 text-blue-400 font-bold">
                           {isAnalyzing ? <Loader2 className="animate-spin" /> : capturedImages.length}
                        </button>
                    )}
                </div>
              </div>
          )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { AppraisalResult, ChatMessage } from '../types';
import { askCurator } from '../services/geminiService';
