      </div>

      {/* FOOTER ACTION */}
      <div className="p-4 bg-zinc-950 border-t border-zinc-800 sticky bottom-0 z-30 pb-[calc(16px+env(safe-area-inset-bottom))]">
        <Button onClick={() => onSave(result)} className="w-full text-lg font-bold py-4 shadow-[0_0_20px_rgba(255,255,255,0.1)] bg-white text-black hover:bg-zinc-200 border-none rounded-xl">
          Secure in Vault
        </Button>
      </div>

      {/* CHAT OVERLAY (THE "ASK CURATOR" FEATURE) */}
      {showChat && (
         <div className="absolute inset-0 z-50 bg-black/80 backdrop-blur-xl flex flex-col animate-in fade-in slide-in-from-bottom-10 duration-300">
            {/* Chat Header */}
            <div className="p-4 pt-[calc(12px+env(safe-area-inset-top))] border-b border-white/10 flex items-center justify-between bg-zinc-900/50">
               <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-full bg-blue-600 flex items-center justify-center text-white shadow-lg shadow-blue-500/30">
                     <MessageSquare size={20} />
                  </div>
                  <div>
                     <h3 className="text-white font-serif font-bold">Curator Assistant</h3>
                     <p className="text-[10px] text-blue-300 font-bold uppercase tracking-wider">Expert Mode Active</p>
                  </div>
               </div>
               <button onClick={() => setShowChat(false)} className="p-2 bg-white/10 rounded-full text-white hover:bg-white/20"><X size={20} /></button>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4">
               {chatHistory.length === 0 && (
                  <div className="text-center mt-20 opacity-50">
                     <p className="text-sm text-zinc-400">Ask me anything about this item.</p>
                     <div className="flex flex-wrap gap-2 justify-center mt-4">
                        <button onClick={() => setChatInput("Is it authentic?")} className="px-3 py-1 bg-white/5 rounded-full text-xs border border-white/10 hover:bg-white/10">Is it authentic?</button>
                        <button onClick={() => setChatInput("How do I clean it?")} className="px-3 py-1 bg-white/5 rounded-full text-xs border border-white/10 hover:bg-white/10">Care tips?</button>
                        <button onClick={() => setChatInput("Where should I sell this?")} className="px-3 py-1 bg-white/5 rounded-full text-xs border border-white/10 hover:bg-white/10">Best marketplace?</button>
                     </div>
                  </div>
               )}
               {chatHistory.map((msg, i) => (
                  <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                     <div className={`max-w-[85%] p-3 rounded-2xl text-sm leading-relaxed ${msg.role === 'user' ? 'bg-blue-600 text-white rounded-br-none' : 'bg-zinc-800 text-zinc-200 rounded-bl-none border border-zinc-700'}`}>
                        {msg.text}
                     </div>
                  </div>
               ))}
               {isChatLoading && (
                  <div className="flex justify-start">
                     <div className="bg-zinc-800 p-3 rounded-2xl rounded-bl-none border border-zinc-700 flex gap-1">
                        <span className="w-1.5 h-1.5 bg-zinc-500 rounded-full animate-bounce"></span>
                        <span className="w-1.5 h-1.5 bg-zinc-500 rounded-full animate-bounce delay-100"></span>
                        <span className="w-1.5 h-1.5 bg-zinc-500 rounded-full animate-bounce delay-200"></span>
                     </div>
                  </div>
               )}
            </div>

            {/* Input */}
            <div className="p-4 bg-zinc-900 border-t border-white/10 pb-[calc(20px+env(safe-area-inset-bottom))]">
               <div className="relative">
                  <input 
                     type="text" 
                     value={chatInput}
                     onChange={(e) => setChatInput(e.target.value)}
                     onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                     placeholder="Type a specific question..."
                     className="w-full pl-4 pr-12 py-3 bg-black border border-zinc-700 rounded-full text-sm text-white focus:border-blue-500 focus:ring-1 focus:ring-blue-500 outline-none placeholder:text-zinc-600"
                  />
                  <button 
                     onClick={handleSendMessage}
                     disabled={!chatInput.trim() || isChatLoading}
                     className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-blue-600 rounded-full text-white hover:bg-blue-500 disabled:opacity-50 disabled:hover:bg-blue-600 transition-colors"
                  >
                     <Send size={16} />
                  </button>
               </div>
            </div>
         </div>
      )}
    </div>
  );
};

