  category: string;
  classification: ItemClassification;
  era: string;
  origin: string;
  condition: string;
  conditionScore: number; // 1-10
  valuation: {
    low: number;
    mid: number;
    high: number;
    currency: string;
  };
  authenticationMarks: string[]; 
  historicalContext: string; 
  materials: string;
  careInstructions: string;
  comparableSales: {
    title: string;
    price: string;
    date: string;
    link: string;
    source: string;
  }[];
  sellingProfile: {
    listingTitle: string;
    listingDescription: string;
    keywords: string[];
    recommendedVenue: string;
    pricingStrategy: string;
  };
  confidence: number;
}

