export type AppTab = 'SCAN' | 'COLLECTION' | 'MARKET' | 'ACCOUNT';

import { GoogleGenAI, Type } from "@google/genai";
import { AppraisalResult, LiveAnalysisUpdate, MarketAnalysis, LensMode } from "../types";

const SYSTEM_INSTRUCTION = `You are a universal item identifier and valuation expert with two distinct modes:

MODE A: THE CURATOR (for Antiques/Collectibles)
- Used for: Items >20 years old, art, rare finds.
- Tone: Scholarly, historical, nuanced.
- Focus: Provenance, craftsmanship, maker's marks, cultural context.

MODE B: THE PRODUCT SPECIALIST (for Modern/Everyday Items)
- Used for: Contemporary electronics, appliances, modern furniture, tools, mass-produced goods.
- Tone: Practical, direct, technical.
- Focus: Brand, model number, specifications, utility, resale value.
- RESTRICTION: Do NOT use words like "patina," "provenance," or "historical context" for modern items. Do not invent history for a 2015 telephone.

YOUR TASK:
1. Classify the image immediately (Antique, Vintage, Modern, New, or Specialty).
2. Adopt the correct MODE based on classification.
3. Provide accurate identification and valuation.
`;

// FULL APPRAISAL (Manual Mode)
export const analyzeItem = async (imageBuffers: string[]): Promise<AppraisalResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Analyze these images. They may show different angles or details of the same item.

  STEP 1: CLASSIFY
  Is this item Antique (100+ yrs), Vintage (20-99 yrs), Modern (Used/Secondhand), New (Current Production), or Specialty?

  STEP 2: IDENTIFY
  - If Modern/New: Identify Brand, Model Number, Year, and Specs.
  - If Antique/Vintage: Identify Maker, Era, Style, and Provenance markers.

  STEP 3: ASSESS CONDITION
  - Rate 1-10. Note specific wear visible across all images.

  STEP 4: VALUATION
  - Estimate Fair Market Value based on its specific market.

  STEP 5: CONTEXT
  - If Modern: Provide technical specs and intended use.
  - If Antique: Provide historical context and cultural significance.

  STEP 6: SELLING STRATEGY
  - Draft a listing title and description.
  - Choose the right venue.

  Return strictly JSON.`;

  const imageParts = imageBuffers.map(buffer => ({
    inlineData: { data: buffer.split(',')[1], mimeType: 'image/jpeg' }
  }));

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        ...imageParts,
        { text: prompt }
      ]
    },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          itemName: { type: Type.STRING },
          category: { type: Type.STRING },
          classification: { type: Type.STRING, enum: ["Antique", "Vintage", "Modern", "New", "Specialty"] },
          era: { type: Type.STRING },
          origin: { type: Type.STRING },
          condition: { type: Type.STRING },
          conditionScore: { type: Type.NUMBER },
          valuation: {
            type: Type.OBJECT,
            properties: {
              low: { type: Type.NUMBER },
              mid: { type: Type.NUMBER },
              high: { type: Type.NUMBER },
              currency: { type: Type.STRING }
            }
          },
          authenticationMarks: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "For modern items, list Model Numbers/Specs. For antiques, list Hallmarks/Signatures." 
          },
          historicalContext: { 
            type: Type.STRING,
            description: "If modern, provide product specs. If antique, provide history."
          },
          materials: { type: Type.STRING },
          careInstructions: { type: Type.STRING },
          comparableSales: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                price: { type: Type.STRING },
                date: { type: Type.STRING },
                link: { type: Type.STRING },
                source: { type: Type.STRING }
              }
            }
          },
          sellingProfile: {
            type: Type.OBJECT,
            properties: {
              listingTitle: { type: Type.STRING },
              listingDescription: { type: Type.STRING },
              keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
              recommendedVenue: { type: Type.STRING },
              pricingStrategy: { type: Type.STRING }
            }
          },
          confidence: { type: Type.NUMBER }
        },
        required: ["itemName", "valuation", "historicalContext", "sellingProfile", "classification"]
      }
    }
  });

  if (!response.text) throw new Error("Analysis failed to return data.");
  return JSON.parse(response.text) as AppraisalResult;
};

// LIVE PROGRESSIVE ANALYSIS (MULTI-LENS)
export const analyzeLiveFrame = async (imageBuffer: string, lensMode: LensMode, previousContext?: string): Promise<LiveAnalysisUpdate> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  let lensPrompt = "";
  if (lensMode === 'IDENTITY') {
    lensPrompt = "FOCUS: Rapid identification. Name, Era, and Origin. Ignore price.";
  } else if (lensMode === 'MARKET') {
    lensPrompt = "FOCUS: Value and Demand. Is it valuable? Is it rare? Estimate price range aggressively.";
  } else if (lensMode === 'FORENSICS') {
    lensPrompt = "FOCUS: Condition and Authenticity. Look for cracks, wear, patina, or signs of fake/reproduction. Be critical.";
  } else if (lensMode === 'DECIPHER') {
    lensPrompt = "FOCUS: Text, Script, Hallmarks, and Signatures. Transcribe any text visible. Identify language or symbol origin. Ignore the object shape, look at the surface marks.";
  }

  const prompt = `You are a real-time visual scanner with a specialized LENS.
  ACTIVE LENS: ${lensMode}. ${lensPrompt}

  PREVIOUS CONTEXT: ${previousContext || "None."}

  TASK:
  1. Identify the MAIN subject based on the LENS.
  2. Provide specific details based on the ACTIVE LENS.
  3. Classify: Antique, Vintage, Modern, New, or Specialty.

  OUTPUT RULES:
  - If nothing is clear, return status "SEARCHING".
  - If object is detected, return status "IDENTIFYING".
  - If analysis is high confidence, return status "LOCKED".

  Provide a JSON response.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview', 
    contents: {
      parts: [
        { inlineData: { data: imageBuffer.split(',')[1], mimeType: 'image/jpeg' } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          status: { type: Type.STRING, enum: ["SEARCHING", "IDENTIFYING", "LOCKED"] },
          shortTitle: { type: Type.STRING },
          classification: { type: Type.STRING, enum: ["Antique", "Vintage", "Modern", "New", "Specialty"] },
          quickFacts: { type: Type.ARRAY, items: { type: Type.STRING }, description: "3 bullet points specific to the active lens" },
          valuationEstimate: { type: Type.STRING, description: "Rough range e.g. '$50-100' or 'Unknown'" },
          detailedNote: { type: Type.STRING, description: "One insightful sentence based on the active lens." },
          confidence: { type: Type.NUMBER }
        }
      }
    }
  });

  if (!response.text) return { status: 'SEARCHING', shortTitle: '', classification: 'Modern', quickFacts: [], confidence: 0, lensMode };
  return { ...JSON.parse(response.text), lensMode };
};

// CHAT WITH CURATOR
export const askCurator = async (itemContext: AppraisalResult, question: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const systemContext = `You are an expert curator discussing a specific item: "${itemContext.itemName}" (${itemContext.era}, ${itemContext.classification}).
  Item Context: ${JSON.stringify(itemContext)}

  User Question: "${question}"

  Provide a helpful, expert answer (max 3 sentences). Be practical.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [{ text: systemContext }] }
  });

  return response.text || "I couldn't generate an answer at this moment.";
};

// REAL-TIME MARKET INTELLIGENCE
export const getMarketAnalysis = async (query: string): Promise<MarketAnalysis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Perform a real-time market analysis for: "${query}".

  Using Google Search, find the latest auction results, sales data, and collector interest for this specific item type.

  Provide:
  1. Market Trend (UP, DOWN, or STABLE)
  2. Estimated percentage change in value over the last year (e.g. "+15%" or "-2%")
  3. A concise, professional executive summary.
  4. One key actionable insight.
  5. Current Demand Level (High, Medium, Low).

  Return strictly JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [{ text: prompt }] },
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          itemName: { type: Type.STRING },
          trend: { type: Type.STRING, enum: ["UP", "DOWN", "STABLE"] },
          changePercent: { type: Type.STRING },
          summary: { type: Type.STRING },
          keyInsight: { type: Type.STRING },
          demandLevel: { type: Type.STRING, enum: ["High", "Medium", "Low"] },
          lastUpdated: { type: Type.STRING }
        },
        required: ["trend", "changePercent", "summary", "keyInsight", "demandLevel"]
      }
    }
  });

  if (!response.text) throw new Error("Market analysis failed.");

  const cleanText = response.text.replace(/```json|```/g, '').trim();
  const data = JSON.parse(cleanText) as MarketAnalysis;

  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  const sources = chunks
    .flatMap((chunk: any) => chunk.web?.uri ? [{ title: chunk.web.title || "Source", url: chunk.web.uri }] : [])
    .filter((v, i, a) => a.findIndex(t => (t.url === v.url)) === i)
    .slice(0, 5);

  return { ...data, sources };
};

import React, { useRef, useState, useCallback, useEffect } from 'react';
import { Image as ImageIcon, Plus, Trash2, X, Zap, ChevronUp, ChevronDown, Save, Fingerprint, DollarSign, Search, ScanLine, Languages, Sparkles } from 'lucide-react';
import { Button } from './Button';
import { analyzeItem, analyzeLiveFrame } from '../services/geminiService';
import { AppraisalResult, LiveAnalysisUpdate, LensMode } from '../types';
import { ItemResult } from './ItemResult';

interface ScannerProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

type ScanMode = 'LIVE' | 'MANUAL';

interface SessionHistoryItem {
  id: string;
  timestamp: Date;
  thumbnail: string;
  data: LiveAnalysisUpdate;
}

// Updated Lens Configuration with Decipher
const LENSES: { id: LensMode; label: string; icon: any; color: string; desc: string; gradient: string }[] = [
  { id: 'IDENTITY', label: 'Identity', icon: Search, color: 'text-blue-400', desc: 'Classification', gradient: 'from-blue-500/20 to-blue-900/10' },
  { id: 'MARKET', label: 'Market', icon: DollarSign, color: 'text-emerald-400', desc: 'Valuation', gradient: 'from-emerald-500/20 to-emerald-900/10' },
  { id: 'FORENSICS', label: 'Forensics', icon: Fingerprint, color: 'text-amber-400', desc: 'Condition', gradient: 'from-amber-500/20 to-amber-900/10' },
  { id: 'DECIPHER', label: 'Decipher', icon: Languages, color: 'text-violet-400', desc: 'OCR & Marks', gradient: 'from-violet-500/20 to-violet-900/10' },
];

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  const [mode, setMode] = useState<ScanMode>('LIVE');
  const [activeLens, setActiveLens] = useState<LensMode>('IDENTITY');
  const [stream, setStream] = useState<MediaStream | null>(null);

  // MANUAL STATE
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [manualResult, setManualResult] = useState<AppraisalResult | null>(null);

  // LIVE STATE
  const [liveData, setLiveData] = useState<LiveAnalysisUpdate | null>(null);
  const [isLivePaused, setIsLivePaused] = useState(false);
  const [lastScanTime, setLastScanTime] = useState<number>(0);
  const [isPulsing, setIsPulsing] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);

  // HISTORY STATE (RAPID STREAM)
  const [sessionHistory, setSessionHistory] = useState<SessionHistoryItem[]>([]);

  const videoRef = useRef<HTMLVideoElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  // --- CAMERA LOGIC ---
  const startCamera = async () => {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } },
        audio: false 
      });
      setStream(s);
      if (videoRef.current) videoRef.current.srcObject = s;
    } catch (err) {
      console.error("Camera access denied", err);
    }
  };

  const stopCamera = () => {
    stream?.getTracks().forEach(t => t.stop());
    setStream(null);
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  useEffect(() => {
    if (stream && videoRef.current) videoRef.current.srcObject = stream;
  }, [stream, mode]); 

  // --- MANUAL MODE HANDLERS ---
  const captureManual = useCallback(() => {
    if (!videoRef.current) return;
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    const ctx = canvas.getContext('2d');
    ctx?.drawImage(videoRef.current, 0, 0);
    const data = canvas.toDataURL('image/jpeg', 0.85);
    setCapturedImages(prev => [...prev, data]);
    setMode('MANUAL');
  }, []);

  const handleManualAnalyze = async () => {
    if (capturedImages.length === 0) return;
    setIsAnalyzing(true);
    try {
      const res = await analyzeItem(capturedImages);
      setManualResult(res);
    } catch (err) {
      alert("Analysis failed. Try again.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  // --- HAPTIC FEEDBACK HELPER ---
  const triggerHaptic = (type: 'lock' | 'tap') => {
    if (navigator.vibrate) {
      if (type === 'lock') navigator.vibrate([30, 50, 30]); // Distinct double pulse
      if (type === 'tap') navigator.vibrate(10);
    }
  };

  // --- LIVE MODE HEARTBEAT ---
  useEffect(() => {
    if (mode !== 'LIVE' || isLivePaused || !stream) return;

    const intervalId = setInterval(async () => {
      const now = Date.now();
      if (now - lastScanTime < 3000) return; // Rate limit 3s

      if (videoRef.current) {
        setIsPulsing(true);
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth / 2;
        canvas.height = videoRef.current.videoHeight / 2;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const frameData = canvas.toDataURL('image/jpeg', 0.6);

        try {
          const context = liveData ? `Previous: ${liveData.shortTitle}.` : "";
          const result = await analyzeLiveFrame(frameData, activeLens, context);

          if (result.status !== 'SEARCHING' || liveData?.status === 'SEARCHING') {
             setLiveData(result);

             if (result.status === 'LOCKED') {
               triggerHaptic('lock');

               // Add to Rapid Stream History automatically if it's a new item
               setSessionHistory(prev => {
                 // Simple de-dupe: don't add if same title as last one
                 if (prev.length > 0 && prev[0].data.shortTitle === result.shortTitle) {
                   return prev;
                 }
                 return [{
                   id: crypto.randomUUID(),
                   timestamp: new Date(),
                   thumbnail: frameData,
                   data: result
                 }, ...prev];
               });
             }
          }
          setLastScanTime(Date.now());
        } catch (e) {
          console.error("Live pulse failed", e);
        } finally {
          setIsPulsing(false);
        }
      }
    }, 1000); 

    return () => clearInterval(intervalId);
  }, [mode, isLivePaused, stream, lastScanTime, liveData, activeLens]);

  // --- RENDER HELPERS ---
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files && files.length > 0) {
      Array.from(files).forEach((file) => {
        const reader = new FileReader();
        reader.onloadend = () => setCapturedImages(prev => [...prev, reader.result as string]);
        reader.readAsDataURL(file as Blob);
      });
      setMode('MANUAL');
    }
  };

  const saveLiveItem = (historyItem?: SessionHistoryItem) => {
    const dataToSave = historyItem?.data || liveData;
    if (!dataToSave) return;

    const imageData = historyItem?.thumbnail || (() => {
        if (!videoRef.current) return '';
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth;
        canvas.height = videoRef.current.videoHeight;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(videoRef.current, 0, 0);
        return canvas.toDataURL('image/jpeg', 0.85);
    })();

    const partialResult: AppraisalResult = {
        itemName: dataToSave.shortTitle,
        category: 'Live Scan Capture',
        classification: dataToSave.classification,
        era: dataToSave.quickFacts[0] || 'Unknown',
        origin: 'Unknown',
        condition: 'Assessed Live',
        conditionScore: 5,
        valuation: { low: 0, mid: 0, high: 0, currency: 'USD' },
        authenticationMarks: [],
        historicalContext: dataToSave.detailedNote || '',
        materials: dataToSave.quickFacts[1] || 'Unknown',
        careInstructions: 'Handle with care.',
        comparableSales: [],
        sellingProfile: { listingTitle: dataToSave.shortTitle, listingDescription: dataToSave.detailedNote || '', keywords: [], recommendedVenue: 'Online', pricingStrategy: 'Auction' },
        confidence: dataToSave.confidence
    };

    onSave(partialResult, imageData);
  };

  if (manualResult && capturedImages.length > 0) {
    return (
      <ItemResult 
        result={manualResult} 
        imageData={capturedImages[0]} 
        onBack={() => setManualResult(null)} 
        onSave={(res) => onSave(res, capturedImages[0])} 
      />
    );
  }

  const currentLens = LENSES.find(l => l.id === activeLens)!;

  return (
    <div className="flex-1 flex flex-col bg-black relative h-full overflow-hidden font-sans select-none">

      {/* TOP HEADER: HUD Status */}
      <div className="absolute top-0 left-0 right-0 z-30 pt-[env(safe-area-inset-top)] p-4 flex justify-between items-start bg-gradient-to-b from-black/90 via-black/40 to-transparent pointer-events-none">
        <div className="flex flex-col">
            <h1 className="text-xl font-serif text-white tracking-wide drop-shadow-md pointer-events-auto flex items-center gap-2">
              Curator <span className="bg-white/10 px-1.5 rounded text-sm font-sans font-bold tracking-wider text-white border border-white/10">PRO</span>
            </h1>
            <div className="flex items-center gap-2 mt-2">
                <div className={`w-1.5 h-1.5 rounded-full ${isPulsing ? 'bg-red-500 shadow-[0_0_10px_red]' : 'bg-zinc-600'}`}></div>
                <span className="text-[9px] uppercase font-bold text-zinc-400 tracking-[0.2em]">{mode} SIGNAL</span>
            </div>
        </div>

        {/* Quick Stream Ribbon (Recent History) */}
        {sessionHistory.length > 0 && mode === 'LIVE' && (
           <div className="flex gap-2 pointer-events-auto overflow-x-auto no-scrollbar max-w-[50vw] pr-2 items-center">
             {sessionHistory.slice(0, 4).map((item) => (
               <button 
                 key={item.id}
                 onClick={() => saveLiveItem(item)}
                 className="relative w-10 h-10 rounded-lg border border-white/20 overflow-hidden flex-shrink-0 hover:border-blue-500 transition-colors"
               >
                 <img src={item.thumbnail} className="w-full h-full object-cover opacity-70" />
                 <div className="absolute inset-0 flex items-center justify-center bg-black/20">
                    <Plus size={12} className="text-white opacity-80" />
                 </div>
               </button>
             ))}
           </div>
        )}
      </div>

      {/* CAMERA VIEWFINDER */}
      <div className="flex-1 relative bg-black">
        <video 
          ref={videoRef} 
          autoPlay 
          playsInline 
          className="absolute inset-0 w-full h-full object-cover opacity-80 mix-blend-screen"
        />

        {/* SCANNING GRID OVERLAY */}
        <div className="absolute inset-0 pointer-events-none opacity-20 bg-[linear-gradient(rgba(255,255,255,0.03)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.03)_1px,transparent_1px)] bg-[size:40px_40px]"></div>

        {/* LENS MODE UI OVERLAYS */}
        {mode === 'LIVE' && (
          <>
            {/* HUD Overlay Graphics */}
            <div className="absolute inset-0 pointer-events-none opacity-60">
               {/* Animated Corners */}
               <div className={`absolute top-24 left-8 w-8 h-8 border-t border-l ${currentLens.color.replace('text-', 'border-')} transition-colors duration-500`}></div>
               <div className={`absolute top-24 right-8 w-8 h-8 border-t border-r ${currentLens.color.replace('text-', 'border-')} transition-colors duration-500`}></div>
               <div className={`absolute bottom-32 left-8 w-8 h-8 border-b border-l ${currentLens.color.replace('text-', 'border-')} transition-colors duration-500`}></div>
               <div className={`absolute bottom-32 right-8 w-8 h-8 border-b border-r ${currentLens.color.replace('text-', 'border-')} transition-colors duration-500`}></div>

               {/* Center Reticle */}
               <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-64 h-64 border border-white/5 rounded-full flex items-center justify-center">
                  <div className={`w-1 h-2 absolute top-0 ${currentLens.color.replace('text-', 'bg-')}`}></div>
                  <div className={`w-1 h-2 absolute bottom-0 ${currentLens.color.replace('text-', 'bg-')}`}></div>
                  <div className={`h-1 w-2 absolute left-0 ${currentLens.color.replace('text-', 'bg-')}`}></div>
                  <div className={`h-1 w-2 absolute right-0 ${currentLens.color.replace('text-', 'bg-')}`}></div>

                  {/* Lock Indicator */}
                  {liveData?.status === 'LOCKED' && (
                     <div className={`absolute inset-0 border-2 ${currentLens.color.replace('text-', 'border-')} rounded-full animate-ping opacity-20`}></div>
                  )}
               </div>
            </div>

            {/* LIVE DATA PANEL (Bottom Card) */}
            <div 
              className={`absolute left-4 right-4 z-30 flex flex-col transition-all duration-500 cubic-bezier(0.34, 1.56, 0.64, 1) ${
                isExpanded 
                  ? 'top-[100px] bottom-36' 
                  : 'top-[calc(100%-320px)] bottom-[100px]' 
              }`}
            >
               {liveData ? (
                 <div className={`glass-panel w-full h-full rounded-3xl overflow-hidden flex flex-col shadow-2xl transition-all duration-500`}>

                    {/* Header */}
                    <div className={`p-5 pb-3 shrink-0 relative cursor-pointer active:bg-white/5 bg-gradient-to-b ${currentLens.gradient}`} onClick={() => { triggerHaptic('tap'); setIsExpanded(!isExpanded); }}>
                       {/* Drag Handle */}
                       <div className="absolute top-2 left-1/2 -translate-x-1/2 w-10 h-1 bg-white/20 rounded-full"></div>

                       <div className="flex justify-between items-start mt-2">
                          <div className="flex-1">
                             <div className="flex items-center gap-2 mb-1">
                                 {/* Status Pill */}
                                 <span className={`px-2 py-0.5 rounded text-[9px] font-bold uppercase tracking-widest border ${liveData.status === 'LOCKED' ? 'border-white/30 bg-white/10 text-white shadow-[0_0_10px_rgba(255,255,255,0.2)]' : 'border-zinc-700 bg-zinc-900/50 text-zinc-400'}`}>
                                   {liveData.status === 'SEARCHING' ? 'Acquiring Target...' : liveData.status}
                                 </span>
                             </div>
