                                  )}
                              </div>
                              <span className={`text-[9px] font-bold uppercase tracking-widest transition-colors ${activeLens === lens.id ? 'text-white' : 'text-zinc-600'}`}>{lens.label}</span>
                          </button>
                      ))}
                  </div>
                  {/* Dial Center Indicator */}
                  <div className="absolute top-0 bottom-0 left-1/2 w-px bg-gradient-to-b from-transparent via-blue-500/50 to-transparent pointer-events-none"></div>
              </div>
          ) : (
              // Manual Mode Controls
              <div className="flex justify-between items-center px-10 py-4">
                <input type="file" ref={fileInputRef} className="hidden" accept="image/*" multiple onChange={handleFileUpload} />
                <button onClick={() => fileInputRef.current?.click()} className="p-4 rounded-full bg-zinc-900 text-zinc-400 hover:text-white border border-zinc-800">
                  <ImageIcon size={24} />
                </button>
                <button onClick={() => {}} className="w-20 h-20 rounded-full border-4 border-zinc-700 p-1 flex items-center justify-center relative group active:scale-95 transition-transform">
                  <div className="w-full h-full bg-white rounded-full shadow-[0_0_30px_rgba(255,255,255,0.3)]"></div>
                </button>
                <div className="w-14 h-14">
                    {capturedImages.length > 0 && (
                        <button onClick={handleManualAnalyze} className="w-full h-full rounded-xl overflow-hidden border-2 border-blue-500 relative flex items-center justify-center bg-blue-500/20 text-blue-400 font-bold">
                           {isAnalyzing ? <ScanLine className="animate-spin" /> : capturedImages.length}
                        </button>
                    )}
                </div>
              </div>
          )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { AppraisalResult, ChatMessage } from '../types';
import { askCurator } from '../services/geminiService';
import { ArrowLeft, Share2, Heart, BadgeCheck, AlertCircle, Info, Tag, BookOpen, Copy, Cpu, History, MessageSquare, Send, X, User, ExternalLink, Calendar } from 'lucide-react';
import { Button } from './Button';

interface ItemResultProps {
  result: AppraisalResult;
  imageData: string;
  onBack: () => void;
  onSave: (result: AppraisalResult) => void;
}

export const ItemResult: React.FC<ItemResultProps> = ({ result, imageData, onBack, onSave }) => {
  const [activeTab, setActiveTab] = useState<'details' | 'context' | 'selling'>('details');
  const [showChat, setShowChat] = useState(false);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [chatInput, setChatInput] = useState("");
  const [isChatLoading, setIsChatLoading] = useState(false);

  // Determine UI Mode based on classification
  const isAntique = ['Antique', 'Vintage'].includes(result.classification);

  // Dynamic Labels
  const labels = {
    contextTab: isAntique ? "History" : "Specs",
    contextTitle: isAntique ? "Historical Context" : "Product Specifications",
    identifiersTitle: isAntique ? "Authentication Marks" : "Key Features",
    identifiersIcon: isAntique ? BadgeCheck : Cpu,
    materialsTitle: isAntique ? "Materials & Craftsmanship" : "Build & Components",
    careTitle: isAntique ? "Preservation" : "Maintenance",
  };

  // Confidence Calculation
  const confidencePercent = Math.round((result.confidence || 0) * 100);
  let confidenceColor = "text-red-400 border-red-500/30 bg-red-500/10";
  let confidenceLabel = "Low";

  if (confidencePercent >= 80) {
    confidenceColor = "text-emerald-400 border-emerald-500/30 bg-emerald-500/10";
    confidenceLabel = "High";
  } else if (confidencePercent >= 50) {
    confidenceColor = "text-amber-400 border-amber-500/30 bg-amber-500/10";
    confidenceLabel = "Medium";
  }

  // Parse Era for Timeline (Simple rough year extraction)
  const extractYear = (text: string) => {
    const match = text.match(/\d{4}/);
    return match ? parseInt(match[0]) : 2024;
  };
  const itemYear = extractYear(result.era);
  const timelineStart = 1900;
  const timelineEnd = 2025;
  const timelinePos = Math.max(0, Math.min(100, ((itemYear - timelineStart) / (timelineEnd - timelineStart)) * 100));

  const handleShare = async () => {
    const shareText = `Curator Appraisal: ${result.itemName}\nVal: $${result.valuation.low} - $${result.valuation.high}`;
    if (navigator.share) {
       await navigator.share({ title: result.itemName, text: shareText, url: window.location.href });
    } else {
       await navigator.clipboard.writeText(shareText);
       alert("Copied to clipboard");
    }
  };

  const handleSendMessage = async () => {
    if (!chatInput.trim()) return;

    const userMsg: ChatMessage = { role: 'user', text: chatInput };
    setChatHistory(prev => [...prev, userMsg]);
    setChatInput("");
    setIsChatLoading(true);

    try {
      const answer = await askCurator(result, userMsg.text);
      setChatHistory(prev => [...prev, { role: 'model', text: answer }]);
    } catch (e) {
      setChatHistory(prev => [...prev, { role: 'model', text: "Connection error. Please try again." }]);
    } finally {
      setIsChatLoading(false);
    }
