// REAL-TIME MARKET INTELLIGENCE
export const getMarketAnalysis = async (query: string): Promise<MarketAnalysis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Perform a real-time market analysis for: "${query}".

  Using Google Search, find the latest auction results, sales data, and collector interest for this specific item type.

  Provide:
  1. Market Trend (UP, DOWN, or STABLE)
  2. Estimated percentage change in value over the last year (e.g. "+15%" or "-2%")
  3. A concise, professional executive summary.
  4. One key actionable insight.
  5. Current Demand Level (High, Medium, Low).

  Return strictly JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [{ text: prompt }] },
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          itemName: { type: Type.STRING },
          trend: { type: Type.STRING, enum: ["UP", "DOWN", "STABLE"] },
          changePercent: { type: Type.STRING },
          summary: { type: Type.STRING },
          keyInsight: { type: Type.STRING },
          demandLevel: { type: Type.STRING, enum: ["High", "Medium", "Low"] },
          lastUpdated: { type: Type.STRING }
        },
        required: ["trend", "changePercent", "summary", "keyInsight", "demandLevel"]
      }
    }
  });

  if (!response.text) throw new Error("Market analysis failed.");

  const cleanText = response.text.replace(/```json|```/g, '').trim();
  const data = JSON.parse(cleanText) as MarketAnalysis;

  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  const sources = chunks
    .flatMap((chunk: any) => chunk.web?.uri ? [{ title: chunk.web.title || "Source", url: chunk.web.uri }] : [])
    .filter((v, i, a) => a.findIndex(t => (t.url === v.url)) === i)
    .slice(0, 5);

  return { ...data, sources };
};

