// --- AUDIO ENGINE ---
class SonicEngine {
  ctx: AudioContext | null = null;
  osc: OscillatorNode | null = null;
  gain: GainNode | null = null;

  init() {
    if (!this.ctx) {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
  }

  playPing(valueTier: 'LOW' | 'MID' | 'HIGH') {
    if (!this.ctx) this.init();
    if (!this.ctx) return;

    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.connect(gain);
    gain.connect(this.ctx.destination);

    // Sound Design: "Treasure Shimmer"
    const now = this.ctx.currentTime;

    if (valueTier === 'HIGH') {
        osc.type = 'sine';
        osc.frequency.setValueAtTime(880, now); // A5
        osc.frequency.exponentialRampToValueAtTime(1760, now + 0.1); // Slide up to A6
        gain.gain.setValueAtTime(0, now);
        gain.gain.linearRampToValueAtTime(0.3, now + 0.05);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.6);
    } else if (valueTier === 'MID') {
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(440, now); // A4
        gain.gain.setValueAtTime(0, now);
        gain.gain.linearRampToValueAtTime(0.2, now + 0.05);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.4);
    } else {
        osc.type = 'sine';
        osc.frequency.setValueAtTime(220, now); // A3
        gain.gain.setValueAtTime(0, now);
        gain.gain.linearRampToValueAtTime(0.1, now + 0.05);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.3);
    }

    osc.start(now);
    osc.stop(now + 0.6);
  }

  playLock() {
    if (!this.ctx) this.init();
    if (!this.ctx) return;
    // Mechanical shutter sound simulation
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();
    osc.connect(gain);
    gain.connect(this.ctx.destination);

    const now = this.ctx.currentTime;
    osc.type = 'square';
    osc.frequency.setValueAtTime(100, now);
    osc.frequency.exponentialRampToValueAtTime(0.01, now + 0.1);

    gain.gain.setValueAtTime(0.3, now);
    gain.gain.exponentialRampToValueAtTime(0.01, now + 0.1);

    osc.start(now);
    osc.stop(now + 0.1);
  }
}

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  const [mode, setMode] = useState<ScanMode>('LIVE');
  const [activeLens, setActiveLens] = useState<LensMode>('IDENTITY');
  const [stream, setStream] = useState<MediaStream | null>(null);

  // CAMERA CONTROLS
  const [zoomLevel, setZoomLevel] = useState(1);
  const [hasHardwareZoom, setHasHardwareZoom] = useState(false);
  const [soundEnabled, setSoundEnabled] = useState(true);

  // MANUAL STATE
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [manualResult, setManualResult] = useState<AppraisalResult | null>(null);

  // LIVE STATE
  const [liveData, setLiveData] = useState<LiveAnalysisUpdate | null>(null);
  const [isLivePaused, setIsLivePaused] = useState(false);
  const [lastScanTime, setLastScanTime] = useState<number>(0);
  const [isPulsing, setIsPulsing] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);

  // HISTORY STATE (RAPID STREAM)
  const [sessionHistory, setSessionHistory] = useState<SessionHistoryItem[]>([]);

  const videoRef = useRef<HTMLVideoElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<SonicEngine>(new SonicEngine());

  // --- CAMERA LOGIC ---
  const startCamera = async () => {
    try {
      const constraints: MediaStreamConstraints = { 
        video: { 
          facingMode: 'environment', 
          width: { ideal: 1920 }, 
          height: { ideal: 1080 },
          zoom: true // Request zoom capability
        } as any, // Type cast for zoom
        audio: false 
      };

      const s = await navigator.mediaDevices.getUserMedia(constraints);
      setStream(s);

      // Check for hardware zoom support
      const track = s.getVideoTracks()[0];
      const capabilities = track.getCapabilities() as any;
      if (capabilities.zoom) {
        setHasHardwareZoom(true);
      }

      if (videoRef.current) videoRef.current.srcObject = s;
    } catch (err) {
      console.error("Camera access denied", err);
    }
  };

  const stopCamera = () => {
    stream?.getTracks().forEach(t => t.stop());
    setStream(null);
  };

  const handleZoom = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newZoom = parseFloat(e.target.value);
    setZoomLevel(newZoom);

    if (stream && hasHardwareZoom) {
      const track = stream.getVideoTracks()[0];
      track.applyConstraints({ advanced: [{ zoom: newZoom }] as any });
    }
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  // --- HAPTIC & AUDIO FEEDBACK ---
  const triggerFeedback = (type: 'lock' | 'scan', valueEstimate?: string) => {
    // Haptics
    if (navigator.vibrate) {
      if (type === 'lock') navigator.vibrate([40, 60, 40]);
    }

    // Audio
    if (soundEnabled) {
        if (type === 'lock') {
            audioRef.current.playLock();
            // Estimate value tier for sound
            let tier: 'LOW' | 'MID' | 'HIGH' = 'LOW';
            if (valueEstimate) {
                if (valueEstimate.includes('$') && (valueEstimate.includes('000') || valueEstimate.includes('500'))) tier = 'HIGH';
                else if (valueEstimate.includes('$1') || valueEstimate.includes('$2')) tier = 'MID';
            }
            // Delay the "ping" slightly after the lock sound
            setTimeout(() => audioRef.current.playPing(tier), 200);
        }
    }
  };

  // --- RENDER HELPERS ---
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files && files.length > 0) {
      Array.from(files).forEach((file) => {
        const reader = new FileReader();
        reader.onloadend = () => setCapturedImages(prev => [...prev, reader.result as string]);
        reader.readAsDataURL(file as Blob);
      });
      setMode('MANUAL');
    }
  };

  const captureFrame = () => {
    if (!videoRef.current) return;
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    const ctx = canvas.getContext('2d');
    if (ctx) {
        ctx.drawImage(videoRef.current, 0, 0);
        const data = canvas.toDataURL('image/jpeg', 0.85);
        setCapturedImages(prev => [...prev, data]);
        triggerFeedback('lock');
    }
  };

  const handleManualAnalyze = async () => {
    if (capturedImages.length === 0) return;
    setIsAnalyzing(true);
    try {
      const result = await analyzeItem(capturedImages);
      setManualResult(result);
    } catch (error) {
      console.error("Manual analysis failed", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const saveLiveItem = (historyItem?: SessionHistoryItem) => {
    const dataToSave = historyItem?.data || liveData;
    if (!dataToSave) return;

    // For manual save, regenerate the thumbnail from current view if needed
    const imageData = historyItem?.thumbnail || (() => {
        if (!videoRef.current) return '';
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth;
        canvas.height = videoRef.current.videoHeight;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(videoRef.current, 0, 0);
        return canvas.toDataURL('image/jpeg', 0.85);
    })();

    const partialResult: AppraisalResult = {
        itemName: dataToSave.shortTitle,
        category: 'Live Scan Capture',
        classification: dataToSave.classification,
        era: dataToSave.quickFacts[0] || 'Unknown',
        origin: 'Unknown',
        condition: 'Assessed Live',
        conditionScore: 5,
        valuation: { low: 0, mid: 0, high: 0, currency: 'USD' },
        authenticationMarks: [],
        historicalContext: dataToSave.detailedNote || '',
        materials: dataToSave.quickFacts[1] || 'Unknown',
        careInstructions: 'Handle with care.',
        comparableSales: [],
        sellingProfile: { listingTitle: dataToSave.shortTitle, listingDescription: dataToSave.detailedNote || '', keywords: [], recommendedVenue: 'Online', pricingStrategy: 'Auction' },
        confidence: dataToSave.confidence
    };

    onSave(partialResult, imageData);
  };

  // --- LIVE MODE HEARTBEAT ---
  useEffect(() => {
    if (mode !== 'LIVE' || isLivePaused || !stream) return;

    const intervalId = setInterval(async () => {
      const now = Date.now();
      if (now - lastScanTime < 3000) return; 

      if (videoRef.current) {
        setIsPulsing(true);
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth / 2;
        canvas.height = videoRef.current.videoHeight / 2;
        const ctx = canvas.getContext('2d');

        // Apply digital zoom crop if hardware zoom isn't available
        if (!hasHardwareZoom && zoomLevel > 1) {
            const w = canvas.width;
            const h = canvas.height;
            const cropW = w / zoomLevel;
            const cropH = h / zoomLevel;
            const cropX = (w - cropW) / 2;
            const cropY = (h - cropH) / 2;
            ctx?.drawImage(videoRef.current, cropX * 2, cropY * 2, cropW * 2, cropH * 2, 0, 0, w, h);
        } else {
            ctx?.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        }

        const frameData = canvas.toDataURL('image/jpeg', 0.6);

        try {
          const context = liveData ? `Previous: ${liveData.shortTitle}.` : "";
          const result = await analyzeLiveFrame(frameData, activeLens, context);

          if (result.status !== 'SEARCHING' || liveData?.status === 'SEARCHING') {
             setLiveData(result);

             if (result.status === 'LOCKED') {
               triggerFeedback('lock', result.valuationEstimate);

               setSessionHistory(prev => {
                 if (prev.length > 0 && prev[0].data.shortTitle === result.shortTitle) return prev;
                 return [{
                   id: crypto.randomUUID(),
                   timestamp: new Date(),
                   thumbnail: frameData,
                   data: result
                 }, ...prev];
               });
             }
          }
          setLastScanTime(Date.now());
        } catch (e) {
          console.error("Live pulse failed", e);
        } finally {
          setIsPulsing(false);
        }
      }
    }, 1000); 

    return () => clearInterval(intervalId);
  }, [mode, isLivePaused, stream, lastScanTime, liveData, activeLens, zoomLevel]);

  // --- MANUAL MODE SWITCH ---
  if (manualResult && capturedImages.length > 0) {
    return (
      <ItemResult 
        result={manualResult} 
        imageData={capturedImages[0]} 
        onBack={() => setManualResult(null)} 
        onSave={(res) => onSave(res, capturedImages[0])} 
      />
    );
  }

  const currentLens = LENSES.find(l => l.id === activeLens)!;

  return (
    <div className="flex-1 flex flex-col bg-black relative h-full overflow-hidden font-sans select-none">

      {/* TOP HEADER: HUD Status */}
      <div className="absolute top-0 left-0 right-0 z-30 pt-[env(safe-area-inset-top)] p-4 flex justify-between items-start bg-gradient-to-b from-black/90 via-black/40 to-transparent pointer-events-none">
        <div className="flex flex-col">
            <h1 className="text-xl font-serif text-white tracking-wide drop-shadow-md pointer-events-auto flex items-center gap-2">
              Curator <span className="bg-white/10 px-1.5 rounded text-sm font-sans font-bold tracking-wider text-white border border-white/10">ELITE</span>
            </h1>
            <div className="flex items-center gap-2 mt-2">
                <div className={`w-1.5 h-1.5 rounded-full ${isPulsing ? 'bg-red-500 shadow-[0_0_10px_red]' : 'bg-zinc-600'}`}></div>
                <span className="text-[9px] uppercase font-bold text-zinc-400 tracking-[0.2em]">{mode} SIGNAL</span>
            </div>
        </div>

        <div className="flex items-center gap-2 pointer-events-auto">
             <button onClick={() => setSoundEnabled(!soundEnabled)} className="w-10 h-10 rounded-full bg-black/40 backdrop-blur border border-white/10 text-white flex items-center justify-center">
                {soundEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}
             </button>
             {/* Quick Stream Ribbon (Recent History) */}
            {sessionHistory.length > 0 && mode === 'LIVE' && (
               <div className="flex gap-2 overflow-x-auto no-scrollbar max-w-[40vw] pr-2 items-center">
                 {sessionHistory.slice(0, 3).map((item) => (
                   <button 
                     key={item.id}
                     onClick={() => saveLiveItem(item)}
                     className="relative w-10 h-10 rounded-lg border border-white/20 overflow-hidden flex-shrink-0 hover:border-blue-500 transition-colors"
                   >
                     <img src={item.thumbnail} className="w-full h-full object-cover opacity-70" />
                     <div className="absolute inset-0 flex items-center justify-center bg-black/20">
                        <Plus size={12} className="text-white opacity-80" />
                     </div>
                   </button>
                 ))}
               </div>
            )}
        </div>
      </div>

      {/* CAMERA VIEWFINDER */}
      <div className="flex-1 relative bg-black overflow-hidden group">
        <video 
          ref={videoRef} 
          autoPlay 
          playsInline 
          className="absolute inset-0 w-full h-full object-cover opacity-90 transition-transform duration-200"
          style={{ transform: !hasHardwareZoom && zoomLevel > 1 ? `scale(${zoomLevel})` : 'scale(1)' }}
        />

        {/* ZOOM CONTROLS OVERLAY */}
        {mode === 'LIVE' && (
            <div className="absolute right-4 top-1/2 -translate-y-1/2 z-30 flex flex-col items-center gap-4 pointer-events-auto opacity-0 group-hover:opacity-100 transition-opacity duration-300">
               <ZoomIn size={16} className="text-white/70" />
               <div className="h-48 w-8 bg-black/40 backdrop-blur rounded-full border border-white/10 flex items-center justify-center py-2 relative">
                   <input 
                     type="range" 
                     min="1" 
                     max="5" 
                     step="0.1" 
                     value={zoomLevel} 
                     onChange={handleZoom}
                     className="absolute w-40 h-8 -rotate-90 appearance-none bg-transparent cursor-pointer [&::-webkit-slider-thumb]:w-4 [&::-webkit-slider-thumb]:h-4 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-white [&::-webkit-slider-track]:bg-white/20 [&::-webkit-slider-track]:rounded-full"
                   />
               </div>
               <span className="text-[10px] font-bold text-white bg-black/50 px-2 py-1 rounded">{zoomLevel}x</span>
            </div>
        )}

        {/* SCANNING GRID & RETICLE */}
        <div className="absolute inset-0 pointer-events-none opacity-20 bg-[linear-gradient(rgba(255,255,255,0.03)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.03)_1px,transparent_1px)] bg-[size:40px_40px]"></div>

        {mode === 'LIVE' && (
          <>
            {/* Professional Camera Reticle */}
            <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
               <div className={`relative transition-all duration-300 ${liveData?.status === 'LOCKED' ? 'w-64 h-64 border-2 border-emerald-500/80 shadow-[0_0_30px_rgba(16,185,129,0.3)]' : 'w-72 h-72 border border-white/20'}`}>
                   {/* Corner Brackets */}
                   <div className="absolute top-0 left-0 w-4 h-4 border-t-2 border-l-2 border-white/50"></div>
                   <div className="absolute top-0 right-0 w-4 h-4 border-t-2 border-r-2 border-white/50"></div>
                   <div className="absolute bottom-0 left-0 w-4 h-4 border-b-2 border-l-2 border-white/50"></div>
                   <div className="absolute bottom-0 right-0 w-4 h-4 border-b-2 border-r-2 border-white/50"></div>

                   {/* Center Cross */}
                   <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2">
                       <div className="w-4 h-0.5 bg-white/30"></div>
                       <div className="h-4 w-0.5 bg-white/30 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2"></div>
                   </div>

                   {/* Lock Animation */}
                   {liveData?.status === 'LOCKED' && (
                       <div className="absolute inset-0 bg-emerald-500/10 animate-pulse"></div>
                   )}
               </div>
            </div>

            {/* LIVE DATA PANEL */}
            <div 
              className={`absolute left-4 right-4 z-30 flex flex-col transition-all duration-500 cubic-bezier(0.34, 1.56, 0.64, 1) ${
                isExpanded 
                  ? 'top-[100px] bottom-36' 
                  : 'top-[calc(100%-320px)] bottom-[100px]' 
              }`}
            >
               {liveData ? (
                 <div className={`glass-panel w-full h-full rounded-3xl overflow-hidden flex flex-col shadow-2xl transition-all duration-500`}>

                    {/* Header */}
                    <div className={`p-5 pb-3 shrink-0 relative cursor-pointer active:bg-white/5 bg-gradient-to-b ${currentLens.gradient}`} onClick={() => { setIsExpanded(!isExpanded); }}>
                       {/* Drag Handle */}
                       <div className="absolute top-2 left-1/2 -translate-x-1/2 w-10 h-1 bg-white/20 rounded-full"></div>

                       <div className="flex justify-between items-start mt-2">
                          <div className="flex-1">
                             <div className="flex items-center gap-2 mb-1">
                                 {/* Status Pill */}
                                 <span className={`px-2 py-0.5 rounded text-[9px] font-bold uppercase tracking-widest border ${liveData.status === 'LOCKED' ? 'border-white/30 bg-white/10 text-white shadow-[0_0_10px_rgba(255,255,255,0.2)]' : 'border-zinc-700 bg-zinc-900/50 text-zinc-400'}`}>
                                   {liveData.status === 'SEARCHING' ? 'Acquiring...' : liveData.status}
                                 </span>
                             </div>
                             <h2 className="text-2xl font-serif text-white leading-tight mt-1 mb-1 drop-shadow-lg">
                                 {liveData.shortTitle || "Analyzing..."}
                             </h2>
                          </div>
                          <div className={`p-2 rounded-full border border-white/10 bg-white/5 ${isExpanded ? 'rotate-180' : ''} transition-transform`}>
