                        <div className={`grid grid-cols-2 gap-3 mt-6 pt-4 border-t border-white/10 transition-all duration-500 ${isExpanded ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4 pointer-events-none'}`}>
