          {mode === 'LIVE' ? (
              <div className="relative w-full overflow-hidden">
                  <div 
                    ref={scrollRef}
                    className="flex justify-start items-center px-[50vw] gap-6 overflow-x-auto no-scrollbar snap-x snap-mandatory py-4"
                    style={{ scrollBehavior: 'smooth' }}
                  >
