                          <button
                            key={lens.id}
                            onClick={() => { setActiveLens(lens.id); if(navigator.vibrate) navigator.vibrate(10); }}
                            className={`flex flex-col items-center gap-3 transition-all duration-300 snap-center min-w-[80px] group`}
                          >
                              <div className={`p-3 rounded-full border-2 transition-all duration-300 relative
