import { GoogleGenAI, Type } from "@google/genai";
import { AppraisalResult, LiveAnalysisUpdate, MarketAnalysis, LensMode } from "../types";

const SYSTEM_INSTRUCTION = `You are a world-renowned Appraiser and Art Historian. 
You do not just identify items; you tell their story. 
You look for the subtle details: the patina, the joinery, the font, the wear patterns.
Your output should feel authoritative, exclusive, and precise.

When analyzing:
1. Be conservative with high valuations unless provenance is clear.
2. Focus on "Why" it is valuable (rarity, maker, demand).
3. If it looks like a reproduction, state it clearly but politely.
`;

// FULL APPRAISAL (Manual Mode)
export const analyzeItem = async (imageBuffers: string[]): Promise<AppraisalResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Perform a "Master Appraisal" on this object.

  Extract specific details:
  - ERA: Narrow down to specific decade or movement (e.g. "Late Art Deco, c. 1935").
  - ORIGIN: Identify city/region/factory if possible.
  - RARITY: Score from 1 (Common) to 10 (Museum Grade). Explain why.

  Provide a JSON response.`;

  const imageParts = imageBuffers.map(buffer => ({
    inlineData: { data: buffer.split(',')[1], mimeType: 'image/jpeg' }
  }));

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        ...imageParts,
        { text: prompt }
      ]
    },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          itemName: { type: Type.STRING },
          category: { type: Type.STRING },
          classification: { type: Type.STRING, enum: ["Antique", "Vintage", "Modern", "New", "Specialty"] },
          era: { type: Type.STRING },
          origin: { type: Type.STRING },
          condition: { type: Type.STRING },
          conditionScore: { type: Type.NUMBER },
          rarityScore: { type: Type.NUMBER, description: "1-10 scale of scarcity" },
          rarityDescription: { type: Type.STRING },
          valuation: {
            type: Type.OBJECT,
            properties: {
              low: { type: Type.NUMBER },
              mid: { type: Type.NUMBER },
              high: { type: Type.NUMBER },
              currency: { type: Type.STRING }
            }
          },
          authenticationMarks: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
          },
          historicalContext: { type: Type.STRING },
          materials: { type: Type.STRING },
          careInstructions: { type: Type.STRING },
          comparableSales: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                price: { type: Type.STRING },
                date: { type: Type.STRING },
                link: { type: Type.STRING },
                source: { type: Type.STRING }
              }
            }
          },
          sellingProfile: {
            type: Type.OBJECT,
            properties: {
              listingTitle: { type: Type.STRING },
              listingDescription: { type: Type.STRING },
              keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
              recommendedVenue: { type: Type.STRING },
              pricingStrategy: { type: Type.STRING }
            }
          },
          confidence: { type: Type.NUMBER }
        },
        required: ["itemName", "valuation", "rarityScore", "rarityDescription"]
      }
    }
  });

  if (!response.text) throw new Error("Analysis failed to return data.");
  return JSON.parse(response.text) as AppraisalResult;
};

// LIVE PROGRESSIVE ANALYSIS
export const analyzeLiveFrame = async (imageBuffer: string, lensMode: LensMode, previousContext?: string): Promise<LiveAnalysisUpdate> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  let lensInstructions = "";
  if (lensMode === 'IDENTITY') {
    lensInstructions = `FOCUS: Establishing Provenance. Identify specific Maker, Period, and Style.`;
  } else if (lensMode === 'MARKET') {
    lensInstructions = `FOCUS: Auction Potential. Estimate 'Hammer Price' range. Assess liquidity.`;
  } else if (lensMode === 'FORENSICS') {
    lensInstructions = `FOCUS: The 'Loupe' View. Look for micro-scratches, patina patterns, casting seams, or hallmarks.`;
  } else if (lensMode === 'DECIPHER') {
    lensInstructions = `FOCUS: Epigraphy. Transcribe text, translate, and identify font styles/dates.`;
  }

  const prompt = `Real-time Scan. Lens: ${lensMode}.
  Instructions: ${lensInstructions}
  Context: ${previousContext || "None."}

  Return brief, high-value insights. Status: LOCKED if confidence > 85%.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview', 
    contents: {
      parts: [
        { inlineData: { data: imageBuffer.split(',')[1], mimeType: 'image/jpeg' } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          status: { type: Type.STRING, enum: ["SEARCHING", "IDENTIFYING", "LOCKED"] },
          shortTitle: { type: Type.STRING },
          classification: { type: Type.STRING },
          quickFacts: { type: Type.ARRAY, items: { type: Type.STRING } },
          valuationEstimate: { type: Type.STRING },
          detailedNote: { type: Type.STRING },
          confidence: { type: Type.NUMBER }
        }
      }
    }
  });

  if (!response.text) return { status: 'SEARCHING', shortTitle: '', classification: 'Modern', quickFacts: [], confidence: 0, lensMode };
  return { ...JSON.parse(response.text), lensMode };
};

export const askCurator = async (itemContext: AppraisalResult, question: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const systemContext = `Context: ${JSON.stringify(itemContext)}. User: "${question}". Answer as a sophisticated curator.`;
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [{ text: systemContext }] }
  });
  return response.text || "Unavailable.";
};

export const getMarketAnalysis = async (query: string): Promise<MarketAnalysis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  // ... existing market analysis implementation ...
  // Re-using existing implementation for brevity, assuming it works as intended.
  // Ideally, this would also be upgraded to use the 'Curator' persona.
  const prompt = `Real-time market analysis for: "${query}". JSON output.`;
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [{ text: prompt }] },
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          itemName: { type: Type.STRING },
          trend: { type: Type.STRING, enum: ["UP", "DOWN", "STABLE"] },
          changePercent: { type: Type.STRING },
          summary: { type: Type.STRING },
          keyInsight: { type: Type.STRING },
          demandLevel: { type: Type.STRING, enum: ["High", "Medium", "Low"] },
          lastUpdated: { type: Type.STRING }
        },
        required: ["trend", "changePercent", "summary", "keyInsight", "demandLevel"]
      }
    }
  });

  if (!response.text) throw new Error("Market analysis failed.");
  const cleanText = response.text.replace(/```json|```/g, '').trim();
  const data = JSON.parse(cleanText) as MarketAnalysis;
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  const sources = chunks.flatMap((chunk: any) => chunk.web?.uri ? [{ title: chunk.web.title || "Source", url: chunk.web.uri }] : []).slice(0, 5);
  return { ...data, sources };
};

import React, { useRef, useState, useEffect } from 'react';
import { Image as ImageIcon, Save, Search, DollarSign, Fingerprint, Languages, Zap, Aperture, Maximize2, X } from 'lucide-react';
import { analyzeItem, analyzeLiveFrame } from '../services/geminiService';
import { AppraisalResult, LiveAnalysisUpdate, LensMode } from '../types';
import { ItemResult } from './ItemResult';

interface ScannerProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

const LENSES: { id: LensMode; label: string; icon: any; color: string }[] = [
  { id: 'IDENTITY', label: 'PROVENANCE', icon: Search, color: 'text-blue-400' },
  { id: 'MARKET', label: 'APPRAISAL', icon: DollarSign, color: 'text-emerald-400' },
  { id: 'FORENSICS', label: 'LOUPE', icon: Fingerprint, color: 'text-amber-400' },
  { id: 'DECIPHER', label: 'EPIGRAPHY', icon: Languages, color: 'text-violet-400' },
];

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  const [activeLens, setActiveLens] = useState<LensMode>('IDENTITY');
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [manualResult, setManualResult] = useState<AppraisalResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [liveData, setLiveData] = useState<LiveAnalysisUpdate | null>(null);
  const [loupePosition, setLoupePosition] = useState({ x: 50, y: 50 }); // % coordinates
  const [isDraggingLoupe, setIsDraggingLoupe] = useState(false);
  const [isPulsing, setIsPulsing] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // --- Loupe Drag Logic ---
  const handleLoupeTouchMove = (e: React.TouchEvent) => {
    if (!containerRef.current) return;
    const touch = e.touches[0];
    const rect = containerRef.current.getBoundingClientRect();
    const x = ((touch.clientX - rect.left) / rect.width) * 100;
    const y = ((touch.clientY - rect.top) / rect.height) * 100;
    setLoupePosition({ 
      x: Math.max(10, Math.min(90, x)), 
      y: Math.max(10, Math.min(90, y)) 
    });
  };

  // --- Camera & AI Loop ---
  useEffect(() => {
    const startCamera = async () => {
      try {
        const s = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } }, audio: false 
        });
        setStream(s);
        if (videoRef.current) videoRef.current.srcObject = s;
      } catch (err) { console.error(err); }
    };
    startCamera();
    return () => stream?.getTracks().forEach(t => t.stop());
  }, []);

  useEffect(() => {
    if (!stream) return;
    const interval = setInterval(async () => {
      if (videoRef.current && !isAnalyzing) {
        setIsPulsing(true);
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth / 2;
        canvas.height = videoRef.current.videoHeight / 2;
        const ctx = canvas.getContext('2d');

        // CROP based on Loupe Position if in Forensics mode
        if (activeLens === 'FORENSICS') {
            const w = canvas.width;
            const h = canvas.height;
            const cx = (loupePosition.x / 100) * w;
            const cy = (loupePosition.y / 100) * h;
            const cropSize = w * 0.4; // 40% zoom area

            ctx?.drawImage(videoRef.current, 
                (cx - cropSize/2) * 2, (cy - cropSize/2) * 2, cropSize * 2, cropSize * 2, 
                0, 0, w, h);
        } else {
            ctx?.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        }

        const data = canvas.toDataURL('image/jpeg', 0.6);
        try {
          const res = await analyzeLiveFrame(data, activeLens, liveData?.shortTitle);
          if (res.status !== 'SEARCHING' || liveData?.status === 'SEARCHING') setLiveData(res);
        } catch(e) {} finally { setIsPulsing(false); }
      }
    }, 1500); // Slower, more deliberate pulse for "Heavy" feel
    return () => clearInterval(interval);
  }, [stream, activeLens, loupePosition, isAnalyzing]);

  // --- Capture Logic ---
  const capture = async () => {
    if (!videoRef.current) return;
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);
    const data = canvas.toDataURL('image/jpeg', 0.9);

    setIsAnalyzing(true);
    try {
      const result = await analyzeItem([data]);
      setManualResult(result);
      setCapturedImages([data]);
    } catch (e) { alert("Analysis disrupted."); }
    setIsAnalyzing(false);
  };

  if (manualResult) {
    return <ItemResult result={manualResult} imageData={capturedImages[0]} onBack={() => setManualResult(null)} onSave={(r) => onSave(r, capturedImages[0])} />;
  }

  const currentLens = LENSES.find(l => l.id === activeLens)!;

  return (
    <div ref={containerRef} className="relative h-full bg-black overflow-hidden select-none font-mono" onTouchMove={handleLoupeTouchMove}>

      {/* 1. Cinematic Video Feed */}
      <video ref={videoRef} autoPlay playsInline className="absolute inset-0 w-full h-full object-cover opacity-60 mix-blend-luminosity" />

      {/* 2. Global Noise/Grain Overlay (Defined in CSS, but reinforced here with vignette) */}
      <div className="absolute inset-0 pointer-events-none bg-[radial-gradient(circle_at_center,transparent_0%,rgba(0,0,0,0.8)_100%)]"></div>

      {/* 3. The "Smart Loupe" (Visible in all modes, but active/highlighted differently) */}
      <div 
        className={`absolute w-64 h-64 rounded-full border border-white/20 backdrop-blur-[2px] shadow-2xl transition-all duration-100 ease-out flex items-center justify-center pointer-events-none
          ${activeLens === 'FORENSICS' ? 'border-amber-400/50 scale-110 shadow-amber-900/40' : 'scale-100'}
        `}
        style={{ left: `${loupePosition.x}%`, top: `${loupePosition.y}%`, transform: 'translate(-50%, -50%)' }}
      >
        <div className="absolute inset-0 border border-white/10 rounded-full animate-[spin_10s_linear_infinite]"></div>
        <div className="w-2 h-2 bg-white/50 rounded-full"></div>
        {/* Crosshairs */}
        <div className="absolute top-0 bottom-0 w-px bg-white/10"></div>
        <div className="absolute left-0 right-0 h-px bg-white/10"></div>

        {/* Loupe Data Floating Label */}
        <div className="absolute -top-8 left-1/2 -translate-x-1/2 text-[10px] text-white/70 tracking-widest bg-black/50 px-2 py-0.5 rounded">
           {Math.round(loupePosition.x)}:{Math.round(loupePosition.y)}
        </div>
      </div>

      {/* 4. Holographic HUD Top */}
      <div className="absolute top-0 left-0 right-0 p-6 pt-12 flex justify-between items-start z-20 pointer-events-none">
         <div>
            <h1 className="font-display text-2xl text-white tracking-widest drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]">CURATOR</h1>
            <div className="flex items-center gap-2 mt-1">
                <div className={`w-2 h-2 rounded-full ${isPulsing ? 'bg-red-500 shadow-[0_0_8px_red]' : 'bg-zinc-800'}`}></div>
                <span className="text-[10px] text-zinc-500 uppercase tracking-[0.2em]">{isAnalyzing ? 'PROCESSING' : 'SYSTEM READY'}</span>
            </div>
         </div>
         {liveData?.status === 'LOCKED' && (
             <div className="text-right animate-in fade-in slide-in-from-right-4 duration-500">
                <div className="text-emerald-400 font-display text-4xl shadow-emerald-900/50 drop-shadow-lg">
                    {activeLens === 'MARKET' ? liveData.valuationEstimate : 'MATCH'}
                </div>
                <div className="text-[10px] text-emerald-600 uppercase tracking-widest font-bold">
                    Confidence {(liveData.confidence * 100).toFixed(0)}%
                </div>
             </div>
         )}
      </div>

      {/* 5. Live Data Feed (Bottom Left) */}
      <div className="absolute bottom-32 left-6 z-20 max-w-[70%] pointer-events-none">
          {liveData && liveData.status !== 'SEARCHING' ? (
              <div className="flex flex-col gap-2 animate-in fade-in slide-in-from-bottom-8">
                  <h2 className="font-display text-3xl text-white leading-none shadow-black drop-shadow-md">
                      {liveData.shortTitle}
                  </h2>
