import React, { useRef, useState, useEffect, useCallback } from 'react';
import { Search, DollarSign, Fingerprint, Languages, X, Volume2, VolumeX, Aperture, ZoomIn, Plus, History } from 'lucide-react';
import { analyzeItem, analyzeLiveFrame } from '../services/geminiService';
import { AppraisalResult, LiveAnalysisUpdate, LensMode } from '../types';
import { ItemResult } from './ItemResult';
import { soundManager } from '../services/soundService';

interface ScannerProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

interface SessionHistoryItem {
  id: string;
  thumbnail: string;
  data: LiveAnalysisUpdate;
}

const LENSES: { id: LensMode; label: string; icon: any; color: string; desc: string }[] = [
  { id: 'IDENTITY', label: 'PROVENANCE', icon: Search, color: 'text-blue-400', desc: 'Identify Maker & Era' },
  { id: 'MARKET', label: 'VALUATION', icon: DollarSign, color: 'text-emerald-400', desc: 'Real-time Pricing' },
  { id: 'FORENSICS', label: 'LOUPE', icon: Fingerprint, color: 'text-amber-400', desc: 'Micro-Detail Analysis' },
  { id: 'DECIPHER', label: 'EPIGRAPHY', icon: Languages, color: 'text-violet-400', desc: 'Read Marks & Text' },
];

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  // State
  const [activeLens, setActiveLens] = useState<LensMode>('IDENTITY');
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [manualResult, setManualResult] = useState<AppraisalResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [liveData, setLiveData] = useState<LiveAnalysisUpdate | null>(null);
  const [history, setHistory] = useState<SessionHistoryItem[]>([]);

  // UI State
  const [loupePosition, setLoupePosition] = useState({ x: 50, y: 50 }); // Percentage
  const [zoom, setZoom] = useState(1);
  const [soundEnabled, setSoundEnabled] = useState(true);
  const [shutterOpen, setShutterOpen] = useState(true); // For animation
  const [lastScanTime, setLastScanTime] = useState(0);

  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // --- Sound Toggle ---
  const toggleSound = () => {
    const muted = soundManager.toggleMute();
    setSoundEnabled(!muted);
    soundManager.playClick();
  };

  // --- Loupe Interaction ---
  const handleTouchMove = (e: React.TouchEvent | React.MouseEvent) => {
    // Only drag if in Forensics mode or explicitly using the loupe
    if (!containerRef.current) return;

    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

    const rect = containerRef.current.getBoundingClientRect();
    const x = ((clientX - rect.left) / rect.width) * 100;
    const y = ((clientY - rect.top) / rect.height) * 100;

    // Clamp to screen
    const clampedX = Math.max(10, Math.min(90, x));
    const clampedY = Math.max(10, Math.min(90, y));

    setLoupePosition({ x: clampedX, y: clampedY });
  };

  // --- Camera Setup ---
  useEffect(() => {
    const startCamera = async () => {
      try {
        const s = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } }, audio: false 
        });
        setStream(s);
        if (videoRef.current) videoRef.current.srcObject = s;
      } catch (err) { console.error("Camera Error:", err); }
    };
    startCamera();
    return () => stream?.getTracks().forEach(t => t.stop());
  }, []);

  // --- The "Pulse" (Live Analysis Loop) ---
  useEffect(() => {
    if (!stream) return;

    const interval = setInterval(async () => {
      const now = Date.now();
      if (videoRef.current && !isAnalyzing && (now - lastScanTime > 2000)) {

        // Prepare Capture
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth / 2; // Downscale for speed
        canvas.height = videoRef.current.videoHeight / 2;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // SMART CROP LOGIC
        // If Forensics mode, crop to the Loupe area
        if (activeLens === 'FORENSICS') {
            const w = canvas.width;
            const h = canvas.height;
            // Convert % position to pixels
            const cx = (loupePosition.x / 100) * w;
            const cy = (loupePosition.y / 100) * h;
            const cropSize = w * 0.35; // 35% of view

            // Draw only the cropped area into the full canvas (digital zoom effect)
            ctx.drawImage(videoRef.current, 
                (cx - cropSize/2) * 2, (cy - cropSize/2) * 2, cropSize * 2, cropSize * 2, 
                0, 0, w, h);
        } else {
            // Standard full frame
            ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        }

        const data = canvas.toDataURL('image/jpeg', 0.6);

        try {
          soundManager.playScanHum(); // Subtle audio cue
          const res = await analyzeLiveFrame(data, activeLens, liveData?.shortTitle);

          // Only update if we found something new or if we aren't locked yet
          if (res.status !== 'SEARCHING' || liveData?.status === 'SEARCHING') {
              setLiveData(res);
              if (res.status === 'LOCKED') {
                  // HISTORY LOGIC: Check if this is a new item to lock onto
                  if (!liveData || liveData.shortTitle !== res.shortTitle) {
                      setHistory(prev => {
                          // Prevent duplicate if title matches top of stack
                          if (prev.length > 0 && prev[0].data.shortTitle === res.shortTitle) return prev;
                          return [{ id: crypto.randomUUID(), thumbnail: data, data: res }, ...prev].slice(0, 4); // Keep last 4
                      });
                  }

                  // Audio/Haptic (only play if not already locked on this item)
                  if (liveData?.shortTitle !== res.shortTitle) {
                      const isHighValue = res.valuationEstimate && (res.valuationEstimate.includes('k') || res.valuationEstimate.length > 5);
                      soundManager.playLock(isHighValue ? 'high' : 'standard');
                      if (navigator.vibrate) navigator.vibrate(50);
                  }
              }
          }
          setLastScanTime(Date.now());
        } catch(e) { 
            // Silent fail for live loop
        }
      }
    }, 1000); // 1s interval for stability

    return () => clearInterval(interval);
  }, [stream, activeLens, loupePosition, isAnalyzing, liveData, lastScanTime]);

  // --- Manual Capture ---
  const capture = async () => {
    if (!videoRef.current) return;

    // 1. Audio/Visual Feedback
    soundManager.playShutter();
    if (navigator.vibrate) navigator.vibrate([20, 50, 20]);
    setShutterOpen(false); // Close iris

    setTimeout(async () => {
        // 2. Capture High-Res Frame
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current!.videoWidth;
        canvas.height = videoRef.current!.videoHeight;
        canvas.getContext('2d')?.drawImage(videoRef.current!, 0, 0);
        const data = canvas.toDataURL('image/jpeg', 0.95);

        setCapturedImages([data]);
        setShutterOpen(true); // Open iris
        setIsAnalyzing(true);

        try {
            const result = await analyzeItem([data]);
            setManualResult(result);
        } catch (e) {
            alert("Analysis Interrupted. Please try again.");
            setIsAnalyzing(false);
        }
    }, 250); // Wait for shutter close animation
  };

  const handleSaveHistory = (item: SessionHistoryItem) => {
    // Quick convert live data to full result structure
    const result: AppraisalResult = {
        itemName: item.data.shortTitle,
        category: 'Live Capture',
        classification: item.data.classification,
        era: item.data.quickFacts[0] || 'Unknown',
        origin: 'Unknown',
        condition: 'Good',
        conditionScore: 5,
        rarityScore: 5,
        rarityDescription: 'Captured via Live Stream',
        valuation: { low: 0, mid: 0, high: 0, currency: 'USD' },
        authenticationMarks: [],
        historicalContext: item.data.detailedNote || '',
        materials: '',
        careInstructions: '',
        comparableSales: [],
        sellingProfile: { listingTitle: item.data.shortTitle, listingDescription: item.data.detailedNote || '', keywords: [], recommendedVenue: '', pricingStrategy: '' },
        confidence: item.data.confidence
    };
    onSave(result, item.thumbnail);
  };

  // --- Render Result View ---
  if (manualResult) {
    return (
        <ItemResult 
            result={manualResult} 
            imageData={capturedImages[0]} 
            onBack={() => { setManualResult(null); setIsAnalyzing(false); }} 
            onSave={(r) => onSave(r, capturedImages[0])} 
        />
    );
  }

  const currentLens = LENSES.find(l => l.id === activeLens)!;

  return (
    <div 
        ref={containerRef} 
        className="relative h-full bg-black overflow-hidden select-none font-mono touch-none"
        onTouchMove={handleTouchMove}
        onMouseMove={handleTouchMove} // For desktop testing
    >

      {/* 1. Viewfinder Layer */}
      <video 
        ref={videoRef} 
        autoPlay 
        playsInline 
        className="absolute inset-0 w-full h-full object-cover opacity-80"
      />

      {/* 2. Cinematic Overlays */}
      {/* Noise/Grain */}
      <div className="absolute inset-0 pointer-events-none opacity-40 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] mix-blend-overlay"></div>

      {/* Mechanical Iris (Shutter Animation) */}
      <div 
        className={`absolute inset-0 bg-black z-50 pointer-events-none transition-all duration-300 ease-out origin-center`}
        style={{ clipPath: shutterOpen ? 'circle(150% at 50% 50%)' : 'circle(0% at 50% 50%)' }}
      ></div>

      {/* 3. The "Smart Loupe" */}
      {/* Visible in all modes but distinct in FORENSICS */}
      <div 
        className={`absolute w-72 h-72 rounded-full border transition-all duration-200 ease-linear flex items-center justify-center pointer-events-none z-30
          ${activeLens === 'FORENSICS' 
            ? 'border-amber-400/80 shadow-[0_0_100px_rgba(251,191,36,0.2)] backdrop-brightness-125 scale-110' 
            : 'border-white/10 opacity-30 scale-90'
          }
        `}
        style={{ left: `${loupePosition.x}%`, top: `${loupePosition.y}%`, transform: 'translate(-50%, -50%)' }}
      >
        {/* Reticle UI */}
        <div className={`absolute w-full h-full rounded-full border border-dashed opacity-50 ${activeLens === 'FORENSICS' ? 'border-amber-400 animate-[spin_20s_linear_infinite]' : 'border-white'}`}></div>
        <div className="w-1.5 h-1.5 bg-white rounded-full shadow-[0_0_10px_white]"></div>

        {/* Real-time coordinates */}
        <div className="absolute bottom-4 text-[9px] font-bold tracking-widest bg-black/60 px-2 py-1 rounded text-white/80">
            SEC: {Math.round(loupePosition.x)}.{Math.round(loupePosition.y)}
        </div>
      </div>

      {/* 4. Top HUD */}
      <div className="absolute top-0 left-0 right-0 p-6 pt-12 flex justify-between items-start z-40 bg-gradient-to-b from-black/80 to-transparent pointer-events-none">
         <div>
            <h1 className="font-display text-2xl text-white tracking-[0.15em] drop-shadow-md">CURATOR</h1>
            <div className="flex items-center gap-2 mt-1 pl-1">
                <div className={`w-1.5 h-1.5 rounded-full ${isAnalyzing ? 'bg-red-500 animate-pulse' : 'bg-emerald-500'}`}></div>
                <span className="text-[9px] text-zinc-400 uppercase tracking-widest font-bold">
                    {isAnalyzing ? 'PROCESSING' : 'LIVE FEED'}
                </span>
            </div>
         </div>

         <div className="flex flex-col items-end gap-2 pointer-events-auto">
             <button onClick={toggleSound} className="w-8 h-8 flex items-center justify-center rounded-full bg-white/10 hover:bg-white/20 text-white backdrop-blur-md">
                 {soundEnabled ? <Volume2 size={14} /> : <VolumeX size={14} />}
             </button>
             {liveData?.status === 'LOCKED' && (
                 <div className="mt-2 bg-emerald-950/80 border border-emerald-500/30 p-3 rounded-lg backdrop-blur-md text-right animate-in fade-in slide-in-from-right-8">
                     <span className="text-[9px] text-emerald-400 uppercase tracking-widest block mb-1">Confidence Match</span>
                     <span className="font-display text-2xl text-white shadow-emerald-500/50">{(liveData.confidence * 100).toFixed(0)}%</span>
                 </div>
             )}
         </div>
      </div>

      {/* 5. Live Data Stream (Left) */}
      <div className="absolute bottom-32 left-0 z-30 w-3/4 p-6 pointer-events-none">
          {liveData && liveData.status !== 'SEARCHING' ? (
              <div className="flex flex-col gap-2 animate-in fade-in slide-in-from-bottom-4 duration-500">
                  <div className="flex items-center gap-2">
                     <div className={`px-2 py-0.5 text-[9px] font-bold uppercase tracking-widest rounded bg-white/10 border border-white/10 backdrop-blur-md text-zinc-300`}>
                        {liveData.classification}
                     </div>
                     <div className="h-px flex-1 bg-gradient-to-r from-white/30 to-transparent"></div>
                  </div>
                  <h2 className="font-display text-3xl text-white leading-none drop-shadow-lg break-words">
                      {liveData.shortTitle}
                  </h2>
                  <p className="font-mono text-xs text-zinc-200 leading-relaxed bg-black/60 p-3 backdrop-blur-md border-l-2 border-white/50 max-w-sm rounded-r-lg">
                      {liveData.detailedNote}
                  </p>
                  {/* Valuation for Market Lens */}
                  {activeLens === 'MARKET' && liveData.valuationEstimate && (
                      <div className="mt-2 flex items-center gap-2">
                          <DollarSign size={16} className="text-emerald-400" />
                          <span className="font-display text-2xl text-emerald-300">{liveData.valuationEstimate}</span>
                      </div>
                  )}
              </div>
          ) : (
             <div className="flex items-center gap-3 opacity-50">
                 <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                 <span className="font-mono text-[10px] text-white tracking-widest uppercase">Scanning Sector...</span>
             </div>
          )}
      </div>

      {/* 6. Session History Stack (Right) */}
      <div className="absolute bottom-32 right-6 z-30 flex flex-col gap-3 pointer-events-auto items-end">
          {history.length > 0 && <div className="text-[8px] text-zinc-400 font-bold uppercase tracking-widest mb-1 bg-black/50 px-2 rounded backdrop-blur-sm">Session Log</div>}
          {history.map(item => (
              <button 
                  key={item.id} 
                  onClick={() => handleSaveHistory(item)}
                  className="w-14 h-14 rounded-lg border border-white/20 bg-zinc-900/80 overflow-hidden relative group transition-all hover:scale-110 hover:border-blue-500 shadow-lg"
              >
                  <img src={item.thumbnail} className="w-full h-full object-cover opacity-80 group-hover:opacity-100" />
                  <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 bg-black/40 backdrop-blur-[1px] transition-opacity">
                      <Plus size={16} className="text-white drop-shadow-md" />
                  </div>
                  {/* Status Indicator */}
                  <div className={`absolute bottom-0 left-0 right-0 h-0.5 ${item.data.classification === 'Antique' ? 'bg-amber-500' : 'bg-blue-500'}`}></div>
              </button>
          ))}
      </div>

      {/* 7. Lens Controller (Bottom) */}
      <div className="absolute bottom-0 left-0 right-0 h-28 bg-gradient-to-t from-black via-black/90 to-transparent z-40 flex items-center justify-between px-8 border-t border-white/5">

          {/* Lens Selector */}
          <div className="flex gap-4 overflow-x-auto no-scrollbar items-center mask-image-linear-gradient w-2/3">
              {LENSES.map((lens) => (
                  <button 
                    key={lens.id}
                    onClick={() => { setActiveLens(lens.id); soundManager.playClick(); }}
                    className={`flex flex-col items-center gap-2 transition-all duration-300 group min-w-[60px] ${activeLens === lens.id ? 'opacity-100' : 'opacity-40 hover:opacity-70'}`}
                  >
                      <div className={`p-2.5 rounded-xl border transition-all ${activeLens === lens.id ? `border-${lens.color.split('-')[1]}-400 bg-white/10 shadow-[0_0_15px_rgba(255,255,255,0.1)]` : 'border-zinc-800 bg-zinc-900'}`}>
                          <lens.icon size={18} className={activeLens === lens.id ? lens.color : 'text-zinc-400'} />
                      </div>
                      <span className="text-[8px] font-bold tracking-widest text-zinc-400 uppercase">{lens.label}</span>
                  </button>
              ))}
          </div>

          {/* Master Shutter */}
          <button 
            onClick={capture}
            disabled={isAnalyzing}
            className="relative w-16 h-16 rounded-full flex items-center justify-center active:scale-95 transition-all duration-100"
          >
              {/* Outer Ring */}
              <div className="absolute inset-0 rounded-full border-2 border-white/20"></div>
              {/* Inner Button */}
              <div className="w-14 h-14 bg-white rounded-full shadow-[0_0_20px_rgba(255,255,255,0.5)] flex items-center justify-center group">
                 {isAnalyzing ? (
                     <div className="w-6 h-6 border-2 border-zinc-300 border-t-zinc-900 rounded-full animate-spin"></div>
                 ) : (
                     <div className="w-10 h-10 rounded-full bg-zinc-100 border border-zinc-300 group-hover:scale-95 transition-transform"></div>
                 )}
              </div>
          </button>
      </div>

    </div>
  );
};

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { Search, DollarSign, Fingerprint, Languages, X, Volume2, VolumeX, Aperture, ZoomIn, Plus, History, Image as ImageIcon } from 'lucide-react';
import { analyzeItem, analyzeLiveFrame } from '../services/geminiService';
import { AppraisalResult, LiveAnalysisUpdate, LensMode } from '../types';
import { ItemResult } from './ItemResult';
import { soundManager } from '../services/soundService';

interface ScannerProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

interface SessionHistoryItem {
  id: string;
  thumbnail: string;
  data: LiveAnalysisUpdate;
}

const LENSES: { id: LensMode; label: string; icon: any; color: string; desc: string }[] = [
  { id: 'IDENTITY', label: 'PROVENANCE', icon: Search, color: 'text-blue-400', desc: 'Identify Maker & Era' },
  { id: 'MARKET', label: 'VALUATION', icon: DollarSign, color: 'text-emerald-400', desc: 'Real-time Pricing' },
  { id: 'FORENSICS', label: 'LOUPE', icon: Fingerprint, color: 'text-amber-400', desc: 'Micro-Detail Analysis' },
  { id: 'DECIPHER', label: 'EPIGRAPHY', icon: Languages, color: 'text-violet-400', desc: 'Read Marks & Text' },
];

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  // State
  const [activeLens, setActiveLens] = useState<LensMode>('IDENTITY');
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [manualResult, setManualResult] = useState<AppraisalResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [liveData, setLiveData] = useState<LiveAnalysisUpdate | null>(null);
  const [history, setHistory] = useState<SessionHistoryItem[]>([]);

  // UI State
  const [loupePosition, setLoupePosition] = useState({ x: 50, y: 50 }); // Percentage
  const [zoom, setZoom] = useState(1);
  const [soundEnabled, setSoundEnabled] = useState(true);
  const [shutterOpen, setShutterOpen] = useState(true); // For animation
  const [lastScanTime, setLastScanTime] = useState(0);

  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- Sound Toggle ---
  const toggleSound = () => {
    const muted = soundManager.toggleMute();
    setSoundEnabled(!muted);
    soundManager.playClick();
  };

  // --- Loupe Interaction ---
  const handleTouchMove = (e: React.TouchEvent | React.MouseEvent) => {
    // Only drag if in Forensics mode or explicitly using the loupe
    if (!containerRef.current) return;

    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

    const rect = containerRef.current.getBoundingClientRect();
    const x = ((clientX - rect.left) / rect.width) * 100;
    const y = ((clientY - rect.top) / rect.height) * 100;

    // Clamp to screen
    const clampedX = Math.max(10, Math.min(90, x));
    const clampedY = Math.max(10, Math.min(90, y));

    setLoupePosition({ x: clampedX, y: clampedY });
  };

  // --- Camera Setup ---
  useEffect(() => {
    const startCamera = async () => {
      try {
        const s = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } }, audio: false 
        });
        setStream(s);
        if (videoRef.current) videoRef.current.srcObject = s;
      } catch (err) { console.error("Camera Error:", err); }
    };
    startCamera();
    return () => stream?.getTracks().forEach(t => t.stop());
  }, []);

  // --- The "Pulse" (Live Analysis Loop) ---
  useEffect(() => {
    if (!stream) return;

    const interval = setInterval(async () => {
      const now = Date.now();
      if (videoRef.current && !isAnalyzing && (now - lastScanTime > 2000)) {

        // Prepare Capture
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth / 2; // Downscale for speed
        canvas.height = videoRef.current.videoHeight / 2;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // SMART CROP LOGIC
        // If Forensics mode, crop to the Loupe area
        if (activeLens === 'FORENSICS') {
            const w = canvas.width;
            const h = canvas.height;
            // Convert % position to pixels
            const cx = (loupePosition.x / 100) * w;
            const cy = (loupePosition.y / 100) * h;
            const cropSize = w * 0.35; // 35% of view

            // Draw only the cropped area into the full canvas (digital zoom effect)
            ctx.drawImage(videoRef.current, 
                (cx - cropSize/2) * 2, (cy - cropSize/2) * 2, cropSize * 2, cropSize * 2, 
                0, 0, w, h);
        } else {
            // Standard full frame
            ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        }

        const data = canvas.toDataURL('image/jpeg', 0.6);

        try {
          soundManager.playScanHum(); // Subtle audio cue
          const res = await analyzeLiveFrame(data, activeLens, liveData?.shortTitle);

          // Only update if we found something new or if we aren't locked yet
          if (res.status !== 'SEARCHING' || liveData?.status === 'SEARCHING') {
              setLiveData(res);
              if (res.status === 'LOCKED') {
                  // HISTORY LOGIC: Check if this is a new item to lock onto
                  if (!liveData || liveData.shortTitle !== res.shortTitle) {
                      setHistory(prev => {
                          // Prevent duplicate if title matches top of stack
                          if (prev.length > 0 && prev[0].data.shortTitle === res.shortTitle) return prev;
                          return [{ id: crypto.randomUUID(), thumbnail: data, data: res }, ...prev].slice(0, 4); // Keep last 4
                      });
                  }

                  // Audio/Haptic (only play if not already locked on this item)
                  if (liveData?.shortTitle !== res.shortTitle) {
                      const isHighValue = res.valuationEstimate && (res.valuationEstimate.includes('k') || res.valuationEstimate.length > 5);
                      soundManager.playLock(isHighValue ? 'high' : 'standard');
                      if (navigator.vibrate) navigator.vibrate(50);
                  }
              }
          }
          setLastScanTime(Date.now());
        } catch(e) { 
            // Silent fail for live loop
        }
      }
    }, 1000); // 1s interval for stability

    return () => clearInterval(interval);
  }, [stream, activeLens, loupePosition, isAnalyzing, liveData, lastScanTime]);

  // --- Manual Capture ---
  const capture = async () => {
    if (!videoRef.current) return;

    // 1. Audio/Visual Feedback
    soundManager.playShutter();
    if (navigator.vibrate) navigator.vibrate([20, 50, 20]);
    setShutterOpen(false); // Close iris

    setTimeout(async () => {
        // 2. Capture High-Res Frame
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current!.videoWidth;
        canvas.height = videoRef.current!.videoHeight;
        canvas.getContext('2d')?.drawImage(videoRef.current!, 0, 0);
        const data = canvas.toDataURL('image/jpeg', 0.95);

        setCapturedImages([data]);
        setShutterOpen(true); // Open iris
        setIsAnalyzing(true);

        try {
            const result = await analyzeItem([data]);
            setManualResult(result);
        } catch (e) {
            alert("Analysis Interrupted. Please try again.");
            setIsAnalyzing(false);
        }
    }, 250); // Wait for shutter close animation
  };

  // --- Gallery Selection ---
  const handleGallerySelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
