                  if (!liveData || liveData.shortTitle !== res.shortTitle) {
                      setHistory(prev => {
                          // Prevent duplicate if title matches top of stack
                          if (prev.length > 0 && prev[0].data.shortTitle === res.shortTitle) return prev;
                          return [{ id: crypto.randomUUID(), thumbnail: data, data: res }, ...prev].slice(0, 4); // Keep last 4
                      });
                  }

