        className={`absolute w-72 h-72 rounded-full border transition-all duration-200 ease-linear flex items-center justify-center pointer-events-none z-30
          ${activeLens === 'FORENSICS' 
            ? 'border-amber-400/80 shadow-[0_0_100px_rgba(251,191,36,0.2)] backdrop-brightness-125 scale-110' 
            : 'border-white/10 opacity-30 scale-90'
          }
        `}
        style={{ left: `${loupePosition.x}%`, top: `${loupePosition.y}%`, transform: 'translate(-50%, -50%)' }}
      >
        {/* Reticle UI */}
