      </div>

      {/* 7. Lens Controller (Bottom) */}
      <div className="absolute bottom-0 left-0 right-0 h-28 bg-gradient-to-t from-black via-black/90 to-transparent z-40 flex items-center justify-between px-6 border-t border-white/5">

