      </div>

      {/* 3. The "Dossier" Content (Scrollable) */}
      <div className={`flex-1 bg-black overflow-y-auto no-scrollbar transition-all duration-500 border-t border-white/10 ${viewMode === 'DETAILS' ? 'opacity-100' : 'opacity-0 pointer-events-none hidden'}`}>
          <div className="p-6 space-y-8 pb-24">

              {/* Valuation Ticket - Brutalist Style */}
              <div className="bg-zinc-900/30 border border-zinc-800 p-0 relative overflow-hidden group hover:border-emerald-500/30 transition-colors">
                  <div className="absolute top-0 left-0 w-1 h-full bg-emerald-500"></div>
                  <div className="absolute top-0 right-0 p-4 opacity-5">
                      <DollarSign size={100} />
                  </div>
                  <div className="p-6">
                      <div className="flex justify-between items-start mb-4">
                        <p className="font-mono text-[9px] text-emerald-500 uppercase tracking-widest">Market Valuation</p>
                        <div className="px-2 py-0.5 bg-emerald-500/10 text-emerald-400 text-[9px] font-bold uppercase border border-emerald-500/20">
                            CONFIDENCE: {(result.confidence * 100).toFixed(0)}%
                        </div>
                      </div>
                      <div className="flex items-baseline gap-2">
                          <span className="font-display text-4xl text-white">${result.valuation.mid.toLocaleString()}</span>
                          <span className="font-mono text-xs text-zinc-500 uppercase">Estimated</span>
                      </div>
                      <div className="w-full h-1 bg-zinc-800 mt-4 relative">
                          <div className="absolute top-0 left-0 h-full bg-emerald-500/50" style={{ width: '60%' }}></div>
                          <div className="absolute top-[-3px] left-[60%] w-2 h-2 bg-emerald-400 rotate-45"></div>
                      </div>
                      <div className="flex justify-between mt-2 text-[9px] font-mono text-zinc-500">
                          <span>LOW: ${result.valuation.low.toLocaleString()}</span>
                          <span>HIGH: ${result.valuation.high.toLocaleString()}</span>
                      </div>
                  </div>
              </div>

              {/* Rarity & Condition Grid */}
              <div className="grid grid-cols-2 gap-4">
                  <div className="p-4 border border-zinc-800 bg-zinc-950/50 hover:bg-zinc-900 transition-colors">
                      <div className="flex items-center gap-2 mb-2 text-amber-500">
                          <Sparkles size={14} />
                          <span className="text-[9px] font-bold uppercase tracking-widest">Rarity</span>
                      </div>
                      <div className="text-2xl font-display text-white mb-1">{result.rarityScore}/10</div>
                      <p className="text-[10px] text-zinc-500 leading-tight">{result.rarityDescription}</p>
                  </div>
                  <div className="p-4 border border-zinc-800 bg-zinc-950/50 hover:bg-zinc-900 transition-colors">
                      <div className="flex items-center gap-2 mb-2 text-blue-400">
                          <Scan size={14} />
                          <span className="text-[9px] font-bold uppercase tracking-widest">Condition</span>
                      </div>
                      <div className="text-2xl font-display text-white mb-1">{result.conditionScore}/10</div>
                      <p className="text-[10px] text-zinc-500 leading-tight line-clamp-2">{result.condition}</p>
                  </div>
              </div>

              {/* Context Text */}
              <div className="space-y-4 border-l border-zinc-800 pl-4">
                  <h3 className="font-mono text-xs text-zinc-400 uppercase tracking-widest">Curator's Notes</h3>
                  <p className="font-serif text-lg leading-relaxed text-zinc-200">
                      {result.historicalContext}
                  </p>
              </div>

              {/* Selling Profile - Tech Style */}
              <div className="bg-black border border-dashed border-zinc-700 p-6 relative">
                  <div className="absolute -top-1 -left-1 w-2 h-2 bg-zinc-500"></div>
                  <div className="absolute -top-1 -right-1 w-2 h-2 bg-zinc-500"></div>
                  <div className="absolute -bottom-1 -left-1 w-2 h-2 bg-zinc-500"></div>
                  <div className="absolute -bottom-1 -right-1 w-2 h-2 bg-zinc-500"></div>

                  <h3 className="font-mono text-[9px] text-zinc-500 uppercase tracking-widest mb-4 flex items-center gap-2">
                      <Box size={12} /> Auction Strategy
                  </h3>
                  <p className="font-sans text-white text-sm italic mb-4">"{result.sellingProfile.listingTitle}"</p>

                  <div className="flex flex-wrap gap-2">
                      {result.sellingProfile.keywords.slice(0,4).map((k,i) => (
                          <span key={i} className="px-2 py-1 bg-zinc-900 text-zinc-400 text-[9px] font-mono border border-zinc-800 uppercase">{k}</span>
                      ))}
                  </div>
              </div>
          </div>

          {/* Action Bar */}
          <div className="p-6 pb-12 bg-black border-t border-zinc-900">
             <Button onClick={() => onSave(result)} className="w-full h-14 bg-white text-black font-bold uppercase tracking-[0.2em] text-xs hover:bg-zinc-200 rounded-none border-0">
                  Secure Asset to Vault
             </Button>
          </div>
      </div>

      {/* Chat Overlay */}
      {showChat && (
          <div className="absolute inset-0 z-[60] bg-black/95 backdrop-blur-xl flex flex-col animate-in slide-in-from-bottom-full duration-500">
               <div className="p-4 border-b border-white/10 flex justify-between items-center bg-zinc-900/50">
                   <div className="flex items-center gap-2">
                       <Zap size={16} className="text-blue-500" />
                       <h2 className="font-display text-lg tracking-wider">CURATOR_AI</h2>
                   </div>
                   <button onClick={() => setShowChat(false)} className="hover:text-red-500"><X /></button>
               </div>
               <div className="flex-1 overflow-y-auto p-4 space-y-6">
                   {chatHistory.map((msg,i) => (
                       <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                           <div className={`p-4 max-w-[85%] text-sm leading-relaxed border ${msg.role === 'user' ? 'bg-blue-950/20 border-blue-900 text-blue-100 rounded-tl-xl rounded-bl-xl rounded-br-xl' : 'bg-zinc-900 border-zinc-800 text-zinc-300 rounded-tr-xl rounded-br-xl rounded-bl-xl'}`}>
                               {msg.text}
                           </div>
                       </div>
                   ))}
                   {isChatLoading && (
                       <div className="flex items-center gap-2 text-xs text-blue-500 font-mono animate-pulse px-4">
                           <span className="w-1 h-1 bg-blue-500"></span> PROCESSING QUERY...
                       </div>
                   )}
               </div>
               <div className="p-4 border-t border-white/10 flex gap-2 bg-black">
                   <input 
                      className="flex-1 bg-zinc-900 border border-zinc-700 p-4 text-sm focus:border-blue-500 outline-none font-mono text-white placeholder:text-zinc-600"
                      placeholder="Identify provenance..."
                      value={chatInput}
                      onChange={(e) => setChatInput(e.target.value)} 
                   />
                   <button onClick={handleChat} className="px-6 bg-white text-black font-bold hover:bg-blue-400 hover:text-white transition-colors"><Send size={18} /></button>
               </div>
          </div>
      )}
    </div>
  );
};

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { Search, DollarSign, Fingerprint, Languages, X, Volume2, VolumeX, Aperture, ZoomIn, Plus, History, Image as ImageIcon, ScanLine } from 'lucide-react';
import { analyzeItem, analyzeLiveFrame } from '../services/geminiService';
import { AppraisalResult, LiveAnalysisUpdate, LensMode } from '../types';
import { ItemResult } from './ItemResult';
import { soundManager } from '../services/soundService';

interface ScannerProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

interface SessionHistoryItem {
  id: string;
  thumbnail: string;
  data: LiveAnalysisUpdate;
}

const LENSES: { id: LensMode; label: string; icon: any; color: string; desc: string }[] = [
  { id: 'IDENTITY', label: 'ID', icon: Search, color: 'text-blue-400', desc: 'Provenance' },
  { id: 'MARKET', label: 'VALUE', icon: DollarSign, color: 'text-emerald-400', desc: 'Appraisal' },
  { id: 'FORENSICS', label: 'LOUPE', icon: Fingerprint, color: 'text-amber-400', desc: 'Details' },
  { id: 'DECIPHER', label: 'TEXT', icon: Languages, color: 'text-violet-400', desc: 'Epigraphy' },
];

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  // State
  const [activeLens, setActiveLens] = useState<LensMode>('IDENTITY');
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [manualResult, setManualResult] = useState<AppraisalResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [liveData, setLiveData] = useState<LiveAnalysisUpdate | null>(null);
  const [history, setHistory] = useState<SessionHistoryItem[]>([]);

  // UI State
  const [loupePosition, setLoupePosition] = useState({ x: 50, y: 50 }); // Percentage
  const [soundEnabled, setSoundEnabled] = useState(true);
  const [shutterOpen, setShutterOpen] = useState(true); // For animation
  const [lastScanTime, setLastScanTime] = useState(0);

  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- Sound Toggle ---
  const toggleSound = () => {
    const muted = soundManager.toggleMute();
    setSoundEnabled(!muted);
    soundManager.playClick();
  };

  // --- Loupe Interaction ---
  const handleTouchMove = (e: React.TouchEvent | React.MouseEvent) => {
    // Only drag if in Forensics mode or explicitly using the loupe
    if (!containerRef.current) return;

    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

    const rect = containerRef.current.getBoundingClientRect();
    const x = ((clientX - rect.left) / rect.width) * 100;
    const y = ((clientY - rect.top) / rect.height) * 100;

    // Clamp to screen
    const clampedX = Math.max(10, Math.min(90, x));
    const clampedY = Math.max(10, Math.min(90, y));

    setLoupePosition({ x: clampedX, y: clampedY });
  };

  // --- Camera Setup ---
  useEffect(() => {
    const startCamera = async () => {
      try {
        const s = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } }, audio: false 
        });
        setStream(s);
        if (videoRef.current) videoRef.current.srcObject = s;
      } catch (err) { console.error("Camera Error:", err); }
    };
    startCamera();
    return () => stream?.getTracks().forEach(t => t.stop());
  }, []);

  // --- The "Pulse" (Live Analysis Loop) ---
  useEffect(() => {
    if (!stream) return;

    const interval = setInterval(async () => {
      const now = Date.now();
      if (videoRef.current && !isAnalyzing && (now - lastScanTime > 2000)) {

        // Prepare Capture
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth / 2; // Downscale for speed
        canvas.height = videoRef.current.videoHeight / 2;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // SMART CROP LOGIC
        if (activeLens === 'FORENSICS') {
            const w = canvas.width;
            const h = canvas.height;
            const cx = (loupePosition.x / 100) * w;
            const cy = (loupePosition.y / 100) * h;
            const cropSize = w * 0.35; 
            ctx.drawImage(videoRef.current, 
                (cx - cropSize/2) * 2, (cy - cropSize/2) * 2, cropSize * 2, cropSize * 2, 
                0, 0, w, h);
        } else {
            ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        }

        const data = canvas.toDataURL('image/jpeg', 0.6);

        try {
          soundManager.playScanHum(); 
          const res = await analyzeLiveFrame(data, activeLens, liveData?.shortTitle);

          if (res.status !== 'SEARCHING' || liveData?.status === 'SEARCHING') {
              setLiveData(res);
              if (res.status === 'LOCKED') {
                  if (!liveData || liveData.shortTitle !== res.shortTitle) {
                      setHistory(prev => {
                          if (prev.length > 0 && prev[0].data.shortTitle === res.shortTitle) return prev;
                          return [{ id: crypto.randomUUID(), thumbnail: data, data: res }, ...prev].slice(0, 4); 
                      });
                  }

                  if (liveData?.shortTitle !== res.shortTitle) {
                      const isHighValue = res.valuationEstimate && (res.valuationEstimate.includes('k') || res.valuationEstimate.length > 5);
                      soundManager.playLock(isHighValue ? 'high' : 'standard');
                      if (navigator.vibrate) navigator.vibrate(50);
                  }
              }
          }
          setLastScanTime(Date.now());
        } catch(e) { }
      }
    }, 1000); 

    return () => clearInterval(interval);
  }, [stream, activeLens, loupePosition, isAnalyzing, liveData, lastScanTime]);

  // --- Manual Capture ---
  const capture = async () => {
    if (!videoRef.current) return;

    soundManager.playShutter();
    if (navigator.vibrate) navigator.vibrate([20, 50, 20]);
    setShutterOpen(false); 

    setTimeout(async () => {
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current!.videoWidth;
        canvas.height = videoRef.current!.videoHeight;
        canvas.getContext('2d')?.drawImage(videoRef.current!, 0, 0);
        const data = canvas.toDataURL('image/jpeg', 0.95);

        setCapturedImages([data]);
        setShutterOpen(true); 
        setIsAnalyzing(true);

        try {
            const result = await analyzeItem([data]);
            setManualResult(result);
        } catch (e) {
            alert("Analysis Interrupted. Please try again.");
            setIsAnalyzing(false);
        }
    }, 250); 
  };

  // --- Gallery Selection ---
  const handleGallerySelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        setIsAnalyzing(true);
        setShutterOpen(false);
        soundManager.playClick();

        const files = Array.from(e.target.files);
        const imagePromises = files.map(file => {
            return new Promise<string>((resolve) => {
                const reader = new FileReader();
                reader.onloadend = () => resolve(reader.result as string);
                reader.readAsDataURL(file as Blob);
            });
        });

        try {
            const images = await Promise.all(imagePromises);
            setCapturedImages(images);

            await new Promise(r => setTimeout(r, 600));
            soundManager.playShutter(); 

            const result = await analyzeItem(images);
            setManualResult(result);
        } catch (err) {
            console.error(err);
            alert("Failed to analyze images.");
        } finally {
            setIsAnalyzing(false);
            setShutterOpen(true);
            if (fileInputRef.current) fileInputRef.current.value = ''; 
        }
    }
  };

  const handleSaveHistory = (item: SessionHistoryItem) => {
    const result: AppraisalResult = {
        itemName: item.data.shortTitle,
        category: 'Live Capture',
        classification: item.data.classification,
        era: item.data.quickFacts[0] || 'Unknown',
        origin: 'Unknown',
        condition: 'Good',
        conditionScore: 5,
        rarityScore: 5,
        rarityDescription: 'Captured via Live Stream',
        valuation: { low: 0, mid: 0, high: 0, currency: 'USD' },
        authenticationMarks: [],
        visualHotspots: [], // No hotspots for live capture save
        historicalContext: item.data.detailedNote || '',
        materials: '',
        careInstructions: '',
        comparableSales: [],
        sellingProfile: { listingTitle: item.data.shortTitle, listingDescription: item.data.detailedNote || '', keywords: [], recommendedVenue: '', pricingStrategy: '' },
        confidence: item.data.confidence
    };
    onSave(result, item.thumbnail);
  };

  // --- Render Result View ---
  if (manualResult) {
    return (
        <ItemResult 
            result={manualResult} 
            imageData={capturedImages[0]} 
            onBack={() => { setManualResult(null); setIsAnalyzing(false); }} 
            onSave={(r) => onSave(r, capturedImages[0])} 
        />
    );
  }

  return (
    <div 
        ref={containerRef} 
        className="relative h-full bg-black overflow-hidden select-none font-mono touch-none"
        onTouchMove={handleTouchMove}
        onMouseMove={handleTouchMove} 
    >

      {/* 1. Viewfinder */}
      <video 
        ref={videoRef} 
        autoPlay 
        playsInline 
        className="absolute inset-0 w-full h-full object-cover opacity-60" // Darker feed for text contrast
      />

      {/* Cinematic Grain & Grid */}
      <div className="absolute inset-0 pointer-events-none opacity-40 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] mix-blend-overlay"></div>
      <div className="absolute inset-0 pointer-events-none opacity-20 bg-[linear-gradient(rgba(255,255,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.05)_1px,transparent_1px)] bg-[size:50px_50px]"></div>

      {/* Shutter Animation */}
      <div 
        className={`absolute inset-0 bg-black z-50 pointer-events-none transition-all duration-300 ease-out origin-center`}
        style={{ clipPath: shutterOpen ? 'polygon(0% 0%, 0% 0%, 100% 0%, 100% 0%, 100% 100%, 100% 100%, 0% 100%, 0% 100%)' : 'polygon(0% 50%, 0% 50%, 100% 50%, 100% 50%, 100% 50%, 100% 50%, 0% 50%, 0% 50%)' }}
      ></div>

      {/* Loupe */}
      <div 
        className={`absolute w-64 h-64 border transition-all duration-100 ease-linear flex items-center justify-center pointer-events-none z-30
          ${activeLens === 'FORENSICS' 
            ? 'border-amber-400 rounded-full shadow-[0_0_100px_rgba(251,191,36,0.3)]' 
            : 'border-white/20 rounded-lg opacity-50'
          }
        `}
        style={{ left: `${loupePosition.x}%`, top: `${loupePosition.y}%`, transform: 'translate(-50%, -50%)' }}
      >
        <div className="absolute top-0 left-0 w-2 h-2 border-t-2 border-l-2 border-current"></div>
        <div className="absolute top-0 right-0 w-2 h-2 border-t-2 border-r-2 border-current"></div>
        <div className="absolute bottom-0 left-0 w-2 h-2 border-b-2 border-l-2 border-current"></div>
        <div className="absolute bottom-0 right-0 w-2 h-2 border-b-2 border-r-2 border-current"></div>

        {/* Crosshair */}
        <div className="w-4 h-0.5 bg-current opacity-50"></div>
        <div className="h-4 w-0.5 bg-current absolute opacity-50"></div>
      </div>

      {/* Top HUD */}
      <div className="absolute top-0 left-0 right-0 p-6 pt-12 flex justify-between items-start z-40 bg-gradient-to-b from-black to-transparent pointer-events-none">
         <div className="pointer-events-auto">
            <h1 className="font-display text-xl text-white tracking-[0.25em]">PRIME<span className="text-blue-500">_SCAN</span></h1>
            <div className="flex items-center gap-2 mt-1">
                <div className={`w-1.5 h-1.5 rounded-full ${isAnalyzing ? 'bg-red-500 animate-ping' : 'bg-emerald-500'}`}></div>
                <span className="text-[9px] text-zinc-500 uppercase tracking-widest font-bold">
                    {isAnalyzing ? 'UPLINK ACTIVE' : 'SYSTEM READY'}
                </span>
            </div>
         </div>

         <div className="flex flex-col items-end gap-2 pointer-events-auto">
             <button onClick={toggleSound} className="p-2 border border-zinc-800 bg-black/50 text-zinc-400 hover:text-white hover:border-zinc-600 transition-colors">
                 {soundEnabled ? <Volume2 size={12} /> : <VolumeX size={12} />}
             </button>
             {liveData?.status === 'LOCKED' && (
                 <div className="mt-2 bg-emerald-500/10 border-r-2 border-emerald-500 p-3 backdrop-blur-md text-right animate-in slide-in-from-right-10">
                     <span className="text-[8px] text-emerald-500 uppercase tracking-[0.2em] block mb-1">Target Locked</span>
                     <span className="font-mono text-xl text-white">{(liveData.confidence * 100).toFixed(0)}%</span>
                 </div>
             )}
         </div>
      </div>

      {/* Live Data Stream */}
      <div className="absolute top-32 left-6 z-30 w-2/3 pointer-events-none">
          {liveData && liveData.status !== 'SEARCHING' && (
              <div className="flex flex-col gap-1 animate-in slide-in-from-left-4 duration-300">
                  <div className="flex items-center gap-2">
                     <span className={`text-[9px] font-bold uppercase tracking-widest px-1 ${liveData.status === 'LOCKED' ? 'bg-emerald-500 text-black' : 'bg-zinc-800 text-zinc-400'}`}>
                        {liveData.status}
                     </span>
                     <div className="h-px w-10 bg-zinc-700"></div>
                  </div>
                  <h2 className="font-display text-2xl text-white leading-none drop-shadow-[0_2px_10px_rgba(0,0,0,0.8)]">
                      {liveData.shortTitle}
                  </h2>
                  <p className="font-mono text-[10px] text-blue-300 bg-blue-900/20 p-2 border-l border-blue-500 max-w-xs backdrop-blur-sm">
                      {liveData.detailedNote}
                  </p>
                  {activeLens === 'MARKET' && liveData.valuationEstimate && (
                      <div className="mt-1 flex items-center gap-1 text-emerald-400">
                          <DollarSign size={12} />
                          <span className="font-mono text-lg tracking-tight">{liveData.valuationEstimate}</span>
                      </div>
                  )}
              </div>
          )}
      </div>

      {/* Session History */}
      <div className="absolute top-32 right-6 z-30 flex flex-col gap-2 pointer-events-auto items-end">
          {history.map(item => (
              <button 
                  key={item.id} 
                  onClick={() => handleSaveHistory(item)}
                  className="w-12 h-12 border border-zinc-800 bg-zinc-900/80 hover:border-blue-500 transition-all group relative overflow-hidden"
              >
                  <img src={item.thumbnail} className="w-full h-full object-cover opacity-60 group-hover:opacity-100 grayscale group-hover:grayscale-0 transition-all" />
                  <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-blue-500"></div>
              </button>
          ))}
      </div>

      {/* Bottom Controls - Cockpit Style */}
      <div className="absolute bottom-0 left-0 right-0 pb-8 pt-12 bg-gradient-to-t from-black via-black/90 to-transparent z-40 flex flex-col items-center gap-6">

          {/* Lens Selector */}
          <div className="flex gap-2 bg-black/40 p-1 border border-zinc-800 backdrop-blur-md rounded-none">
              {LENSES.map((lens) => (
                  <button 
                    key={lens.id}
                    onClick={() => { setActiveLens(lens.id); soundManager.playClick(); }}
                    className={`px-4 py-2 flex items-center gap-2 transition-all ${activeLens === lens.id ? 'bg-white text-black' : 'text-zinc-500 hover:text-zinc-300'}`}
                  >
                      <lens.icon size={12} />
                      <span className="text-[9px] font-bold tracking-widest uppercase">{lens.label}</span>
                  </button>
              ))}
          </div>

          <div className="flex items-center gap-8 w-full justify-center px-8">
            {/* Gallery Upload */}
            <button 
                onClick={() => { soundManager.playClick(); fileInputRef.current?.click(); }}
                disabled={isAnalyzing}
                className="w-12 h-12 border border-zinc-700 flex items-center justify-center text-zinc-500 hover:text-white hover:border-white hover:bg-white/5 transition-all"
            >
                <ImageIcon size={20} />
            </button>

            {/* Master Shutter - Geometric */}
            <button 
                onClick={capture}
                disabled={isAnalyzing}
                className="relative w-20 h-20 flex items-center justify-center group"
            >
                {/* Rotating Ring */}
                <div className={`absolute inset-0 border border-zinc-600 ${isAnalyzing ? 'animate-spin border-dashed' : 'rotate-45'}`}></div>
                <div className="absolute inset-2 border border-white/20"></div>

                {/* Core */}
                <div className="w-16 h-16 bg-white flex items-center justify-center hover:scale-95 transition-transform">
                    {isAnalyzing ? (
                        <ScanLine size={24} className="text-black animate-pulse" />
                    ) : (
                        <div className="w-2 h-2 bg-black"></div>
                    )}
                </div>
            </button>

             {/* Placeholder for future feature */}
            <div className="w-12 h-12 border border-zinc-800 flex items-center justify-center opacity-30">
                <Aperture size={20} />
            </div>
          </div>
      </div>

      {/* Hidden File Input */}
      <input 
        type="file" 
        multiple 
        accept="image/*" 
        ref={fileInputRef} 
        className="hidden" 
        onChange={handleGallerySelect} 
      />

    </div>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { Search, DollarSign, Fingerprint, Languages, Volume2, VolumeX, Image as ImageIcon, ScanLine, Aperture } from 'lucide-react';
import { analyzeItem, analyzeLiveFrame } from '../services/geminiService';
import { AppraisalResult, LiveAnalysisUpdate, LensMode } from '../types';
import { ItemResult } from './ItemResult';
import { soundManager } from '../services/soundService';

interface ScannerProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

interface SessionHistoryItem {
  id: string;
  thumbnail: string;
  data: LiveAnalysisUpdate;
}

const LENSES: { id: LensMode; label: string; icon: any; color: string; desc: string }[] = [
  { id: 'IDENTITY', label: 'ID', icon: Search, color: 'text-blue-400', desc: 'Provenance' },
  { id: 'MARKET', label: 'VALUE', icon: DollarSign, color: 'text-emerald-400', desc: 'Appraisal' },
  { id: 'FORENSICS', label: 'LOUPE', icon: Fingerprint, color: 'text-amber-400', desc: 'Details' },
  { id: 'DECIPHER', label: 'TEXT', icon: Languages, color: 'text-violet-400', desc: 'Epigraphy' },
];

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  // Core State
  const [activeLens, setActiveLens] = useState<LensMode>('IDENTITY');
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [manualResult, setManualResult] = useState<AppraisalResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [liveData, setLiveData] = useState<LiveAnalysisUpdate | null>(null);
  const [history, setHistory] = useState<SessionHistoryItem[]>([]);

  // UI State
  const [loupePosition, setLoupePosition] = useState({ x: 50, y: 50 }); 
  const [soundEnabled, setSoundEnabled] = useState(true);
  const [flashTriggered, setFlashTriggered] = useState(false);
  const [lastScanTime, setLastScanTime] = useState(0);

  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Sound Toggle
  const toggleSound = () => {
    const muted = soundManager.toggleMute();
    setSoundEnabled(!muted);
    soundManager.playClick();
  };

  // Loupe Interaction
  const handleTouchMove = (e: React.TouchEvent | React.MouseEvent) => {
    if (!containerRef.current) return;

    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

    const rect = containerRef.current.getBoundingClientRect();
    const x = ((clientX - rect.left) / rect.width) * 100;
    const y = ((clientY - rect.top) / rect.height) * 100;

    setLoupePosition({ 
        x: Math.max(10, Math.min(90, x)), 
        y: Math.max(10, Math.min(90, y)) 
    });
  };

  // Camera Init
  useEffect(() => {
    const startCamera = async () => {
      try {
        const s = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } }, audio: false 
        });
        setStream(s);
        if (videoRef.current) videoRef.current.srcObject = s;
      } catch (err) { console.error("Camera Error:", err); }
    };
    startCamera();
    return () => stream?.getTracks().forEach(t => t.stop());
  }, []);

  // Live Analysis Loop
  useEffect(() => {
    if (!stream) return;
    const interval = setInterval(async () => {
      const now = Date.now();
      if (videoRef.current && !isAnalyzing && (now - lastScanTime > 1500)) {

        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth / 3; 
        canvas.height = videoRef.current.videoHeight / 3;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Smart Crop for Forensics
        if (activeLens === 'FORENSICS') {
            const w = canvas.width;
            const h = canvas.height;
            const cx = (loupePosition.x / 100) * w;
            const cy = (loupePosition.y / 100) * h;
            const cropSize = w * 0.4; 
            ctx.drawImage(videoRef.current, 
                (cx - cropSize/2) * 3, (cy - cropSize/2) * 3, cropSize * 3, cropSize * 3, 
                0, 0, w, h);
        } else {
            ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        }

        const data = canvas.toDataURL('image/jpeg', 0.5);

        try {
          soundManager.playScanHum(); 
          const res = await analyzeLiveFrame(data, activeLens, liveData?.shortTitle);

          if (res.status !== 'SEARCHING' || liveData?.status === 'SEARCHING') {
              setLiveData(res);
              if (res.status === 'LOCKED') {
                  if (!liveData || liveData.shortTitle !== res.shortTitle) {
                      setHistory(prev => {
                          if (prev.length > 0 && prev[0].data.shortTitle === res.shortTitle) return prev;
                          return [{ id: crypto.randomUUID(), thumbnail: data, data: res }, ...prev].slice(0, 4); 
                      });

                      const isHighValue = res.valuationEstimate && (res.valuationEstimate.includes('k') || res.valuationEstimate.length > 5);
                      soundManager.playLock(isHighValue ? 'high' : 'standard');
                      if (navigator.vibrate) navigator.vibrate(50);
                  }
              }
          }
          setLastScanTime(Date.now());
        } catch(e) { }
      }
    }, 1000); 
    return () => clearInterval(interval);
  }, [stream, activeLens, loupePosition, isAnalyzing, liveData, lastScanTime]);

  // Capture Logic
  const capture = async () => {
    if (!videoRef.current) return;

    soundManager.playShutter();
    if (navigator.vibrate) navigator.vibrate([20, 50, 20]);
    setFlashTriggered(true); // Visual Flash
    setTimeout(() => setFlashTriggered(false), 300);

    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);
    const data = canvas.toDataURL('image/jpeg', 0.95);

    setCapturedImages([data]);
    setIsAnalyzing(true);

    try {
        const result = await analyzeItem([data]);
        setManualResult(result);
    } catch (e) {
        alert("Analysis Interrupted. Please ensure network connection.");
        setIsAnalyzing(false);
    }
  };

  const handleGallerySelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        setIsAnalyzing(true);
        soundManager.playClick();
        const files = Array.from(e.target.files);
        const imagePromises = files.map(file => {
            return new Promise<string>((resolve) => {
                const reader = new FileReader();
                reader.onloadend = () => resolve(reader.result as string);
                reader.readAsDataURL(file as Blob);
            });
        });

        try {
            const images = await Promise.all(imagePromises);
            setCapturedImages(images);
            soundManager.playShutter(); 
            const result = await analyzeItem(images);
            setManualResult(result);
        } catch (err) {
            alert("Failed to analyze images.");
            setIsAnalyzing(false);
        } finally {
            if (fileInputRef.current) fileInputRef.current.value = ''; 
        }
    }
  };

  const handleSaveHistory = (item: SessionHistoryItem) => {
    // Convert history item to a saveable format
    const result: AppraisalResult = {
        itemName: item.data.shortTitle,
        category: 'Live Capture',
        classification: item.data.classification,
        era: item.data.quickFacts[0] || 'Unknown',
        origin: 'Unknown',
        condition: 'Good',
        conditionScore: 5,
        rarityScore: 5,
        rarityDescription: 'Captured via Live Stream',
        valuation: { low: 0, mid: 0, high: 0, currency: 'USD' },
        authenticationMarks: [],
        visualHotspots: [],
        historicalContext: item.data.detailedNote || '',
        materials: '',
        careInstructions: '',
        comparableSales: [],
        sellingProfile: { listingTitle: item.data.shortTitle, listingDescription: item.data.detailedNote || '', keywords: [], recommendedVenue: '', pricingStrategy: '' },
        confidence: item.data.confidence
    };
    onSave(result, item.thumbnail);
  };

  if (manualResult) {
    return (
        <ItemResult 
            result={manualResult} 
            imageData={capturedImages[0]} 
            onBack={() => { setManualResult(null); setIsAnalyzing(false); }} 
            onSave={(r) => onSave(r, capturedImages[0])} 
        />
    );
  }

  return (
    <div 
        ref={containerRef} 
        className="relative h-full bg-black overflow-hidden select-none font-mono touch-none scan-overlay"
        onTouchMove={handleTouchMove}
        onMouseMove={handleTouchMove} 
    >
      <video ref={videoRef} autoPlay playsInline className="absolute inset-0 w-full h-full object-cover opacity-75" />

      {/* Visual Effects */}
      <div className="absolute inset-0 pointer-events-none opacity-30 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] mix-blend-overlay"></div>

      {/* Flash Effect */}
      {flashTriggered && <div className="absolute inset-0 bg-white z-[60] animate-flash pointer-events-none"></div>}

      {/* Loupe Overlay */}
      <div 
        className={`absolute w-72 h-72 border transition-all duration-150 ease-out flex items-center justify-center pointer-events-none z-30
          ${activeLens === 'FORENSICS' 
            ? 'border-amber-400 rounded-full shadow-[0_0_100px_rgba(251,191,36,0.3)] bg-amber-900/10 backdrop-brightness-125' 
            : 'border-white/20 rounded-lg opacity-40'
          }
        `}
        style={{ left: `${loupePosition.x}%`, top: `${loupePosition.y}%`, transform: 'translate(-50%, -50%)' }}
      >
        {/* Reticle Graphics */}
        <div className="absolute top-0 left-0 w-3 h-3 border-t-2 border-l-2 border-current"></div>
        <div className="absolute top-0 right-0 w-3 h-3 border-t-2 border-r-2 border-current"></div>
        <div className="absolute bottom-0 left-0 w-3 h-3 border-b-2 border-l-2 border-current"></div>
        <div className="absolute bottom-0 right-0 w-3 h-3 border-b-2 border-r-2 border-current"></div>
        <div className="w-1 h-1 bg-white rounded-full shadow-[0_0_5px_white]"></div>
        <div className="absolute top-2 left-1/2 -translate-x-1/2 text-[9px] font-bold tracking-widest bg-black/50 px-1">
            {activeLens === 'FORENSICS' ? 'MAGNIFICATION 3X' : 'TARGET ACQUISITION'}
        </div>
      </div>

      {/* Top HUD */}
      <div className="absolute top-0 left-0 right-0 p-5 pt-12 flex justify-between items-start z-40 bg-gradient-to-b from-black via-black/80 to-transparent pointer-events-none">
         <div className="pointer-events-auto">
            <h1 className="font-display text-xl text-white tracking-[0.2em] drop-shadow-lg">PRIME<span className="text-blue-500">_OS</span></h1>
            <div className="flex items-center gap-2 mt-1">
                <div className={`w-1.5 h-1.5 rounded-full ${isAnalyzing ? 'bg-red-500 animate-ping' : 'bg-emerald-500'}`}></div>
                <span className="text-[9px] text-zinc-400 uppercase tracking-widest font-bold">
                    {isAnalyzing ? 'UPLINK ESTABLISHED...' : 'SYSTEM OPTIMAL'}
                </span>
            </div>
         </div>

         <div className="flex flex-col items-end gap-3 pointer-events-auto">
             <button onClick={toggleSound} className="p-2.5 rounded-full bg-white/10 border border-white/10 text-zinc-300 hover:text-white hover:bg-white/20 backdrop-blur-md transition-all">
                 {soundEnabled ? <Volume2 size={14} /> : <VolumeX size={14} />}
             </button>
             {liveData?.status === 'LOCKED' && (
                 <div className="bg-emerald-950/90 border-l-2 border-emerald-500 p-3 backdrop-blur-md text-right animate-in slide-in-from-right-10 shadow-lg shadow-emerald-900/20">
                     <span className="text-[8px] text-emerald-400 uppercase tracking-[0.2em] block mb-1">Confidence</span>
                     <span className="font-mono text-xl text-white shadow-emerald-500/50">{(liveData.confidence * 100).toFixed(0)}%</span>
                 </div>
             )}
         </div>
      </div>

      {/* Live Data Feed */}
      <div className="absolute top-32 left-6 z-30 w-[70%] pointer-events-none">
          {liveData && liveData.status !== 'SEARCHING' && (
              <div className="flex flex-col gap-2 animate-in slide-in-from-left-4 fade-in duration-500">
                  <div className="flex items-center gap-2">
                     <span className={`text-[9px] font-bold uppercase tracking-widest px-1.5 py-0.5 rounded-sm ${liveData.status === 'LOCKED' ? 'bg-emerald-500 text-black' : 'bg-zinc-800 text-zinc-400'}`}>
                        {liveData.status}
                     </span>
                     <div className="h-px w-12 bg-zinc-700"></div>
                  </div>
                  <h2 className="font-display text-2xl text-white leading-none drop-shadow-xl">
                      {liveData.shortTitle}
                  </h2>
                  <div className="font-mono text-[10px] text-blue-200 bg-blue-950/40 p-3 border-l-2 border-blue-500 backdrop-blur-sm rounded-r-lg leading-relaxed shadow-lg">
                      {liveData.detailedNote}
                  </div>
              </div>
          )}
      </div>

      {/* History Stack (Right Side) */}
      <div className="absolute top-32 right-6 z-30 flex flex-col gap-3 pointer-events-auto items-end">
          {history.map(item => (
              <button 
                  key={item.id} 
                  onClick={() => handleSaveHistory(item)}
                  className="w-12 h-12 border border-zinc-700 bg-zinc-900/80 hover:border-blue-500 hover:scale-110 transition-all rounded-lg overflow-hidden shadow-lg group"
              >
                  <img src={item.thumbnail} className="w-full h-full object-cover opacity-70 group-hover:opacity-100 grayscale group-hover:grayscale-0 transition-all" />
              </button>
          ))}
      </div>

      {/* Bottom Controls */}
      <div className="absolute bottom-0 left-0 right-0 pb-8 pt-12 bg-gradient-to-t from-black via-black/95 to-transparent z-40 flex flex-col items-center gap-6">

          {/* Lens Switcher */}
          <div className="flex gap-1 bg-zinc-900/60 p-1 border border-zinc-800/50 backdrop-blur-xl rounded-full">
              {LENSES.map((lens) => (
                  <button 
                    key={lens.id}
                    onClick={() => { setActiveLens(lens.id); soundManager.playClick(); }}
                    className={`px-4 py-2 flex items-center gap-2 rounded-full transition-all duration-300 ${activeLens === lens.id ? 'bg-white text-black shadow-[0_0_15px_rgba(255,255,255,0.1)]' : 'text-zinc-500 hover:text-zinc-300'}`}
                  >
                      <lens.icon size={14} />
                      <span className="text-[9px] font-bold tracking-widest uppercase hidden sm:inline">{lens.label}</span>
                  </button>
              ))}
          </div>

          <div className="flex items-center gap-10 w-full justify-center px-8 relative">
            {/* Gallery Upload */}
            <button 
                onClick={() => { soundManager.playClick(); fileInputRef.current?.click(); }}
                disabled={isAnalyzing}
                className="w-12 h-12 rounded-full bg-zinc-900 border border-zinc-700 flex items-center justify-center text-zinc-500 hover:text-white hover:border-white hover:bg-zinc-800 transition-all active:scale-95"
            >
                <ImageIcon size={20} />
            </button>

            {/* Master Capture Button */}
            <button 
                onClick={capture}
                disabled={isAnalyzing}
                className="relative w-20 h-20 flex items-center justify-center group"
            >
                <div className={`absolute inset-0 rounded-full border-2 border-zinc-600 transition-all duration-500 ${isAnalyzing ? 'animate-spin border-dashed border-blue-500 opacity-50' : 'group-hover:border-white group-hover:scale-110'}`}></div>
                <div className="absolute inset-2 rounded-full border border-white/10"></div>
                <div className="w-16 h-16 rounded-full bg-white shadow-[0_0_30px_rgba(255,255,255,0.3)] flex items-center justify-center transition-transform active:scale-90">
                    {isAnalyzing ? (
                        <ScanLine size={24} className="text-zinc-900 animate-pulse" />
                    ) : (
                        <div className="w-10 h-10 rounded-full bg-zinc-100 group-hover:scale-90 transition-transform"></div>
                    )}
                </div>
            </button>

             {/* Placeholder / Future Feature */}
            <button className="w-12 h-12 rounded-full bg-zinc-900 border border-zinc-700 flex items-center justify-center text-zinc-600 opacity-50 cursor-not-allowed">
                <Aperture size={20} />
            </button>
          </div>
      </div>

      <input type="file" multiple accept="image/*" ref={fileInputRef} className="hidden" onChange={handleGallerySelect} />
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { AppraisalResult, VisualHotspot } from '../types';
import { askCurator } from '../services/geminiService';
import { ArrowLeft, X, Send, Sparkles, Box, DollarSign, Zap, Info, Layers, ChevronUp, Crosshair, FileText, Globe } from 'lucide-react';
import { Button } from './Button';
import { soundManager } from '../services/soundService';

interface ItemResultProps {
  result: AppraisalResult;
  imageData: string;
  onBack: () => void;
  onSave: (result: AppraisalResult) => void;
}

// Typewriter Component for cool text revealing
const TypewriterText: React.FC<{ text: string; delay?: number }> = ({ text, delay = 0 }) => {
  const [displayed, setDisplayed] = useState('');

  useEffect(() => {
    let i = 0;
    const startTimeout = setTimeout(() => {
        const interval = setInterval(() => {
            setDisplayed(text.substring(0, i));
            i++;
            if (i > text.length) clearInterval(interval);
        }, 10); // Speed
        return () => clearInterval(interval);
    }, delay);
    return () => clearTimeout(startTimeout);
  }, [text, delay]);

  return <span>{displayed}<span className="cursor-blink text-blue-500">_</span></span>;
};

export const ItemResult: React.FC<ItemResultProps> = ({ result, imageData, onBack, onSave }) => {
  const [showChat, setShowChat] = useState(false);
  const [chatInput, setChatInput] = useState("");
  const [chatHistory, setChatHistory] = useState<{role:string, text:string}[]>([]);
  const [isChatLoading, setIsChatLoading] = useState(false);

  const [activeHotspot, setActiveHotspot] = useState<VisualHotspot | null>(null);
  const [viewMode, setViewMode] = useState<'DETAILS' | 'EXPLORE'>('EXPLORE');

  // Determine Rarity Colors
  const isRare = result.rarityScore > 7;
  const themeColor = isRare ? 'amber' : 'blue';
  const rarityColorClass = isRare ? 'text-amber-400 border-amber-500/50' : 'text-blue-400 border-blue-500/50';

  useEffect(() => {
    soundManager.playLock(isRare ? 'high' : 'standard');
  }, []);

  const handleChat = async () => {
    if (!chatInput) return;
    const q = chatInput;
    setChatInput("");
    soundManager.playClick();
    setChatHistory(prev => [...prev, { role: 'user', text: q }]);
    setIsChatLoading(true);
    try {
        const ans = await askCurator(result, q);
        setChatHistory(prev => [...prev, { role: 'model', text: ans }]);
    } catch {
        setChatHistory(prev => [...prev, { role: 'model', text: "Connection severed. Cannot retrieve data." }]);
    }
    setIsChatLoading(false);
    soundManager.playLock();
  };

  return (
    <div className="h-full bg-black text-white font-sans overflow-hidden relative flex flex-col">

      {/* 1. TOP COMMAND BAR */}
      <div className="absolute top-0 left-0 right-0 z-50 flex justify-between items-start p-4 pt-[calc(16px+env(safe-area-inset-top))] bg-gradient-to-b from-black/90 via-black/50 to-transparent pointer-events-none">

        {/* Back Button */}
        <button 
            onClick={() => { soundManager.playClick(); onBack(); }} 
            className="pointer-events-auto p-2 group flex items-center gap-2 bg-black/40 backdrop-blur-md border border-white/10 rounded-sm hover:border-red-500/50 transition-all"
        >
            <ArrowLeft size={16} className="text-zinc-400 group-hover:text-red-400" />
            <span className="font-mono text-[10px] tracking-widest text-zinc-500 group-hover:text-red-400 transition-colors">ABORT</span>
        </button>

        {/* View Switcher */}
        <div className="flex gap-1 pointer-events-auto bg-black/40 backdrop-blur-md p-1 border border-white/10 rounded-sm">
             <button 
                onClick={() => { soundManager.playClick(); setViewMode('EXPLORE'); }} 
                className={`px-3 py-1.5 text-[9px] font-bold tracking-widest uppercase transition-all flex items-center gap-2 ${viewMode === 'EXPLORE' ? 'bg-white text-black' : 'text-zinc-500 hover:text-zinc-300'}`}
             >
                 <Crosshair size={12} /> Explore
             </button>
             <button 
                onClick={() => { soundManager.playClick(); setViewMode('DETAILS'); }} 
                className={`px-3 py-1.5 text-[9px] font-bold tracking-widest uppercase transition-all flex items-center gap-2 ${viewMode === 'DETAILS' ? 'bg-white text-black' : 'text-zinc-500 hover:text-zinc-300'}`}
             >
                 <FileText size={12} /> Dossier
             </button>
        </div>

        {/* Chat Toggle */}
        <button 
            onClick={() => { soundManager.playClick(); setShowChat(true); }} 
            className="pointer-events-auto flex items-center gap-2 px-3 py-2 bg-blue-500/10 border border-blue-500/30 text-blue-400 text-[10px] font-bold uppercase tracking-widest hover:bg-blue-500 hover:text-white transition-all backdrop-blur-md rounded-sm"
        >
             <Zap size={12} /> AI
        </button>
      </div>

      {/* 2. MAIN VISUAL INTERFACE (EXPLORE MODE) */}
      <div className={`relative w-full transition-all duration-500 ease-[cubic-bezier(0.23,1,0.32,1)] ${viewMode === 'EXPLORE' ? 'h-full' : 'h-[35vh]'}`}>
          <img src={imageData} className="w-full h-full object-cover opacity-90" />

          {/* Scanlines & Grain */}
          <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 mix-blend-overlay pointer-events-none"></div>
          <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-black/40 pointer-events-none"></div>

          {/* === INTERACTIVE HOTSPOTS LAYER === */}
          {result.visualHotspots && result.visualHotspots.map((spot, idx) => (
             <button 
                key={idx}
                className="absolute w-12 h-12 flex items-center justify-center cursor-pointer group z-30 focus:outline-none"
                style={{ top: `${spot.y}%`, left: `${spot.x}%`, transform: 'translate(-50%, -50%)' }}
                onClick={(e) => { e.stopPropagation(); soundManager.playClick(); setActiveHotspot(activeHotspot === spot ? null : spot); }}
             >
                 {/* Pulse Animation */}
                 <div className={`absolute inset-0 rounded-full border opacity-0 group-hover:opacity-100 transition-all duration-300 ${activeHotspot === spot ? 'border-white animate-ping' : 'border-white/50'}`}></div>

                 {/* The Node */}
                 <div className={`w-3 h-3 rotate-45 border transition-all duration-300 shadow-[0_0_15px_rgba(0,0,0,0.8)] ${activeHotspot === spot ? 'bg-white border-white scale-150' : 'bg-black/40 border-white/80 hover:bg-white'}`}></div>

                 {/* Label on Hover */}
                 <div className={`absolute left-6 top-1/2 -translate-y-1/2 ml-4 px-2 py-1 bg-black/80 border border-white/20 backdrop-blur-md whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none`}>
                     <span className="text-[9px] font-mono text-white uppercase tracking-wider">{spot.label}</span>
                 </div>
             </button>
          ))}

          {/* Hotspot Detail Card (Pop-up) */}
          {activeHotspot && (
              <div className="absolute top-[20%] left-6 right-6 z-40 animate-in fade-in slide-in-from-bottom-4 duration-300 pointer-events-none">
                  <div className="bg-black/80 backdrop-blur-xl border-l-2 border-white p-5 pointer-events-auto shadow-[0_10px_40px_rgba(0,0,0,0.8)] relative max-w-sm mx-auto">
                      <button onClick={() => setActiveHotspot(null)} className="absolute top-2 right-2 p-2 text-zinc-500 hover:text-white"><X size={14} /></button>
                      <h4 className="font-mono text-[9px] text-zinc-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                          <Crosshair size={10} /> Feature Detected
                      </h4>
                      <h3 className="font-display text-xl text-white mb-2">{activeHotspot.label}</h3>
                      <p className="font-sans text-sm text-zinc-300 leading-relaxed">
                          {activeHotspot.description}
                      </p>
                  </div>
              </div>
