            </div>

            {/* Sources */}
            {analysis.sources && analysis.sources.length > 0 && (
              <div className="space-y-2">
                <h3 className="font-bold text-zinc-600 text-[10px] uppercase tracking-widest pl-2">Verified Channels</h3>
                {analysis.sources.map((source, idx) => (
                  <a 
                    key={idx} 
                    href={source.url} 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="flex items-center justify-between p-3 bg-zinc-900 border border-zinc-800 hover:border-zinc-600 transition-colors group"
                  >
                    <span className="text-[10px] text-zinc-300 truncate max-w-[80%] uppercase">{source.title}</span>
                    <ExternalLink size={10} className="text-zinc-600 group-hover:text-white" />
                  </a>
                ))}
              </div>
            )}
          </div>
        )}

        {/* Inventory Stats */}
        <div className="grid grid-cols-2 gap-2">
           {sortedCategories.map(([cat, count], i) => (
             <div key={i} className="bg-zinc-900 p-3 border border-zinc-800 flex justify-between items-center">
               <span className="text-[9px] text-zinc-500 uppercase font-bold tracking-widest">{cat}</span>
               <span className="text-sm font-mono text-white">x{count}</span>
             </div>
           ))}
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { Search, DollarSign, Fingerprint, Languages, Volume2, VolumeX, Image as ImageIcon, ScanLine, Aperture } from 'lucide-react';
import { analyzeItem, analyzeLiveFrame } from '../services/geminiService';
import { AppraisalResult, LiveAnalysisUpdate, LensMode } from '../types';
import { ItemResult } from './ItemResult';
import { soundManager } from '../services/soundService';

interface ScannerProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

interface SessionHistoryItem {
  id: string;
  thumbnail: string;
  data: LiveAnalysisUpdate;
}

const LENSES: { id: LensMode; label: string; icon: any; color: string; desc: string }[] = [
  { id: 'IDENTITY', label: 'ID', icon: Search, color: 'text-blue-400', desc: 'Provenance' },
  { id: 'MARKET', label: 'VALUE', icon: DollarSign, color: 'text-emerald-400', desc: 'Appraisal' },
  { id: 'FORENSICS', label: 'LOUPE', icon: Fingerprint, color: 'text-amber-400', desc: 'Details' },
  { id: 'DECIPHER', label: 'TEXT', icon: Languages, color: 'text-violet-400', desc: 'Epigraphy' },
];

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  // Core State
  const [activeLens, setActiveLens] = useState<LensMode>('IDENTITY');
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [manualResult, setManualResult] = useState<AppraisalResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [liveData, setLiveData] = useState<LiveAnalysisUpdate | null>(null);
  const [history, setHistory] = useState<SessionHistoryItem[]>([]);

  // UI State
  const [loupePosition, setLoupePosition] = useState({ x: 50, y: 50 }); 
  const [soundEnabled, setSoundEnabled] = useState(true);
  const [flashTriggered, setFlashTriggered] = useState(false);
  const [lastScanTime, setLastScanTime] = useState(0);

  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Sound Toggle
  const toggleSound = () => {
    const muted = soundManager.toggleMute();
    setSoundEnabled(!muted);
    soundManager.playClick();
  };

  // Loupe Interaction
  const handleTouchMove = (e: React.TouchEvent | React.MouseEvent) => {
    if (!containerRef.current) return;

    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

    const rect = containerRef.current.getBoundingClientRect();
    const x = ((clientX - rect.left) / rect.width) * 100;
    const y = ((clientY - rect.top) / rect.height) * 100;

    setLoupePosition({ 
        x: Math.max(10, Math.min(90, x)), 
        y: Math.max(10, Math.min(90, y)) 
    });
  };

  // Camera Init
  useEffect(() => {
    const startCamera = async () => {
      try {
        const s = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } }, audio: false 
        });
        setStream(s);
        if (videoRef.current) videoRef.current.srcObject = s;
      } catch (err) { console.error("Camera Error:", err); }
    };
    startCamera();
    return () => stream?.getTracks().forEach(t => t.stop());
  }, []);

  // Live Analysis Loop
  useEffect(() => {
    if (!stream) return;
    const interval = setInterval(async () => {
      const now = Date.now();
      if (videoRef.current && !isAnalyzing && (now - lastScanTime > 1500)) {

        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth / 3; 
        canvas.height = videoRef.current.videoHeight / 3;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Smart Crop for Forensics
        if (activeLens === 'FORENSICS') {
            const w = canvas.width;
            const h = canvas.height;
            const cx = (loupePosition.x / 100) * w;
            const cy = (loupePosition.y / 100) * h;
            const cropSize = w * 0.4; 
            ctx.drawImage(videoRef.current, 
                (cx - cropSize/2) * 3, (cy - cropSize/2) * 3, cropSize * 3, cropSize * 3, 
                0, 0, w, h);
        } else {
            ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        }

        const data = canvas.toDataURL('image/jpeg', 0.5);

        try {
          soundManager.playScanHum(); 
          const res = await analyzeLiveFrame(data, activeLens, liveData?.shortTitle);

          if (res.status !== 'SEARCHING' || liveData?.status === 'SEARCHING') {
              setLiveData(res);
              if (res.status === 'LOCKED') {
                  if (!liveData || liveData.shortTitle !== res.shortTitle) {
                      setHistory(prev => {
                          if (prev.length > 0 && prev[0].data.shortTitle === res.shortTitle) return prev;
                          return [{ id: crypto.randomUUID(), thumbnail: data, data: res }, ...prev].slice(0, 4); 
                      });

                      const isHighValue = res.valuationEstimate && (res.valuationEstimate.includes('k') || res.valuationEstimate.length > 5);
                      soundManager.playLock(isHighValue ? 'high' : 'standard');
                      if (navigator.vibrate) navigator.vibrate(50);
                  }
              }
          }
          setLastScanTime(Date.now());
        } catch(e) { }
      }
    }, 1000); 
    return () => clearInterval(interval);
  }, [stream, activeLens, loupePosition, isAnalyzing, liveData, lastScanTime]);

  // Capture Logic
  const capture = async () => {
    if (!videoRef.current) return;

    soundManager.playShutter();
    if (navigator.vibrate) navigator.vibrate([20, 50, 20]);
    setFlashTriggered(true); // Visual Flash
    setTimeout(() => setFlashTriggered(false), 300);

    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);
    const data = canvas.toDataURL('image/jpeg', 0.95);

    setCapturedImages([data]);
    setIsAnalyzing(true);

    try {
        const result = await analyzeItem([data]);
        setManualResult(result);
    } catch (e) {
        alert("Analysis Interrupted. Please ensure network connection.");
        setIsAnalyzing(false);
    }
  };

  const handleGallerySelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        setIsAnalyzing(true);
        soundManager.playClick();
        const files = Array.from(e.target.files);
        const imagePromises = files.map(file => {
            return new Promise<string>((resolve) => {
                const reader = new FileReader();
                reader.onloadend = () => resolve(reader.result as string);
                reader.readAsDataURL(file as Blob);
            });
        });

        try {
            const images = await Promise.all(imagePromises);
            setCapturedImages(images);
            soundManager.playShutter(); 
            const result = await analyzeItem(images);
            setManualResult(result);
        } catch (err) {
            alert("Failed to analyze images.");
            setIsAnalyzing(false);
        } finally {
            if (fileInputRef.current) fileInputRef.current.value = ''; 
        }
    }
  };

  const handleSaveHistory = (item: SessionHistoryItem) => {
    // Convert history item to a saveable format
    const result: AppraisalResult = {
        itemName: item.data.shortTitle,
        category: 'Live Capture',
        classification: item.data.classification,
        era: item.data.quickFacts[0] || 'Unknown',
        origin: 'Unknown',
        condition: 'Good',
        conditionScore: 5,
        rarityScore: 5,
        rarityDescription: 'Captured via Live Stream',
        valuation: { low: 0, mid: 0, high: 0, currency: 'USD' },
        authenticationMarks: [],
        visualHotspots: [],
        historicalContext: item.data.detailedNote || '',
        materials: '',
        careInstructions: '',
        comparableSales: [],
        sellingProfile: { listingTitle: item.data.shortTitle, listingDescription: item.data.detailedNote || '', keywords: [], recommendedVenue: '', pricingStrategy: '' },
        confidence: item.data.confidence
    };
    onSave(result, item.thumbnail);
  };

  if (manualResult) {
    return (
        <ItemResult 
            result={manualResult} 
            imageData={capturedImages[0]} 
            onBack={() => { setManualResult(null); setIsAnalyzing(false); }} 
            onSave={(r) => onSave(r, capturedImages[0])} 
        />
    );
  }

  return (
    <div 
        ref={containerRef} 
        className="relative h-full bg-black overflow-hidden select-none font-mono touch-none scan-overlay"
        onTouchMove={handleTouchMove}
        onMouseMove={handleTouchMove} 
    >
      <video ref={videoRef} autoPlay playsInline className="absolute inset-0 w-full h-full object-cover opacity-75" />

      {/* Visual Effects */}
      <div className="absolute inset-0 pointer-events-none opacity-30 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] mix-blend-overlay"></div>

      {/* Flash Effect */}
      {flashTriggered && <div className="absolute inset-0 bg-white z-[60] animate-flash pointer-events-none"></div>}

      {/* Loupe Overlay */}
      <div 
        className={`absolute w-72 h-72 border transition-all duration-150 ease-out flex items-center justify-center pointer-events-none z-30
          ${activeLens === 'FORENSICS' 
            ? 'border-amber-400 rounded-full shadow-[0_0_100px_rgba(251,191,36,0.3)] bg-amber-900/10 backdrop-brightness-125' 
            : 'border-white/20 rounded-lg opacity-40'
          }
        `}
        style={{ left: `${loupePosition.x}%`, top: `${loupePosition.y}%`, transform: 'translate(-50%, -50%)' }}
      >
        {/* Reticle Graphics */}
        <div className="absolute top-0 left-0 w-3 h-3 border-t-2 border-l-2 border-current"></div>
        <div className="absolute top-0 right-0 w-3 h-3 border-t-2 border-r-2 border-current"></div>
        <div className="absolute bottom-0 left-0 w-3 h-3 border-b-2 border-l-2 border-current"></div>
        <div className="absolute bottom-0 right-0 w-3 h-3 border-b-2 border-r-2 border-current"></div>
        <div className="w-1 h-1 bg-white rounded-full shadow-[0_0_5px_white]"></div>
        <div className="absolute top-2 left-1/2 -translate-x-1/2 text-[9px] font-bold tracking-widest bg-black/50 px-1">
            {activeLens === 'FORENSICS' ? 'MAGNIFICATION 3X' : 'TARGET ACQUISITION'}
        </div>
      </div>

      {/* Top HUD */}
      <div className="absolute top-0 left-0 right-0 p-5 pt-[calc(16px+env(safe-area-inset-top))] flex justify-between items-start z-40 bg-gradient-to-b from-black via-black/80 to-transparent pointer-events-none">
         <div className="pointer-events-auto">
            <h1 className="font-display text-xl text-white tracking-[0.2em] drop-shadow-lg">PRIME<span className="text-blue-500">_OS</span></h1>
            <div className="flex items-center gap-2 mt-1">
                <div className={`w-1.5 h-1.5 rounded-full ${isAnalyzing ? 'bg-red-500 animate-ping' : 'bg-emerald-500'}`}></div>
                <span className="text-[9px] text-zinc-400 uppercase tracking-widest font-bold">
                    {isAnalyzing ? 'UPLINK ESTABLISHED...' : 'SYSTEM OPTIMAL'}
                </span>
            </div>
         </div>

         <div className="flex flex-col items-end gap-3 pointer-events-auto">
             <button onClick={toggleSound} className="p-2.5 rounded-full bg-white/10 border border-white/10 text-zinc-300 hover:text-white hover:bg-white/20 backdrop-blur-md transition-all">
                 {soundEnabled ? <Volume2 size={14} /> : <VolumeX size={14} />}
             </button>
             {liveData?.status === 'LOCKED' && (
                 <div className="bg-emerald-950/90 border-l-2 border-emerald-500 p-3 backdrop-blur-md text-right animate-in slide-in-from-right-10 shadow-lg shadow-emerald-900/20">
                     <span className="text-[8px] text-emerald-400 uppercase tracking-[0.2em] block mb-1">Confidence</span>
                     <span className="font-mono text-xl text-white shadow-emerald-500/50">{(liveData.confidence * 100).toFixed(0)}%</span>
                 </div>
             )}
         </div>
      </div>

      {/* Live Data Feed */}
      <div className="absolute top-32 left-6 z-30 w-[70%] pointer-events-none">
          {liveData && liveData.status !== 'SEARCHING' && (
              <div className="flex flex-col gap-2 animate-in slide-in-from-left-4 fade-in duration-500">
                  <div className="flex items-center gap-2">
                     <span className={`text-[9px] font-bold uppercase tracking-widest px-1.5 py-0.5 rounded-sm ${liveData.status === 'LOCKED' ? 'bg-emerald-500 text-black' : 'bg-zinc-800 text-zinc-400'}`}>
                        {liveData.status}
                     </span>
                     <div className="h-px w-12 bg-zinc-700"></div>
                  </div>
                  <h2 className="font-display text-2xl text-white leading-none drop-shadow-xl">
                      {liveData.shortTitle}
                  </h2>
                  <div className="font-mono text-[10px] text-blue-200 bg-blue-950/40 p-3 border-l-2 border-blue-500 backdrop-blur-sm leading-relaxed shadow-lg max-w-xs">
                      {liveData.detailedNote}
                  </div>
              </div>
          )}
      </div>

      {/* History Stack (Right Side) */}
      <div className="absolute top-32 right-6 z-30 flex flex-col gap-3 pointer-events-auto items-end">
          {history.map(item => (
              <button 
                  key={item.id} 
                  onClick={() => handleSaveHistory(item)}
                  className="w-12 h-12 border border-zinc-700 bg-zinc-900/80 hover:border-blue-500 hover:scale-110 transition-all rounded-sm overflow-hidden shadow-lg group"
              >
                  <img src={item.thumbnail} className="w-full h-full object-cover opacity-70 group-hover:opacity-100 grayscale group-hover:grayscale-0 transition-all" />
              </button>
          ))}
      </div>

      {/* Bottom Controls */}
      <div className="absolute bottom-0 left-0 right-0 pb-8 pt-12 bg-gradient-to-t from-black via-black/95 to-transparent z-40 flex flex-col items-center gap-6">

          {/* Lens Switcher */}
          <div className="flex gap-1 bg-zinc-900/60 p-1 border border-zinc-800/50 backdrop-blur-xl rounded-full">
              {LENSES.map((lens) => (
                  <button 
                    key={lens.id}
                    onClick={() => { setActiveLens(lens.id); soundManager.playClick(); }}
                    className={`px-4 py-2 flex items-center gap-2 rounded-full transition-all duration-300 ${activeLens === lens.id ? 'bg-white text-black shadow-[0_0_15px_rgba(255,255,255,0.1)]' : 'text-zinc-500 hover:text-zinc-300'}`}
                  >
                      <lens.icon size={14} />
                      <span className="text-[9px] font-bold tracking-widest uppercase hidden sm:inline">{lens.label}</span>
                  </button>
              ))}
          </div>

          <div className="flex items-center gap-10 w-full justify-center px-8 relative pb-[env(safe-area-inset-bottom)]">
            {/* Gallery Upload */}
            <button 
                onClick={() => { soundManager.playClick(); fileInputRef.current?.click(); }}
                disabled={isAnalyzing}
                className="w-12 h-12 rounded-full bg-zinc-900 border border-zinc-700 flex items-center justify-center text-zinc-500 hover:text-white hover:border-white hover:bg-zinc-800 transition-all active:scale-95"
            >
                <ImageIcon size={20} />
            </button>

            {/* Master Capture Button */}
            <button 
                onClick={capture}
                disabled={isAnalyzing}
                className="relative w-20 h-20 flex items-center justify-center group"
            >
                <div className={`absolute inset-0 rounded-full border-2 border-zinc-600 transition-all duration-500 ${isAnalyzing ? 'animate-spin border-dashed border-blue-500 opacity-50' : 'group-hover:border-white group-hover:scale-110'}`}></div>
                <div className="absolute inset-2 rounded-full border border-white/10"></div>
                <div className="w-16 h-16 rounded-full bg-white shadow-[0_0_30px_rgba(255,255,255,0.3)] flex items-center justify-center transition-transform active:scale-90">
                    {isAnalyzing ? (
                        <ScanLine size={24} className="text-zinc-900 animate-pulse" />
                    ) : (
                        <div className="w-10 h-10 rounded-full bg-zinc-100 group-hover:scale-90 transition-transform"></div>
                    )}
                </div>
            </button>

             {/* Placeholder / Future Feature */}
            <button className="w-12 h-12 rounded-full bg-zinc-900 border border-zinc-700 flex items-center justify-center text-zinc-600 opacity-50 cursor-not-allowed">
                <Aperture size={20} />
            </button>
          </div>
      </div>

      <input type="file" multiple accept="image/*" ref={fileInputRef} className="hidden" onChange={handleGallerySelect} />
    </div>
  );
};

