import React, { useState, useEffect } from 'react';
import { AppTab, CollectionItem, AppraisalResult } from './types';
import { Scanner } from './components/ScanTerminal';
import { CollectionManager } from './components/VaultTerminal';
import { MarketTrends } from './components/DataTerminal';
import { ItemResult } from './components/ItemResult';
import { ScanLine, Box, BarChart3 } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>('SCAN');
  const [collection, setCollection] = useState<CollectionItem[]>([]);
  const [selectedItem, setSelectedItem] = useState<CollectionItem | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('curator_collection');
    if (saved) setCollection(JSON.parse(saved));
  }, []);

  const saveToCollection = (result: AppraisalResult, imageData: string) => {
    const newItem: CollectionItem = {
      ...result,
      id: crypto.randomUUID(),
      dateScanned: new Date().toISOString(),
      imageUrl: imageData
    };
    const updated = [newItem, ...collection];
    setCollection(updated);
    localStorage.setItem('curator_collection', JSON.stringify(updated));
    setActiveTab('COLLECTION');
    setSelectedItem(null);
  };

  const updateCollectionItem = (result: AppraisalResult) => {
      // If we are viewing an existing item and "save" is clicked, we essentially update it.
      // Since ItemResult returns an AppraisalResult, we merge it with the existing ID.
      if (!selectedItem) return;

      const updatedItems = collection.map(item => {
          if (item.id === selectedItem.id) {
              return { ...item, ...result };
          }
          return item;
      });
      setCollection(updatedItems);
      localStorage.setItem('curator_collection', JSON.stringify(updatedItems));
      setSelectedItem(null); // Go back to list
  };

  const deleteItem = (id: string) => {
    const updated = collection.filter(i => i.id !== id);
    setCollection(updated);
    localStorage.setItem('curator_collection', JSON.stringify(updated));
    if (selectedItem?.id === id) setSelectedItem(null);
  };

  const renderContent = () => {
    // If an item is selected from the vault, show the full analysis view
    if (activeTab === 'COLLECTION' && selectedItem) {
        return (
            <ItemResult 
                result={selectedItem} 
                imageData={selectedItem.imageUrl} 
                onBack={() => setSelectedItem(null)}
                onSave={updateCollectionItem} // Treat "Save" as "Update"
            />
        );
    }

    switch (activeTab) {
      case 'SCAN': return <Scanner onSave={saveToCollection} />;
      case 'COLLECTION': return <CollectionManager items={collection} onDelete={deleteItem} onSelect={setSelectedItem} />;
      case 'MARKET': return <MarketTrends items={collection} />;
      default: return <Scanner onSave={saveToCollection} />;
    }
  };

  return (
    // Dark mode container
    <div className="flex flex-col h-[100dvh] w-full bg-zinc-950 text-zinc-100 selection:bg-blue-500/30">

      {/* Main Content Area */}
      <main className="flex-1 relative overflow-hidden flex flex-col">
        {renderContent()}
      </main>

      {/* Bottom Navigation - Dark Industrial Style */}
      {/* Hide nav when viewing detailed item to give full immersion */}
      {!(activeTab === 'COLLECTION' && selectedItem) && (
          <nav className="bg-zinc-950 border-t border-zinc-800 px-6 pb-[calc(12px+env(safe-area-inset-bottom))] pt-3 flex justify-between items-end z-50 shadow-[0_-10px_40px_rgba(0,0,0,0.5)]">
            <button 
              onClick={() => setActiveTab('COLLECTION')}
              className={`flex flex-col items-center gap-1.5 p-2 transition-all duration-300 ${activeTab === 'COLLECTION' ? 'text-white scale-105' : 'text-zinc-600 hover:text-zinc-400'}`}
            >
              <Box size={22} strokeWidth={activeTab === 'COLLECTION' ? 2.5 : 2} />
              <span className="text-[9px] font-bold tracking-widest uppercase">Vault</span>
            </button>

            <div className="relative -top-6">
              <button 
                onClick={() => setActiveTab('SCAN')}
                className="w-16 h-16 bg-gradient-to-br from-blue-600 to-violet-600 rounded-2xl text-white shadow-lg shadow-blue-600/20 flex items-center justify-center hover:brightness-110 transition-transform active:scale-95 border border-white/10 ring-4 ring-zinc-950"
              >
                <ScanLine size={28} strokeWidth={2.5} />
              </button>
            </div>

            <button 
              onClick={() => setActiveTab('MARKET')}
              className={`flex flex-col items-center gap-1.5 p-2 transition-all duration-300 ${activeTab === 'MARKET' ? 'text-white scale-105' : 'text-zinc-600 hover:text-zinc-400'}`}
            >
              <BarChart3 size={22} strokeWidth={activeTab === 'MARKET' ? 2.5 : 2} />
              <span className="text-[9px] font-bold tracking-widest uppercase">Intel</span>
            </button>
          </nav>
      )}
    </div>
  );
};

