// Typewriter Component
const TypewriterText: React.FC<{ text: string; delay?: number }> = ({ text, delay = 0 }) => {
  const [displayed, setDisplayed] = useState('');
  useEffect(() => {
    let i = 0;
    const startTimeout = setTimeout(() => {
        const interval = setInterval(() => {
            setDisplayed(text.substring(0, i));
            i++;
            if (i > text.length) clearInterval(interval);
        }, 10); 
        return () => clearInterval(interval);
    }, delay);
    return () => clearTimeout(startTimeout);
  }, [text, delay]);
  return <span>{displayed}<span className="cursor-blink text-blue-500">_</span></span>;
};

type ViewMode = 'EXPLORE' | 'DETAILS' | 'RESTORE';
type DetailTab = 'ANALYSIS' | 'FINANCIAL' | 'PROVENANCE' | 'TOOLS';

export const ItemResult: React.FC<ItemResultProps> = ({ result, imageData, onBack, onSave }) => {
  const [currentResult, setCurrentResult] = useState(result); // Local state for edits
  const [showChat, setShowChat] = useState(false);
  const [chatInput, setChatInput] = useState("");
  const [chatHistory, setChatHistory] = useState<{role:string, text:string}[]>([]);
  const [isChatLoading, setIsChatLoading] = useState(false);

  const [activeHotspot, setActiveHotspot] = useState<VisualHotspot | null>(null);
  const [viewMode, setViewMode] = useState<ViewMode>('EXPLORE');
  const [detailTab, setDetailTab] = useState<DetailTab>('ANALYSIS');

  // Tool State
  const [activeTool, setActiveTool] = useState<string | null>(null);
  const [toolOutput, setToolOutput] = useState<string | null>(null);
  const [isToolLoading, setIsToolLoading] = useState(false);

  // Use primary image or the first in the evidence chain
  const displayImage = currentResult.images && currentResult.images.length > 0 ? currentResult.images[0] : imageData;
  const [activeEvidenceImage, setActiveEvidenceImage] = useState(displayImage);

  // Intelligent Prompts State
  const [prompts, setPrompts] = useState<string[]>(result.insightfulPrompts || []);
  const [isCyclingPrompts, setIsCyclingPrompts] = useState(false);

  // Sync state if props change (unlikely in this flow but good practice)
  useEffect(() => { setCurrentResult(result); }, [result]);

  // Determine Rarity Colors
  const isRare = currentResult.rarityScore > 7;
  const rarityColorClass = isRare ? 'text-amber-400 border-amber-500/50' : 'text-blue-400 border-blue-500/50';

  useEffect(() => {
    soundManager.playLock(isRare ? 'high' : 'standard');
  }, []);

  const handleChat = async (text?: string) => {
    const q = text || chatInput;
    if (!q) return;

    setChatInput("");
    if (!showChat) setShowChat(true);
    soundManager.playClick();

    setChatHistory(prev => [...prev, { role: 'user', text: q }]);
    setIsChatLoading(true);
    try {
        const ans = await askCurator(currentResult, q);
        setChatHistory(prev => [...prev, { role: 'model', text: ans }]);
    } catch {
        setChatHistory(prev => [...prev, { role: 'model', text: "Connection severed. Cannot retrieve data." }]);
    }
    setIsChatLoading(false);
    soundManager.playLock();
  };

  const executeTool = async (toolId: string) => {
      setActiveTool(toolId);
      setToolOutput(null);
      setIsToolLoading(true);
      soundManager.playClick();

      try {
          const output = await executeItemTool(currentResult, toolId);
          setToolOutput(output);
          soundManager.playLock();
      } catch (e) {
          setToolOutput("Module Error. AI Service Unreachable.");
      } finally {
          setIsToolLoading(false);
      }
  };

  const cyclePrompts = async () => {
      soundManager.playClick();
      setIsCyclingPrompts(true);
      try {
          const newPrompts = await generateDynamicPrompts(currentResult);
          setPrompts(newPrompts);
      } catch (e) {
          // Fallback if offline
          setPrompts(["Analyze the craftsmanship.", "Is this a forgery?", "Who bought this originally?"]);
      }
      setIsCyclingPrompts(false);
  };

  const deleteImage = (imgToDelete: string) => {
      soundManager.playClick();
      if (!currentResult.images || currentResult.images.length <= 1) {
          alert("Cannot delete the last remaining evidence. Add more scans first.");
          return;
      }

      const updatedImages = currentResult.images.filter(img => img !== imgToDelete);

      // Update Trust Tier based on remaining images
      let newTier = 'Level 1 (Snapshot)';
      if (updatedImages.length >= 3) newTier = 'Level 3 (Verified)';
      else if (updatedImages.length === 2) newTier = 'Level 2 (Visual)';

      const updatedItem = {
          ...currentResult,
          images: updatedImages,
          imageUrl: updatedImages[0], // Ensure primary thumb exists
          provenance: {
              ...currentResult.provenance,
              trustTier: newTier as any
          }
      };

      setCurrentResult(updatedItem);
      // Determine new active image
      if (activeEvidenceImage === imgToDelete) {
          setActiveEvidenceImage(updatedImages[0]);
      }

      // Auto-save the deletion
      onSave(updatedItem);
  };

  return (
    <div className="h-full bg-black text-white font-sans overflow-hidden relative flex flex-col">

      {/* 1. TOP COMMAND BAR */}
      <div className="absolute top-0 left-0 right-0 z-50 flex justify-between items-start p-4 pt-[calc(16px+env(safe-area-inset-top))] bg-gradient-to-b from-black/90 via-black/50 to-transparent pointer-events-none">

        {/* Back Button */}
        <button 
            onClick={() => { soundManager.playClick(); onBack(); }} 
            className="pointer-events-auto p-2 group flex items-center gap-2 bg-black/40 backdrop-blur-md border border-white/10 rounded-sm hover:border-red-500/50 transition-all"
        >
            <ArrowLeft size={16} className="text-zinc-400 group-hover:text-red-400" />
            <span className="font-mono text-[10px] tracking-widest text-zinc-500 group-hover:text-red-400 transition-colors">ABORT</span>
        </button>

        {/* View Switcher */}
        <div className="flex gap-1 pointer-events-auto bg-black/40 backdrop-blur-md p-1 border border-white/10 rounded-sm">
             <button 
                onClick={() => { soundManager.playClick(); setViewMode('EXPLORE'); }} 
                className={`px-3 py-1.5 text-[9px] font-bold tracking-widest uppercase transition-all flex items-center gap-2 ${viewMode === 'EXPLORE' ? 'bg-white text-black' : 'text-zinc-500 hover:text-zinc-300'}`}
             >
                 <Crosshair size={12} /> Explore
             </button>
             <button 
                onClick={() => { soundManager.playClick(); setViewMode('RESTORE'); }} 
                className={`px-3 py-1.5 text-[9px] font-bold tracking-widest uppercase transition-all flex items-center gap-2 ${viewMode === 'RESTORE' ? 'bg-emerald-500 text-black' : 'text-zinc-500 hover:text-zinc-300'}`}
             >
                 <Wrench size={12} /> Restore
             </button>
             <button 
                onClick={() => { soundManager.playClick(); setViewMode('DETAILS'); }} 
                className={`px-3 py-1.5 text-[9px] font-bold tracking-widest uppercase transition-all flex items-center gap-2 ${viewMode === 'DETAILS' ? 'bg-white text-black' : 'text-zinc-500 hover:text-zinc-300'}`}
             >
                 <FileText size={12} /> Dossier
             </button>
        </div>

        {/* Chat Toggle */}
        <button 
            onClick={() => { soundManager.playClick(); setShowChat(true); }} 
            className="pointer-events-auto flex items-center gap-2 px-3 py-2 bg-blue-500/10 border border-blue-500/30 text-blue-400 text-[10px] font-bold uppercase tracking-widest hover:bg-blue-500 hover:text-white transition-all backdrop-blur-md rounded-sm"
        >
             <Zap size={12} /> AI
        </button>
      </div>

      {/* 2. MAIN VISUAL INTERFACE */}
      <div className={`relative w-full transition-all duration-500 ease-[cubic-bezier(0.23,1,0.32,1)] ${viewMode === 'DETAILS' ? 'h-[30vh]' : 'h-full'}`}>

          {/* Main Image Layer */}
          <div className="relative w-full h-full overflow-hidden">
             <img 
               src={viewMode === 'EXPLORE' ? activeEvidenceImage : displayImage} 
               className={`w-full h-full object-cover transition-all duration-700 ${viewMode === 'RESTORE' ? 'grayscale contrast-125 opacity-40 blur-[2px] scale-105' : 'opacity-90'}`} 
             />

             {/* Evidence Switcher Overlay (Explore Mode) */}
             {viewMode === 'EXPLORE' && currentResult.images && currentResult.images.length > 1 && (
                 <div className="absolute bottom-32 left-0 right-0 flex justify-center gap-2 z-40 pointer-events-auto px-6 overflow-x-auto pb-2 scrollbar-hide">
                     {currentResult.images.map((img, idx) => (
                         <button 
                            key={idx}
                            onClick={(e) => { e.stopPropagation(); setActiveEvidenceImage(img); }}
                            className={`w-10 h-10 rounded-sm border-2 overflow-hidden transition-all shrink-0 ${activeEvidenceImage === img ? 'border-white scale-110 shadow-[0_0_10px_white]' : 'border-white/30 opacity-70'}`}
                         >
                             <img src={img} className="w-full h-full object-cover" />
                         </button>
                     ))}
                 </div>
