import { MarketTrends } from './components/DataTerminal';
import { ItemResult } from './components/ItemResult';
import { ScanLine, Box, BarChart3 } from 'lucide-react';
import { soundManager } from './services/soundService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>('SCAN');
  const [collection, setCollection] = useState<CollectionItem[]>([]);
  const [selectedItem, setSelectedItem] = useState<CollectionItem | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('curator_collection');
    if (saved) setCollection(JSON.parse(saved));
  }, []);

  // SMART CONSOLIDATION PROTOCOL
  const saveToCollection = (result: AppraisalResult, primaryImage: string) => {
    // 1. Check for existing item (Exact match on Name + Era + Classification)
    const existingIndex = collection.findIndex(
        item => item.itemName === result.itemName && 
                item.era === result.era && 
                item.classification === result.classification
    );

    let updatedCollection = [...collection];
    let savedItem: CollectionItem;

    if (existingIndex > -1) {
        // MERGE LOGIC
        const existingItem = updatedCollection[existingIndex];

        // Merge images (deduplicate)
        const newImages = result.images || [primaryImage];
        const existingImages = existingItem.images || [existingItem.imageUrl];
        const combinedImages = Array.from(new Set([...existingImages, ...newImages]));

        // Calculate new Trust Tier
        let newTier = existingItem.provenance.trustTier;
        if (combinedImages.length >= 3) newTier = 'Level 3 (Verified)';
        else if (combinedImages.length === 2) newTier = 'Level 2 (Visual)';

        const mergedItem: CollectionItem = {
            ...existingItem,
            // Update dynamic fields with latest scan data
            valuation: result.valuation, 
            forecast: result.forecast,
            condition: result.condition, // Assume latest scan has best condition data
            conditionScore: result.conditionScore,
            // Keep static/historical fields or update if longer
            historicalContext: result.historicalContext.length > existingItem.historicalContext.length ? result.historicalContext : existingItem.historicalContext,
            // Update Evidence
            images: combinedImages,
            imageUrl: combinedImages[0], // Keep primary thumb
            provenance: {
                ...existingItem.provenance,
                trustTier: newTier as any
            },
            dateScanned: new Date().toISOString() // Bump to top of recent
        };

        updatedCollection[existingIndex] = mergedItem;
        // Move to top
        updatedCollection.splice(existingIndex, 1);
        updatedCollection.unshift(mergedItem);
        savedItem = mergedItem;
        soundManager.playLock('high'); // Distinct sound for merge/update

    } else {
        // NEW ENTRY LOGIC
        const newItem: CollectionItem = {
            ...result,
            id: crypto.randomUUID(),
            dateScanned: new Date().toISOString(),
            imageUrl: primaryImage,
            images: result.images || [primaryImage]
        };
        updatedCollection = [newItem, ...updatedCollection];
        savedItem = newItem;
        soundManager.playLock('standard');
    }

    setCollection(updatedCollection);
    localStorage.setItem('curator_collection', JSON.stringify(updatedCollection));

    // Auto-navigate to the saved item in Vault
    setSelectedItem(savedItem);
    setActiveTab('COLLECTION');
  };

  const updateCollectionItem = (result: AppraisalResult) => {
      if (!selectedItem) return;

      const updatedItems = collection.map(item => {
          if (item.id === selectedItem.id) {
              // Ensure we don't lose the ID or images if the result doesn't have them
              return { 
                  ...item, 
                  ...result, 
                  images: result.images || item.images, // specific safety check
                  id: item.id 
              };
          }
          return item;
      });
      setCollection(updatedItems);
      localStorage.setItem('curator_collection', JSON.stringify(updatedItems));

      // Update the currently selected item view seamlessly
      const updatedSelected = updatedItems.find(i => i.id === selectedItem.id);
      if (updatedSelected) setSelectedItem(updatedSelected);
  };

  const deleteItem = (id: string) => {
    const updated = collection.filter(i => i.id !== id);
    setCollection(updated);
    localStorage.setItem('curator_collection', JSON.stringify(updated));
    if (selectedItem?.id === id) setSelectedItem(null);
  };

  const renderContent = () => {
    if (activeTab === 'COLLECTION' && selectedItem) {
        return (
            <ItemResult 
                result={selectedItem} 
                imageData={selectedItem.imageUrl} 
                onBack={() => { setSelectedItem(null); setActiveTab('COLLECTION'); }}
                onSave={updateCollectionItem} 
            />
        );
    }

    switch (activeTab) {
      case 'SCAN': return <Scanner onSave={saveToCollection} />;
      case 'COLLECTION': return <CollectionManager items={collection} onDelete={deleteItem} onSelect={setSelectedItem} />;
      case 'MARKET': return <MarketTrends items={collection} />;
      default: return <Scanner onSave={saveToCollection} />;
    }
  };

  return (
    <div className="flex flex-col h-[100dvh] w-full bg-zinc-950 text-zinc-100 selection:bg-blue-500/30">

      <main className="flex-1 relative overflow-hidden flex flex-col">
        {renderContent()}
      </main>

      {/* Navigation */}
      {!(activeTab === 'COLLECTION' && selectedItem) && (
          <nav className="bg-zinc-950 border-t border-zinc-800 px-6 pb-[calc(12px+env(safe-area-inset-bottom))] pt-3 flex justify-between items-end z-50 shadow-[0_-10px_40px_rgba(0,0,0,0.5)]">
            <button 
              onClick={() => setActiveTab('COLLECTION')}
              className={`flex flex-col items-center gap-1.5 p-2 transition-all duration-300 ${activeTab === 'COLLECTION' ? 'text-white scale-105' : 'text-zinc-600 hover:text-zinc-400'}`}
            >
              <Box size={22} strokeWidth={activeTab === 'COLLECTION' ? 2.5 : 2} />
              <span className="text-[9px] font-bold tracking-widest uppercase">Vault</span>
            </button>

            <div className="relative -top-6">
              <button 
                onClick={() => setActiveTab('SCAN')}
                className="w-16 h-16 bg-gradient-to-br from-blue-600 to-violet-600 rounded-2xl text-white shadow-lg shadow-blue-600/20 flex items-center justify-center hover:brightness-110 transition-transform active:scale-95 border border-white/10 ring-4 ring-zinc-950"
              >
                <ScanLine size={28} strokeWidth={2.5} />
              </button>
            </div>

            <button 
              onClick={() => setActiveTab('MARKET')}
              className={`flex flex-col items-center gap-1.5 p-2 transition-all duration-300 ${activeTab === 'MARKET' ? 'text-white scale-105' : 'text-zinc-600 hover:text-zinc-400'}`}
            >
              <BarChart3 size={22} strokeWidth={activeTab === 'MARKET' ? 2.5 : 2} />
              <span className="text-[9px] font-bold tracking-widest uppercase">Intel</span>
            </button>
          </nav>
      )}
    </div>
  );
};

export default App;

import React, { useRef, useState, useEffect } from 'react';
import { Search, DollarSign, Fingerprint, Languages, Volume2, VolumeX, Image as ImageIcon, ScanLine, Aperture, Loader2, Shield, Camera, CheckCircle2 } from 'lucide-react';
import { analyzeItem, analyzeLiveFrame } from '../services/geminiService';
import { AppraisalResult, LiveAnalysisUpdate, LensMode } from '../types';
import { ItemResult } from './ItemResult';
import { soundManager } from '../services/soundService';

interface ScannerProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

interface SessionHistoryItem {
  id: string;
  thumbnail: string;
  data: LiveAnalysisUpdate;
}

const LENSES: { id: LensMode; label: string; icon: any; color: string; desc: string }[] = [
  { id: 'IDENTITY', label: 'ID', icon: Search, color: 'text-blue-400', desc: 'Provenance' },
  { id: 'MARKET', label: 'VALUE', icon: DollarSign, color: 'text-emerald-400', desc: 'Appraisal' },
  { id: 'FORENSICS', label: 'LOUPE', icon: Fingerprint, color: 'text-amber-400', desc: 'Details' },
  { id: 'DECIPHER', label: 'TEXT', icon: Languages, color: 'text-violet-400', desc: 'Epigraphy' },
];

const PROCESSING_STEPS = [
    "INITIALIZING NEURAL LINK...",
    "SYNTHESIZING MULTI-ANGLE DATA...",
    "VALIDATING MAKER'S MARKS...",
    "CALCULATING GLOBAL MARKET VALUE..."
];

const PASSPORT_STEPS = [
    { label: "FRONT VIEW", instruction: "Capture the full item, centered and well-lit." },
    { label: "REVERSE / BASE", instruction: "Flip item. Capture maker's marks or signatures." },
    { label: "DETAILS / WEAR", instruction: "Close up on texture, damage, or unique features." }
];

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  // Core State
  const [activeLens, setActiveLens] = useState<LensMode>('IDENTITY');
  const [scanMode, setScanMode] = useState<'QUICK' | 'PASSPORT'>('PASSPORT'); // Default to Passport for legitimacy
  const [passportStep, setPassportStep] = useState(0);

  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [liveData, setLiveData] = useState<LiveAnalysisUpdate | null>(null);
  const [processingStep, setProcessingStep] = useState(0);

  // UI State
  const [loupePosition, setLoupePosition] = useState({ x: 50, y: 50 }); 
  const [soundEnabled, setSoundEnabled] = useState(true);
  const [flashTriggered, setFlashTriggered] = useState(false);
  const [lastScanTime, setLastScanTime] = useState(0);

  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Cycle processing text
  useEffect(() => {
    if (isAnalyzing) {
        setProcessingStep(0);
        const interval = setInterval(() => {
            setProcessingStep(p => (p + 1) % PROCESSING_STEPS.length);
        }, 1500);
        return () => clearInterval(interval);
    }
  }, [isAnalyzing]);

  // Sound Toggle
  const toggleSound = () => {
    const muted = soundManager.toggleMute();
    setSoundEnabled(!muted);
    soundManager.playClick();
  };

  // Loupe Interaction
  const handleTouchMove = (e: React.TouchEvent | React.MouseEvent) => {
    if (!containerRef.current) return;

    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

    const rect = containerRef.current.getBoundingClientRect();
    const x = ((clientX - rect.left) / rect.width) * 100;
    const y = ((clientY - rect.top) / rect.height) * 100;

    setLoupePosition({ 
        x: Math.max(10, Math.min(90, x)), 
        y: Math.max(10, Math.min(90, y)) 
    });
  };

  // Camera Init
  useEffect(() => {
    const startCamera = async () => {
      try {
        const s = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } }, audio: false 
        });
        setStream(s);
        if (videoRef.current) videoRef.current.srcObject = s;
      } catch (err) { console.error("Camera Error:", err); }
    };
    startCamera();
    return () => stream?.getTracks().forEach(t => t.stop());
  }, []);

  // Live Analysis Loop
  useEffect(() => {
    if (!stream) return;
    // Don't run live analysis if we are in the middle of a passport sequence (distracting)
    if (scanMode === 'PASSPORT' && passportStep > 0) return;

    const interval = setInterval(async () => {
      const now = Date.now();
      if (videoRef.current && !isAnalyzing && (now - lastScanTime > 1500)) {

        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth / 3; 
        canvas.height = videoRef.current.videoHeight / 3;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Smart Crop for Forensics
        if (activeLens === 'FORENSICS') {
            const w = canvas.width;
            const h = canvas.height;
            const cx = (loupePosition.x / 100) * w;
            const cy = (loupePosition.y / 100) * h;
            const cropSize = w * 0.4; 
            ctx.drawImage(videoRef.current, 
                (cx - cropSize/2) * 3, (cy - cropSize/2) * 3, cropSize * 3, cropSize * 3, 
                0, 0, w, h);
        } else {
            ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        }

        const data = canvas.toDataURL('image/jpeg', 0.5);

        try {
          if (!isAnalyzing) soundManager.playScanHum(); 
          const res = await analyzeLiveFrame(data, activeLens, liveData?.shortTitle);

          if (res.status !== 'SEARCHING' || liveData?.status === 'SEARCHING') {
              setLiveData(res);
              if (res.status === 'LOCKED') {
                  if (!liveData || liveData.shortTitle !== res.shortTitle) {
                      const isHighValue = res.valuationEstimate && (res.valuationEstimate.includes('k') || res.valuationEstimate.length > 5);
                      soundManager.playLock(isHighValue ? 'high' : 'standard');
                      if (navigator.vibrate) navigator.vibrate(50);
                  }
              }
          }
          setLastScanTime(Date.now());
        } catch(e) { }
      }
    }, 1000); 
    return () => clearInterval(interval);
  }, [stream, activeLens, loupePosition, isAnalyzing, liveData, lastScanTime, scanMode, passportStep]);

  // Main Capture Logic
  const handleCapture = async () => {
    if (!videoRef.current) return;

    // 1. Capture Frame
    soundManager.playShutter();
    if (navigator.vibrate) navigator.vibrate([20, 50, 20]);
    setFlashTriggered(true);
    setTimeout(() => setFlashTriggered(false), 300);

    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);
    const data = canvas.toDataURL('image/jpeg', 0.95);

    // 2. Logic Branch
    if (scanMode === 'QUICK') {
        // QUICK MODE: Instant Analysis
        setCapturedImages([data]);
        runAnalysis([data]);
    } else {
        // PASSPORT MODE: Accumulate Images
        const newImages = [...capturedImages, data];
        setCapturedImages(newImages);

        if (passportStep < PASSPORT_STEPS.length - 1) {
            // Advance Step
            setPassportStep(prev => prev + 1);
            soundManager.playClick();
        } else {
            // Complete - Run Analysis
            setPassportStep(0); // Reset for next time
            runAnalysis(newImages);
        }
    }
  };

  const runAnalysis = async (images: string[]) => {
      setIsAnalyzing(true);
      try {
          const result = await analyzeItem(images);
          // Auto-save immediately to Vault
          onSave(result, images[0]);
          // Reset local state (component will likely unmount)
          setIsAnalyzing(false);
          setCapturedImages([]);
      } catch (e) {
          alert("Analysis Interrupted. Please ensure network connection.");
          setIsAnalyzing(false);
          setCapturedImages([]); // Reset
      }
  };

  // Upload Logic (Gallery)
  const handleGallerySelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        soundManager.playClick();
        const files = Array.from(e.target.files);

        const imagePromises = files.map(file => {
            return new Promise<string>((resolve) => {
                const reader = new FileReader();
                reader.onloadend = () => resolve(reader.result as string);
                reader.readAsDataURL(file as Blob);
            });
        });

        try {
            const images = await Promise.all(imagePromises);
            setCapturedImages(images);
            runAnalysis(images);
        } catch (err) {
            alert("Failed to analyze images.");
            setIsAnalyzing(false);
            setCapturedImages([]);
        } finally {
            if (fileInputRef.current) fileInputRef.current.value = ''; 
        }
    }
  };

  return (
    <div 
        ref={containerRef} 
        className="relative h-full bg-black overflow-hidden select-none font-mono touch-none scan-overlay"
        onTouchMove={handleTouchMove}
        onMouseMove={handleTouchMove} 
    >
      <video ref={videoRef} autoPlay playsInline className="absolute inset-0 w-full h-full object-cover opacity-75" />

      {/* Visual Effects */}
      <div className="absolute inset-0 pointer-events-none opacity-30 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] mix-blend-overlay"></div>
      {flashTriggered && <div className="absolute inset-0 bg-white z-[60] animate-flash pointer-events-none"></div>}

      {/* === PASSPORT PROTOCOL OVERLAY === */}
      {scanMode === 'PASSPORT' && !isAnalyzing && (
          <div className="absolute top-[25%] left-0 right-0 z-30 flex justify-center pointer-events-none">
               <div className="bg-black/60 backdrop-blur-md border border-white/20 p-4 rounded-xl text-center max-w-xs animate-in slide-in-from-top-4">
                   <div className="flex justify-center mb-2">
                       <Shield size={24} className="text-blue-500 animate-pulse" />
                   </div>
                   <h3 className="text-blue-400 font-display text-lg tracking-widest">{PASSPORT_STEPS[passportStep].label}</h3>
                   <p className="text-zinc-300 text-xs font-sans mt-1">{PASSPORT_STEPS[passportStep].instruction}</p>

                   {/* Step Indicator */}
                   <div className="flex gap-2 justify-center mt-3">
                       {PASSPORT_STEPS.map((_, idx) => (
                           <div key={idx} className={`w-2 h-2 rounded-full transition-all ${idx === passportStep ? 'bg-blue-500 scale-125' : idx < passportStep ? 'bg-emerald-500' : 'bg-zinc-700'}`}></div>
                       ))}
                   </div>
               </div>
          </div>
      )}

      {/* === PROCESSING OVERLAY === */}
      {isAnalyzing && capturedImages.length > 0 && (
          <div className="absolute inset-0 z-[100] bg-zinc-950 flex flex-col items-center justify-center p-8 animate-in fade-in duration-300">
              <div className="absolute inset-0 overflow-hidden opacity-40">
                  <img src={capturedImages[0]} className="w-full h-full object-cover blur-xl scale-110" />
                  <div className="absolute inset-0 bg-black/60"></div>
              </div>

              <div className="relative w-full max-w-sm aspect-[4/5] bg-black border border-zinc-800 rounded-lg overflow-hidden shadow-2xl flex flex-col">
                   <div className="relative flex-1 overflow-hidden">
                       <img src={capturedImages[0]} className="w-full h-full object-cover" />
                       <div className="absolute inset-0 bg-gradient-to-b from-transparent via-blue-500/20 to-transparent h-[40%] animate-scanline"></div>
                       <div className="absolute top-0 left-0 right-0 h-0.5 bg-blue-400 shadow-[0_0_15px_#60a5fa] animate-scanline"></div>
                       {/* Overlay multiple thumbs if available */}
                       <div className="absolute bottom-2 left-2 flex gap-1">
                           {capturedImages.slice(1).map((img, i) => (
                               <img key={i} src={img} className="w-12 h-12 object-cover border border-white/50 rounded-sm" />
                           ))}
                       </div>
                   </div>

                   <div className="p-5 border-t border-zinc-800 bg-zinc-900/90 backdrop-blur">
                       <div className="flex items-center gap-3 mb-3">
                           <Loader2 className="animate-spin text-blue-500" size={18} />
                           <span className="text-xs font-bold text-blue-400 tracking-widest uppercase">
                               {scanMode === 'PASSPORT' ? 'AUTHENTICATING PASSPORT' : 'QUICK ANALYSIS'}
                           </span>
                       </div>
                       <h3 className="font-display text-xl text-white mb-1">PROCESSING {capturedImages.length} ANGLE{capturedImages.length > 1 ? 'S' : ''}</h3>
                       <p className="font-mono text-[10px] text-zinc-500 h-4">
                           {PROCESSING_STEPS[processingStep]}
                       </p>
                   </div>
              </div>
          </div>
      )}

      {/* === HUD (Hidden when analyzing) === */}
      {!isAnalyzing && (
        <>
            {/* Loupe (Only in Quick Mode or Idle) */}
            {scanMode === 'QUICK' && (
                <div 
                    className={`absolute w-72 h-72 border transition-all duration-150 ease-out flex items-center justify-center pointer-events-none z-30
                    ${activeLens === 'FORENSICS' 
                        ? 'border-amber-400 rounded-full shadow-[0_0_100px_rgba(251,191,36,0.3)] bg-amber-900/10 backdrop-brightness-125' 
                        : 'border-white/20 rounded-lg opacity-40'
                    }
                    `}
                    style={{ left: `${loupePosition.x}%`, top: `${loupePosition.y}%`, transform: 'translate(-50%, -50%)' }}
                >
                    <div className="absolute top-0 left-0 w-3 h-3 border-t-2 border-l-2 border-current"></div>
                    <div className="absolute top-0 right-0 w-3 h-3 border-t-2 border-r-2 border-current"></div>
                    <div className="absolute bottom-0 left-0 w-3 h-3 border-b-2 border-l-2 border-current"></div>
                    <div className="absolute bottom-0 right-0 w-3 h-3 border-b-2 border-r-2 border-current"></div>
                </div>
            )}

            {/* Top HUD */}
            <div className="absolute top-0 left-0 right-0 p-5 pt-[calc(16px+env(safe-area-inset-top))] flex justify-between items-start z-40 bg-gradient-to-b from-black via-black/80 to-transparent pointer-events-none">
                <div className="pointer-events-auto">
                    <h1 className="font-display text-xl text-white tracking-[0.2em] drop-shadow-lg">PRIME<span className="text-blue-500">_OS</span></h1>

                    {/* Mode Toggle */}
                    <div className="flex gap-2 mt-2 bg-zinc-900/80 p-1 rounded-full border border-zinc-800 inline-flex">
                        <button 
                            onClick={() => { setScanMode('QUICK'); soundManager.playClick(); }}
                            className={`px-3 py-1 text-[9px] font-bold rounded-full transition-all ${scanMode === 'QUICK' ? 'bg-zinc-700 text-white' : 'text-zinc-500'}`}
                        >
                            QUICK ID
                        </button>
                        <button 
                            onClick={() => { setScanMode('PASSPORT'); soundManager.playClick(); }}
                            className={`px-3 py-1 text-[9px] font-bold rounded-full transition-all flex items-center gap-1 ${scanMode === 'PASSPORT' ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/20' : 'text-zinc-500'}`}
                        >
                            <Shield size={10} /> PASSPORT
                        </button>
                    </div>
                </div>

                <div className="flex flex-col items-end gap-3 pointer-events-auto">
                    <button onClick={toggleSound} className="p-2.5 rounded-full bg-white/10 border border-white/10 text-zinc-300 hover:text-white hover:bg-white/20 backdrop-blur-md transition-all">
                        {soundEnabled ? <Volume2 size={14} /> : <VolumeX size={14} />}
                    </button>
                </div>
            </div>

            {/* Live Data Feed (Only Quick Mode) */}
            {scanMode === 'QUICK' && (
                <div className="absolute top-32 left-6 z-30 w-[70%] pointer-events-none">
                    {liveData && liveData.status !== 'SEARCHING' && (
                        <div className="flex flex-col gap-2 animate-in slide-in-from-left-4 fade-in duration-500">
                            <div className="flex items-center gap-2">
                                <span className={`text-[9px] font-bold uppercase tracking-widest px-1.5 py-0.5 rounded-sm ${liveData.status === 'LOCKED' ? 'bg-emerald-500 text-black' : 'bg-zinc-800 text-zinc-400'}`}>
                                    {liveData.status}
                                </span>
                            </div>
                            <h2 className="font-display text-2xl text-white leading-none drop-shadow-xl">{liveData.shortTitle}</h2>
                        </div>
                    )}
                </div>
            )}

            {/* Bottom Controls */}
            <div className="absolute bottom-0 left-0 right-0 pb-8 pt-12 bg-gradient-to-t from-black via-black/95 to-transparent z-40 flex flex-col items-center gap-6">

                {/* Lens Switcher (Only Quick Mode) */}
                {scanMode === 'QUICK' && (
                    <div className="flex gap-1 bg-zinc-900/60 p-1 border border-zinc-800/50 backdrop-blur-xl rounded-full">
                        {LENSES.map((lens) => (
                            <button 
                                key={lens.id}
                                onClick={() => { setActiveLens(lens.id); soundManager.playClick(); }}
                                className={`px-4 py-2 flex items-center gap-2 rounded-full transition-all duration-300 ${activeLens === lens.id ? 'bg-white text-black' : 'text-zinc-500 hover:text-zinc-300'}`}
                            >
                                <lens.icon size={14} />
                                <span className="text-[9px] font-bold tracking-widest uppercase hidden sm:inline">{lens.label}</span>
                            </button>
                        ))}
                    </div>
                )}

                <div className="flex items-center gap-10 w-full justify-center px-8 relative pb-[env(safe-area-inset-bottom)]">
                    {/* Gallery Upload */}
                    <button 
                        onClick={() => { soundManager.playClick(); fileInputRef.current?.click(); }}
                        disabled={isAnalyzing}
                        className="w-12 h-12 rounded-full bg-zinc-900 border border-zinc-700 flex items-center justify-center text-zinc-500 hover:text-white hover:border-white hover:bg-zinc-800 transition-all active:scale-95"
                    >
                        <ImageIcon size={20} />
                    </button>

                    {/* Master Capture Button */}
                    <button 
                        onClick={handleCapture}
                        disabled={isAnalyzing}
                        className="relative w-20 h-20 flex items-center justify-center group"
                    >
                        <div className={`absolute inset-0 rounded-full border-2 border-zinc-600 transition-all duration-500 ${isAnalyzing ? 'animate-spin border-dashed border-blue-500 opacity-50' : 'group-hover:border-white group-hover:scale-110'}`}></div>
                        <div className="absolute inset-2 rounded-full border border-white/10"></div>
                        <div className={`w-16 h-16 rounded-full shadow-[0_0_30px_rgba(255,255,255,0.3)] flex items-center justify-center transition-transform active:scale-90 ${scanMode === 'PASSPORT' ? 'bg-blue-600' : 'bg-white'}`}>
                            {scanMode === 'PASSPORT' ? (
                                <div className="text-white font-bold text-[10px] flex flex-col items-center leading-none">
                                    <span>STEP</span>
                                    <span className="text-sm">{passportStep + 1}/3</span>
                                </div>
                            ) : (
                                <div className="w-10 h-10 rounded-full bg-zinc-100 group-hover:scale-90 transition-transform"></div>
                            )}
                        </div>
                    </button>

                    {/* Passport Progress Preview */}
                    <button className="w-12 h-12 rounded-full bg-zinc-900 border border-zinc-700 flex items-center justify-center text-zinc-600">
                        {capturedImages.length > 0 ? (
                            <div className="relative w-full h-full rounded-full overflow-hidden">
                                <img src={capturedImages[capturedImages.length - 1]} className="w-full h-full object-cover opacity-80" />
                                <div className="absolute inset-0 flex items-center justify-center bg-black/40 text-xs font-bold text-white">
                                    {capturedImages.length}
                                </div>
                            </div>
                        ) : (
                             <Shield size={20} />
                        )}
                    </button>
                </div>
            </div>
        </>
      )}

      <input type="file" multiple accept="image/*" ref={fileInputRef} className="hidden" onChange={handleGallerySelect} />
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { CollectionItem } from '../types';
import { Search, Trash2, ArrowRight, ShieldCheck, Grip, List, Database, Lock, SlidersHorizontal, ArrowDownWideNarrow, ArrowUpNarrowWide, Clock, DollarSign, ALargeSmall, Filter, Check, X } from 'lucide-react';
import { soundManager } from '../services/soundService';

interface CollectionManagerProps {
  items: CollectionItem[];
  onDelete: (id: string) => void;
  onSelect: (item: CollectionItem) => void;
}

type SortOption = 'RECENT' | 'VALUE_HIGH' | 'VALUE_LOW' | 'ALPHA';

interface FilterState {
    minCondition: number;
    eras: string[];
    origins: string[];
}

export const CollectionManager: React.FC<CollectionManagerProps> = ({ items, onDelete, onSelect }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('list');
  const [sortBy, setSortBy] = useState<SortOption>('RECENT');
  const [showSortMenu, setShowSortMenu] = useState(false);

  // Filter State
  const [showFilterMenu, setShowFilterMenu] = useState(false);
  const [filters, setFilters] = useState<FilterState>({
      minCondition: 0,
      eras: [],
      origins: []
  });

  const totalValue = items.reduce((sum, item) => sum + item.valuation.mid, 0);

  // Derived Options for Filters
  const availableEras = useMemo(() => Array.from(new Set(items.map(i => i.era))).filter(Boolean).sort(), [items]);
  const availableOrigins = useMemo(() => Array.from(new Set(items.map(i => i.origin))).filter(Boolean).sort(), [items]);

  const activeFilterCount = (filters.minCondition > 0 ? 1 : 0) + filters.eras.length + filters.origins.length;

  // Sorting & Filtering Logic
  const filteredAndSortedItems = useMemo(() => {
      let res = items.filter(i => {
          // 1. Search Term
          const matchesSearch = i.itemName.toLowerCase().includes(searchTerm.toLowerCase()) || 
                                i.classification.toLowerCase().includes(searchTerm.toLowerCase());

          // 2. Condition Filter
          const matchesCondition = i.conditionScore >= filters.minCondition;

          // 3. Era Filter
          const matchesEra = filters.eras.length === 0 || filters.eras.includes(i.era);

          // 4. Origin Filter
          const matchesOrigin = filters.origins.length === 0 || filters.origins.includes(i.origin);

          return matchesSearch && matchesCondition && matchesEra && matchesOrigin;
      });

      return res.sort((a, b) => {
          switch (sortBy) {
              case 'VALUE_HIGH': return b.valuation.mid - a.valuation.mid;
              case 'VALUE_LOW': return a.valuation.mid - b.valuation.mid;
              case 'ALPHA': return a.itemName.localeCompare(b.itemName);
              case 'RECENT': default: return new Date(b.dateScanned).getTime() - new Date(a.dateScanned).getTime();
          }
      });
  }, [items, searchTerm, sortBy, filters]);

  const handleSortChange = (option: SortOption) => {
      soundManager.playClick();
      setSortBy(option);
      setShowSortMenu(false);
  };

  const toggleFilter = (type: 'eras' | 'origins', value: string) => {
      soundManager.playClick();
      setFilters(prev => {
          const list = prev[type];
          return {
              ...prev,
              [type]: list.includes(value) ? list.filter(v => v !== value) : [...list, value]
          };
      });
  };

  const setConditionFilter = (score: number) => {
      soundManager.playClick();
      setFilters(prev => ({ ...prev, minCondition: prev.minCondition === score ? 0 : score }));
  };

  const clearFilters = () => {
      soundManager.playClick();
      setFilters({ minCondition: 0, eras: [], origins: [] });
  };

  const getSortLabel = () => {
      switch(sortBy) {
          case 'VALUE_HIGH': return 'Highest Value';
          case 'VALUE_LOW': return 'Lowest Value';
          case 'ALPHA': return 'A - Z';
