                      <button onClick={() => handleSortChange('ALPHA')} className={`w-full text-left px-4 py-3 text-xs flex items-center gap-2 hover:bg-zinc-800 ${sortBy === 'ALPHA' ? 'text-blue-400' : 'text-zinc-300'}`}>
                          <ALargeSmall size={14} /> Name (A-Z)
