import React, { useRef, useState, useEffect } from 'react';
import { Search, DollarSign, Fingerprint, Languages, Volume2, VolumeX, Image as ImageIcon, ScanLine, Aperture, Loader2, Shield, Camera, CheckCircle2, Zap, Target } from 'lucide-react';
import { analyzeItem, analyzeLiveFrame } from '../services/geminiService';
import { AppraisalResult, LiveAnalysisUpdate, LensMode } from '../types';
import { ItemResult } from './ItemResult';
import { soundManager } from '../services/soundService';

interface ScannerProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

const LENSES: { id: LensMode; label: string; icon: any; color: string; desc: string }[] = [
  { id: 'IDENTITY', label: 'ID', icon: Search, color: 'text-blue-400', desc: 'Provenance' },
  { id: 'MARKET', label: 'VALUE', icon: DollarSign, color: 'text-emerald-400', desc: 'Appraisal' },
  { id: 'FORENSICS', label: 'LOUPE', icon: Fingerprint, color: 'text-amber-400', desc: 'Details' },
  { id: 'DECIPHER', label: 'TEXT', icon: Languages, color: 'text-violet-400', desc: 'Epigraphy' },
];

const PROCESSING_STEPS = [
    "INITIALIZING NEURAL LINK...",
    "SYNTHESIZING MULTI-ANGLE DATA...",
    "VALIDATING MAKER'S MARKS...",
    "CALCULATING GLOBAL MARKET VALUE..."
];

const PASSPORT_STEPS = [
    { label: "FRONT VIEW", instruction: "Capture the full item, centered and well-lit." },
    { label: "REVERSE / BASE", instruction: "Flip item. Capture maker's marks or signatures." },
    { label: "DETAILS / WEAR", instruction: "Close up on texture, damage, or unique features." }
];

type ScanMode = 'MANUAL' | 'LIVE' | 'PASSPORT';

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  // Core State
  const [scanMode, setScanMode] = useState<ScanMode>('MANUAL');
  const [activeLens, setActiveLens] = useState<LensMode>('IDENTITY');
  const [passportStep, setPassportStep] = useState(0);

  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [liveData, setLiveData] = useState<LiveAnalysisUpdate | null>(null);
  const [processingStep, setProcessingStep] = useState(0);

  // UI State
  const [loupePosition, setLoupePosition] = useState({ x: 50, y: 50 }); 
  const [soundEnabled, setSoundEnabled] = useState(true);
  const [flashTriggered, setFlashTriggered] = useState(false);
  const [lastScanTime, setLastScanTime] = useState(0);

  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Cycle processing text
  useEffect(() => {
    if (isAnalyzing) {
        setProcessingStep(0);
        const interval = setInterval(() => {
            setProcessingStep(p => (p + 1) % PROCESSING_STEPS.length);
        }, 1500);
        return () => clearInterval(interval);
    }
  }, [isAnalyzing]);

  // Sound Toggle
  const toggleSound = () => {
    const muted = soundManager.toggleMute();
    setSoundEnabled(!muted);
    soundManager.playClick();
  };

  // Loupe Interaction
  const handleTouchMove = (e: React.TouchEvent | React.MouseEvent) => {
    if (!containerRef.current) return;

    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

    const rect = containerRef.current.getBoundingClientRect();
    const x = ((clientX - rect.left) / rect.width) * 100;
    const y = ((clientY - rect.top) / rect.height) * 100;

    setLoupePosition({ 
        x: Math.max(10, Math.min(90, x)), 
        y: Math.max(10, Math.min(90, y)) 
    });
  };

  // Camera Init
  useEffect(() => {
    const startCamera = async () => {
      try {
        const s = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } }, audio: false 
        });
        setStream(s);
        if (videoRef.current) videoRef.current.srcObject = s;
      } catch (err) { console.error("Camera Error:", err); }
    };
    startCamera();
    return () => stream?.getTracks().forEach(t => t.stop());
  }, []);

  // Live Analysis Loop (Only runs in LIVE mode)
  useEffect(() => {
    if (!stream) return;
    if (scanMode !== 'LIVE') return; // Optimized: Do not run AI loop in Manual/Passport modes

    const interval = setInterval(async () => {
      const now = Date.now();
      if (videoRef.current && !isAnalyzing && (now - lastScanTime > 1500)) {

        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth / 3; 
        canvas.height = videoRef.current.videoHeight / 3;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Smart Crop for Forensics
        if (activeLens === 'FORENSICS') {
            const w = canvas.width;
            const h = canvas.height;
            const cx = (loupePosition.x / 100) * w;
            const cy = (loupePosition.y / 100) * h;
            const cropSize = w * 0.4; 
            ctx.drawImage(videoRef.current, 
                (cx - cropSize/2) * 3, (cy - cropSize/2) * 3, cropSize * 3, cropSize * 3, 
                0, 0, w, h);
        } else {
            ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        }

        const data = canvas.toDataURL('image/jpeg', 0.5);

        try {
          if (!isAnalyzing) soundManager.playScanHum(); 
          const res = await analyzeLiveFrame(data, activeLens, liveData?.shortTitle);

          if (res.status !== 'SEARCHING' || liveData?.status === 'SEARCHING') {
              setLiveData(res);
              if (res.status === 'LOCKED') {
                  if (!liveData || liveData.shortTitle !== res.shortTitle) {
                      const isHighValue = res.valuationEstimate && (res.valuationEstimate.includes('k') || res.valuationEstimate.length > 5);
                      soundManager.playLock(isHighValue ? 'high' : 'standard');
                      if (navigator.vibrate) navigator.vibrate(50);
                  }
              }
          }
          setLastScanTime(Date.now());
        } catch(e) { }
      }
    }, 1000); 
    return () => clearInterval(interval);
  }, [stream, activeLens, loupePosition, isAnalyzing, liveData, lastScanTime, scanMode]);

  // Main Capture Logic
  const handleCapture = async () => {
    if (!videoRef.current) return;

    // 1. Capture Frame
    soundManager.playShutter();
    if (navigator.vibrate) navigator.vibrate([20, 50, 20]);
    setFlashTriggered(true);
    setTimeout(() => setFlashTriggered(false), 300);

    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);
    const data = canvas.toDataURL('image/jpeg', 0.95);

    // 2. Logic Branch
    if (scanMode === 'PASSPORT') {
        // PASSPORT MODE: Accumulate Images
        const newImages = [...capturedImages, data];
        setCapturedImages(newImages);

        if (passportStep < PASSPORT_STEPS.length - 1) {
            setPassportStep(prev => prev + 1);
            soundManager.playClick();
        } else {
            setPassportStep(0); // Reset for next time
            runAnalysis(newImages);
        }
    } else {
        // MANUAL & LIVE: Single shot instant analysis
        setCapturedImages([data]);
        runAnalysis([data]);
    }
  };

  const runAnalysis = async (images: string[]) => {
      setIsAnalyzing(true);
      try {
          const result = await analyzeItem(images);
          // Auto-save immediately to Vault
          onSave(result, images[0]);
          // Reset local state (component will likely unmount)
          setIsAnalyzing(false);
          setCapturedImages([]);
      } catch (e) {
          alert("Analysis Interrupted. Please ensure network connection.");
          setIsAnalyzing(false);
          setCapturedImages([]); // Reset
      }
  };

  // Upload Logic (Gallery)
  const handleGallerySelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        soundManager.playClick();
        const files = Array.from(e.target.files);

        const imagePromises = files.map(file => {
            return new Promise<string>((resolve) => {
                const reader = new FileReader();
                reader.onloadend = () => resolve(reader.result as string);
                reader.readAsDataURL(file as Blob);
            });
        });

        try {
            const images = await Promise.all(imagePromises);
            setCapturedImages(images);
            runAnalysis(images);
        } catch (err) {
            alert("Failed to analyze images.");
            setIsAnalyzing(false);
            setCapturedImages([]);
        } finally {
            if (fileInputRef.current) fileInputRef.current.value = ''; 
        }
    }
  };

  const switchMode = (mode: ScanMode) => {
    setScanMode(mode);
    setCapturedImages([]);
    setPassportStep(0);
    soundManager.playClick();
  };

  return (
    <div 
        ref={containerRef} 
        className="relative h-full bg-black overflow-hidden select-none font-mono touch-none scan-overlay"
        onTouchMove={handleTouchMove}
        onMouseMove={handleTouchMove} 
    >
      <video ref={videoRef} autoPlay playsInline className="absolute inset-0 w-full h-full object-cover opacity-75" />

      {/* Visual Effects */}
      <div className="absolute inset-0 pointer-events-none opacity-30 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] mix-blend-overlay"></div>
      {flashTriggered && <div className="absolute inset-0 bg-white z-[60] animate-flash pointer-events-none"></div>}

      {/* === MANUAL MODE RETICLE === */}
      {scanMode === 'MANUAL' && !isAnalyzing && (
          <div className="absolute inset-8 border border-white/20 rounded-lg pointer-events-none z-10">
              <div className="absolute top-0 left-0 w-4 h-4 border-t-2 border-l-2 border-white"></div>
              <div className="absolute top-0 right-0 w-4 h-4 border-t-2 border-r-2 border-white"></div>
              <div className="absolute bottom-0 left-0 w-4 h-4 border-b-2 border-l-2 border-white"></div>
              <div className="absolute bottom-0 right-0 w-4 h-4 border-b-2 border-r-2 border-white"></div>
              <div className="absolute inset-0 flex items-center justify-center opacity-30">
                  <Target size={32} strokeWidth={1} />
              </div>
          </div>
      )}

      {/* === PASSPORT PROTOCOL OVERLAY === */}
      {scanMode === 'PASSPORT' && !isAnalyzing && (
          <div className="absolute top-[25%] left-0 right-0 z-30 flex justify-center pointer-events-none">
               <div className="bg-black/60 backdrop-blur-md border border-white/20 p-4 rounded-xl text-center max-w-xs animate-in slide-in-from-top-4">
                   <div className="flex justify-center mb-2">
                       <Shield size={24} className="text-blue-500 animate-pulse" />
                   </div>
                   <h3 className="text-blue-400 font-display text-lg tracking-widest">{PASSPORT_STEPS[passportStep].label}</h3>
                   <p className="text-zinc-300 text-xs font-sans mt-1">{PASSPORT_STEPS[passportStep].instruction}</p>

                   {/* Step Indicator */}
                   <div className="flex gap-2 justify-center mt-3">
                       {PASSPORT_STEPS.map((_, idx) => (
                           <div key={idx} className={`w-2 h-2 rounded-full transition-all ${idx === passportStep ? 'bg-blue-500 scale-125' : idx < passportStep ? 'bg-emerald-500' : 'bg-zinc-700'}`}></div>
                       ))}
                   </div>
               </div>
          </div>
      )}

      {/* === PROCESSING OVERLAY === */}
      {isAnalyzing && capturedImages.length > 0 && (
          <div className="absolute inset-0 z-[100] bg-zinc-950 flex flex-col items-center justify-center p-8 animate-in fade-in duration-300">
              <div className="absolute inset-0 overflow-hidden opacity-40">
                  <img src={capturedImages[0]} className="w-full h-full object-cover blur-xl scale-110" />
                  <div className="absolute inset-0 bg-black/60"></div>
              </div>

              <div className="relative w-full max-w-sm aspect-[4/5] bg-black border border-zinc-800 rounded-lg overflow-hidden shadow-2xl flex flex-col">
                   <div className="relative flex-1 overflow-hidden">
                       <img src={capturedImages[0]} className="w-full h-full object-cover" />
                       <div className="absolute inset-0 bg-gradient-to-b from-transparent via-blue-500/20 to-transparent h-[40%] animate-scanline"></div>
                       <div className="absolute top-0 left-0 right-0 h-0.5 bg-blue-400 shadow-[0_0_15px_#60a5fa] animate-scanline"></div>
                       {/* Overlay multiple thumbs if available */}
                       <div className="absolute bottom-2 left-2 flex gap-1">
                           {capturedImages.slice(1).map((img, i) => (
                               <img key={i} src={img} className="w-12 h-12 object-cover border border-white/50 rounded-sm" />
                           ))}
                       </div>
                   </div>

                   <div className="p-5 border-t border-zinc-800 bg-zinc-900/90 backdrop-blur">
                       <div className="flex items-center gap-3 mb-3">
                           <Loader2 className="animate-spin text-blue-500" size={18} />
                           <span className="text-xs font-bold text-blue-400 tracking-widest uppercase">
                               {scanMode === 'PASSPORT' ? 'AUTHENTICATING PASSPORT' : 'ANALYZING ASSET'}
                           </span>
                       </div>
                       <h3 className="font-display text-xl text-white mb-1">PROCESSING {capturedImages.length} ANGLE{capturedImages.length > 1 ? 'S' : ''}</h3>
                       <p className="font-mono text-[10px] text-zinc-500 h-4">
                           {PROCESSING_STEPS[processingStep]}
                       </p>
                   </div>
              </div>
          </div>
      )}

      {/* === HUD (Hidden when analyzing) === */}
      {!isAnalyzing && (
        <>
            {/* Loupe (Only in LIVE Mode) */}
            {scanMode === 'LIVE' && (
                <div 
                    className={`absolute w-72 h-72 border transition-all duration-150 ease-out flex items-center justify-center pointer-events-none z-30
                    ${activeLens === 'FORENSICS' 
                        ? 'border-amber-400 rounded-full shadow-[0_0_100px_rgba(251,191,36,0.3)] bg-amber-900/10 backdrop-brightness-125' 
                        : 'border-white/20 rounded-lg opacity-40'
                    }
                    `}
                    style={{ left: `${loupePosition.x}%`, top: `${loupePosition.y}%`, transform: 'translate(-50%, -50%)' }}
                >
                    <div className="absolute top-0 left-0 w-3 h-3 border-t-2 border-l-2 border-current"></div>
                    <div className="absolute top-0 right-0 w-3 h-3 border-t-2 border-r-2 border-current"></div>
                    <div className="absolute bottom-0 left-0 w-3 h-3 border-b-2 border-l-2 border-current"></div>
                    <div className="absolute bottom-0 right-0 w-3 h-3 border-b-2 border-r-2 border-current"></div>
                </div>
            )}

            {/* Top HUD */}
            <div className="absolute top-0 left-0 right-0 p-5 pt-[calc(16px+env(safe-area-inset-top))] flex justify-between items-start z-40 bg-gradient-to-b from-black via-black/80 to-transparent pointer-events-none">
                <div className="pointer-events-auto">
                    <h1 className="font-display text-xl text-white tracking-[0.2em] drop-shadow-lg mb-2">PRIME<span className="text-blue-500">_OS</span></h1>

                    {/* Mode Toggle */}
                    <div className="flex gap-1 bg-zinc-900/80 p-1 rounded-md border border-zinc-800 inline-flex backdrop-blur-md">
                        <button 
                            onClick={() => switchMode('MANUAL')}
