                        >
                            <Camera size={10} /> MANUAL
                        </button>
                        <button 
                            onClick={() => switchMode('LIVE')}
                            className={`px-3 py-1.5 text-[9px] font-bold rounded-sm transition-all flex items-center gap-1 ${scanMode === 'LIVE' ? 'bg-amber-500 text-black' : 'text-zinc-500 hover:text-white'}`}
                        >
                            <Zap size={10} /> LIVE
                        </button>
                        <button 
                            onClick={() => switchMode('PASSPORT')}
                            className={`px-3 py-1.5 text-[9px] font-bold rounded-sm transition-all flex items-center gap-1 ${scanMode === 'PASSPORT' ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/20' : 'text-zinc-500 hover:text-white'}`}
                        >
                            <Shield size={10} /> PASSPORT
                        </button>
                    </div>
                </div>

                <div className="flex flex-col items-end gap-3 pointer-events-auto">
                    <button onClick={toggleSound} className="p-2.5 rounded-full bg-white/10 border border-white/10 text-zinc-300 hover:text-white hover:bg-white/20 backdrop-blur-md transition-all">
                        {soundEnabled ? <Volume2 size={14} /> : <VolumeX size={14} />}
                    </button>
                </div>
            </div>

            {/* Live Data Feed (Only LIVE Mode) */}
            {scanMode === 'LIVE' && (
                <div className="absolute top-32 left-6 z-30 w-[70%] pointer-events-none">
                    {liveData && liveData.status !== 'SEARCHING' && (
                        <div className="flex flex-col gap-2 animate-in slide-in-from-left-4 fade-in duration-500">
                            <div className="flex items-center gap-2">
                                <span className={`text-[9px] font-bold uppercase tracking-widest px-1.5 py-0.5 rounded-sm ${liveData.status === 'LOCKED' ? 'bg-emerald-500 text-black' : 'bg-zinc-800 text-zinc-400'}`}>
                                    {liveData.status}
                                </span>
                            </div>
                            <h2 className="font-display text-2xl text-white leading-none drop-shadow-xl">{liveData.shortTitle}</h2>
                        </div>
                    )}
                </div>
            )}

            {/* Bottom Controls */}
            <div className="absolute bottom-0 left-0 right-0 pb-8 pt-12 bg-gradient-to-t from-black via-black/95 to-transparent z-40 flex flex-col items-center gap-6">

                {/* Lens Switcher (Only LIVE Mode) */}
                {scanMode === 'LIVE' && (
                    <div className="flex gap-1 bg-zinc-900/60 p-1 border border-zinc-800/50 backdrop-blur-xl rounded-full animate-in slide-in-from-bottom-4 fade-in">
                        {LENSES.map((lens) => (
                            <button 
                                key={lens.id}
                                onClick={() => { setActiveLens(lens.id); soundManager.playClick(); }}
                                className={`px-4 py-2 flex items-center gap-2 rounded-full transition-all duration-300 ${activeLens === lens.id ? 'bg-white text-black' : 'text-zinc-500 hover:text-zinc-300'}`}
                            >
                                <lens.icon size={14} />
                                <span className="text-[9px] font-bold tracking-widest uppercase hidden sm:inline">{lens.label}</span>
