                    </button>
                </div>
            </div>
        </>
      )}

      <input type="file" multiple accept="image/*" ref={fileInputRef} className="hidden" onChange={handleGallerySelect} />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppTab, CollectionItem, AppraisalResult } from './types';
import { Scanner } from './components/ScanTerminal';
import { CollectionManager } from './components/VaultTerminal';
import { MarketTrends } from './components/DataTerminal';
import { ItemResult } from './components/ItemResult';
import { ScanLine, Box, BarChart3, Hexagon } from 'lucide-react';
import { soundManager } from './services/soundService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>('SCAN');
  const [collection, setCollection] = useState<CollectionItem[]>([]);
  const [selectedItem, setSelectedItem] = useState<CollectionItem | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('curator_collection');
    if (saved) setCollection(JSON.parse(saved));
  }, []);

  const saveToCollection = (result: AppraisalResult, primaryImage: string) => {
    // 1. Check for existing item (Exact match on Name + Era + Classification)
    const existingIndex = collection.findIndex(
        item => item.itemName === result.itemName && 
                item.era === result.era && 
                item.classification === result.classification
    );

    let updatedCollection = [...collection];
    let savedItem: CollectionItem;

    if (existingIndex > -1) {
        // MERGE LOGIC
        const existingItem = updatedCollection[existingIndex];
        const newImages = result.images || [primaryImage];
        const existingImages = existingItem.images || [existingItem.imageUrl];
        const combinedImages = Array.from(new Set([...existingImages, ...newImages]));

        let newTier = existingItem.provenance.trustTier;
        if (combinedImages.length >= 3) newTier = 'Level 3 (Verified)';
        else if (combinedImages.length === 2) newTier = 'Level 2 (Visual)';

        const mergedItem: CollectionItem = {
            ...existingItem,
            valuation: result.valuation, 
            forecast: result.forecast,
            condition: result.condition,
            conditionScore: result.conditionScore,
            historicalContext: result.historicalContext.length > existingItem.historicalContext.length ? result.historicalContext : existingItem.historicalContext,
            images: combinedImages,
            imageUrl: combinedImages[0],
            provenance: {
                ...existingItem.provenance,
                trustTier: newTier as any
            },
            dateScanned: new Date().toISOString()
        };

        updatedCollection[existingIndex] = mergedItem;
        updatedCollection.splice(existingIndex, 1);
        updatedCollection.unshift(mergedItem);
        savedItem = mergedItem;
        soundManager.playLock('high');

    } else {
        // NEW ENTRY LOGIC
        const newItem: CollectionItem = {
            ...result,
            id: crypto.randomUUID(),
            dateScanned: new Date().toISOString(),
            imageUrl: primaryImage,
            images: result.images || [primaryImage]
        };
        updatedCollection = [newItem, ...updatedCollection];
        savedItem = newItem;
        soundManager.playLock('standard');
    }

    setCollection(updatedCollection);
    localStorage.setItem('curator_collection', JSON.stringify(updatedCollection));

    setSelectedItem(savedItem);
    setActiveTab('COLLECTION');
  };

  const updateCollectionItem = (result: AppraisalResult) => {
      if (!selectedItem) return;

      const updatedItems = collection.map(item => {
          if (item.id === selectedItem.id) {
              return { 
                  ...item, 
                  ...result, 
                  images: result.images || item.images,
                  id: item.id 
              };
          }
          return item;
      });
      setCollection(updatedItems);
      localStorage.setItem('curator_collection', JSON.stringify(updatedItems));

      const updatedSelected = updatedItems.find(i => i.id === selectedItem.id);
      if (updatedSelected) setSelectedItem(updatedSelected);
  };

  const deleteItem = (id: string) => {
    const updated = collection.filter(i => i.id !== id);
    setCollection(updated);
    localStorage.setItem('curator_collection', JSON.stringify(updated));
    if (selectedItem?.id === id) setSelectedItem(null);
  };

  const renderContent = () => {
    if (activeTab === 'COLLECTION' && selectedItem) {
        return (
            <ItemResult 
                result={selectedItem} 
                imageData={selectedItem.imageUrl} 
                onBack={() => { setSelectedItem(null); setActiveTab('COLLECTION'); }}
                onSave={updateCollectionItem} 
            />
        );
    }

    switch (activeTab) {
      case 'SCAN': return <Scanner onSave={saveToCollection} />;
      case 'COLLECTION': return <CollectionManager items={collection} onDelete={deleteItem} onSelect={setSelectedItem} />;
      case 'MARKET': return <MarketTrends items={collection} />;
      default: return <Scanner onSave={saveToCollection} />;
    }
  };

  return (
    <div className="flex flex-col h-[100dvh] w-full bg-black text-zinc-100 font-sans selection:bg-white/20">

      {/* Global Ambient Glow */}
      <div className="fixed inset-0 pointer-events-none z-0">
          <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-blue-900/10 blur-[120px] rounded-full mix-blend-screen"></div>
          <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-emerald-900/10 blur-[120px] rounded-full mix-blend-screen"></div>
      </div>

      <main className="flex-1 relative overflow-hidden flex flex-col z-10">
        {renderContent()}
      </main>

      {/* Floating Island Navigation */}
      {!(activeTab === 'COLLECTION' && selectedItem) && (
          <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-50 animate-in slide-in-from-bottom-8 duration-500">
             <div className="bg-black/80 backdrop-blur-xl border border-white/10 rounded-full px-2 py-2 flex items-center gap-1 shadow-[0_20px_40px_rgba(0,0,0,0.6)] ring-1 ring-white/5">

                <button 
                  onClick={() => { setActiveTab('COLLECTION'); soundManager.playClick(); }}
                  className={`w-12 h-12 rounded-full flex items-center justify-center transition-all duration-300 relative group ${activeTab === 'COLLECTION' ? 'bg-zinc-800 text-white' : 'text-zinc-500 hover:text-zinc-300 hover:bg-white/5'}`}
                >
                  <Box size={20} strokeWidth={activeTab === 'COLLECTION' ? 2 : 1.5} />
                  {activeTab === 'COLLECTION' && <div className="absolute -bottom-1 w-1 h-1 bg-white rounded-full"></div>}
                </button>

                <button 
                  onClick={() => { setActiveTab('SCAN'); soundManager.playClick(); }}
                  className={`w-16 h-16 rounded-full flex items-center justify-center transition-all duration-300 mx-2 shadow-lg relative ${activeTab === 'SCAN' ? 'bg-white text-black scale-110 shadow-white/10' : 'bg-zinc-900 text-zinc-400 border border-white/10'}`}
                >
                  <ScanLine size={24} strokeWidth={2} />
                  {activeTab === 'SCAN' && <div className="absolute inset-0 rounded-full border border-black/10"></div>}
                </button>

                <button 
                  onClick={() => { setActiveTab('MARKET'); soundManager.playClick(); }}
                  className={`w-12 h-12 rounded-full flex items-center justify-center transition-all duration-300 relative group ${activeTab === 'MARKET' ? 'bg-zinc-800 text-white' : 'text-zinc-500 hover:text-zinc-300 hover:bg-white/5'}`}
                >
                  <BarChart3 size={20} strokeWidth={activeTab === 'MARKET' ? 2 : 1.5} />
                  {activeTab === 'MARKET' && <div className="absolute -bottom-1 w-1 h-1 bg-white rounded-full"></div>}
                </button>

             </div>
          </div>
      )}
    </div>
  );
};

export default App;

import React, { useRef, useState, useEffect } from 'react';
import { Search, DollarSign, Fingerprint, Languages, Volume2, VolumeX, Image as ImageIcon, Shield, Camera, Zap, Target, X, ChevronRight, Layers } from 'lucide-react';
import { analyzeItem, analyzeLiveFrame } from '../services/geminiService';
import { AppraisalResult, LiveAnalysisUpdate, LensMode } from '../types';
import { soundManager } from '../services/soundService';

interface ScannerProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

const LENSES: { id: LensMode; label: string; icon: any; }[] = [
  { id: 'IDENTITY', label: 'Identity', icon: Search },
  { id: 'MARKET', label: 'Valuation', icon: DollarSign },
  { id: 'FORENSICS', label: 'Forensics', icon: Fingerprint },
  { id: 'DECIPHER', label: 'Text', icon: Languages },
];

const PASSPORT_STEPS = [
    { label: "PRIMARY ANGLE", instruction: "Align item within the frame." },
    { label: "MAKER'S MARK", instruction: "Capture signature or base markings." },
    { label: "FINE DETAILS", instruction: "Focus on texture or unique wear." }
];

type ScanMode = 'MANUAL' | 'LIVE' | 'PASSPORT';

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  const [scanMode, setScanMode] = useState<ScanMode>('MANUAL');
  const [activeLens, setActiveLens] = useState<LensMode>('IDENTITY');
  const [passportStep, setPassportStep] = useState(0);

  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [liveData, setLiveData] = useState<LiveAnalysisUpdate | null>(null);

  const [loupePosition, setLoupePosition] = useState({ x: 50, y: 50 }); 
  const [soundEnabled, setSoundEnabled] = useState(true);
  const [flashTriggered, setFlashTriggered] = useState(false);
  const [lastScanTime, setLastScanTime] = useState(0);

  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const toggleSound = () => {
    const muted = soundManager.toggleMute();
    setSoundEnabled(!muted);
    soundManager.playClick();
  };

  const handleTouchMove = (e: React.TouchEvent | React.MouseEvent) => {
    if (!containerRef.current) return;
    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
    const rect = containerRef.current.getBoundingClientRect();
    const x = ((clientX - rect.left) / rect.width) * 100;
    const y = ((clientY - rect.top) / rect.height) * 100;
    setLoupePosition({ x: Math.max(10, Math.min(90, x)), y: Math.max(10, Math.min(90, y)) });
  };

  useEffect(() => {
    const startCamera = async () => {
      try {
        const s = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } }, audio: false 
        });
        setStream(s);
        if (videoRef.current) videoRef.current.srcObject = s;
      } catch (err) { console.error("Camera Error:", err); }
    };
    startCamera();
    return () => stream?.getTracks().forEach(t => t.stop());
  }, []);

  useEffect(() => {
    if (!stream || scanMode !== 'LIVE') return;
    const interval = setInterval(async () => {
      const now = Date.now();
      if (videoRef.current && !isAnalyzing && (now - lastScanTime > 1500)) {
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth / 3; 
        canvas.height = videoRef.current.videoHeight / 3;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        if (activeLens === 'FORENSICS') {
            const w = canvas.width;
            const h = canvas.height;
            const cx = (loupePosition.x / 100) * w;
            const cy = (loupePosition.y / 100) * h;
            const cropSize = w * 0.4; 
            ctx.drawImage(videoRef.current, (cx - cropSize/2) * 3, (cy - cropSize/2) * 3, cropSize * 3, cropSize * 3, 0, 0, w, h);
        } else {
            ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        }

        const data = canvas.toDataURL('image/jpeg', 0.5);
        try {
          if (!isAnalyzing) soundManager.playScanHum(); 
          const res = await analyzeLiveFrame(data, activeLens, liveData?.shortTitle);
          if (res.status !== 'SEARCHING' || liveData?.status === 'SEARCHING') {
              setLiveData(res);
              if (res.status === 'LOCKED' && (!liveData || liveData.shortTitle !== res.shortTitle)) {
                  soundManager.playLock('standard');
                  if (navigator.vibrate) navigator.vibrate(50);
              }
          }
          setLastScanTime(Date.now());
        } catch(e) { }
      }
    }, 1000); 
    return () => clearInterval(interval);
  }, [stream, activeLens, loupePosition, isAnalyzing, liveData, lastScanTime, scanMode]);

  const handleCapture = async () => {
    if (!videoRef.current) return;
    soundManager.playShutter();
    if (navigator.vibrate) navigator.vibrate([20, 50, 20]);
    setFlashTriggered(true);
    setTimeout(() => setFlashTriggered(false), 300);

    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);
    const data = canvas.toDataURL('image/jpeg', 0.95);

    if (scanMode === 'PASSPORT') {
        const newImages = [...capturedImages, data];
        setCapturedImages(newImages);
        if (passportStep < PASSPORT_STEPS.length - 1) {
            setPassportStep(prev => prev + 1);
            soundManager.playClick();
        } else {
            setPassportStep(0);
            runAnalysis(newImages);
        }
    } else {
        setCapturedImages([data]);
        runAnalysis([data]);
    }
  };

  // Fixed: The right button now acts as a Reset/Clear button
  const handleClearBatch = () => {
      if (capturedImages.length > 0) {
          soundManager.playClick();
          if (confirm("Discard current scan sequence?")) {
            setCapturedImages([]);
            setPassportStep(0);
          }
      }
  };

  const runAnalysis = async (images: string[]) => {
      setIsAnalyzing(true);
      try {
          const result = await analyzeItem(images);
          onSave(result, images[0]);
          setIsAnalyzing(false);
          setCapturedImages([]);
      } catch (e) {
          alert("Connection Lost. Analysis halted.");
          setIsAnalyzing(false);
          setCapturedImages([]);
      }
  };

  const handleGallerySelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        soundManager.playClick();
        const files = Array.from(e.target.files);
        const imagePromises = files.map(file => new Promise<string>((resolve) => {
            const reader = new FileReader();
            reader.onloadend = () => resolve(reader.result as string);
            reader.readAsDataURL(file as Blob);
        }));
        try {
            const images = await Promise.all(imagePromises);
            setCapturedImages(images);
            runAnalysis(images);
        } catch (err) { setIsAnalyzing(false); } 
        finally { if (fileInputRef.current) fileInputRef.current.value = ''; }
    }
  };

  const switchMode = (mode: ScanMode) => {
    setScanMode(mode);
    setCapturedImages([]);
    setPassportStep(0);
    soundManager.playClick();
  };

  return (
    <div 
        ref={containerRef} 
        className="relative h-full bg-black overflow-hidden select-none font-sans touch-none"
        onTouchMove={handleTouchMove}
        onMouseMove={handleTouchMove} 
    >
      <video ref={videoRef} autoPlay playsInline className="absolute inset-0 w-full h-full object-cover opacity-80" />

      {/* Cinematic Vignette & Grain */}
      <div className="absolute inset-0 pointer-events-none bg-[radial-gradient(circle_at_center,transparent_0%,rgba(0,0,0,0.4)_100%)]"></div>
      <div className="absolute inset-0 pointer-events-none opacity-[0.03] bg-[url('https://grainy-gradients.vercel.app/noise.svg')]"></div>
      {flashTriggered && <div className="absolute inset-0 bg-white z-[60] animate-flash pointer-events-none"></div>}

      {/* === MANUAL MODE RETICLE === */}
      {scanMode === 'MANUAL' && !isAnalyzing && (
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
              <div className="w-64 h-64 border border-white/30 rounded-[32px] relative flex items-center justify-center">
                  <div className="absolute top-0 left-0 w-6 h-6 border-t-2 border-l-2 border-white"></div>
                  <div className="absolute top-0 right-0 w-6 h-6 border-t-2 border-r-2 border-white"></div>
                  <div className="absolute bottom-0 left-0 w-6 h-6 border-b-2 border-l-2 border-white"></div>
                  <div className="absolute bottom-0 right-0 w-6 h-6 border-b-2 border-r-2 border-white"></div>
                  <div className="w-1 h-1 bg-white/50 rounded-full"></div>
              </div>
          </div>
      )}

      {/* === PASSPORT OVERLAY === */}
      {scanMode === 'PASSPORT' && !isAnalyzing && (
          <div className="absolute top-[20%] left-0 right-0 z-30 flex justify-center pointer-events-none">
               <div className="bg-black/40 backdrop-blur-xl border border-white/10 px-6 py-4 rounded-full text-center animate-in slide-in-from-top-4 shadow-2xl">
                   <div className="flex items-center gap-3">
                       <Shield size={16} className="text-blue-500" />
                       <div className="h-4 w-px bg-white/20"></div>
                       <div>
                           <h3 className="text-white font-bold text-xs tracking-[0.15em] uppercase">{PASSPORT_STEPS[passportStep].label}</h3>
                           <p className="text-zinc-400 text-[10px] mt-0.5">{PASSPORT_STEPS[passportStep].instruction}</p>
                       </div>
                   </div>
               </div>
          </div>
      )}

      {/* === LOADING STATE === */}
      {isAnalyzing && (
          <div className="absolute inset-0 z-[100] bg-black/90 backdrop-blur-md flex flex-col items-center justify-center p-8 animate-in fade-in duration-500">
              <div className="w-16 h-16 border-t-2 border-l-2 border-white rounded-full animate-spin mb-8"></div>
              <h3 className="font-display text-2xl text-white tracking-widest mb-2">ANALYZING</h3>
              <p className="text-zinc-500 font-mono text-xs uppercase">Processing Vector Data...</p>
          </div>
      )}

      {!isAnalyzing && (
        <>
            {/* Live Mode HUD */}
            {scanMode === 'LIVE' && (
                <div 
                    className={`absolute w-64 h-64 border transition-all duration-100 ease-linear pointer-events-none z-30
                    ${activeLens === 'FORENSICS' ? 'border-amber-500/50 rounded-full bg-amber-500/5' : 'border-white/20 rounded-lg'}
                    `}
                    style={{ left: `${loupePosition.x}%`, top: `${loupePosition.y}%`, transform: 'translate(-50%, -50%)' }}
                >
                    <div className="absolute -top-6 left-1/2 -translate-x-1/2 text-[10px] font-bold text-white/50 tracking-widest uppercase">
                        {LENSES.find(l => l.id === activeLens)?.label}
                    </div>
                </div>
            )}

            {/* Top Bar */}
            <div className="absolute top-0 left-0 right-0 p-6 pt-[calc(20px+env(safe-area-inset-top))] flex justify-between items-start z-40 bg-gradient-to-b from-black/80 to-transparent pointer-events-none">
                <div className="pointer-events-auto">
                    <div className="flex gap-1 bg-black/40 backdrop-blur-xl p-1 rounded-full border border-white/10 shadow-xl">
                        {(['MANUAL', 'LIVE', 'PASSPORT'] as ScanMode[]).map(m => (
                            <button 
                                key={m}
                                onClick={() => switchMode(m)}
                                className={`px-4 py-2 text-[10px] font-bold rounded-full transition-all ${scanMode === m ? 'bg-white text-black shadow-lg' : 'text-zinc-500 hover:text-white'}`}
                            >
                                {m}
                            </button>
                        ))}
                    </div>
                </div>

                <button onClick={toggleSound} className="pointer-events-auto w-10 h-10 rounded-full bg-black/40 backdrop-blur-md border border-white/10 flex items-center justify-center text-zinc-400 hover:text-white transition-colors">
                    {soundEnabled ? <Volume2 size={16} /> : <VolumeX size={16} />}
                </button>
            </div>

            {/* Bottom Controls */}
            <div className="absolute bottom-24 left-0 right-0 z-40 flex flex-col items-center gap-8">

                {/* Lenses (Live Mode) */}
                {scanMode === 'LIVE' && (
                    <div className="flex gap-4 overflow-x-auto px-6 py-2 pb-4 scrollbar-hide max-w-full mask-linear-fade">
                        {LENSES.map((lens) => (
                            <button 
                                key={lens.id}
                                onClick={() => { setActiveLens(lens.id); soundManager.playClick(); }}
                                className={`flex flex-col items-center gap-2 transition-all ${activeLens === lens.id ? 'opacity-100 scale-110' : 'opacity-40 hover:opacity-70'}`}
                            >
                                <div className={`w-10 h-10 rounded-full flex items-center justify-center border ${activeLens === lens.id ? 'bg-white text-black border-white' : 'bg-black/50 text-white border-white/30'}`}>
                                    <lens.icon size={16} />
                                </div>
                                <span className="text-[9px] font-bold tracking-widest uppercase text-white shadow-black drop-shadow-md">{lens.label}</span>
                            </button>
                        ))}
                    </div>
                )}

                <div className="flex items-center gap-8 w-full justify-center px-10">

                    {/* Gallery Import */}
                    <button 
                        onClick={() => { soundManager.playClick(); fileInputRef.current?.click(); }}
                        className="w-14 h-14 rounded-full bg-zinc-900/80 backdrop-blur border border-white/10 flex items-center justify-center text-zinc-400 hover:text-white hover:bg-zinc-800 transition-all active:scale-95"
                    >
                        <ImageIcon size={20} />
                    </button>

                    {/* Shutter Button */}
                    <button 
                        onClick={handleCapture}
                        className="relative w-24 h-24 flex items-center justify-center group"
                    >
                        <div className="absolute inset-0 rounded-full border border-white/20 scale-100 group-hover:scale-110 transition-transform duration-500"></div>
                        <div className="absolute inset-1 rounded-full border border-white/10"></div>
                        <div className={`w-20 h-20 rounded-full flex items-center justify-center transition-all duration-200 active:scale-90 shadow-[0_0_30px_rgba(255,255,255,0.1)] ${scanMode === 'PASSPORT' ? 'bg-blue-600 shadow-blue-900/50' : scanMode === 'LIVE' ? 'bg-amber-500 shadow-amber-900/50' : 'bg-white'}`}>
                            {scanMode === 'PASSPORT' && (
                                <div className="text-white text-[10px] font-bold">{passportStep + 1}/3</div>
                            )}
                        </div>
                    </button>

                    {/* Passport Stack Manager (Fixed Dud Button) */}
                    <button 
                        onClick={handleClearBatch}
                        disabled={capturedImages.length === 0}
                        className={`w-14 h-14 rounded-full flex items-center justify-center transition-all border
                            ${capturedImages.length > 0 
                                ? 'bg-zinc-900 text-white border-white/30 hover:border-red-500 hover:text-red-500' 
                                : 'bg-zinc-900/50 text-zinc-700 border-white/5 cursor-default'
                            }`}
                    >
                        {capturedImages.length > 0 ? (
                            <div className="relative w-full h-full flex items-center justify-center group">
                                <div className="absolute inset-0.5 rounded-full overflow-hidden opacity-50 group-hover:opacity-20 transition-opacity">
                                    <img src={capturedImages[capturedImages.length-1]} className="w-full h-full object-cover" />
                                </div>
                                <div className="relative z-10 flex flex-col items-center">
                                     <Layers size={16} />
                                     <span className="text-[9px] font-bold mt-0.5">{capturedImages.length}</span>
                                </div>
                                {/* Hover Hint */}
                                <div className="absolute -top-8 bg-red-600 text-white text-[9px] px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none">
                                    Clear Batch
                                </div>
                            </div>
                        ) : (
                            <Layers size={20} />
                        )}
                    </button>
                </div>
            </div>
        </>
      )}
      <input type="file" multiple accept="image/*" ref={fileInputRef} className="hidden" onChange={handleGallerySelect} />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppraisalResult, VisualHotspot } from '../types';
import { askCurator, generateDynamicPrompts, executeItemTool } from '../services/geminiService';
import { ArrowLeft, X, Send, Sparkles, Box, Zap, Info, Layers, Crosshair, FileText, Wrench, ShieldCheck, Users, TrendingUp, RefreshCw, MessageSquare, Terminal, Tag, Scroll, Globe, Triangle } from 'lucide-react';
import { Button } from './Button';
import { soundManager } from '../services/soundService';
import { AreaChart, Area, ResponsiveContainer, XAxis, YAxis, Tooltip } from 'recharts';

interface ItemResultProps {
  result: AppraisalResult;
  imageData: string;
  onBack: () => void;
  onSave: (result: AppraisalResult) => void;
}

const TypewriterText: React.FC<{ text: string; delay?: number }> = ({ text, delay = 0 }) => {
  const [displayed, setDisplayed] = useState('');
  useEffect(() => {
    let i = 0;
    const startTimeout = setTimeout(() => {
        const interval = setInterval(() => {
            setDisplayed(text.substring(0, i));
            i++;
            if (i > text.length) clearInterval(interval);
        }, 10); 
        return () => clearInterval(interval);
    }, delay);
    return () => clearTimeout(startTimeout);
  }, [text, delay]);
  return <span>{displayed}<span className="cursor-blink text-blue-500">_</span></span>;
};

type ViewMode = 'EXPLORE' | 'DETAILS';

export const ItemResult: React.FC<ItemResultProps> = ({ result, imageData, onBack, onSave }) => {
  const [currentResult, setCurrentResult] = useState(result);
  const [showChat, setShowChat] = useState(false);
  const [chatInput, setChatInput] = useState("");
  const [chatHistory, setChatHistory] = useState<{role:string, text:string}[]>([]);
  const [isChatLoading, setIsChatLoading] = useState(false);

  const [activeHotspot, setActiveHotspot] = useState<VisualHotspot | null>(null);
  const [viewMode, setViewMode] = useState<ViewMode>('EXPLORE');

  const [activeTool, setActiveTool] = useState<string | null>(null);
  const [toolOutput, setToolOutput] = useState<string | null>(null);
  const [isToolLoading, setIsToolLoading] = useState(false);

  const displayImage = currentResult.images && currentResult.images.length > 0 ? currentResult.images[0] : imageData;
  const [activeEvidenceImage, setActiveEvidenceImage] = useState(displayImage);
  const [prompts, setPrompts] = useState<string[]>(result.insightfulPrompts || []);
  const [isCyclingPrompts, setIsCyclingPrompts] = useState(false);

  useEffect(() => { setCurrentResult(result); }, [result]);
  useEffect(() => { soundManager.playLock(currentResult.rarityScore > 7 ? 'high' : 'standard'); }, []);

  const handleChat = async (text?: string) => {
    const q = text || chatInput;
    if (!q) return;
    setChatInput("");
    if (!showChat) setShowChat(true);
    soundManager.playClick();
    setChatHistory(prev => [...prev, { role: 'user', text: q }]);
    setIsChatLoading(true);
    try {
        const ans = await askCurator(currentResult, q);
        setChatHistory(prev => [...prev, { role: 'model', text: ans }]);
    } catch {
        setChatHistory(prev => [...prev, { role: 'model', text: "Signal Lost." }]);
    }
    setIsChatLoading(false);
    soundManager.playLock();
  };

  const executeTool = async (toolId: string) => {
      setActiveTool(toolId);
      setToolOutput(null);
      setIsToolLoading(true);
      soundManager.playClick();
      try {
          const output = await executeItemTool(currentResult, toolId);
          setToolOutput(output);
          soundManager.playLock();
      } catch (e) {
          setToolOutput("Module Offline.");
      } finally { setIsToolLoading(false); }
  };

  const cyclePrompts = async () => {
      soundManager.playClick();
      setIsCyclingPrompts(true);
      try {
          const newPrompts = await generateDynamicPrompts(currentResult);
          setPrompts(newPrompts);
      } catch (e) { setPrompts(["Market Analysis", "Authentication Protocol", "Maintenance"]); }
      setIsCyclingPrompts(false);
  };

  return (
    <div className="h-full bg-black text-white font-sans overflow-hidden relative flex flex-col">

      {/* 1. TOP NAV */}
      <div className="absolute top-0 left-0 right-0 z-50 flex justify-between items-start p-4 pt-[calc(20px+env(safe-area-inset-top))] pointer-events-none">
        <button onClick={() => { soundManager.playClick(); onBack(); }} className="pointer-events-auto p-3 rounded-full bg-black/20 backdrop-blur-md border border-white/10 hover:bg-white hover:text-black transition-colors">
            <ArrowLeft size={18} />
        </button>

        <div className="flex gap-1 pointer-events-auto bg-black/40 backdrop-blur-md p-1 border border-white/10 rounded-full shadow-lg">
             <button onClick={() => { soundManager.playClick(); setViewMode('EXPLORE'); }} className={`px-4 py-2 text-[10px] font-bold tracking-widest uppercase rounded-full transition-all ${viewMode === 'EXPLORE' ? 'bg-white text-black' : 'text-zinc-400 hover:text-white'}`}>
                 Visual
             </button>
             <button onClick={() => { soundManager.playClick(); setViewMode('DETAILS'); }} className={`px-4 py-2 text-[10px] font-bold tracking-widest uppercase rounded-full transition-all ${viewMode === 'DETAILS' ? 'bg-white text-black' : 'text-zinc-400 hover:text-white'}`}>
                 Data
             </button>
        </div>

        <button onClick={() => { soundManager.playClick(); setShowChat(true); }} className="pointer-events-auto p-3 rounded-full bg-blue-500/10 border border-blue-500/50 text-blue-400 hover:bg-blue-500 hover:text-white transition-all backdrop-blur-md">
             <Zap size={18} />
        </button>
      </div>

      {/* 2. VISUAL LAYER */}
      <div className={`relative w-full transition-all duration-700 ease-[cubic-bezier(0.87,0,0.13,1)] ${viewMode === 'DETAILS' ? 'h-[35vh] opacity-40 grayscale' : 'h-full opacity-100'}`}>
          <img src={viewMode === 'EXPLORE' ? activeEvidenceImage : displayImage} className="w-full h-full object-cover" />
          <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent"></div>

          {/* Evidence Thumbnails */}
          {viewMode === 'EXPLORE' && currentResult.images && currentResult.images.length > 1 && (
             <div className="absolute bottom-32 left-0 right-0 flex justify-center gap-3 z-40 pointer-events-auto px-6 overflow-x-auto pb-4">
                 {currentResult.images.map((img, idx) => (
                     <button key={idx} onClick={(e) => { e.stopPropagation(); setActiveEvidenceImage(img); }} className={`w-12 h-12 rounded-lg overflow-hidden transition-all border-2 ${activeEvidenceImage === img ? 'border-white scale-110 shadow-lg' : 'border-white/20 opacity-60'}`}>
                         <img src={img} className="w-full h-full object-cover" />
                     </button>
                 ))}
             </div>
          )}

          {/* Hotspots */}
          {viewMode === 'EXPLORE' && currentResult.visualHotspots?.map((spot, idx) => (
             <button key={idx} className="absolute w-12 h-12 flex items-center justify-center z-30" style={{ top: `${spot.y}%`, left: `${spot.x}%`, transform: 'translate(-50%, -50%)' }} onClick={(e) => { e.stopPropagation(); setActiveHotspot(activeHotspot === spot ? null : spot); }}>
                 <div className={`w-4 h-4 rounded-full border-2 transition-all duration-500 ${activeHotspot === spot ? 'bg-white border-white scale-125' : 'bg-black/30 border-white/80 hover:scale-110'}`}></div>
                 {activeHotspot === spot && <div className="absolute top-6 w-px h-8 bg-white/50"></div>}
             </button>
          ))}

          {/* Feature Card */}
          {activeHotspot && viewMode === 'EXPLORE' && (
              <div className="absolute top-[25%] left-1/2 -translate-x-1/2 w-64 bg-black/60 backdrop-blur-xl border border-white/20 p-5 rounded-2xl text-center animate-in zoom-in-95 duration-300">
                  <h3 className="font-display text-lg text-white mb-1">{activeHotspot.label}</h3>
                  <p className="text-xs text-zinc-300">{activeHotspot.description}</p>
              </div>
          )}

          {/* Hero Title */}
          <div className={`absolute bottom-0 left-0 right-0 p-8 transition-all duration-500 ${viewMode === 'DETAILS' ? 'translate-y-4 opacity-0' : 'translate-y-0 opacity-100'}`}>
              <div className="inline-block px-2 py-1 bg-white/10 backdrop-blur border border-white/20 rounded-md text-[9px] font-bold uppercase tracking-widest mb-3">
                  {currentResult.classification}
              </div>
              <h1 className="font-display text-4xl md:text-5xl text-white leading-none mb-2">{currentResult.itemName}</h1>
              <div className="flex gap-3 text-xs font-mono text-zinc-400">
                  <span>{currentResult.era}</span>
                  <span className="text-zinc-600">|</span>
                  <span>{currentResult.origin}</span>
              </div>
          </div>
      </div>

      {/* 3. DATA LAYER (BENTO GRID) */}
      <div className={`flex-1 bg-black relative transition-all duration-700 border-t border-white/10 ${viewMode === 'DETAILS' ? 'translate-y-0' : 'translate-y-full'}`}>
