                      <button onClick={() => handleSortChange('VALUE_HIGH')} className={`w-full text-left px-4 py-3 text-xs flex items-center gap-2 hover:bg-zinc-800 ${sortBy === 'VALUE_HIGH' ? 'text-blue-400' : 'text-zinc-300'}`}>
