          </div>
        )}

        {/* Inventory Stats */}
        <div className="grid grid-cols-2 gap-2">
           {sortedCategories.map(([cat, count], i) => (
             <div key={i} className="bg-zinc-900 p-3 border border-zinc-800 flex justify-between items-center">
               <span className="text-[9px] text-zinc-500 uppercase font-bold tracking-widest">{cat}</span>
               <span className="text-sm font-mono text-white">x{count}</span>
             </div>
           ))}
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { Search, DollarSign, Fingerprint, Languages, Volume2, VolumeX, Image as ImageIcon, Shield, Camera, Zap, Target, X, ChevronRight, Layers, Scan } from 'lucide-react';
import { analyzeItem, analyzeLiveFrame } from '../services/geminiService';
import { AppraisalResult, LiveAnalysisUpdate, LensMode } from '../types';
import { soundManager } from '../services/soundService';
import { toast } from './Toast';

interface ScannerProps {
  onSave: (result: AppraisalResult, imageData: string) => void;
}

const LENSES: { id: LensMode; label: string; icon: any; }[] = [
  { id: 'IDENTITY', label: 'Identity', icon: Search },
  { id: 'MARKET', label: 'Valuation', icon: DollarSign },
  { id: 'FORENSICS', label: 'Forensics', icon: Fingerprint },
  { id: 'DECIPHER', label: 'Text', icon: Languages },
];

const PASSPORT_STEPS = [
    { label: "PRIMARY ANGLE", instruction: "Align item within the frame." },
    { label: "MAKER'S MARK", instruction: "Capture signature or base markings." },
    { label: "FINE DETAILS", instruction: "Focus on texture or unique wear." }
];

type ScanMode = 'MANUAL' | 'LIVE' | 'PASSPORT';

export const Scanner: React.FC<ScannerProps> = ({ onSave }) => {
  const [scanMode, setScanMode] = useState<ScanMode>('MANUAL');
  const [activeLens, setActiveLens] = useState<LensMode>('IDENTITY');
  const [passportStep, setPassportStep] = useState(0);

  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [liveData, setLiveData] = useState<LiveAnalysisUpdate | null>(null);

  const [loupePosition, setLoupePosition] = useState({ x: 50, y: 50 }); 
  const [soundEnabled, setSoundEnabled] = useState(true);
  const [flashTriggered, setFlashTriggered] = useState(false);
  const [lastScanTime, setLastScanTime] = useState(0);

  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const toggleSound = () => {
    const muted = soundManager.toggleMute();
    setSoundEnabled(!muted);
    soundManager.playClick();
    toast.info(muted ? "Audio Systems Muted" : "Audio Systems Active");
  };

  const handleTouchMove = (e: React.TouchEvent | React.MouseEvent) => {
    if (!containerRef.current) return;
    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
    const rect = containerRef.current.getBoundingClientRect();
    const x = ((clientX - rect.left) / rect.width) * 100;
    const y = ((clientY - rect.top) / rect.height) * 100;
    setLoupePosition({ x: Math.max(10, Math.min(90, x)), y: Math.max(10, Math.min(90, y)) });
  };

  useEffect(() => {
    const startCamera = async () => {
      try {
        const s = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } }, audio: false 
        });
        setStream(s);
        if (videoRef.current) videoRef.current.srcObject = s;
      } catch (err) { 
          console.error("Camera Error:", err);
          toast.error("Camera Access Denied or Unavailable");
      }
    };
    startCamera();
    return () => stream?.getTracks().forEach(t => t.stop());
  }, []);

  useEffect(() => {
    if (!stream || scanMode !== 'LIVE') return;
    const interval = setInterval(async () => {
      const now = Date.now();
      if (videoRef.current && !isAnalyzing && (now - lastScanTime > 1500)) {
        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth / 3; 
        canvas.height = videoRef.current.videoHeight / 3;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        if (activeLens === 'FORENSICS') {
            const w = canvas.width;
            const h = canvas.height;
            const cx = (loupePosition.x / 100) * w;
            const cy = (loupePosition.y / 100) * h;
            const cropSize = w * 0.4; 
            ctx.drawImage(videoRef.current, (cx - cropSize/2) * 3, (cy - cropSize/2) * 3, cropSize * 3, cropSize * 3, 0, 0, w, h);
        } else {
            ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        }

        const data = canvas.toDataURL('image/jpeg', 0.5);
        try {
          if (!isAnalyzing) soundManager.playScanHum(); 
          const res = await analyzeLiveFrame(data, activeLens, liveData?.shortTitle);
          if (res.status !== 'SEARCHING' || liveData?.status === 'SEARCHING') {
              setLiveData(res);
              if (res.status === 'LOCKED' && (!liveData || liveData.shortTitle !== res.shortTitle)) {
                  soundManager.playLock('standard');
                  if (navigator.vibrate) navigator.vibrate(50);
              }
          }
          setLastScanTime(Date.now());
        } catch(e) { }
      }
    }, 1000); 
    return () => clearInterval(interval);
  }, [stream, activeLens, loupePosition, isAnalyzing, liveData, lastScanTime, scanMode]);

  const handleCapture = async () => {
    if (!videoRef.current) return;
    soundManager.playShutter();
    if (navigator.vibrate) navigator.vibrate([20, 50, 20]);
    setFlashTriggered(true);
    setTimeout(() => setFlashTriggered(false), 300);

    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);
    const data = canvas.toDataURL('image/jpeg', 0.95);

    if (scanMode === 'PASSPORT') {
        const newImages = [...capturedImages, data];
        setCapturedImages(newImages);
        if (passportStep < PASSPORT_STEPS.length - 1) {
            setPassportStep(prev => prev + 1);
            soundManager.playClick();
        } else {
            setPassportStep(0);
            runAnalysis(newImages);
        }
    } else {
        setCapturedImages([data]);
        runAnalysis([data]);
    }
  };

  const handleClearBatch = () => {
      if (capturedImages.length > 0) {
          soundManager.playClick();
          setCapturedImages([]);
          setPassportStep(0);
          toast.info("Scan Batch Cleared");
      }
  };

  const runAnalysis = async (images: string[]) => {
      setIsAnalyzing(true);
      try {
          const result = await analyzeItem(images);
          onSave(result, images[0]);
          setIsAnalyzing(false);
          setCapturedImages([]);
      } catch (e) {
          toast.error("Analysis Network Lost. Retrying...");
          setIsAnalyzing(false);
          setCapturedImages([]);
      }
  };

  const handleGallerySelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        soundManager.playClick();
        const files = Array.from(e.target.files);
        const imagePromises = files.map(file => new Promise<string>((resolve) => {
            const reader = new FileReader();
            reader.onloadend = () => resolve(reader.result as string);
            reader.readAsDataURL(file as Blob);
        }));
        try {
            const images = await Promise.all(imagePromises);
            setCapturedImages(images);
            runAnalysis(images);
        } catch (err) { setIsAnalyzing(false); } 
        finally { if (fileInputRef.current) fileInputRef.current.value = ''; }
    }
  };

  const switchMode = (mode: ScanMode) => {
    setScanMode(mode);
    setCapturedImages([]);
    setPassportStep(0);
    soundManager.playClick();
  };

  return (
    <div 
        ref={containerRef} 
        className="relative h-full bg-black overflow-hidden select-none font-sans touch-none"
        onTouchMove={handleTouchMove}
        onMouseMove={handleTouchMove} 
    >
      <video ref={videoRef} autoPlay playsInline className="absolute inset-0 w-full h-full object-cover opacity-80" />

      {/* Cinematic Vignette */}
      <div className="absolute inset-0 pointer-events-none bg-[radial-gradient(circle_at_center,transparent_0%,rgba(0,0,0,0.6)_100%)]"></div>

      {flashTriggered && <div className="absolute inset-0 bg-white z-[60] animate-flash pointer-events-none"></div>}

      {/* === MANUAL MODE RETICLE === */}
      {scanMode === 'MANUAL' && !isAnalyzing && (
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
              <div className="w-72 h-72 relative flex items-center justify-center">

                  {/* Outer Technical Brackets (SVG) */}
                  <svg className="absolute inset-0 w-full h-full text-white/40 drop-shadow-[0_0_10px_rgba(255,255,255,0.2)]" viewBox="0 0 100 100" fill="none" stroke="currentColor" strokeWidth="1">
                      {/* Top Left */}
                      <path d="M 10 30 L 10 10 L 30 10" />
                      {/* Top Right */}
                      <path d="M 70 10 L 90 10 L 90 30" />
                      {/* Bottom Right */}
                      <path d="M 90 70 L 90 90 L 70 90" />
                      {/* Bottom Left */}
                      <path d="M 30 90 L 10 90 L 10 70" />

                      {/* Decorative notches */}
                      <rect x="48" y="2" width="4" height="2" fill="currentColor" opacity="0.8" />
                      <rect x="48" y="96" width="4" height="2" fill="currentColor" opacity="0.8" />
                      <rect x="2" y="48" width="2" height="4" fill="currentColor" opacity="0.8" />
                      <rect x="96" y="48" width="2" height="4" fill="currentColor" opacity="0.8" />
                  </svg>

                  {/* Inner Rotating Ring */}
                  <div className="absolute inset-4 border border-dashed border-white/20 rounded-full animate-[spin_10s_linear_infinite]"></div>

                  {/* Center Crosshair */}
                  <div className="absolute w-4 h-4">
                      <div className="absolute top-1/2 left-0 w-full h-px bg-white/50"></div>
                      <div className="absolute left-1/2 top-0 h-full w-px bg-white/50"></div>
                  </div>

                  {/* Searching Scan Line */}
                  <div className="absolute top-10 bottom-10 left-10 right-10 overflow-hidden opacity-30">
                      <div className="w-full h-0.5 bg-blue-400 shadow-[0_0_15px_rgba(59,130,246,1)] animate-[scanline_2s_ease-in-out_infinite]"></div>
                  </div>
              </div>
          </div>
      )}

      {/* === PASSPORT OVERLAY === */}
      {scanMode === 'PASSPORT' && !isAnalyzing && (
          <div className="absolute top-[20%] left-0 right-0 z-30 flex justify-center pointer-events-none">
               <div className="bg-black/60 backdrop-blur-xl border border-white/10 px-8 py-4 rounded-full text-center animate-in slide-in-from-top-4 shadow-2xl flex items-center gap-4">
                   <div className="w-8 h-8 rounded-full bg-blue-500/20 flex items-center justify-center border border-blue-500">
                       <span className="text-blue-400 font-mono font-bold text-xs">{passportStep + 1}</span>
                   </div>
                   <div className="text-left">
                       <h3 className="text-white font-bold text-xs tracking-[0.2em] uppercase">{PASSPORT_STEPS[passportStep].label}</h3>
                       <p className="text-zinc-400 text-[10px] uppercase font-mono mt-0.5">{PASSPORT_STEPS[passportStep].instruction}</p>
                   </div>
               </div>
          </div>
      )}

      {/* === LOADING STATE === */}
      {isAnalyzing && (
          <div className="absolute inset-0 z-[100] bg-black/95 backdrop-blur-xl flex flex-col items-center justify-center p-8 animate-in fade-in duration-500">
              <div className="relative w-24 h-24 mb-8">
                  <div className="absolute inset-0 rounded-full border-t-2 border-emerald-500 animate-spin"></div>
                  <div className="absolute inset-2 rounded-full border-r-2 border-blue-500 animate-[spin_1.5s_linear_infinite_reverse]"></div>
                  <div className="absolute inset-0 flex items-center justify-center font-mono text-xs text-white animate-pulse">AI</div>
              </div>
              <h3 className="font-display text-2xl text-white tracking-[0.2em] mb-2">PROCESSING</h3>
              <p className="text-zinc-500 font-mono text-[10px] uppercase tracking-widest">Decrypting Visual Vectors...</p>
          </div>
      )}

      {!isAnalyzing && (
        <>
            {/* Live Mode HUD */}
            {scanMode === 'LIVE' && (
                <>
                    {/* Dynamic Reticle based on Lens */}
                    <div 
                        className={`absolute w-64 h-64 transition-all duration-300 ease-[cubic-bezier(0.34,1.56,0.64,1)] pointer-events-none z-30 flex items-center justify-center
                        ${activeLens === 'FORENSICS' ? 'scale-110' : 'scale-100'}
                        `}
                        style={{ left: `${loupePosition.x}%`, top: `${loupePosition.y}%`, transform: 'translate(-50%, -50%)' }}
                    >
                         {/* LENS: IDENTITY (Precision) */}
                         {activeLens === 'IDENTITY' && (
                             <>
                                <div className={`absolute inset-0 border-2 rounded-xl transition-colors duration-300 ${liveData?.status === 'LOCKED' ? 'border-emerald-500 bg-emerald-500/5' : 'border-blue-400/50'}`}></div>
                                <div className="absolute -top-1 -left-1 w-3 h-3 border-t-2 border-l-2 border-blue-400"></div>
                                <div className="absolute -top-1 -right-1 w-3 h-3 border-t-2 border-r-2 border-blue-400"></div>
                                <div className="absolute -bottom-1 -left-1 w-3 h-3 border-b-2 border-l-2 border-blue-400"></div>
                                <div className="absolute -bottom-1 -right-1 w-3 h-3 border-b-2 border-r-2 border-blue-400"></div>
                                {/* Center Ring */}
                                <div className={`w-12 h-12 rounded-full border border-dashed transition-all duration-500 ${liveData?.status === 'LOCKED' ? 'border-emerald-400 scale-125' : 'border-white/50 animate-[spin_8s_linear_infinite]'}`}></div>
                             </>
                         )}

                         {/* LENS: MARKET (Data) */}
                         {activeLens === 'MARKET' && (
                             <>
                                <div className="absolute inset-0 border border-green-500/30 rounded-sm"></div>
                                <div className="absolute top-0 left-0 right-0 h-1 bg-green-500/50"></div>
                                <div className="absolute bottom-0 left-0 right-0 h-1 bg-green-500/50"></div>
                                <div className="absolute left-2 top-2 text-[8px] font-mono text-green-400">VALUATION_MATRIX</div>
                                <div className="absolute inset-0 flex items-center justify-center">
                                    <div className="w-full h-px bg-green-500/20"></div>
                                    <div className="h-full w-px bg-green-500/20"></div>
                                </div>
                             </>
                         )}

                         {/* LENS: FORENSICS (Heat/Radar) */}
                         {activeLens === 'FORENSICS' && (
                             <>
                                <div className="absolute inset-0 rounded-full border border-amber-500/30"></div>
                                <div className="absolute inset-2 rounded-full border border-dashed border-amber-500/50 animate-[spin_4s_linear_infinite]"></div>
                                {/* Radar Sweep */}
                                <div className="absolute inset-0 rounded-full bg-[conic-gradient(from_0deg,transparent_0deg,rgba(245,158,11,0.2)_360deg)] animate-[spin_2s_linear_infinite]"></div>
                                <div className="absolute w-2 h-2 bg-red-500 rounded-full shadow-[0_0_10px_red] top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 animate-pulse"></div>
                             </>
                         )}

                         {/* LENS: DECIPHER (Text) */}
                         {activeLens === 'DECIPHER' && (
                             <>
                                <div className="absolute inset-x-0 top-0 h-8 border-b border-purple-500/50 bg-purple-500/10"></div>
                                <div className="absolute inset-x-0 bottom-0 h-8 border-t border-purple-500/50 bg-purple-500/10"></div>
                                <div className="absolute inset-0 flex flex-col justify-center gap-2 opacity-30">
                                    <div className="w-full h-1 bg-purple-400"></div>
                                    <div className="w-3/4 h-1 bg-purple-400"></div>
                                    <div className="w-5/6 h-1 bg-purple-400"></div>
                                </div>
                             </>
                         )}

                         {/* Confidence Badge (Live) */}
                         {liveData && liveData.status !== 'SEARCHING' && (
                             <div className="absolute -bottom-10 left-1/2 -translate-x-1/2 flex flex-col items-center">
                                 <div className={`px-2 py-1 rounded bg-black/80 backdrop-blur border text-[9px] font-mono font-bold uppercase tracking-widest ${liveData.status === 'LOCKED' ? 'border-emerald-500 text-emerald-400' : 'border-white/20 text-white'}`}>
                                     {liveData.status === 'LOCKED' ? 'TARGET LOCKED' : 'ANALYZING...'}
                                 </div>
                                 {liveData.shortTitle && (
                                     <div className="mt-1 text-[10px] font-bold text-white bg-black/50 px-2 py-0.5 rounded">
                                         {liveData.shortTitle}
                                     </div>
                                 )}
                             </div>
                         )}
                    </div>
                </>
            )}

            {/* Top Controls: Mode Switcher & Sound */}
            <div className="absolute top-0 left-0 right-0 p-6 pt-[calc(20px+env(safe-area-inset-top))] flex justify-between items-center z-40 bg-gradient-to-b from-black/80 to-transparent pointer-events-none">
                <div className="pointer-events-auto bg-black/50 backdrop-blur-md rounded-full border border-white/10 p-0.5 flex relative">
                    {/* Active Pill Background */}
                    <div 
                        className="absolute top-0.5 bottom-0.5 rounded-full bg-white transition-all duration-300 shadow-[0_0_10px_rgba(255,255,255,0.3)]"
                        style={{
                            left: scanMode === 'MANUAL' ? '2px' : scanMode === 'LIVE' ? '33%' : '66%',
                            width: '32%',
                            transform: scanMode === 'MANUAL' ? 'translateX(0)' : scanMode === 'LIVE' ? 'translateX(0)' : 'translateX(-2px)'
                        }}
                    ></div>

                    {(['MANUAL', 'LIVE', 'PASSPORT'] as ScanMode[]).map(m => (
                        <button 
                            key={m}
                            onClick={() => switchMode(m)}
                            className={`relative px-4 py-2 text-[10px] font-bold rounded-full transition-colors z-10 w-20 text-center tracking-wide ${scanMode === m ? 'text-black' : 'text-zinc-400 hover:text-white'}`}
                        >
                            {m}
                        </button>
                    ))}
                </div>

                <button onClick={toggleSound} className="pointer-events-auto w-10 h-10 rounded-full bg-black/40 backdrop-blur-md border border-white/10 flex items-center justify-center text-zinc-400 hover:text-white transition-colors">
                    {soundEnabled ? <Volume2 size={16} /> : <VolumeX size={16} />}
                </button>
            </div>

            {/* Bottom Controls */}
            <div className="absolute bottom-24 left-0 right-0 z-40 flex flex-col items-center gap-8">

                {/* Lenses (Live Mode) */}
                {scanMode === 'LIVE' && (
                    <div className="flex gap-4 overflow-x-auto px-6 py-2 pb-4 scrollbar-hide max-w-full mask-linear-fade">
                        {LENSES.map((lens) => (
                            <button 
                                key={lens.id}
                                onClick={() => { setActiveLens(lens.id); soundManager.playClick(); }}
                                className={`flex flex-col items-center gap-2 transition-all ${activeLens === lens.id ? 'opacity-100 scale-110' : 'opacity-40 hover:opacity-70'}`}
                            >
                                <div className={`w-10 h-10 rounded-full flex items-center justify-center border transition-all ${activeLens === lens.id ? 'bg-white text-black border-white shadow-[0_0_15px_rgba(255,255,255,0.3)]' : 'bg-black/50 text-white border-white/30'}`}>
                                    <lens.icon size={16} />
                                </div>
                                <span className="text-[9px] font-bold tracking-widest uppercase text-white shadow-black drop-shadow-md">{lens.label}</span>
                            </button>
                        ))}
                    </div>
                )}

                <div className="flex items-center gap-8 w-full justify-center px-10">

                    {/* Gallery Import */}
                    <button 
                        onClick={() => { soundManager.playClick(); fileInputRef.current?.click(); }}
                        className="w-14 h-14 rounded-full bg-zinc-900/80 backdrop-blur border border-white/10 flex items-center justify-center text-zinc-400 hover:text-white hover:bg-zinc-800 transition-all active:scale-95"
                    >
                        <ImageIcon size={20} />
                    </button>

                    {/* Shutter Button */}
                    <button 
                        onClick={handleCapture}
                        className="relative w-24 h-24 flex items-center justify-center group"
                    >
                        <div className="absolute inset-0 rounded-full border border-white/20 scale-100 group-hover:scale-110 transition-transform duration-500"></div>
                        <div className="absolute inset-1 rounded-full border border-white/10"></div>
                        <div className={`w-20 h-20 rounded-full flex items-center justify-center transition-all duration-200 active:scale-90 shadow-[0_0_30px_rgba(255,255,255,0.1)] ${scanMode === 'PASSPORT' ? 'bg-blue-600 shadow-blue-900/50' : scanMode === 'LIVE' ? 'bg-amber-500 shadow-amber-900/50' : 'bg-white'}`}>
                            {scanMode === 'PASSPORT' && (
                                <div className="text-white text-[10px] font-bold">{passportStep + 1}/3</div>
                            )}
                        </div>
                    </button>

                    {/* Passport Stack Manager */}
                    <button 
                        onClick={handleClearBatch}
                        disabled={capturedImages.length === 0}
                        className={`w-14 h-14 rounded-full flex items-center justify-center transition-all border
                            ${capturedImages.length > 0 
                                ? 'bg-zinc-900 text-white border-white/30 hover:border-red-500 hover:text-red-500' 
                                : 'bg-zinc-900/50 text-zinc-700 border-white/5 cursor-default'
                            }`}
                    >
                        {capturedImages.length > 0 ? (
                            <div className="relative w-full h-full flex items-center justify-center group">
                                <div className="absolute inset-0.5 rounded-full overflow-hidden opacity-50 group-hover:opacity-20 transition-opacity">
                                    <img src={capturedImages[capturedImages.length-1]} className="w-full h-full object-cover" />
                                </div>
                                <div className="relative z-10 flex flex-col items-center">
                                     <Layers size={16} />
                                     <span className="text-[9px] font-bold mt-0.5">{capturedImages.length}</span>
                                </div>
                            </div>
                        ) : (
                            <Layers size={20} />
                        )}
                    </button>
                </div>
            </div>
        </>
      )}
      <input type="file" multiple accept="image/*" ref={fileInputRef} className="hidden" onChange={handleGallerySelect} />
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { CollectionItem } from '../types';
import { Search, Trash2, ArrowRight, ShieldCheck, ShieldAlert, Shield, Grip, List, Database, Lock, SlidersHorizontal, ArrowDownWideNarrow, ArrowUpNarrowWide, Clock, DollarSign, ALargeSmall, Filter, Check, X, ScanLine, Plus } from 'lucide-react';
import { soundManager } from '../services/soundService';
import { toast } from './Toast';

interface CollectionManagerProps {
  items: CollectionItem[];
  onDelete: (id: string) => void;
  onSelect: (item: CollectionItem) => void;
  onAddItem: () => void;
}

type SortOption = 'RECENT' | 'VALUE_HIGH' | 'VALUE_LOW' | 'ALPHA';

interface FilterState {
    minCondition: number;
    eras: string[];
    origins: string[];
}

export const CollectionManager: React.FC<CollectionManagerProps> = ({ items, onDelete, onSelect, onAddItem }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('list');
  const [sortBy, setSortBy] = useState<SortOption>('RECENT');
  const [showSortMenu, setShowSortMenu] = useState(false);

  // Filter State
  const [showFilterMenu, setShowFilterMenu] = useState(false);
  const [filters, setFilters] = useState<FilterState>({
      minCondition: 0,
      eras: [],
      origins: []
  });

  const totalValue = items.reduce((sum, item) => sum + item.valuation.mid, 0);

  // Derived Options for Filters
  const availableEras = useMemo(() => Array.from(new Set(items.map(i => i.era))).filter(Boolean).sort(), [items]);
  const availableOrigins = useMemo(() => Array.from(new Set(items.map(i => i.origin))).filter(Boolean).sort(), [items]);

  const activeFilterCount = (filters.minCondition > 0 ? 1 : 0) + filters.eras.length + filters.origins.length;

  // Sorting & Filtering Logic
  const filteredAndSortedItems = useMemo(() => {
      let res = items.filter(i => {
          // 1. Search Term
          const matchesSearch = i.itemName.toLowerCase().includes(searchTerm.toLowerCase()) || 
                                i.classification.toLowerCase().includes(searchTerm.toLowerCase());

          // 2. Condition Filter
          const matchesCondition = i.conditionScore >= filters.minCondition;

          // 3. Era Filter
          const matchesEra = filters.eras.length === 0 || filters.eras.includes(i.era);

          // 4. Origin Filter
          const matchesOrigin = filters.origins.length === 0 || filters.origins.includes(i.origin);

          return matchesSearch && matchesCondition && matchesEra && matchesOrigin;
      });

      return res.sort((a, b) => {
          switch (sortBy) {
              case 'VALUE_HIGH': return b.valuation.mid - a.valuation.mid;
              case 'VALUE_LOW': return a.valuation.mid - b.valuation.mid;
              case 'ALPHA': return a.itemName.localeCompare(b.itemName);
              case 'RECENT': default: return new Date(b.dateScanned).getTime() - new Date(a.dateScanned).getTime();
          }
      });
  }, [items, searchTerm, sortBy, filters]);

  const handleSortChange = (option: SortOption) => {
      soundManager.playClick();
      setSortBy(option);
      setShowSortMenu(false);
  };

  const toggleFilter = (type: 'eras' | 'origins', value: string) => {
      soundManager.playClick();
      setFilters(prev => {
          const list = prev[type];
          return {
              ...prev,
              [type]: list.includes(value) ? list.filter(v => v !== value) : [...list, value]
          };
      });
  };

  const setConditionFilter = (score: number) => {
      soundManager.playClick();
      setFilters(prev => ({ ...prev, minCondition: prev.minCondition === score ? 0 : score }));
  };

  const clearFilters = () => {
      soundManager.playClick();
      setFilters({ minCondition: 0, eras: [], origins: [] });
      toast.info("Filters Cleared");
  };

  const getSortLabel = () => {
      switch(sortBy) {
          case 'VALUE_HIGH': return 'Highest Value';
          case 'VALUE_LOW': return 'Lowest Value';
          case 'ALPHA': return 'A - Z';
          default: return 'Recently Added';
      }
  };

  const getTrustBadge = (tier: string) => {
      if (tier.includes('Level 3')) return { icon: ShieldCheck, color: 'text-emerald-500', bg: 'bg-emerald-500/10' };
      if (tier.includes('Level 2')) return { icon: Shield, color: 'text-blue-500', bg: 'bg-blue-500/10' };
      return { icon: ShieldAlert, color: 'text-amber-500', bg: 'bg-amber-500/10' };
  };

  return (
    <div className="h-full flex flex-col bg-black font-sans relative">

      {/* 1. Secure Header */}
      <div className="bg-black/90 backdrop-blur-md p-6 pt-[calc(20px+env(safe-area-inset-top))] border-b border-zinc-800 sticky top-0 z-20 shadow-lg">
        <div className="flex justify-between items-start mb-6">
          <div>
            <div className="flex items-center gap-2 mb-1">
                <Lock size={12} className="text-emerald-500" />
                <span className="text-[10px] font-mono text-emerald-500 uppercase tracking-widest">SECURE_VAULT_V4</span>
            </div>
            <h1 className="text-3xl font-display text-white tracking-wide">DATABASE</h1>
          </div>

          <div className="text-right flex flex-col items-end gap-2">
               {/* Prominent Manual Add Button */}
               <button 
                  onClick={onAddItem}
                  className="flex items-center gap-2 bg-white text-black px-4 py-2 rounded-sm hover:bg-zinc-200 transition-colors shadow-[0_0_15px_rgba(255,255,255,0.2)] group"
               >
                   <Plus size={16} className="group-hover:rotate-90 transition-transform duration-300" />
                   <span className="text-xs font-bold uppercase tracking-widest">New Asset</span>
               </button>
               <div className="flex items-center gap-2 text-zinc-500 mt-1">
                 <span className="text-[10px] uppercase tracking-widest">Total Valuation</span>
                 <span className="font-display text-lg text-white tracking-tight leading-none">${totalValue.toLocaleString()}</span>
               </div>
          </div>
        </div>

        {/* Controls */}
        <div className="flex gap-3">
          {/* Search Bar */}
          <div className="relative flex-1 group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-600 group-focus-within:text-white transition-colors" size={14} />
            <input 
              type="text" 
              placeholder="SEARCH ASSET ID..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-3 bg-zinc-900 border border-zinc-800 text-sm text-white focus:border-blue-500 focus:bg-zinc-900 outline-none placeholder:text-zinc-700 transition-all font-mono uppercase rounded-sm"
            />
          </div>

          {/* Filter Button */}
          <div className="relative">
              <button 
                  onClick={() => { setShowFilterMenu(!showFilterMenu); setShowSortMenu(false); soundManager.playClick(); }}
                  className={`h-full px-3 border flex items-center gap-2 transition-all rounded-sm relative ${showFilterMenu || activeFilterCount > 0 ? 'bg-blue-600 border-blue-500 text-white' : 'bg-zinc-900 border-zinc-800 text-zinc-400 hover:text-white'}`}
              >
                  <Filter size={16} />
                  {activeFilterCount > 0 && (
                      <span className="absolute -top-2 -right-2 w-4 h-4 bg-white text-blue-600 text-[9px] font-bold flex items-center justify-center rounded-full shadow-lg">
                          {activeFilterCount}
                      </span>
                  )}
              </button>

              {/* Filter Panel */}
              {showFilterMenu && (
                  <div className="absolute top-full right-0 mt-2 w-72 bg-zinc-900 border border-zinc-700 shadow-2xl z-50 rounded-sm overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
                      <div className="flex justify-between items-center px-4 py-3 border-b border-zinc-800">
                          <span className="text-[9px] font-bold text-zinc-400 uppercase tracking-widest">Advanced Filters</span>
                          <button onClick={clearFilters} className="text-[9px] text-zinc-500 hover:text-white uppercase tracking-wider flex items-center gap-1">
                              <X size={10} /> Clear
                          </button>
                      </div>

                      <div className="max-h-[60vh] overflow-y-auto p-4 space-y-5">
                          {/* Condition Filter */}
                          <div>
                              <div className="text-[9px] font-bold text-blue-500 uppercase tracking-widest mb-2">Min. Condition</div>
                              <div className="grid grid-cols-4 gap-2">
                                  {[
                                      { label: 'All', score: 0 },
                                      { label: 'Fair+', score: 4 },
                                      { label: 'Good+', score: 7 },
                                      { label: 'Mint', score: 9 }
                                  ].map((opt) => (
                                      <button 
                                          key={opt.score}
                                          onClick={() => setConditionFilter(opt.score)}
                                          className={`py-1.5 text-[9px] uppercase font-bold border rounded-sm transition-colors ${filters.minCondition === opt.score ? 'bg-white text-black border-white' : 'bg-black text-zinc-500 border-zinc-800 hover:border-zinc-600'}`}
                                      >
                                          {opt.label}
                                      </button>
                                  ))}
                              </div>
                          </div>

                          {/* Era Filter */}
                          {availableEras.length > 0 && (
                              <div>
                                  <div className="text-[9px] font-bold text-amber-500 uppercase tracking-widest mb-2">Historical Era</div>
                                  <div className="flex flex-wrap gap-2">
                                      {availableEras.map(era => (
                                          <button
                                              key={era}
                                              onClick={() => toggleFilter('eras', era)}
                                              className={`px-2 py-1 text-[9px] border rounded-sm transition-all flex items-center gap-1 ${filters.eras.includes(era) ? 'bg-amber-900/30 border-amber-500 text-amber-100' : 'bg-black border-zinc-800 text-zinc-500 hover:border-zinc-600'}`}
                                          >
                                              {era} {filters.eras.includes(era) && <Check size={8} />}
                                          </button>
                                      ))}
                                  </div>
                              </div>
                          )}

                          {/* Origin Filter */}
                          {availableOrigins.length > 0 && (
                              <div>
                                  <div className="text-[9px] font-bold text-emerald-500 uppercase tracking-widest mb-2">Origin / Maker</div>
                                  <div className="flex flex-wrap gap-2">
                                      {availableOrigins.map(origin => (
                                          <button
                                              key={origin}
                                              onClick={() => toggleFilter('origins', origin)}
                                              className={`px-2 py-1 text-[9px] border rounded-sm transition-all flex items-center gap-1 ${filters.origins.includes(origin) ? 'bg-emerald-900/30 border-emerald-500 text-emerald-100' : 'bg-black border-zinc-800 text-zinc-500 hover:border-zinc-600'}`}
                                          >
                                              {origin} {filters.origins.includes(origin) && <Check size={8} />}
                                          </button>
                                      ))}
                                  </div>
                              </div>
                          )}
                      </div>
                  </div>
              )}
          </div>

          {/* Sort Button */}
          <div className="relative">
              <button 
                  onClick={() => { setShowSortMenu(!showSortMenu); setShowFilterMenu(false); soundManager.playClick(); }}
                  className={`h-full px-3 border border-zinc-800 flex items-center gap-2 transition-colors rounded-sm ${showSortMenu ? 'bg-zinc-800 text-white' : 'bg-zinc-900 text-zinc-400 hover:text-white'}`}
              >
                  <SlidersHorizontal size={16} />
              </button>

              {/* Sort Dropdown */}
              {showSortMenu && (
                  <div className="absolute top-full right-0 mt-2 w-48 bg-zinc-900 border border-zinc-700 shadow-xl z-50 rounded-sm overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
                      <div className="px-3 py-2 text-[9px] font-bold text-zinc-500 uppercase tracking-widest border-b border-zinc-800">Sort Assets By</div>
                      <button onClick={() => handleSortChange('RECENT')} className={`w-full text-left px-4 py-3 text-xs flex items-center gap-2 hover:bg-zinc-800 ${sortBy === 'RECENT' ? 'text-blue-400' : 'text-zinc-300'}`}>
                          <Clock size={14} /> Recent
                      </button>
                      <button onClick={() => handleSortChange('VALUE_HIGH')} className={`w-full text-left px-4 py-3 text-xs flex items-center gap-2 hover:bg-zinc-800 ${sortBy === 'VALUE_HIGH' ? 'text-blue-400' : 'text-zinc-300'}`}>
                          <ArrowDownWideNarrow size={14} /> Value (High)
                      </button>
                      <button onClick={() => handleSortChange('VALUE_LOW')} className={`w-full text-left px-4 py-3 text-xs flex items-center gap-2 hover:bg-zinc-800 ${sortBy === 'VALUE_LOW' ? 'text-blue-400' : 'text-zinc-300'}`}>
                          <ArrowUpNarrowWide size={14} /> Value (Low)
                      </button>
                      <button onClick={() => handleSortChange('ALPHA')} className={`w-full text-left px-4 py-3 text-xs flex items-center gap-2 hover:bg-zinc-800 ${sortBy === 'ALPHA' ? 'text-blue-400' : 'text-zinc-300'}`}>
                          <ALargeSmall size={14} /> Name (A-Z)
                      </button>
                  </div>
              )}
          </div>

          {/* View Toggle */}
          <div className="flex bg-zinc-900 border border-zinc-800 rounded-sm overflow-hidden">
              <button 
                onClick={() => { setViewMode('list'); soundManager.playClick(); }}
                className={`p-3 transition-colors ${viewMode === 'list' ? 'bg-white text-black' : 'text-zinc-600 hover:text-white'}`}
              >
                  <List size={18} />
              </button>
              <div className="w-px bg-zinc-800"></div>
              <button 
                onClick={() => { setViewMode('grid'); soundManager.playClick(); }}
                className={`p-3 transition-colors ${viewMode === 'grid' ? 'bg-white text-black' : 'text-zinc-600 hover:text-white'}`}
              >
                  <Grip size={18} />
              </button>
          </div>
        </div>

        {/* Active Sort Label */}
        <div className="mt-4 flex items-center gap-2">
            <div className="h-px bg-zinc-800 flex-1"></div>
            <span className="text-[9px] font-mono text-zinc-500 uppercase tracking-widest">Sorted By: {getSortLabel()}</span>
            <div className="h-px bg-zinc-800 flex-1"></div>
        </div>
      </div>

      {/* 2. Asset Grid/List */}
      <div className="flex-1 min-h-0 overflow-auto p-4 bg-black relative">
        {/* Grid Background */}
        <div className="absolute inset-0 pointer-events-none opacity-10 bg-[linear-gradient(rgba(59,130,246,0.1)_1px,transparent_1px),linear-gradient(90deg,rgba(59,130,246,0.1)_1px,transparent_1px)] bg-[size:40px_40px]"></div>

        {filteredAndSortedItems.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-[50vh] text-zinc-800 text-center">
            <div className="w-20 h-20 rounded-full bg-zinc-900 border border-zinc-800 flex items-center justify-center mb-6">
                 <ShieldCheck size={32} className="opacity-20 text-white" />
            </div>
            <h3 className="font-display text-lg text-white mb-2">VAULT EMPTY</h3>
            <p className="font-mono text-xs text-zinc-600 max-w-xs mb-6 uppercase">No encrypted assets found in local storage. Initiate scan sequence to populate database.</p>
            {activeFilterCount > 0 ? (
                <button onClick={clearFilters} className="px-6 py-2 bg-zinc-800 text-white text-xs uppercase font-bold rounded hover:bg-zinc-700">Clear Filters</button>
            ) : (
                <div className="flex items-center gap-2 text-blue-500 text-xs font-bold animate-pulse">
                    <ScanLine size={14} /> <span>READY TO SCAN</span>
                </div>
            )}
          </div>
        ) : (
          <div className={`${viewMode === 'grid' ? 'grid grid-cols-2 gap-3' : 'flex flex-col gap-3'} relative z-10 pb-20`}>
            {filteredAndSortedItems.map((item) => {
              const Badge = getTrustBadge(item.provenance.trustTier);
              return (
              <div 
                key={item.id} 
                onClick={() => { soundManager.playClick(); onSelect(item); }}
                className={`group bg-zinc-950 border border-zinc-800 hover:border-blue-500/50 cursor-pointer transition-all duration-300 overflow-hidden relative shadow-lg
                    ${viewMode === 'list' ? 'flex h-32 rounded-sm' : 'flex flex-col rounded-sm'}
                `}
              >
                {/* Image Section */}
                <div className={`${viewMode === 'list' ? 'w-32 h-full' : 'h-40 w-full'} relative bg-zinc-900 shrink-0 overflow-hidden`}>
                  <img src={item.imageUrl} className="w-full h-full object-cover opacity-80 group-hover:opacity-100 transition-all duration-500 grayscale group-hover:grayscale-0 group-hover:scale-110" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/90 to-transparent opacity-60"></div>

                  {/* Item Count Badge */}
                  {(item.images?.length || 0) > 1 && (
                      <div className="absolute bottom-1 right-1 px-1.5 py-0.5 bg-black/60 backdrop-blur border border-white/10 text-[8px] font-bold text-white flex items-center gap-1 rounded-sm">
                          <Database size={8} /> {item.images?.length}
                      </div>
                  )}

                  {/* Category Tag */}
                  <div className="absolute top-2 left-2 px-1.5 py-0.5 bg-blue-600/20 backdrop-blur border border-blue-500/30 text-[8px] font-bold text-blue-200 uppercase tracking-wider rounded-sm">
                      {item.classification}
                  </div>
                </div>

                {/* Data Section */}
                <div className="p-4 flex-1 flex flex-col justify-between relative overflow-hidden">

                   <div>
                       <div className="flex justify-between items-start">
                           <h3 className={`font-display text-white leading-tight mb-1 group-hover:text-blue-400 transition-colors ${viewMode === 'list' ? 'text-lg' : 'text-sm line-clamp-2'}`}>
                               {item.itemName}
                           </h3>
                       </div>
                       <p className="text-[10px] text-zinc-500 font-mono uppercase tracking-wide truncate mb-2">
                           {item.era} // {item.origin}
                       </p>

                       {/* Trust Tier Indicator (Enhanced) */}
                       <div className="flex items-center gap-1.5 mt-1">
                           <div className={`p-1 rounded-full ${Badge.bg}`}>
                               <Badge.icon size={10} className={Badge.color} />
                           </div>
                           <span className={`text-[8px] uppercase tracking-widest font-bold ${Badge.color}`}>{item.provenance.trustTier.split(' ')[0]} {item.provenance.trustTier.split(' ')[1]}</span>
                       </div>
                   </div>

                   <div className="flex items-end justify-between mt-3">
                       <div>
                           <span className="text-[8px] text-zinc-600 uppercase block">Est. Market Value</span>
                           <p className="font-display text-emerald-500 text-lg shadow-emerald-500/20 drop-shadow-sm">${item.valuation.mid.toLocaleString()}</p>
                       </div>

                       <div className="flex gap-2 relative z-10">
                           <button 
                             onClick={(e) => { e.stopPropagation(); onDelete(item.id); soundManager.playClick(); }} 
                             className="p-2 rounded-sm hover:bg-red-950/50 text-zinc-600 hover:text-red-500 border border-transparent hover:border-red-900 transition-all"
                           >
                               <Trash2 size={14} />
                           </button>
                           <button className="p-2 rounded-sm bg-zinc-800 hover:bg-white text-zinc-400 hover:text-black transition-colors">
                               <ArrowRight size={14} />
                           </button>
                       </div>
                   </div>
                </div>
              </div>
            );})}
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppTab, CollectionItem, AppraisalResult } from './types';
import { Scanner } from './components/ScanTerminal';
import { CollectionManager } from './components/VaultTerminal';
import { MarketTrends } from './components/DataTerminal';
import { ItemResult } from './components/ItemResult';
import { ScanLine, Box, BarChart3, Hexagon, Loader2, Cpu, Fingerprint, Globe } from 'lucide-react';
import { soundManager } from './services/soundService';
import { ToastContainer, ToastMessage, toast } from './components/Toast';

const App: React.FC = () => {
  const [isBooting, setIsBooting] = useState(true);
  const [bootStep, setBootStep] = useState(0);

  const [activeTab, setActiveTab] = useState<AppTab>('SCAN');
  const [collection, setCollection] = useState<CollectionItem[]>([]);
  const [selectedItem, setSelectedItem] = useState<CollectionItem | null>(null);

  // Toast State
  const [toasts, setToasts] = useState<ToastMessage[]>([]);

  useEffect(() => {
    // Toast Listener
    const handleToast = (t: ToastMessage) => setToasts(prev => [...prev, t]);
    toast.listeners.add(handleToast);

    // Load Data
    const saved = localStorage.getItem('curator_collection');
    if (saved) setCollection(JSON.parse(saved));

    // Boot Sequence Simulation
    const timer1 = setTimeout(() => setBootStep(1), 500); // Modules
    const timer2 = setTimeout(() => setBootStep(2), 1200); // Network
    const timer3 = setTimeout(() => setBootStep(3), 1800); // Auth
    const timer4 = setTimeout(() => setIsBooting(false), 2400); // Complete

    return () => {
        toast.listeners.delete(handleToast);
        clearTimeout(timer1); clearTimeout(timer2); clearTimeout(timer3); clearTimeout(timer4);
    };
  }, []);

  const removeToast = (id: string) => setToasts(prev => prev.filter(t => t.id !== id));

  const saveToCollection = (result: AppraisalResult, primaryImage: string) => {
    const existingIndex = collection.findIndex(
        item => item.itemName === result.itemName && 
                item.era === result.era && 
                item.classification === result.classification
    );

    let updatedCollection = [...collection];
    let savedItem: CollectionItem;

    if (existingIndex > -1) {
        const existingItem = updatedCollection[existingIndex];
        const newImages = result.images || [primaryImage];
        const existingImages = existingItem.images || [existingItem.imageUrl];
        const combinedImages = Array.from(new Set([...existingImages, ...newImages]));

        let newTier = existingItem.provenance.trustTier;
        if (combinedImages.length >= 3) newTier = 'Level 3 (Verified)';
        else if (combinedImages.length === 2) newTier = 'Level 2 (Visual)';

        const mergedItem: CollectionItem = {
            ...existingItem,
            valuation: result.valuation, 
            forecast: result.forecast,
            condition: result.condition,
            conditionScore: result.conditionScore,
            historicalContext: result.historicalContext.length > existingItem.historicalContext.length ? result.historicalContext : existingItem.historicalContext,
            images: combinedImages,
            imageUrl: combinedImages[0],
            provenance: {
                ...existingItem.provenance,
                trustTier: newTier as any
            },
            dateScanned: new Date().toISOString()
        };

        updatedCollection[existingIndex] = mergedItem;
        updatedCollection.splice(existingIndex, 1);
        updatedCollection.unshift(mergedItem);
        savedItem = mergedItem;
        soundManager.playLock('high');
        toast.success("Asset Merged & Updated");

    } else {
        const newItem: CollectionItem = {
            ...result,
            id: crypto.randomUUID(),
            dateScanned: new Date().toISOString(),
            imageUrl: primaryImage,
            images: result.images || [primaryImage]
        };
        updatedCollection = [newItem, ...updatedCollection];
        savedItem = newItem;
        soundManager.playLock('standard');
        toast.success("New Asset Securely Vaulted");
    }

    setCollection(updatedCollection);
    localStorage.setItem('curator_collection', JSON.stringify(updatedCollection));

    setSelectedItem(savedItem);
    setActiveTab('COLLECTION');
  };

  const updateCollectionItem = (result: AppraisalResult) => {
      if (!selectedItem) return;

      const updatedItems = collection.map(item => {
          if (item.id === selectedItem.id) {
              return { 
                  ...item, 
                  ...result, 
                  images: result.images || item.images,
                  id: item.id 
              };
          }
          return item;
      });
      setCollection(updatedItems);
      localStorage.setItem('curator_collection', JSON.stringify(updatedItems));

      const updatedSelected = updatedItems.find(i => i.id === selectedItem.id);
      if (updatedSelected) setSelectedItem(updatedSelected);
      toast.success("Database Record Updated");
  };

  const deleteItem = (id: string) => {
    const updated = collection.filter(i => i.id !== id);
    setCollection(updated);
    localStorage.setItem('curator_collection', JSON.stringify(updated));
    if (selectedItem?.id === id) setSelectedItem(null);
    toast.info("Asset Purged from Vault");
  };

  const renderContent = () => {
    if (activeTab === 'COLLECTION' && selectedItem) {
        return (
            <ItemResult 
                result={selectedItem} 
                imageData={selectedItem.imageUrl} 
                onBack={() => { setSelectedItem(null); setActiveTab('COLLECTION'); }}
                onSave={updateCollectionItem} 
            />
        );
    }

    switch (activeTab) {
      case 'SCAN': return <Scanner onSave={saveToCollection} />;
      case 'COLLECTION': return (
        <CollectionManager 
            items={collection} 
            onDelete={deleteItem} 
            onSelect={setSelectedItem} 
            onAddItem={() => { setActiveTab('SCAN'); soundManager.playClick(); }}
        />
      );
      case 'MARKET': return <MarketTrends items={collection} />;
      default: return <Scanner onSave={saveToCollection} />;
    }
  };

  if (isBooting) {
      return (
          <div className="fixed inset-0 bg-black flex flex-col items-center justify-center z-[999] text-emerald-500 font-mono">
              <div className="w-64 relative">
                  <div className="flex justify-between items-end mb-2">
                      <h1 className="text-xl font-display text-white tracking-widest">CURATOR<span className="text-emerald-500">_OS</span></h1>
                      <span className="text-xs">v4.1.0</span>
                  </div>
                  <div className="h-1 bg-zinc-800 w-full mb-4 overflow-hidden">
                      <div className="h-full bg-emerald-500 animate-[loading_2.4s_ease-in-out_forwards]"></div>
                  </div>
                  <div className="space-y-1">
                      <div className={`flex items-center gap-2 text-xs transition-opacity duration-300 ${bootStep >= 0 ? 'opacity-100' : 'opacity-0'}`}>
                          <Cpu size={12} /> <span>INITIALIZING CORE...</span> <span className="text-white ml-auto">OK</span>
                      </div>
                      <div className={`flex items-center gap-2 text-xs transition-opacity duration-300 ${bootStep >= 1 ? 'opacity-100' : 'opacity-0'}`}>
                          <Globe size={12} /> <span>GEMINI VISION LINK...</span> <span className="text-white ml-auto">SECURE</span>
                      </div>
                      <div className={`flex items-center gap-2 text-xs transition-opacity duration-300 ${bootStep >= 2 ? 'opacity-100' : 'opacity-0'}`}>
